window.VLSI_DATA = {"subjects":[{"slug":"digital-electronics","title":"Digital Electronics","description":"Gates, combinational logic, sequential logic, counters, and FSM basics.","phase":1,"is_premium":false,"monthly_price_inr":0,"id":1},{"slug":"verilog-hdl","title":"Verilog HDL","description":"Synthesizable Verilog, procedural blocks, and testbench basics.","phase":1,"is_premium":false,"monthly_price_inr":0,"id":2},{"slug":"sta-basics","title":"STA Basics","description":"Timing paths, setup/hold, constraints, and slack analysis.","phase":1,"is_premium":false,"monthly_price_inr":0,"id":3},{"slug":"systemverilog-rtl","title":"SystemVerilog RTL","description":"Always_comb/ff/latch, packed types, and RTL coding style.","phase":2,"is_premium":false,"monthly_price_inr":0,"id":4},{"slug":"systemverilog-verification","title":"SystemVerilog Verification","description":"OOP, interfaces, mailboxes, constrained random, and checkers.","phase":2,"is_premium":false,"monthly_price_inr":0,"id":5},{"slug":"uvm","title":"UVM","description":"UVM architecture, sequences, drivers, monitors, scoreboards.","phase":2,"is_premium":false,"monthly_price_inr":0,"id":6},{"slug":"sva","title":"SVA Assertions","description":"Concurrent assertions, implication operators, and formal intent.","phase":2,"is_premium":false,"monthly_price_inr":0,"id":7},{"slug":"physical-design","title":"Physical Design","description":"Floorplan, placement, CTS, routing, congestion, and ECO flow.","phase":2,"is_premium":false,"monthly_price_inr":0,"id":8},{"slug":"bus-protocols","title":"Bus Protocols (AXI/APB/AHB)","description":"Handshake behavior and throughput/latency tradeoffs.","phase":2,"is_premium":false,"monthly_price_inr":0,"id":9},{"slug":"interview-core-vlsi","title":"Interview Core VLSI Pack","description":"Interview-oriented mixed rounds across RTL, STA, and verification.","phase":3,"is_premium":true,"monthly_price_inr":299,"id":10},{"slug":"interview-company-qualcomm","title":"Company Pack: Qualcomm","description":"Patterned questions and coding rounds inspired by Qualcomm style.","phase":3,"is_premium":true,"monthly_price_inr":299,"id":11},{"slug":"interview-company-nvidia-amd","title":"Company Pack: NVIDIA + AMD","description":"High-difficulty architecture and verification interview drills.","phase":3,"is_premium":true,"monthly_price_inr":299,"id":12}],"mcqs":[{"question_text":"Which assignment type should be preferred in combinational always blocks?","option_a":"Blocking (=)","option_b":"Non-blocking (\u003c=)","option_c":"Continuous assign only","option_d":"Force/release","correct_option":"A","explanation":"Blocking assignments are standard in combinational procedural logic.","difficulty":"easy","subject_id":2,"id":1},{"question_text":"What happens if a combinational always block misses a sensitivity signal in Verilog-2001?","option_a":"Compilation fails","option_b":"Simulation may mismatch synthesized logic","option_c":"Synthesis ignores the block","option_d":"Clock gets inferred","correct_option":"B","explanation":"Incomplete sensitivity can cause stale simulation outputs while synthesis infers full logic.","difficulty":"medium","subject_id":2,"id":2},{"question_text":"Which construct is synthesizable for simple mux logic?","option_a":"initial begin ... end","option_b":"forever begin ... end","option_c":"assign y = sel ? b : a;","option_d":"$display","correct_option":"C","explanation":"Continuous assignment is synthesizable for combinational mux logic.","difficulty":"easy","subject_id":2,"id":3},{"question_text":"When using non-blocking assignments in sequential logic, updates occur:","option_a":"Immediately in source order","option_b":"At the end of current simulation time step","option_c":"Only on reset","option_d":"Only in synthesis","correct_option":"B","explanation":"Non-blocking assignments schedule updates for the NBA region.","difficulty":"medium","subject_id":2,"id":4},{"question_text":"Setup slack is computed as:","option_a":"Data arrival - Data required","option_b":"Data required - Data arrival","option_c":"Launch clk - Capture clk","option_d":"Hold margin - uncertainty","correct_option":"B","explanation":"Positive setup slack means required time exceeds arrival time.","difficulty":"easy","subject_id":3,"id":5},{"question_text":"Hold checks are associated with which capture edge relative to launch?","option_a":"Previous edge","option_b":"Same active edge (minimum delay path)","option_c":"Two cycles later","option_d":"No edge relationship","correct_option":"B","explanation":"Hold verifies data is stable just after launch for same-edge capture relation.","difficulty":"medium","subject_id":3,"id":6},{"question_text":"Clock uncertainty usually affects timing by:","option_a":"Relaxing both setup and hold","option_b":"Tightening setup and hold margins","option_c":"Changing netlist functionality","option_d":"Removing false paths","correct_option":"B","explanation":"Uncertainty subtracts from available margins for robust closure.","difficulty":"medium","subject_id":3,"id":7},{"question_text":"A path declared as false path in SDC means:","option_a":"It is physically disconnected","option_b":"It is skipped for timing closure checks","option_c":"It gets extra optimization priority","option_d":"It is removed from synthesis","correct_option":"B","explanation":"False path constraints tell STA engine not to analyze that path for timing violations.","difficulty":"easy","subject_id":3,"id":8},{"question_text":"always_ff is intended for:","option_a":"Combinational logic only","option_b":"Level-sensitive latch only","option_c":"Edge-triggered sequential logic","option_d":"Assertions","correct_option":"C","explanation":"always_ff enforces sequential coding semantics around clocked blocks.","difficulty":"easy","subject_id":4,"id":9},{"question_text":"A packed struct in SystemVerilog is useful because:","option_a":"It cannot be sliced","option_b":"It maps to contiguous bits and supports bit operations","option_c":"It is only for classes","option_d":"It disables synthesis","correct_option":"B","explanation":"Packed types are bit-contiguous and synthesizable for RTL datapaths.","difficulty":"medium","subject_id":4,"id":10},{"question_text":"A mailbox is primarily used for:","option_a":"Clock gating","option_b":"Inter-process communication between testbench components","option_c":"Synthesis constraints","option_d":"Coverage closure","correct_option":"B","explanation":"Mailboxes pass transactions between generator/driver/scoreboard threads.","difficulty":"easy","subject_id":5,"id":11},{"question_text":"Constrained-random generation improves verification by:","option_a":"Eliminating all directed tests","option_b":"Exploring legal input space with variability","option_c":"Reducing simulation runtime to zero","option_d":"Making coverage unnecessary","correct_option":"B","explanation":"Randomized scenarios reveal corner cases while constraints keep them valid.","difficulty":"medium","subject_id":5,"id":12},{"question_text":"Which UVM component drives pin-level signals from sequence items?","option_a":"Monitor","option_b":"Driver","option_c":"Scoreboard","option_d":"Subscriber","correct_option":"B","explanation":"UVM driver converts transactions into interface activity.","difficulty":"easy","subject_id":6,"id":13},{"question_text":"The primary role of a scoreboard is to:","option_a":"Generate clocks","option_b":"Compare expected and actual behavior","option_c":"Compile tests","option_d":"Synthesize DUT","correct_option":"B","explanation":"Scoreboards implement functional checking and mismatch reporting.","difficulty":"easy","subject_id":6,"id":14},{"question_text":"The operator |-\u003e in SVA denotes:","option_a":"Overlapped implication","option_b":"Non-overlapped implication","option_c":"Logical OR","option_d":"Bitwise shift","correct_option":"A","explanation":"Overlapped implication starts consequent evaluation in same cycle.","difficulty":"medium","subject_id":7,"id":15},{"question_text":"assert property is typically used to:","option_a":"Collect functional coverage only","option_b":"Specify and check protocol/temporal behavior","option_c":"Declare modules","option_d":"Infer memory macros","correct_option":"B","explanation":"Assertions capture intended temporal rules and flag violations.","difficulty":"easy","subject_id":7,"id":16},{"question_text":"CTS stands for:","option_a":"Clock Timing Synthesis","option_b":"Clock Tree Synthesis","option_c":"Chip Tree Structure","option_d":"Capture Timing Setup","correct_option":"B","explanation":"CTS builds balanced clock distribution network across sinks.","difficulty":"easy","subject_id":8,"id":17},{"question_text":"Main purpose of placement legalization is to:","option_a":"Randomize cell locations","option_b":"Align cells to legal rows/sites while preserving optimization intent","option_c":"Bypass routing","option_d":"Skip DRC","correct_option":"B","explanation":"Legalization ensures placement is physically valid for downstream stages.","difficulty":"medium","subject_id":8,"id":18},{"question_text":"AXI allows which key performance feature compared to APB?","option_a":"No handshake","option_b":"Pipelined and outstanding transactions","option_c":"Single clock cycle only","option_d":"No burst support","correct_option":"B","explanation":"AXI supports high throughput via independent channels and outstanding transfers.","difficulty":"medium","subject_id":9,"id":19},{"question_text":"APB is commonly used for:","option_a":"High-bandwidth cache coherent traffic","option_b":"Simple low-bandwidth peripheral access","option_c":"GPU memory interfaces","option_d":"DDR PHY calibration","correct_option":"B","explanation":"APB targets low-complexity peripherals with simple protocol timing.","difficulty":"easy","subject_id":9,"id":20},{"question_text":"In interview timing questions, useful-skew is best described as:","option_a":"Uncontrolled random skew","option_b":"Intentional clock latency tuning to improve slack","option_c":"Jitter increase method","option_d":"Hold violation injection","correct_option":"B","explanation":"Useful skew intentionally shifts clock arrival to improve setup/hold balance.","difficulty":"hard","subject_id":10,"id":21},{"question_text":"When debugging X-propagation in RTL simulation, first practical step is:","option_a":"Increase synthesis effort","option_b":"Trace reset sequencing and uninitialized flops","option_c":"Disable assertions","option_d":"Remove clocks","correct_option":"B","explanation":"Most X issues are caused by reset or initialization gaps.","difficulty":"hard","subject_id":10,"id":22},{"question_text":"A robust CDC interview answer should include:","option_a":"Single flop synchronizer for all buses","option_b":"No need for constraints","option_c":"2-flop sync for control and protocol for multi-bit data","option_d":"Asynchronous clocks are equivalent","correct_option":"C","explanation":"Control and data require different CDC strategies to avoid corruption.","difficulty":"hard","subject_id":10,"id":23},{"question_text":"In throughput-focused SoC interview rounds, AXI bottleneck analysis should start with:","option_a":"Color theme of waveform viewer","option_b":"Channel utilization and back-pressure points","option_c":"Disabling bursts","option_d":"Removing QoS","correct_option":"B","explanation":"Utilization and stall hotspots reveal system throughput constraints.","difficulty":"hard","subject_id":11,"id":24},{"question_text":"For low-power interview scenarios, retention flop planning primarily addresses:","option_a":"Clock uncertainty","option_b":"State preservation across power gating","option_c":"Pin assignment","option_d":"IR drop signoff only","correct_option":"B","explanation":"Retention keeps critical state while domain power is off.","difficulty":"hard","subject_id":11,"id":25},{"question_text":"A practical verification interview answer for constrained random closure includes:","option_a":"Only 100% line coverage","option_b":"Functional coverage goals plus targeted test refinement","option_c":"No scoreboard required","option_d":"No seed control","correct_option":"B","explanation":"Coverage-driven refinement with checkers is key to closure quality.","difficulty":"hard","subject_id":11,"id":26},{"question_text":"For GPU-style pipelines, common interview focus is:","option_a":"Single-cycle global memory latency","option_b":"Deep pipelining and hazard management","option_c":"No clock domains","option_d":"No verification needed","correct_option":"B","explanation":"High-performance pipelines rely on deep staging and robust hazard controls.","difficulty":"hard","subject_id":12,"id":27},{"question_text":"In physical closure interviews, ECO loops are typically driven by:","option_a":"Restaurant menu","option_b":"Timing, congestion, and DRC tradeoffs","option_c":"Random net deletions","option_d":"Ignoring setup paths","correct_option":"B","explanation":"Closure needs iterative balancing of timing and manufacturability.","difficulty":"hard","subject_id":12,"id":28},{"question_text":"A strong architecture interview response on cache hierarchy should include:","option_a":"Only L1 size","option_b":"Latency, bandwidth, hit rate, and coherence implications","option_c":"No replacement policy","option_d":"No workload assumptions","correct_option":"B","explanation":"Hierarchy decisions are multi-dimensional and workload dependent.","difficulty":"hard","subject_id":12,"id":29},{"question_text":"AMBA is a bus architecture standard developed by:","option_a":"Intel","option_b":"ARM","option_c":"Xilinx","option_d":"IBM","correct_option":"B","explanation":"AMBA (Advanced Microcontroller Bus Architecture) is from ARM.","difficulty":"easy","is_premium":false,"subject_id":9,"id":30},{"question_text":"Which AMBA protocol is a high-performance, burst-capable bus?","option_a":"APB","option_b":"AHB","option_c":"UART","option_d":"SPI","correct_option":"B","explanation":"AHB is the high-bandwidth Advanced High-performance Bus.","difficulty":"easy","is_premium":false,"subject_id":9,"id":31},{"question_text":"Which AMBA protocol is a simple, low-power peripheral bus?","option_a":"AXI","option_b":"APB","option_c":"AHB","option_d":"ACE","correct_option":"B","explanation":"APB is the Advanced Peripheral Bus for low-bandwidth peripherals.","difficulty":"easy","is_premium":false,"subject_id":9,"id":32},{"question_text":"AXI stands for:","option_a":"Advanced eXtensible Interface","option_b":"Asynchronous eXternal Interface","option_c":"ARM eXpress Interconnect","option_d":"Advanced X Interconnect","correct_option":"A","explanation":"AXI is the Advanced eXtensible Interface.","difficulty":"easy","is_premium":false,"subject_id":9,"id":33},{"question_text":"How many independent channels does AXI4 have?","option_a":"1","option_b":"3","option_c":"5","option_d":"2","correct_option":"C","explanation":"AXI has 5 channels: write address, write data, write response, read address, read data.","difficulty":"medium","is_premium":false,"subject_id":9,"id":34},{"question_text":"The AXI write address channel is abbreviated:","option_a":"AR","option_b":"AW","option_c":"W","option_d":"B","correct_option":"B","explanation":"AW = write address channel.","difficulty":"easy","is_premium":false,"subject_id":9,"id":35},{"question_text":"The AXI write response channel is abbreviated:","option_a":"B","option_b":"R","option_c":"AW","option_d":"W","correct_option":"A","explanation":"B = write response channel.","difficulty":"easy","is_premium":false,"subject_id":9,"id":36},{"question_text":"The AXI read data channel is abbreviated:","option_a":"AR","option_b":"R","option_c":"W","option_d":"B","correct_option":"B","explanation":"R = read data (and read response) channel.","difficulty":"easy","is_premium":false,"subject_id":9,"id":37},{"question_text":"Each AXI channel uses which handshake?","option_a":"REQ/ACK","option_b":"VALID/READY","option_c":"START/STOP","option_d":"SCL/SDA","correct_option":"B","explanation":"AXI uses a VALID/READY handshake on every channel.","difficulty":"easy","is_premium":false,"subject_id":9,"id":38},{"question_text":"An AXI transfer occurs on the cycle when:","option_a":"VALID only is high","option_b":"Both VALID and READY are high","option_c":"READY only is high","option_d":"Neither is high","correct_option":"B","explanation":"Data moves when VALID \u0026\u0026 READY are asserted together.","difficulty":"easy","is_premium":false,"subject_id":9,"id":39},{"question_text":"In AXI, once VALID is asserted it must:","option_a":"Be deasserted immediately","option_b":"Remain asserted until the handshake (READY) completes","option_c":"Toggle every cycle","option_d":"Wait for reset","correct_option":"B","explanation":"VALID must stay high until the corresponding READY completes the transfer.","difficulty":"medium","is_premium":false,"subject_id":9,"id":40},{"question_text":"Can AXI READY be asserted before VALID?","option_a":"No, never","option_b":"Yes, READY may assert before or after VALID","option_c":"Only during reset","option_d":"Only for reads","correct_option":"B","explanation":"READY can lead or lag VALID; the transfer happens when both are high.","difficulty":"medium","is_premium":false,"subject_id":9,"id":41},{"question_text":"AXI supports out-of-order completion using:","option_a":"Burst length","option_b":"Transaction IDs (AWID/ARID/BID/RID)","option_c":"Clock gating","option_d":"Strobes","correct_option":"B","explanation":"ID tags allow responses to return out of order and be matched.","difficulty":"hard","is_premium":false,"subject_id":9,"id":42},{"question_text":"AXI burst type INCR means:","option_a":"Fixed address","option_b":"Incrementing address per beat","option_c":"Wrapping address","option_d":"Random address","correct_option":"B","explanation":"INCR increases the address by the transfer size each beat.","difficulty":"medium","is_premium":false,"subject_id":9,"id":43},{"question_text":"AXI burst type WRAP is used for:","option_a":"Streaming","option_b":"Cache line accesses that wrap at a boundary","option_c":"Fixed FIFO addresses","option_d":"Single transfers only","correct_option":"B","explanation":"WRAP bursts wrap around aligned boundaries, ideal for cache lines.","difficulty":"hard","is_premium":false,"subject_id":9,"id":44},{"question_text":"AXI burst type FIXED is used for:","option_a":"Incrementing memory","option_b":"Repeated access to the same address (e.g., a FIFO port)","option_c":"Cache fills","option_d":"Random","correct_option":"B","explanation":"FIXED keeps the same address each beat, useful for peripheral FIFOs.","difficulty":"medium","is_premium":false,"subject_id":9,"id":45},{"question_text":"AWLEN in AXI4 encodes burst length as:","option_a":"Exact number of beats","option_b":"Number of beats minus 1 (0 means 1 beat)","option_c":"Bytes","option_d":"Words times 4","correct_option":"B","explanation":"AxLEN = beats - 1; AXI4 allows up to 256 beats (LEN 0-255).","difficulty":"medium","is_premium":false,"subject_id":9,"id":46},{"question_text":"AWSIZE in AXI specifies:","option_a":"Total burst bytes","option_b":"Bytes per beat (transfer size)","option_c":"Address width","option_d":"ID width","correct_option":"B","explanation":"AxSIZE encodes the number of bytes in each beat.","difficulty":"medium","is_premium":false,"subject_id":9,"id":47},{"question_text":"WSTRB (write strobe) indicates:","option_a":"Clock enable","option_b":"Which byte lanes carry valid write data","option_c":"Burst type","option_d":"Response code","correct_option":"B","explanation":"WSTRB marks valid bytes for sparse/partial writes.","difficulty":"medium","is_premium":false,"subject_id":9,"id":48},{"question_text":"The AXI WLAST signal indicates:","option_a":"First beat","option_b":"The last beat of a write burst","option_c":"An error","option_d":"Read ready","correct_option":"B","explanation":"WLAST marks the final data beat of the write burst.","difficulty":"easy","is_premium":false,"subject_id":9,"id":49},{"question_text":"The AXI RLAST signal indicates:","option_a":"Read burst\u0027s last beat","option_b":"Write address valid","option_c":"Reset","option_d":"Strobe","correct_option":"A","explanation":"RLAST marks the last beat of a read data burst.","difficulty":"easy","is_premium":false,"subject_id":9,"id":50},{"question_text":"AXI response code OKAY means:","option_a":"Error","option_b":"Normal successful transfer","option_c":"Decode error","option_d":"Retry","correct_option":"B","explanation":"OKAY indicates a successful normal access.","difficulty":"easy","is_premium":false,"subject_id":9,"id":51},{"question_text":"AXI response SLVERR indicates:","option_a":"Success","option_b":"The slave signaled an error during the transfer","option_c":"No slave decoded","option_d":"Exclusive okay","correct_option":"B","explanation":"SLVERR is a slave error response.","difficulty":"medium","is_premium":false,"subject_id":9,"id":52},{"question_text":"AXI response DECERR indicates:","option_a":"Slave error","option_b":"No slave at the address (decode error from interconnect)","option_c":"Success","option_d":"Exclusive access okay","correct_option":"B","explanation":"DECERR means the interconnect found no slave for the address.","difficulty":"medium","is_premium":false,"subject_id":9,"id":53},{"question_text":"AXI EXOKAY response relates to:","option_a":"Normal writes","option_b":"Successful exclusive (atomic) access","option_c":"Decode error","option_d":"Reset","correct_option":"B","explanation":"EXOKAY confirms a successful exclusive access.","difficulty":"hard","is_premium":false,"subject_id":9,"id":54},{"question_text":"AXI4-Lite is a subset that:","option_a":"Adds bursts","option_b":"Supports only single (non-burst) transfers, simplifying control registers","option_c":"Removes handshakes","option_d":"Adds caching","correct_option":"B","explanation":"AXI4-Lite restricts to single transfers, ideal for register interfaces.","difficulty":"medium","is_premium":false,"subject_id":9,"id":55},{"question_text":"AXI4-Stream is designed for:","option_a":"Addressed memory","option_b":"Unidirectional data streaming without addresses","option_c":"Register access","option_d":"Cache coherence","correct_option":"B","explanation":"AXI-Stream carries continuous data flows with no address channel.","difficulty":"medium","is_premium":false,"subject_id":9,"id":56},{"question_text":"In AXI4-Stream, TLAST marks:","option_a":"First byte","option_b":"The end of a packet/frame","option_c":"An error","option_d":"Reset","correct_option":"B","explanation":"TLAST denotes the last beat of a packet boundary.","difficulty":"easy","is_premium":false,"subject_id":9,"id":57},{"question_text":"In AXI4-Stream, TKEEP/TSTRB indicate:","option_a":"Clock enable","option_b":"Which bytes are valid/are data vs position bytes","option_c":"Burst length","option_d":"ID","correct_option":"B","explanation":"TKEEP marks valid bytes; TSTRB distinguishes data vs position bytes.","difficulty":"hard","is_premium":false,"subject_id":9,"id":58},{"question_text":"ACE (AXI Coherency Extensions) adds:","option_a":"Streaming","option_b":"Hardware cache coherency support to AXI","option_c":"Low-power peripherals","option_d":"JTAG","correct_option":"B","explanation":"ACE extends AXI with snoop channels for cache coherence.","difficulty":"hard","is_premium":false,"subject_id":9,"id":59},{"question_text":"AHB transfers are pipelined into which two phases?","option_a":"Read and write","option_b":"Address phase and data phase","option_c":"Setup and access","option_d":"Idle and busy","correct_option":"B","explanation":"AHB pipelines address and data phases across cycles.","difficulty":"medium","is_premium":false,"subject_id":9,"id":60},{"question_text":"AHB HREADY signal indicates:","option_a":"Reset","option_b":"The slave is ready to complete the current transfer (extends with wait states)","option_c":"Burst type","option_d":"Error only","correct_option":"B","explanation":"HREADY low inserts wait states; high completes the transfer.","difficulty":"medium","is_premium":false,"subject_id":9,"id":61},{"question_text":"AHB HTRANS encodes:","option_a":"Data size","option_b":"Transfer type: IDLE, BUSY, NONSEQ, SEQ","option_c":"Burst length","option_d":"Response","correct_option":"B","explanation":"HTRANS distinguishes IDLE/BUSY/NONSEQ/SEQ transfers.","difficulty":"medium","is_premium":false,"subject_id":9,"id":62},{"question_text":"AHB HRESP indicates:","option_a":"Transfer type","option_b":"OKAY or ERROR response from the slave","option_c":"Burst","option_d":"Size","correct_option":"B","explanation":"HRESP signals OKAY/ERROR for the transfer.","difficulty":"easy","is_premium":false,"subject_id":9,"id":63},{"question_text":"An AHB ERROR response uses how many cycles?","option_a":"1","option_b":"A two-cycle response (to allow pipeline cleanup)","option_c":"0","option_d":"256","correct_option":"B","explanation":"AHB error is a two-cycle response giving the master time to react.","difficulty":"hard","is_premium":false,"subject_id":9,"id":64},{"question_text":"AHB arbitration is handled by the:","option_a":"Slave","option_b":"Arbiter granting bus access to one master at a time","option_c":"Decoder","option_d":"Clock","correct_option":"B","explanation":"An arbiter selects which master drives the shared AHB.","difficulty":"medium","is_premium":false,"subject_id":9,"id":65},{"question_text":"The AHB decoder is responsible for:","option_a":"Arbitration","option_b":"Selecting the target slave based on the address (HSEL)","option_c":"Clocking","option_d":"Reset","correct_option":"B","explanation":"The decoder generates HSEL to choose the addressed slave.","difficulty":"medium","is_premium":false,"subject_id":9,"id":66},{"question_text":"APB transfers complete in how many cycles minimum?","option_a":"1","option_b":"2 (setup and access phases)","option_c":"5","option_d":"256","correct_option":"B","explanation":"APB uses a setup cycle then an access cycle (min 2).","difficulty":"medium","is_premium":false,"subject_id":9,"id":67},{"question_text":"APB PSEL indicates:","option_a":"Clock","option_b":"The selected slave for the current transfer","option_c":"Burst","option_d":"Error","correct_option":"B","explanation":"PSEL selects the targeted peripheral.","difficulty":"easy","is_premium":false,"subject_id":9,"id":68},{"question_text":"APB PENABLE high marks the:","option_a":"Setup phase","option_b":"Access phase (second cycle of the transfer)","option_c":"Idle","option_d":"Reset","correct_option":"B","explanation":"PENABLE asserts during the access phase after setup.","difficulty":"medium","is_premium":false,"subject_id":9,"id":69},{"question_text":"APB PREADY is used to:","option_a":"Select a slave","option_b":"Allow the slave to extend the access with wait states","option_c":"Encode burst","option_d":"Reset","correct_option":"B","explanation":"PREADY low inserts wait states; high finishes the access.","difficulty":"medium","is_premium":false,"subject_id":9,"id":70},{"question_text":"APB PSLVERR signals:","option_a":"Success","option_b":"A peripheral error response","option_c":"Burst length","option_d":"Clock","correct_option":"B","explanation":"PSLVERR optionally indicates an error from the peripheral.","difficulty":"easy","is_premium":false,"subject_id":9,"id":71},{"question_text":"Why is APB preferred for simple peripherals over AXI?","option_a":"Higher bandwidth","option_b":"Low complexity/power, sufficient for low-throughput control registers","option_c":"Cache coherence","option_d":"Out-of-order","correct_option":"B","explanation":"APB\u0027s simplicity suits low-bandwidth register-style peripherals.","difficulty":"medium","is_premium":false,"subject_id":9,"id":72},{"question_text":"Independent read/write channels in AXI enable:","option_a":"Lower clock","option_b":"Simultaneous read and write transactions","option_c":"No bursts","option_d":"Single master only","correct_option":"B","explanation":"Separate channels let reads and writes proceed concurrently.","difficulty":"medium","is_premium":false,"subject_id":9,"id":73},{"question_text":"AXI write data interleaving across different IDs is:","option_a":"Always allowed in AXI4","option_b":"Removed in AXI4 (write data must be in order)","option_c":"Required","option_d":"Only for reads","correct_option":"B","explanation":"AXI4 removed write data interleaving; write data follows AW order.","difficulty":"hard","is_premium":false,"subject_id":9,"id":74},{"question_text":"AXI read data of different IDs may be:","option_a":"Never interleaved","option_b":"Interleaved/returned out of order using RID","option_c":"Only in order","option_d":"Combined into one","correct_option":"B","explanation":"Read data for different IDs can interleave, tagged by RID.","difficulty":"hard","is_premium":false,"subject_id":9,"id":75},{"question_text":"I2C uses how many wires?","option_a":"1","option_b":"2 (SDA and SCL)","option_c":"4","option_d":"8","correct_option":"B","explanation":"I2C is a 2-wire bus: serial data (SDA) and clock (SCL).","difficulty":"easy","is_premium":false,"subject_id":9,"id":76},{"question_text":"I2C lines are driven as:","option_a":"Push-pull","option_b":"Open-drain with pull-up resistors","option_c":"Differential","option_d":"Tri-state random","correct_option":"B","explanation":"I2C uses open-drain lines and external pull-ups (wired-AND).","difficulty":"medium","is_premium":false,"subject_id":9,"id":77},{"question_text":"An I2C START condition is:","option_a":"SCL falling","option_b":"SDA falling while SCL is high","option_c":"SDA rising while SCL high","option_d":"Both low","correct_option":"B","explanation":"START = SDA high-to-low transition while SCL is high.","difficulty":"medium","is_premium":false,"subject_id":9,"id":78},{"question_text":"An I2C STOP condition is:","option_a":"SDA rising while SCL is high","option_b":"SDA falling while SCL low","option_c":"SCL rising","option_d":"Both lines toggling","correct_option":"A","explanation":"STOP = SDA low-to-high transition while SCL is high.","difficulty":"medium","is_premium":false,"subject_id":9,"id":79},{"question_text":"I2C addressing is typically:","option_a":"32-bit","option_b":"7-bit (or 10-bit) device addresses","option_c":"No address","option_d":"64-bit","correct_option":"B","explanation":"I2C uses 7-bit (sometimes 10-bit) addresses.","difficulty":"easy","is_premium":false,"subject_id":9,"id":80},{"question_text":"After each I2C byte, the receiver sends:","option_a":"A STOP","option_b":"An ACK/NACK bit","option_c":"A reset","option_d":"A clock burst","correct_option":"B","explanation":"The 9th bit is an ACK (low) or NACK (high) from the receiver.","difficulty":"medium","is_premium":false,"subject_id":9,"id":81},{"question_text":"I2C clock stretching allows a slave to:","option_a":"Speed the clock","option_b":"Hold SCL low to pause the master until ready","option_c":"Change address","option_d":"Send STOP","correct_option":"B","explanation":"A slow slave can hold SCL low (stretch) to gain time.","difficulty":"hard","is_premium":false,"subject_id":9,"id":82},{"question_text":"I2C arbitration between multiple masters relies on:","option_a":"A central arbiter","option_b":"Wired-AND: a master driving 0 wins over one driving 1","option_c":"Clock priority","option_d":"Address size","correct_option":"B","explanation":"Multi-master I2C arbitrates by monitoring SDA; the 0-driver wins.","difficulty":"hard","is_premium":false,"subject_id":9,"id":83},{"question_text":"SPI uses which signals (basic 4-wire)?","option_a":"SDA, SCL","option_b":"SCLK, MOSI, MISO, SS/CS","option_c":"TX, RX","option_d":"D+, D-","correct_option":"B","explanation":"SPI: clock, master-out/slave-in, master-in/slave-out, chip select.","difficulty":"easy","is_premium":false,"subject_id":9,"id":84},{"question_text":"SPI is:","option_a":"Half-duplex","option_b":"Full-duplex (simultaneous send/receive)","option_c":"Simplex","option_d":"Open-drain","correct_option":"B","explanation":"SPI shifts data both directions simultaneously (full-duplex).","difficulty":"medium","is_premium":false,"subject_id":9,"id":85},{"question_text":"SPI CPOL/CPHA define:","option_a":"Address width","option_b":"Clock polarity and phase (sampling/driving edges)","option_c":"Burst length","option_d":"Chip count","correct_option":"B","explanation":"CPOL/CPHA set the idle clock level and the sampling edge (modes 0-3).","difficulty":"hard","is_premium":false,"subject_id":9,"id":86},{"question_text":"Selecting an SPI slave is done by:","option_a":"An address byte","option_b":"Asserting that slave\u0027s chip-select (usually active-low)","option_c":"A START bit","option_d":"Clock stretching","correct_option":"B","explanation":"Each slave has a dedicated CS line, typically active-low.","difficulty":"easy","is_premium":false,"subject_id":9,"id":87},{"question_text":"Compared to I2C, SPI generally offers:","option_a":"Fewer wires","option_b":"Higher throughput but more pins (per-slave CS)","option_c":"Built-in addressing","option_d":"Multi-master ease","correct_option":"B","explanation":"SPI is faster but needs more pins and lacks addressing.","difficulty":"medium","is_premium":false,"subject_id":9,"id":88},{"question_text":"UART is:","option_a":"Synchronous with a shared clock","option_b":"Asynchronous serial (no shared clock; uses start/stop bits)","option_c":"A parallel bus","option_d":"Open-drain only","correct_option":"B","explanation":"UART is asynchronous, framing data with start/stop bits.","difficulty":"easy","is_premium":false,"subject_id":9,"id":89},{"question_text":"UART framing typically includes:","option_a":"Address + burst","option_b":"Start bit, data bits, optional parity, stop bit(s)","option_c":"VALID/READY","option_d":"CS lines","correct_option":"B","explanation":"A UART frame: start, data, optional parity, stop bits.","difficulty":"easy","is_premium":false,"subject_id":9,"id":90},{"question_text":"Both UART ends must agree on:","option_a":"Chip select","option_b":"Baud rate (and framing format)","option_c":"Burst length","option_d":"Cache policy","correct_option":"B","explanation":"Matching baud rate/format is essential since there is no shared clock.","difficulty":"medium","is_premium":false,"subject_id":9,"id":91},{"question_text":"A UART parity bit is used for:","option_a":"Addressing","option_b":"Simple single-bit error detection","option_c":"Flow control","option_d":"Clocking","correct_option":"B","explanation":"Parity detects single-bit errors in a frame.","difficulty":"easy","is_premium":false,"subject_id":9,"id":92},{"question_text":"Hardware flow control in UART uses:","option_a":"SDA/SCL","option_b":"RTS/CTS signals","option_c":"MOSI/MISO","option_d":"VALID/READY","correct_option":"B","explanation":"RTS/CTS provide handshaking flow control in UART links.","difficulty":"medium","is_premium":false,"subject_id":9,"id":93},{"question_text":"PCIe is fundamentally:","option_a":"A shared parallel bus","option_b":"A point-to-point, packet-based serial interconnect (lanes)","option_c":"Open-drain","option_d":"Asynchronous UART","correct_option":"B","explanation":"PCIe uses point-to-point serial lanes with packetized transactions.","difficulty":"medium","is_premium":false,"subject_id":9,"id":94},{"question_text":"A PCIe \u0027lane\u0027 consists of:","option_a":"One wire","option_b":"Two differential pairs (TX and RX)","option_c":"Eight single-ended wires","option_d":"SDA/SCL","correct_option":"B","explanation":"Each PCIe lane has a differential transmit and receive pair.","difficulty":"medium","is_premium":false,"subject_id":9,"id":95},{"question_text":"PCIe link layers include (bottom-up):","option_a":"Application, Session, Presentation","option_b":"Physical, Data Link, Transaction layers","option_c":"MAC, LLC, IP","option_d":"APB, AHB, AXI","correct_option":"B","explanation":"PCIe has Physical, Data Link, and Transaction layers.","difficulty":"hard","is_premium":false,"subject_id":9,"id":96},{"question_text":"A TLP in PCIe is a:","option_a":"Test pattern","option_b":"Transaction Layer Packet carrying requests/completions","option_c":"Clock","option_d":"Reset","correct_option":"B","explanation":"TLPs carry read/write requests and completions at the transaction layer.","difficulty":"hard","is_premium":false,"subject_id":9,"id":97},{"question_text":"AXI interconnect connects:","option_a":"One master to one slave only","option_b":"Multiple masters and slaves with arbitration and routing","option_c":"Clocks only","option_d":"Reset trees","correct_option":"B","explanation":"The interconnect routes between multiple AXI masters and slaves.","difficulty":"medium","is_premium":false,"subject_id":9,"id":98},{"question_text":"A bus matrix (crossbar) allows:","option_a":"One transfer at a time only","option_b":"Concurrent transfers between non-conflicting master/slave pairs","option_c":"No arbitration","option_d":"Open-drain","correct_option":"B","explanation":"Crossbars enable parallel paths for different master-slave pairs.","difficulty":"hard","is_premium":false,"subject_id":9,"id":99},{"question_text":"AXI backpressure is applied by:","option_a":"Driving VALID low","option_b":"Deasserting READY to stall the sender","option_c":"Asserting WLAST","option_d":"Changing ID","correct_option":"B","explanation":"A receiver lowers READY to apply backpressure.","difficulty":"medium","is_premium":false,"subject_id":9,"id":100},{"question_text":"AXI requires the address to be associated with data via:","option_a":"A shared clock only","option_b":"Matching IDs and protocol ordering rules","option_c":"Chip select","option_d":"Parity","correct_option":"B","explanation":"ID tagging and ordering rules associate addresses, data, and responses.","difficulty":"hard","is_premium":false,"subject_id":9,"id":101},{"question_text":"An AXI exclusive access is used to implement:","option_a":"Bursts","option_b":"Atomic read-modify-write (e.g., semaphores)","option_c":"Streaming","option_d":"Clock gating","correct_option":"B","explanation":"Exclusive accesses support atomic operations like locks.","difficulty":"hard","is_premium":false,"subject_id":9,"id":102},{"question_text":"AXI QoS signals (AxQOS) are used to:","option_a":"Encode burst","option_b":"Hint priority/quality-of-service for arbitration","option_c":"Carry data","option_d":"Reset","correct_option":"B","explanation":"AxQOS provides priority hints to the interconnect.","difficulty":"hard","is_premium":false,"subject_id":9,"id":103},{"question_text":"AXI AxPROT signals encode:","option_a":"Burst length","option_b":"Access protection: privileged/secure/instruction attributes","option_c":"Response","option_d":"Strobe","correct_option":"B","explanation":"AxPROT conveys privilege, security, and data/instruction type.","difficulty":"hard","is_premium":false,"subject_id":9,"id":104},{"question_text":"AXI AxCACHE indicates:","option_a":"Cache size","option_b":"Memory attributes (bufferable, cacheable, etc.)","option_c":"Response code","option_d":"Clock","correct_option":"B","explanation":"AxCACHE specifies caching/buffering memory attributes.","difficulty":"hard","is_premium":false,"subject_id":9,"id":105},{"question_text":"Why does AXI separate address and data channels?","option_a":"To slow transfers","option_b":"To allow address issue ahead of data and improve pipelining/throughput","option_c":"To reduce pins","option_d":"For open-drain","correct_option":"B","explanation":"Decoupled channels enable outstanding transactions and pipelining.","difficulty":"medium","is_premium":false,"subject_id":9,"id":106},{"question_text":"An \u0027outstanding transaction\u0027 in AXI means:","option_a":"A completed transfer","option_b":"A transaction issued but whose response has not yet returned","option_c":"A reset","option_d":"A burst beat","correct_option":"B","explanation":"Multiple outstanding transactions can be in flight before responses arrive.","difficulty":"medium","is_premium":false,"subject_id":9,"id":107},{"question_text":"Why is a register slice/skid buffer added in AXI interconnects?","option_a":"To remove handshakes","option_b":"To pipeline VALID/READY paths for timing closure without losing data","option_c":"To add bursts","option_d":"To gate clocks","correct_option":"B","explanation":"Register slices break long handshake paths while preserving the protocol.","difficulty":"hard","is_premium":false,"subject_id":9,"id":108},{"question_text":"Wishbone is:","option_a":"An ARM bus","option_b":"An open-source SoC interconnect standard (OpenCores)","option_c":"A serial protocol","option_d":"A test interface","correct_option":"B","explanation":"Wishbone is a royalty-free open interconnect standard.","difficulty":"medium","is_premium":false,"subject_id":9,"id":109},{"question_text":"CAN bus is widely used in:","option_a":"GPUs","option_b":"Automotive/industrial networks (robust, multi-master)","option_c":"DRAM","option_d":"PCIe cards","correct_option":"B","explanation":"CAN is a robust automotive/industrial differential bus.","difficulty":"medium","is_premium":false,"subject_id":9,"id":110},{"question_text":"CAN arbitration is:","option_a":"Token-based","option_b":"Non-destructive bitwise (dominant 0 wins) using message IDs","option_c":"Central arbiter","option_d":"Random","correct_option":"B","explanation":"CAN uses CSMA/CD with bitwise arbitration; the dominant bit wins.","difficulty":"hard","is_premium":false,"subject_id":9,"id":111},{"question_text":"A key advantage of differential signaling (e.g., LVDS, CAN, PCIe) is:","option_a":"Fewer wires","option_b":"Common-mode noise rejection and higher speed","option_c":"Open-drain simplicity","option_d":"No clock","correct_option":"B","explanation":"Differential pairs reject common-mode noise, enabling high speeds.","difficulty":"medium","is_premium":false,"subject_id":9,"id":112},{"question_text":"Why does AXI mandate VALID must not depend on READY?","option_a":"For lower power","option_b":"To prevent combinational deadlock loops in the handshake","option_c":"To add bursts","option_d":"For addressing","correct_option":"B","explanation":"VALID must not wait on READY to avoid a circular dependency deadlock.","difficulty":"hard","is_premium":false,"subject_id":9,"id":113},{"question_text":"However, AXI allows READY to depend on VALID, which means:","option_a":"Deadlock","option_b":"A slave may wait to see VALID before asserting READY (legal)","option_c":"Illegal","option_d":"Burst error","correct_option":"B","explanation":"READY depending on VALID is permitted and common.","difficulty":"hard","is_premium":false,"subject_id":9,"id":114},{"question_text":"An unaligned AXI transfer is handled using:","option_a":"Bursts only","option_b":"WSTRB byte lane strobes to select valid bytes","option_c":"Clock gating","option_d":"IDs","correct_option":"B","explanation":"Strobes enable correct byte placement for unaligned/partial writes.","difficulty":"hard","is_premium":false,"subject_id":9,"id":115},{"question_text":"Burst boundary rule in AXI: a burst must not cross:","option_a":"Any boundary","option_b":"A 4KB address boundary","option_c":"A 1-byte boundary","option_d":"A cache line only","correct_option":"B","explanation":"AXI bursts cannot cross a 4KB boundary (page protection).","difficulty":"hard","is_premium":false,"subject_id":9,"id":116},{"question_text":"Why the 4KB burst boundary restriction?","option_a":"For clocking","option_b":"It aligns with typical memory page size, simplifying address decode/protection","option_c":"For parity","option_d":"For chip select","correct_option":"B","explanation":"4KB matches common page granularity for decode and protection.","difficulty":"hard","is_premium":false,"subject_id":9,"id":117},{"question_text":"A bridge between AXI and APB is used to:","option_a":"Speed APB","option_b":"Convert high-performance AXI transactions to simple APB peripheral accesses","option_c":"Add coherence","option_d":"Generate clocks","correct_option":"B","explanation":"An AXI-to-APB bridge adapts the fast bus to simple peripherals.","difficulty":"medium","is_premium":false,"subject_id":9,"id":118},{"question_text":"AHB-Lite differs from full AHB by:","option_a":"Adding more masters","option_b":"Supporting a single master (no arbitration needed)","option_c":"Removing data phase","option_d":"Adding coherence","correct_option":"B","explanation":"AHB-Lite simplifies to one master, dropping arbitration complexity.","difficulty":"medium","is_premium":false,"subject_id":9,"id":119},{"question_text":"A \u0027split\u0027 or \u0027retry\u0027 response in classic AHB lets a slave:","option_a":"Speed the clock","option_b":"Release the bus and complete later, improving utilization","option_c":"Change address","option_d":"Add parity","correct_option":"B","explanation":"SPLIT/RETRY free the bus for other masters while a slow slave works.","difficulty":"hard","is_premium":false,"subject_id":9,"id":120},{"question_text":"Why use IDs to enforce ordering only within the same ID in AXI?","option_a":"To slow transfers","option_b":"Same-ID transactions stay ordered while different IDs can reorder for performance","option_c":"For parity","option_d":"For clocking","correct_option":"B","explanation":"Per-ID ordering balances correctness with out-of-order performance.","difficulty":"hard","is_premium":false,"subject_id":9,"id":121},{"question_text":"A common AXI master verification check is that responses match:","option_a":"Random IDs","option_b":"The IDs and order rules of issued requests","option_c":"Clock edges","option_d":"Parity","correct_option":"B","explanation":"Responses must correlate to request IDs and obey ordering rules.","difficulty":"medium","is_premium":false,"subject_id":9,"id":122},{"question_text":"Why is APB write data driven in the same cycle as PENABLE?","option_a":"For bursts","option_b":"APB is simple/non-pipelined; data is stable during the access phase","option_c":"For coherence","option_d":"For streaming","correct_option":"B","explanation":"APB\u0027s simple two-phase model holds data stable in the access phase.","difficulty":"medium","is_premium":false,"subject_id":9,"id":123},{"question_text":"Which protocol best fits a high-bandwidth DMA to DRAM?","option_a":"APB","option_b":"AXI (bursts, outstanding, separate R/W)","option_c":"UART","option_d":"I2C","correct_option":"B","explanation":"AXI\u0027s bursts and outstanding transactions suit high-throughput memory access.","difficulty":"medium","is_premium":false,"subject_id":9,"id":124},{"question_text":"Which protocol best fits reading a temperature sensor occasionally?","option_a":"AXI","option_b":"I2C (simple, few wires, low speed)","option_c":"PCIe","option_d":"AXI-Stream","correct_option":"B","explanation":"I2C\u0027s simplicity suits low-rate sensor reads.","difficulty":"easy","is_premium":false,"subject_id":9,"id":125},{"question_text":"Which protocol best fits continuous video pixel streaming on-chip?","option_a":"APB","option_b":"AXI4-Stream (no addresses, continuous data)","option_c":"I2C","option_d":"UART","correct_option":"B","explanation":"AXI-Stream is designed for continuous, address-less data flows like video.","difficulty":"medium","is_premium":false,"subject_id":9,"id":126},{"question_text":"The fundamental reason buses use handshaking is to:","option_a":"Increase clock","option_b":"Coordinate producers and consumers running at different rates safely","option_c":"Add parity","option_d":"Reduce wires","correct_option":"B","explanation":"Handshakes provide flow control between elements of differing speeds.","difficulty":"easy","is_premium":false,"subject_id":9,"id":127},{"question_text":"AXI default burst ordering for a WRAP read returns the critical word:","option_a":"Last","option_b":"First (critical-word-first), then wraps to fill the line","option_c":"Never","option_d":"In random order","correct_option":"B","explanation":"WRAP bursts deliver the requested (critical) word first to reduce CPU stall.","difficulty":"hard","is_premium":false,"subject_id":9,"id":128},{"question_text":"Compared to a shared bus, a point-to-point link offers:","option_a":"More contention","option_b":"Dedicated bandwidth and easier timing closure at higher speeds","option_c":"Fewer pins always","option_d":"No need for protocol","correct_option":"B","explanation":"Point-to-point links avoid shared-bus contention and ease high-speed timing.","difficulty":"medium","is_premium":false,"subject_id":9,"id":129},{"question_text":"The decimal value of binary 1011 is:","option_a":"9","option_b":"11","option_c":"13","option_d":"15","correct_option":"B","explanation":"1011 = 8+0+2+1 = 11.","difficulty":"easy","is_premium":false,"subject_id":1,"id":130},{"question_text":"How many bits are needed to represent decimal 255?","option_a":"6","option_b":"7","option_c":"8","option_d":"9","correct_option":"C","explanation":"255 = 2^8 - 1, needs 8 bits.","difficulty":"easy","is_premium":false,"subject_id":1,"id":131},{"question_text":"The hexadecimal equivalent of binary 11110000 is:","option_a":"0F","option_b":"F0","option_c":"FF","option_d":"00","correct_option":"B","explanation":"1111=F, 0000=0, so F0.","difficulty":"easy","is_premium":false,"subject_id":1,"id":132},{"question_text":"Gray code is primarily used because:","option_a":"It is faster to add","option_b":"Only one bit changes between consecutive values","option_c":"It uses fewer bits","option_d":"It is decimal based","correct_option":"B","explanation":"Single-bit transitions reduce errors in position encoders.","difficulty":"easy","is_premium":false,"subject_id":1,"id":133},{"question_text":"The 2\u0027s complement of 0101 (4-bit) is:","option_a":"1010","option_b":"1011","option_c":"1101","option_d":"0011","correct_option":"B","explanation":"Invert to 1010, add 1 -\u003e 1011.","difficulty":"easy","is_premium":false,"subject_id":1,"id":134},{"question_text":"BCD code 1001 represents decimal:","option_a":"7","option_b":"8","option_c":"9","option_d":"Invalid","correct_option":"C","explanation":"1001 = 9, a valid BCD digit.","difficulty":"easy","is_premium":false,"subject_id":1,"id":135},{"question_text":"Which BCD value is invalid?","option_a":"0111","option_b":"1001","option_c":"1010","option_d":"0000","correct_option":"C","explanation":"BCD digits range 0-9; 1010 = 10 is invalid.","difficulty":"easy","is_premium":false,"subject_id":1,"id":136},{"question_text":"Excess-3 code of decimal 5 is:","option_a":"0101","option_b":"1000","option_c":"0111","option_d":"1001","correct_option":"B","explanation":"5 + 3 = 8 = 1000.","difficulty":"medium","is_premium":false,"subject_id":1,"id":137},{"question_text":"Which gate is known as a universal gate?","option_a":"AND","option_b":"OR","option_c":"NAND","option_d":"XOR","correct_option":"C","explanation":"NAND (and NOR) can implement any Boolean function.","difficulty":"easy","is_premium":false,"subject_id":1,"id":138},{"question_text":"The output of a 2-input XOR gate is high when:","option_a":"Both inputs are 0","option_b":"Both inputs are 1","option_c":"Inputs are different","option_d":"Inputs are equal","correct_option":"C","explanation":"XOR outputs 1 only when inputs differ.","difficulty":"easy","is_premium":false,"subject_id":1,"id":139},{"question_text":"A NOR gate output is 1 only when:","option_a":"All inputs are 1","option_b":"All inputs are 0","option_c":"Any input is 1","option_d":"Inputs differ","correct_option":"B","explanation":"NOR is OR followed by NOT, so high only when all inputs are 0.","difficulty":"easy","is_premium":false,"subject_id":1,"id":140},{"question_text":"According to De Morgan\u0027s theorem, (A.B)\u0027 equals:","option_a":"A\u0027.B\u0027","option_b":"A\u0027+B\u0027","option_c":"A+B","option_d":"A.B","correct_option":"B","explanation":"(A.B)\u0027 = A\u0027 + B\u0027.","difficulty":"easy","is_premium":false,"subject_id":1,"id":141},{"question_text":"The Boolean expression A + A\u0027B simplifies to:","option_a":"A","option_b":"B","option_c":"A + B","option_d":"A\u0027B","correct_option":"C","explanation":"A + A\u0027B = A + B by absorption.","difficulty":"medium","is_premium":false,"subject_id":1,"id":142},{"question_text":"A.(A + B) simplifies to:","option_a":"A","option_b":"B","option_c":"A + B","option_d":"A.B","correct_option":"A","explanation":"Absorption law: A.(A+B) = A.","difficulty":"medium","is_premium":false,"subject_id":1,"id":143},{"question_text":"The dual of the expression A + 0 = A is:","option_a":"A . 1 = A","option_b":"A + 1 = 1","option_c":"A . 0 = 0","option_d":"A + A = A","correct_option":"A","explanation":"Dual swaps + with . and 0 with 1: A.1 = A.","difficulty":"medium","is_premium":false,"subject_id":1,"id":144},{"question_text":"How many 2-input NAND gates are needed to implement an inverter?","option_a":"1","option_b":"2","option_c":"3","option_d":"4","correct_option":"A","explanation":"Tie both NAND inputs together to invert.","difficulty":"easy","is_premium":false,"subject_id":1,"id":145},{"question_text":"The expression XY + XY\u0027 equals:","option_a":"X","option_b":"Y","option_c":"X + Y","option_d":"0","correct_option":"A","explanation":"X(Y+Y\u0027) = X.1 = X.","difficulty":"easy","is_premium":false,"subject_id":1,"id":146},{"question_text":"An XNOR gate is also called:","option_a":"Inequality detector","option_b":"Equality detector","option_c":"Universal gate","option_d":"Buffer","correct_option":"B","explanation":"XNOR outputs 1 when inputs are equal.","difficulty":"easy","is_premium":false,"subject_id":1,"id":147},{"question_text":"In a K-map, a group of 4 adjacent 1s eliminates how many variables?","option_a":"1","option_b":"2","option_c":"3","option_d":"4","correct_option":"B","explanation":"Group of 2^n eliminates n variables; 4 -\u003e 2.","difficulty":"easy","is_premium":false,"subject_id":1,"id":148},{"question_text":"A \u0027don\u0027t care\u0027 condition in a K-map can be treated as:","option_a":"Always 0","option_b":"Always 1","option_c":"Either 0 or 1 to simplify","option_d":"Ignored entirely","correct_option":"C","explanation":"Don\u0027t cares are used flexibly to enlarge groups.","difficulty":"easy","is_premium":false,"subject_id":1,"id":149},{"question_text":"A prime implicant that covers a minterm not covered by any other is called:","option_a":"Redundant implicant","option_b":"Essential prime implicant","option_c":"Non-prime implicant","option_d":"Don\u0027t care","correct_option":"B","explanation":"Essential prime implicants must appear in the minimal cover.","difficulty":"medium","is_premium":false,"subject_id":1,"id":150},{"question_text":"For a 4-variable K-map, the maximum group size possible is:","option_a":"4","option_b":"8","option_c":"16","option_d":"32","correct_option":"C","explanation":"All 16 cells can form one group if all are 1.","difficulty":"medium","is_premium":false,"subject_id":1,"id":151},{"question_text":"The Quine-McCluskey method is preferred over K-map when:","option_a":"Variables are few","option_b":"Number of variables is large","option_c":"Only 2 variables exist","option_d":"Output is single bit","correct_option":"B","explanation":"Tabular method scales and is automatable for many variables.","difficulty":"medium","is_premium":false,"subject_id":1,"id":152},{"question_text":"Sum-of-products (SOP) form consists of:","option_a":"ANDed sum terms","option_b":"ORed product terms","option_c":"Only NOT terms","option_d":"XOR terms","correct_option":"B","explanation":"SOP is an OR of AND (product) terms.","difficulty":"easy","is_premium":false,"subject_id":1,"id":153},{"question_text":"Minimizing F(A,B,C) = Σ(0,1,2,3) gives:","option_a":"A\u0027","option_b":"A","option_c":"B\u0027","option_d":"C","correct_option":"A","explanation":"Minterms 0-3 cover A=0 for all B,C, so F = A\u0027.","difficulty":"hard","is_premium":false,"subject_id":1,"id":154},{"question_text":"Static-1 hazard occurs when output momentarily goes:","option_a":"1 to 0 to 1 while it should stay 1","option_b":"0 to 1 to 0 while it should stay 0","option_c":"High permanently","option_d":"Tri-state","correct_option":"A","explanation":"Static-1 hazard is a brief 0 glitch in a steady-1 output.","difficulty":"hard","is_premium":false,"subject_id":1,"id":155},{"question_text":"A 2-to-1 multiplexer requires how many select lines?","option_a":"1","option_b":"2","option_c":"3","option_d":"4","correct_option":"A","explanation":"2 inputs need 1 select line.","difficulty":"easy","is_premium":false,"subject_id":1,"id":156},{"question_text":"An 8-to-1 multiplexer has how many select lines?","option_a":"2","option_b":"3","option_c":"4","option_d":"8","correct_option":"B","explanation":"2^3 = 8, so 3 select lines.","difficulty":"easy","is_premium":false,"subject_id":1,"id":157},{"question_text":"A 3-to-8 decoder activates how many outputs at a time (active high, normal operation)?","option_a":"0","option_b":"1","option_c":"3","option_d":"8","correct_option":"B","explanation":"A decoder asserts exactly one output for each input code.","difficulty":"easy","is_premium":false,"subject_id":1,"id":158},{"question_text":"The sum output of a half adder is generated by:","option_a":"AND gate","option_b":"OR gate","option_c":"XOR gate","option_d":"NAND gate","correct_option":"C","explanation":"Sum = A XOR B; carry = A AND B.","difficulty":"easy","is_premium":false,"subject_id":1,"id":159},{"question_text":"A full adder can be built using how many half adders (plus an OR gate)?","option_a":"1","option_b":"2","option_c":"3","option_d":"4","correct_option":"B","explanation":"Two half adders plus an OR for carry.","difficulty":"medium","is_premium":false,"subject_id":1,"id":160},{"question_text":"A multiplexer can implement any combinational function because it is a:","option_a":"Memory element","option_b":"Universal logic module","option_c":"Sequential block","option_d":"Clock divider","correct_option":"B","explanation":"A mux can realize a truth table by routing data/constants.","difficulty":"medium","is_premium":false,"subject_id":1,"id":161},{"question_text":"To build a 4-to-16 decoder from 3-to-8 decoders, how many are needed?","option_a":"1","option_b":"2","option_c":"3","option_d":"4","correct_option":"B","explanation":"Two 3-to-8 decoders with an enable on the MSB.","difficulty":"medium","is_premium":false,"subject_id":1,"id":162},{"question_text":"A magnitude comparator\u0027s A\u003eB output for 2-bit numbers requires:","option_a":"Only XOR gates","option_b":"Combination of AND/OR with bit comparisons","option_c":"Flip-flops","option_d":"A counter","correct_option":"B","explanation":"Comparators use bitwise compares combined with priority logic.","difficulty":"medium","is_premium":false,"subject_id":1,"id":163},{"question_text":"A priority encoder differs from a normal encoder because it:","option_a":"Has fewer inputs","option_b":"Resolves multiple active inputs by priority","option_c":"Cannot output binary","option_d":"Requires a clock","correct_option":"B","explanation":"Priority encoders select the highest-priority active input.","difficulty":"medium","is_premium":false,"subject_id":1,"id":164},{"question_text":"Carry look-ahead adders improve speed by:","option_a":"Using more flip-flops","option_b":"Computing carries in parallel","option_c":"Slowing the clock","option_d":"Serializing addition","correct_option":"B","explanation":"Generate/propagate logic computes carries without rippling.","difficulty":"hard","is_premium":false,"subject_id":1,"id":165},{"question_text":"In a carry look-ahead adder, the generate term Gi equals:","option_a":"Ai XOR Bi","option_b":"Ai OR Bi","option_c":"Ai AND Bi","option_d":"Ai NAND Bi","correct_option":"C","explanation":"Gi = Ai.Bi generates a carry regardless of carry-in.","difficulty":"hard","is_premium":false,"subject_id":1,"id":166},{"question_text":"An SR latch enters an invalid state when:","option_a":"S=0, R=0","option_b":"S=1, R=0","option_c":"S=0, R=1","option_d":"S=1, R=1","correct_option":"D","explanation":"S=R=1 is forbidden for a NOR-based SR latch.","difficulty":"easy","is_premium":false,"subject_id":1,"id":167},{"question_text":"A D flip-flop output Q after a clock edge equals:","option_a":"Previous Q","option_b":"D input","option_c":"Inverted D","option_d":"0","correct_option":"B","explanation":"D flip-flop captures D at the active edge.","difficulty":"easy","is_premium":false,"subject_id":1,"id":168},{"question_text":"The main difference between a latch and a flip-flop is:","option_a":"Latch is edge triggered","option_b":"Flip-flop is level sensitive","option_c":"Latch is level sensitive, flip-flop is edge triggered","option_d":"No difference","correct_option":"C","explanation":"Latches are level-sensitive; flip-flops are edge-triggered.","difficulty":"easy","is_premium":false,"subject_id":1,"id":169},{"question_text":"A JK flip-flop with J=K=1 will:","option_a":"Set","option_b":"Reset","option_c":"Hold","option_d":"Toggle","correct_option":"D","explanation":"J=K=1 toggles the output each clock.","difficulty":"easy","is_premium":false,"subject_id":1,"id":170},{"question_text":"A T flip-flop toggles when T equals:","option_a":"0","option_b":"1","option_c":"Z","option_d":"X","correct_option":"B","explanation":"T=1 toggles; T=0 holds.","difficulty":"easy","is_premium":false,"subject_id":1,"id":171},{"question_text":"The characteristic equation of a D flip-flop is:","option_a":"Q(next) = D","option_b":"Q(next) = Q","option_c":"Q(next) = D\u0027","option_d":"Q(next) = T XOR Q","correct_option":"A","explanation":"Next state of a D-FF equals its D input.","difficulty":"medium","is_premium":false,"subject_id":1,"id":172},{"question_text":"The characteristic equation of a JK flip-flop is:","option_a":"Q+ = JQ\u0027 + K\u0027Q","option_b":"Q+ = J\u0027Q + KQ\u0027","option_c":"Q+ = JK","option_d":"Q+ = J + K","correct_option":"A","explanation":"Q(next) = J.Q\u0027 + K\u0027.Q.","difficulty":"hard","is_premium":false,"subject_id":1,"id":173},{"question_text":"A master-slave flip-flop is used to avoid:","option_a":"Setup time","option_b":"Race-around condition","option_c":"Fan-out","option_d":"Propagation delay","correct_option":"B","explanation":"Master-slave structure prevents race-around in JK flip-flops.","difficulty":"medium","is_premium":false,"subject_id":1,"id":174},{"question_text":"Converting a JK flip-flop to a D flip-flop requires:","option_a":"J=D, K=D\u0027","option_b":"J=D, K=D","option_c":"J=K=D","option_d":"J=D\u0027, K=D","correct_option":"A","explanation":"Set J=D and K=D\u0027 to mimic a D flip-flop.","difficulty":"hard","is_premium":false,"subject_id":1,"id":175},{"question_text":"A modulo-8 counter requires how many flip-flops?","option_a":"2","option_b":"3","option_c":"4","option_d":"8","correct_option":"B","explanation":"2^3 = 8 states need 3 flip-flops.","difficulty":"easy","is_premium":false,"subject_id":1,"id":176},{"question_text":"A ripple counter is also known as:","option_a":"Synchronous counter","option_b":"Asynchronous counter","option_c":"Ring counter","option_d":"Johnson counter","correct_option":"B","explanation":"Ripple counters are asynchronous; FF clocks cascade.","difficulty":"easy","is_premium":false,"subject_id":1,"id":177},{"question_text":"An n-bit ring counter has how many valid states?","option_a":"n","option_b":"2n","option_c":"2^n","option_d":"n^2","correct_option":"A","explanation":"A ring counter cycles through n states (one-hot).","difficulty":"medium","is_premium":false,"subject_id":1,"id":178},{"question_text":"A Johnson (twisted ring) counter with n flip-flops has how many states?","option_a":"n","option_b":"2n","option_c":"2^n","option_d":"n/2","correct_option":"B","explanation":"Johnson counter provides 2n unique states.","difficulty":"medium","is_premium":false,"subject_id":1,"id":179},{"question_text":"The main advantage of a synchronous counter over ripple is:","option_a":"Fewer flip-flops","option_b":"No clock needed","option_c":"Reduced accumulated propagation delay","option_d":"Lower cost only","correct_option":"C","explanation":"All FFs share the clock, avoiding ripple delay.","difficulty":"medium","is_premium":false,"subject_id":1,"id":180},{"question_text":"A 4-bit SISO shift register takes how many clocks to output the first loaded bit?","option_a":"1","option_b":"2","option_c":"3","option_d":"4","correct_option":"D","explanation":"Serial-in serial-out 4-bit needs 4 clocks to shift out.","difficulty":"medium","is_premium":false,"subject_id":1,"id":181},{"question_text":"A decade counter counts from:","option_a":"0 to 9","option_b":"0 to 10","option_c":"0 to 15","option_d":"1 to 10","correct_option":"A","explanation":"Decade (mod-10) counts 0 through 9.","difficulty":"easy","is_premium":false,"subject_id":1,"id":182},{"question_text":"An LFSR is commonly used to generate:","option_a":"Clock signals","option_b":"Pseudo-random sequences","option_c":"Analog voltages","option_d":"Power supply","correct_option":"B","explanation":"Linear feedback shift registers produce pseudo-random patterns.","difficulty":"hard","is_premium":false,"subject_id":1,"id":183},{"question_text":"In a Mealy machine, outputs depend on:","option_a":"Present state only","option_b":"Present state and inputs","option_c":"Next state only","option_d":"Clock only","correct_option":"B","explanation":"Mealy outputs depend on state and current inputs.","difficulty":"easy","is_premium":false,"subject_id":1,"id":184},{"question_text":"In a Moore machine, outputs depend on:","option_a":"Present state only","option_b":"Inputs only","option_c":"State and inputs","option_d":"Clock edges","correct_option":"A","explanation":"Moore outputs are a function of state alone.","difficulty":"easy","is_premium":false,"subject_id":1,"id":185},{"question_text":"Compared to Moore, a Mealy machine usually needs:","option_a":"More states","option_b":"Fewer or equal states","option_c":"No states","option_d":"More clocks","correct_option":"B","explanation":"Mealy machines often need fewer states for the same function.","difficulty":"medium","is_premium":false,"subject_id":1,"id":186},{"question_text":"State minimization reduces:","option_a":"Clock frequency","option_b":"Number of redundant equivalent states","option_c":"Input count","option_d":"Output width","correct_option":"B","explanation":"Merging equivalent states reduces hardware.","difficulty":"medium","is_premium":false,"subject_id":1,"id":187},{"question_text":"One-hot state encoding uses:","option_a":"Minimum flip-flops","option_b":"One flip-flop per state","option_c":"Binary encoded states","option_d":"Gray-coded states","correct_option":"B","explanation":"One-hot dedicates a flip-flop to each state.","difficulty":"medium","is_premium":false,"subject_id":1,"id":188},{"question_text":"A glitch on a Mealy machine output most often arises from:","option_a":"Stable inputs","option_b":"Asynchronous input changes between clock edges","option_c":"Constant clock","option_d":"Power gating","correct_option":"B","explanation":"Mealy outputs can glitch when inputs change mid-cycle.","difficulty":"hard","is_premium":false,"subject_id":1,"id":189},{"question_text":"A ROM is classified as a:","option_a":"Volatile memory","option_b":"Non-volatile memory","option_c":"Register file","option_d":"Cache only","correct_option":"B","explanation":"ROM retains data without power.","difficulty":"easy","is_premium":false,"subject_id":1,"id":190},{"question_text":"A 1K x 8 ROM has how many address lines?","option_a":"8","option_b":"10","option_c":"12","option_d":"1024","correct_option":"B","explanation":"1K = 1024 = 2^10, so 10 address lines.","difficulty":"medium","is_premium":false,"subject_id":1,"id":191},{"question_text":"A PLA differs from a PROM in that a PLA has:","option_a":"Fixed AND, programmable OR","option_b":"Programmable AND and programmable OR","option_c":"Fixed AND and fixed OR","option_d":"No arrays","correct_option":"B","explanation":"PLA has both arrays programmable; PROM has fixed AND.","difficulty":"hard","is_premium":false,"subject_id":1,"id":192},{"question_text":"Static RAM stores a bit using:","option_a":"A capacitor","option_b":"A cross-coupled latch","option_c":"A fuse","option_d":"A diode","correct_option":"B","explanation":"SRAM uses cross-coupled inverters (a latch).","difficulty":"medium","is_premium":false,"subject_id":1,"id":193},{"question_text":"Setup time is the interval during which data must be stable:","option_a":"After the clock edge","option_b":"Before the clock edge","option_c":"During reset","option_d":"At power-up","correct_option":"B","explanation":"Setup time is required before the active clock edge.","difficulty":"easy","is_premium":false,"subject_id":1,"id":194},{"question_text":"Metastability in a flip-flop occurs when:","option_a":"Clock is stopped","option_b":"Setup/hold timing is violated","option_c":"Power is high","option_d":"Inputs are grounded","correct_option":"B","explanation":"Timing violations can drive a flop into a metastable state.","difficulty":"hard","is_premium":false,"subject_id":1,"id":195},{"question_text":"Tri-state buffers are mainly used to:","option_a":"Increase voltage","option_b":"Share a common bus among multiple drivers","option_c":"Generate clocks","option_d":"Store data","correct_option":"B","explanation":"High-impedance state lets multiple drivers share a bus.","difficulty":"medium","is_premium":false,"subject_id":1,"id":196},{"question_text":"Fan-out of a logic gate refers to:","option_a":"Number of inputs it has","option_b":"Number of gate inputs it can drive","option_c":"Its propagation delay","option_d":"Its supply voltage","correct_option":"B","explanation":"Fan-out is how many loads a gate output can reliably drive.","difficulty":"easy","is_premium":false,"subject_id":1,"id":197},{"question_text":"A clock divider that produces a 50% duty cycle divide-by-2 output is best built using a:","option_a":"Combinational AND gate","option_b":"T flip-flop toggling every clock","option_c":"RS latch","option_d":"Multiplexer","correct_option":"B","explanation":"A toggle flip-flop divides frequency by 2 with a clean 50% duty cycle.","difficulty":"medium","is_premium":false,"subject_id":1,"id":198},{"question_text":"Gray code is preferred for asynchronous counters crossing clock domains because:","option_a":"It is faster to add","option_b":"Only one bit changes between adjacent values","option_c":"It uses fewer bits","option_d":"It needs no flip-flops","correct_option":"B","explanation":"Single-bit transitions avoid multi-bit sampling errors during synchronization.","difficulty":"hard","is_premium":false,"subject_id":1,"id":199},{"question_text":"Setup time is the minimum time data must be stable:","option_a":"After the clock edge","option_b":"Before the active clock edge","option_c":"During reset","option_d":"Between two clocks","correct_option":"B","explanation":"Setup time is the interval before the clock edge during which data must be stable.","difficulty":"easy","is_premium":false,"subject_id":10,"id":200},{"question_text":"Hold time is the minimum time data must be stable:","option_a":"Before the clock edge","option_b":"After the active clock edge","option_c":"During power-up","option_d":"Never","correct_option":"B","explanation":"Hold time is the interval after the clock edge that data must remain stable.","difficulty":"easy","is_premium":false,"subject_id":10,"id":201},{"question_text":"Setup violations are typically fixed by:","option_a":"Increasing clock frequency","option_b":"Reducing combinational delay or relaxing the clock period","option_c":"Adding more hold buffers","option_d":"Removing flip-flops","correct_option":"B","explanation":"Setup is a max-delay problem; reduce logic delay or slow the clock.","difficulty":"medium","is_premium":false,"subject_id":10,"id":202},{"question_text":"Hold violations are typically fixed by:","option_a":"Slowing the clock","option_b":"Adding delay (buffers) on the data path","option_c":"Reducing combinational logic","option_d":"Increasing fanout","correct_option":"B","explanation":"Hold is a min-delay problem; add delay buffers on the short path.","difficulty":"medium","is_premium":false,"subject_id":10,"id":203},{"question_text":"Metastability occurs when:","option_a":"Clock is too slow","option_b":"A flop samples data violating setup/hold, settling unpredictably","option_c":"Reset is asserted","option_d":"Power is off","correct_option":"B","explanation":"Setup/hold violations can drive a flop into a metastable state.","difficulty":"medium","is_premium":false,"subject_id":10,"id":204},{"question_text":"A 2-flop synchronizer is used to:","option_a":"Divide the clock","option_b":"Safely pass a single-bit signal across clock domains","option_c":"Increase frequency","option_d":"Reduce area","correct_option":"B","explanation":"Two cascaded flops reduce metastability probability for CDC of one bit.","difficulty":"medium","is_premium":false,"subject_id":10,"id":205},{"question_text":"To pass a multi-bit bus across clock domains, you should use:","option_a":"A single 2-flop synchronizer per bit","option_b":"Gray coding or an asynchronous FIFO/handshake","option_c":"No synchronization","option_d":"A latch","correct_option":"B","explanation":"Multi-bit CDC needs Gray code (pointers) or async FIFO/handshake to avoid skew issues.","difficulty":"hard","is_premium":false,"subject_id":10,"id":206},{"question_text":"Why is Gray code used for FIFO pointers in CDC?","option_a":"It is faster","option_b":"Only one bit changes per increment, so synchronization can\u0027t sample a wrong multi-bit value","option_c":"It uses fewer bits","option_d":"It avoids reset","correct_option":"B","explanation":"Single-bit transitions make a partially-synchronized value still valid (off by one).","difficulty":"hard","is_premium":false,"subject_id":10,"id":207},{"question_text":"Clock skew is:","option_a":"Clock jitter","option_b":"Difference in clock arrival times at different registers","option_c":"Clock period","option_d":"Duty cycle","correct_option":"B","explanation":"Skew is the spatial difference in clock arrival between endpoints.","difficulty":"easy","is_premium":false,"subject_id":10,"id":208},{"question_text":"Clock jitter is:","option_a":"Spatial clock difference","option_b":"Cycle-to-cycle variation in clock edge timing","option_c":"Routing delay","option_d":"Setup time","correct_option":"B","explanation":"Jitter is temporal variation of the clock edge from cycle to cycle.","difficulty":"medium","is_premium":false,"subject_id":10,"id":209},{"question_text":"Useful skew can be applied to:","option_a":"Always hurt timing","option_b":"Borrow time by intentionally delaying a capture clock to fix setup","option_c":"Remove all flops","option_d":"Increase jitter","correct_option":"B","explanation":"Intentional skew shifts the timing budget between paths to help closure.","difficulty":"hard","is_premium":false,"subject_id":10,"id":210},{"question_text":"The setup timing equation requires Tclk \u003e=","option_a":"Tcq + Tlogic + Tsetup - Tskew","option_b":"Tcq - Tlogic","option_c":"Thold only","option_d":"Tskew only","correct_option":"A","explanation":"Tclk + Tskew \u003e= Tcq + Tlogic + Tsetup for setup.","difficulty":"hard","is_premium":false,"subject_id":10,"id":211},{"question_text":"Slack in STA is:","option_a":"Clock period","option_b":"Required time minus arrival time (positive is good)","option_c":"Setup time","option_d":"Skew","correct_option":"B","explanation":"Slack = required - arrival; negative slack means a violation.","difficulty":"medium","is_premium":false,"subject_id":10,"id":212},{"question_text":"Dynamic power is proportional to:","option_a":"1/f","option_b":"C * V^2 * f * activity","option_c":"V only","option_d":"Area only","correct_option":"B","explanation":"Switching power ~ alpha*C*V^2*f.","difficulty":"medium","is_premium":false,"subject_id":10,"id":213},{"question_text":"Leakage power is dominated by:","option_a":"Switching activity","option_b":"Subthreshold and gate leakage currents (static)","option_c":"Clock frequency","option_d":"Fanout","correct_option":"B","explanation":"Leakage is static current flowing even when idle.","difficulty":"medium","is_premium":false,"subject_id":10,"id":214},{"question_text":"Clock gating reduces power by:","option_a":"Lowering voltage","option_b":"Stopping the clock to idle registers (cuts dynamic power)","option_c":"Adding buffers","option_d":"Increasing area","correct_option":"B","explanation":"Gating idle clocks removes unnecessary switching power.","difficulty":"medium","is_premium":false,"subject_id":10,"id":215},{"question_text":"Power gating reduces:","option_a":"Dynamic power only","option_b":"Leakage by switching off power to idle blocks","option_c":"Skew","option_d":"Jitter","correct_option":"B","explanation":"Power gating shuts off supply to idle regions, cutting leakage.","difficulty":"hard","is_premium":false,"subject_id":10,"id":216},{"question_text":"DVFS stands for:","option_a":"Dual Voltage Frequency Scaling","option_b":"Dynamic Voltage and Frequency Scaling","option_c":"Digital Verilog FSM","option_d":"Delay Variation Fix Scheme","correct_option":"B","explanation":"DVFS adjusts voltage and frequency to balance power and performance.","difficulty":"medium","is_premium":false,"subject_id":10,"id":217},{"question_text":"A latch is:","option_a":"Edge-triggered","option_b":"Level-sensitive (transparent when enable active)","option_c":"Asynchronous only","option_d":"Combinational","correct_option":"B","explanation":"Latches are level-sensitive; flops are edge-triggered.","difficulty":"easy","is_premium":false,"subject_id":10,"id":218},{"question_text":"Unintended latches in RTL usually come from:","option_a":"Using flip-flops","option_b":"Incomplete if/case in combinational always blocks","option_c":"Too many wires","option_d":"Reset","correct_option":"B","explanation":"Missing else/default leaves signals un-assigned, inferring latches.","difficulty":"medium","is_premium":false,"subject_id":10,"id":219},{"question_text":"Blocking (=) assignments are recommended for:","option_a":"Sequential clocked logic","option_b":"Combinational logic modeling","option_c":"Reset","option_d":"Testbenches only","correct_option":"B","explanation":"Use blocking for combinational, non-blocking for sequential logic.","difficulty":"medium","is_premium":false,"subject_id":10,"id":220},{"question_text":"Non-blocking (\u003c=) assignments are recommended for:","option_a":"Combinational logic","option_b":"Sequential (clocked) logic to model registers correctly","option_c":"Continuous assigns","option_d":"Parameters","correct_option":"B","explanation":"Non-blocking models concurrent register updates correctly.","difficulty":"medium","is_premium":false,"subject_id":10,"id":221},{"question_text":"A Mealy FSM output depends on:","option_a":"State only","option_b":"Current state and inputs","option_c":"Clock only","option_d":"Reset only","correct_option":"B","explanation":"Mealy outputs are a function of state and inputs.","difficulty":"medium","is_premium":false,"subject_id":10,"id":222},{"question_text":"A Moore FSM output depends on:","option_a":"State and inputs","option_b":"Current state only","option_c":"Inputs only","option_d":"Next state only","correct_option":"B","explanation":"Moore outputs depend solely on the current state.","difficulty":"medium","is_premium":false,"subject_id":10,"id":223},{"question_text":"One-hot FSM encoding uses:","option_a":"log2(N) bits","option_b":"One flip-flop per state (one bit set)","option_c":"Gray code","option_d":"Binary counting","correct_option":"B","explanation":"One-hot uses N flops, simplifying next-state logic and timing.","difficulty":"medium","is_premium":false,"subject_id":10,"id":224},{"question_text":"Synchronous reset advantage over async reset:","option_a":"Faster recovery","option_b":"No metastability on reset removal; cleaner timing","option_c":"Less logic","option_d":"No clock needed","correct_option":"B","explanation":"Synchronous reset avoids async recovery/removal metastability but needs a running clock.","difficulty":"hard","is_premium":false,"subject_id":10,"id":225},{"question_text":"Reset synchronizer (async assert, sync deassert) solves:","option_a":"Setup violations","option_b":"Reset recovery/removal metastability at deassertion","option_c":"Clock skew","option_d":"Power","correct_option":"B","explanation":"Async-assert/sync-deassert avoids metastability when reset is removed.","difficulty":"hard","is_premium":false,"subject_id":10,"id":226},{"question_text":"A multiplexer can be built from:","option_a":"Only flip-flops","option_b":"AND/OR/NOT gates or tri-state buffers","option_c":"Only latches","option_d":"Resistors","correct_option":"B","explanation":"A mux is combinational select logic from basic gates.","difficulty":"easy","is_premium":false,"subject_id":10,"id":227},{"question_text":"Two\u0027s complement of an N-bit number is formed by:","option_a":"Inverting bits only","option_b":"Inverting all bits and adding 1","option_c":"Adding 1 only","option_d":"Shifting left","correct_option":"B","explanation":"Two\u0027s complement = bitwise NOT + 1.","difficulty":"easy","is_premium":false,"subject_id":10,"id":228},{"question_text":"A ripple-carry adder\u0027s main drawback is:","option_a":"Too much area","option_b":"Carry propagation delay grows with bit width","option_c":"No carry out","option_d":"Cannot subtract","correct_option":"B","explanation":"Carry ripples serially, making delay proportional to width.","difficulty":"medium","is_premium":false,"subject_id":10,"id":229},{"question_text":"A carry-lookahead adder improves speed by:","option_a":"Serial carry","option_b":"Computing carries in parallel via generate/propagate","option_c":"Removing the carry","option_d":"Using latches","correct_option":"B","explanation":"CLA precomputes carries using G/P terms to reduce delay.","difficulty":"hard","is_premium":false,"subject_id":10,"id":230},{"question_text":"How many 2-input gates minimum for a 2:1 mux (using NANDs)?","option_a":"1","option_b":"About 4 NAND gates","option_c":"10","option_d":"0","correct_option":"B","explanation":"A 2:1 mux can be built with ~4 NAND gates.","difficulty":"medium","is_premium":false,"subject_id":10,"id":231},{"question_text":"Number of flip-flops to divide a clock by 8:","option_a":"8","option_b":"3 (a 3-bit counter)","option_c":"1","option_d":"4","correct_option":"B","explanation":"log2(8)=3 toggle/counter stages divide by 8.","difficulty":"medium","is_premium":false,"subject_id":10,"id":232},{"question_text":"To detect the sequence 101 (overlapping), you need an FSM with at least:","option_a":"1 state","option_b":"3-4 states","option_c":"16 states","option_d":"0 states","correct_option":"B","explanation":"A small FSM (idle, got1, got10) detects 101 with overlap.","difficulty":"medium","is_premium":false,"subject_id":10,"id":233},{"question_text":"A glitch is:","option_a":"A reset","option_b":"A momentary unwanted transition due to unequal path delays","option_c":"Metastability","option_d":"Setup time","correct_option":"B","explanation":"Glitches arise from converging signals with different delays.","difficulty":"medium","is_premium":false,"subject_id":10,"id":234},{"question_text":"Why register outputs of combinational logic before crossing modules?","option_a":"To add area","option_b":"To break timing paths and avoid glitches propagating","option_c":"To slow the clock","option_d":"To remove resets","correct_option":"B","explanation":"Registering cleans glitches and improves timing closure.","difficulty":"medium","is_premium":false,"subject_id":10,"id":235},{"question_text":"Fan-out of a gate refers to:","option_a":"Number of inputs","option_b":"Number of gate inputs it drives","option_c":"Supply voltage","option_d":"Clock period","correct_option":"B","explanation":"Fan-out is how many loads a gate output drives.","difficulty":"easy","is_premium":false,"subject_id":10,"id":236},{"question_text":"High fan-out nets are typically fixed with:","option_a":"Slower clock","option_b":"Buffer/inverter trees to distribute load","option_c":"More flops","option_d":"Removing the net","correct_option":"B","explanation":"Buffer trees split large loads to meet timing.","difficulty":"medium","is_premium":false,"subject_id":10,"id":237},{"question_text":"Static CMOS inverter consumes significant power mainly during:","option_a":"Steady state","option_b":"Switching transitions","option_c":"Reset","option_d":"Never","correct_option":"B","explanation":"Dynamic/short-circuit power occurs during switching.","difficulty":"medium","is_premium":false,"subject_id":10,"id":238},{"question_text":"A pull-up network in CMOS is built from:","option_a":"NMOS","option_b":"PMOS transistors","option_c":"Resistors only","option_d":"Diodes","correct_option":"B","explanation":"PMOS forms the pull-up; NMOS forms the pull-down.","difficulty":"easy","is_premium":false,"subject_id":10,"id":239},{"question_text":"Which has lower delay: NAND or NOR (same size) in CMOS, generally?","option_a":"NOR (PMOS in parallel)","option_b":"NAND (PMOS in parallel, NMOS in series) is usually faster","option_c":"Equal always","option_d":"Neither switches","correct_option":"B","explanation":"NAND\u0027s parallel PMOS makes it faster than NOR with series PMOS.","difficulty":"hard","is_premium":false,"subject_id":10,"id":240},{"question_text":"DRC (Design Rule Check) verifies:","option_a":"Functionality","option_b":"Layout obeys foundry geometric rules","option_c":"Timing","option_d":"Power only","correct_option":"B","explanation":"DRC checks spacing/width manufacturing rules.","difficulty":"medium","is_premium":false,"subject_id":10,"id":241},{"question_text":"LVS (Layout vs Schematic) verifies:","option_a":"Timing","option_b":"Layout netlist matches the schematic netlist","option_c":"Power grid","option_d":"Reset","correct_option":"B","explanation":"LVS confirms layout connectivity equals the schematic.","difficulty":"medium","is_premium":false,"subject_id":10,"id":242},{"question_text":"Antenna effect in fabrication is mitigated by:","option_a":"More flops","option_b":"Adding antenna diodes or jumping to higher metal","option_c":"Slower clock","option_d":"Gray code","correct_option":"B","explanation":"Diodes/metal jumps discharge accumulated charge to protect gates.","difficulty":"hard","is_premium":false,"subject_id":10,"id":243},{"question_text":"Electromigration is:","option_a":"Clock skew","option_b":"Metal atom displacement from high current density over time","option_c":"Leakage","option_d":"Jitter","correct_option":"B","explanation":"High current density erodes metal, a reliability concern.","difficulty":"hard","is_premium":false,"subject_id":10,"id":244},{"question_text":"IR drop refers to:","option_a":"Clock delay","option_b":"Voltage drop across power grid resistance under current load","option_c":"Setup time","option_d":"Jitter","correct_option":"B","explanation":"IR drop lowers local supply, degrading speed.","difficulty":"hard","is_premium":false,"subject_id":10,"id":245},{"question_text":"Why pipeline a design?","option_a":"To reduce throughput","option_b":"To increase throughput/clock frequency by shortening critical paths","option_c":"To add latches","option_d":"To remove registers","correct_option":"B","explanation":"Pipelining splits long paths, raising clock rate and throughput.","difficulty":"medium","is_premium":false,"subject_id":10,"id":246},{"question_text":"The cost of pipelining is increased:","option_a":"Throughput","option_b":"Latency (in cycles) and area","option_c":"Clock period","option_d":"Skew only","correct_option":"B","explanation":"More pipeline stages add latency and register area.","difficulty":"medium","is_premium":false,"subject_id":10,"id":247},{"question_text":"Retiming is a technique that:","option_a":"Removes clocks","option_b":"Moves registers across logic to balance path delays","option_c":"Adds resets","option_d":"Changes function","correct_option":"B","explanation":"Retiming relocates flops to optimize timing without altering behavior.","difficulty":"hard","is_premium":false,"subject_id":10,"id":248},{"question_text":"The single most important habit in a VLSI interview problem is to:","option_a":"Memorize answers","option_b":"Clarify assumptions and reason through timing/CDC/power tradeoffs","option_c":"Avoid questions","option_d":"Use only one tool","correct_option":"B","explanation":"Interviewers value structured reasoning about constraints and tradeoffs.","difficulty":"easy","is_premium":false,"subject_id":10,"id":249},{"question_text":"A flop has Tcq=120ps, setup=80ps. Combinational delay is 600ps, clock skew (capture later) is +50ps, jitter 30ps. What is the minimum clock period for setup?","option_a":"800ps","option_b":"780ps","option_c":"830ps","option_d":"750ps","correct_option":"B","explanation":"Tclk \u003e= Tcq + Tlogic + Tsu + Tjitter - Tskew = 120+600+80+30-50 = 780ps. Positive skew (capture later) relaxes setup.","difficulty":"hard","is_premium":true,"subject_id":10,"id":250},{"question_text":"Which condition causes a hold violation that CANNOT be fixed by lowering the clock frequency?","option_a":"Long combinational path","option_b":"Short data path with positive clock skew at capture","option_c":"High fanout net","option_d":"Large setup time","correct_option":"B","explanation":"Hold checks are independent of period; a too-fast (short) path plus skew causes hold failure regardless of frequency. Fix with buffers/delay.","difficulty":"hard","is_premium":true,"subject_id":10,"id":251},{"question_text":"For an asynchronous FIFO, why must read/write pointers be Gray-coded before synchronization?","option_a":"To save power","option_b":"Only one bit changes per increment, avoiding multi-bit sampling errors","option_c":"To increase depth","option_d":"Gray code is faster to add","correct_option":"B","explanation":"Binary pointers can have multiple bits changing simultaneously; sampling mid-transition gives a wrong value. Gray code changes one bit per step, so a metastable sample yields either the old or new value, both safe.","difficulty":"hard","is_premium":true,"subject_id":10,"id":252},{"question_text":"Two-flop synchronizer MTBF improves most strongly with:","option_a":"Lower data toggle rate and lower clock frequency","option_b":"More combinational logic","option_c":"Higher capacitance","option_d":"Smaller flops","correct_option":"A","explanation":"MTBF grows exponentially with the settling time available (T - Tcq - Tsu) and inversely with data and clock frequencies. Slower clk/data and more settling time increase MTBF.","difficulty":"hard","is_premium":true,"subject_id":10,"id":253},{"question_text":"A design crosses from a 100MHz to a 400MHz domain. Best structure for a multi-bit data bus is:","option_a":"One 2-flop synchronizer per bit","option_b":"Asynchronous FIFO or a req/ack handshake with data held stable","option_c":"Direct connection","option_d":"Combinational mux","correct_option":"B","explanation":"Per-bit synchronizers can resolve bits in different cycles, corrupting the word. Use an async FIFO (streaming) or handshake holding data stable until acknowledged.","difficulty":"hard","is_premium":true,"subject_id":10,"id":254},{"question_text":"Glitches on a combinational output feeding a flip-flop D pin are generally harmless because:","option_a":"Flops ignore glitches","option_b":"The value only needs to be stable in the setup/hold window around the edge","option_c":"Glitches cancel out","option_d":"D pins are filtered","correct_option":"B","explanation":"An edge-triggered flop samples only around the clock edge. As long as the signal settles before setup and stays through hold, intermediate glitches do not matter.","difficulty":"medium","is_premium":true,"subject_id":10,"id":255},{"question_text":"Which is TRUE about a divide-by-3 clock with 50% duty cycle?","option_a":"Achievable with a single flop","option_b":"Requires using both clock edges (e.g., two counters on pos/neg edge ORed)","option_c":"Impossible","option_d":"Needs a PLL only","correct_option":"B","explanation":"Odd-division with 50% duty needs logic clocked on both edges; a negedge-shifted copy is combined so the output is symmetric.","difficulty":"hard","is_premium":true,"subject_id":10,"id":256},{"question_text":"A synchronous reset\u0027s main drawback compared to asynchronous reset is:","option_a":"It cannot reset flops","option_b":"Reset is ignored if the clock is not running","option_c":"It causes metastability","option_d":"It needs more power always","correct_option":"B","explanation":"Synchronous reset requires an active clock edge to take effect; if the clock is gated/stopped, the reset will not apply.","difficulty":"medium","is_premium":true,"subject_id":10,"id":257},{"question_text":"Reset synchronizer (asynchronous assert, synchronous de-assert) is used to:","option_a":"Lower power","option_b":"Avoid reset removal recovery/removal timing violations and metastability on de-assertion","option_c":"Speed up reset","option_d":"Reduce area","correct_option":"B","explanation":"Asserting asynchronously is immediate; de-asserting synchronously through 2 flops prevents recovery/removal violations when reset releases near a clock edge.","difficulty":"hard","is_premium":true,"subject_id":10,"id":258},{"question_text":"Minimum async FIFO depth depends on:","option_a":"Only the clock ratio","option_b":"Burst length, and the read vs write rate difference during the burst","option_c":"Data width only","option_d":"Number of synchronizer flops only","correct_option":"B","explanation":"Depth must absorb the worst-case backlog = items written minus items read over the burst duration, accounting for rate mismatch and idle cycles.","difficulty":"hard","is_premium":true,"subject_id":10,"id":259},{"question_text":"In a gated clock, the enable must be captured by a low-active latch (not a flop) to:","option_a":"Save a flop","option_b":"Prevent enable changes during the high phase from chopping the clock pulse (glitch-free gating)","option_c":"Increase frequency","option_d":"Reduce skew","correct_option":"B","explanation":"The latch holds the enable stable through the clock high phase, so the AND gate produces clean full pulses with no glitches.","difficulty":"hard","is_premium":true,"subject_id":10,"id":260},{"question_text":"Which statement about setup vs hold and OCV derating is correct?","option_a":"Both checks derate launch and capture the same way","option_b":"For setup, launch is slowed and capture sped up; for hold, the opposite, to model worst case","option_c":"OCV only affects hold","option_d":"OCV speeds all paths equally","correct_option":"B","explanation":"OCV pessimistically derates: setup uses late launch/early capture; hold uses early launch/late capture, capturing on-die variation worst cases.","difficulty":"hard","is_premium":true,"subject_id":10,"id":261},{"question_text":"A 1-deep skid buffer in a valid/ready pipeline is needed to:","option_a":"Increase throughput beyond 1/cycle","option_b":"Register both data and the ready backpressure without dropping a beat when downstream stalls","option_c":"Reduce latency to zero","option_d":"Convert AXI to APB","correct_option":"B","explanation":"When you register valid/ready, a stall can leave an in-flight beat; the skid buffer stores it so no data is lost while maintaining full throughput.","difficulty":"hard","is_premium":true,"subject_id":10,"id":262},{"question_text":"Why is one-hot FSM encoding often preferred in FPGAs?","option_a":"Fewest flip-flops","option_b":"Simple next-state/decode logic and fast timing, since FFs are plentiful in FPGAs","option_c":"Lowest power always","option_d":"Smaller in ASIC too","correct_option":"B","explanation":"One-hot trades more flops for simpler combinational decode and faster Fmax. FPGAs have abundant FFs, making this favorable.","difficulty":"medium","is_premium":true,"subject_id":10,"id":263},{"question_text":"Clock domain crossing of a control signal is declared in SDC as:","option_a":"set_max_delay","option_b":"set_false_path or set_clock_groups -asynchronous between the domains","option_c":"create_clock","option_d":"set_load","correct_option":"B","explanation":"Asynchronous CDC paths are excluded from single-cycle timing via false paths or asynchronous clock groups; the synchronizer handles metastability.","difficulty":"medium","is_premium":true,"subject_id":10,"id":264},{"question_text":"A net with very high fanout typically degrades timing because:","option_a":"It lowers voltage","option_b":"Large load increases transition/delay; needs buffering or cloning to fix","option_c":"It causes LVS errors","option_d":"It always shorts","correct_option":"B","explanation":"High fanout means high capacitive load, slow slews and added delay. Buffer trees or driver cloning restore timing.","difficulty":"medium","is_premium":true,"subject_id":10,"id":265},{"question_text":"What does a negative slack of -50ps on a setup path mean?","option_a":"Path passes with 50ps margin","option_b":"Path is 50ps too slow and violates timing","option_c":"Hold is fine","option_d":"Clock is too slow","correct_option":"B","explanation":"Slack = required - arrival. Negative slack means the data arrives later than required; the path fails setup by 50ps.","difficulty":"easy","is_premium":true,"subject_id":10,"id":266},{"question_text":"Multicycle path set_multicycle_path 2 -setup usually also needs:","option_a":"Nothing else","option_b":"set_multicycle_path 1 -hold to move the hold check back to the correct edge","option_c":"A new clock","option_d":"set_false_path","correct_option":"B","explanation":"Relaxing setup by N cycles shifts the default hold check; you add a hold MCP (N-1) so hold is checked at the correct adjacent edge.","difficulty":"hard","is_premium":true,"subject_id":10,"id":267},{"question_text":"A metastable flop output is dangerous mainly because:","option_a":"It draws too much current","option_b":"Different downstream gates may interpret the intermediate voltage as different logic values","option_c":"It resets the chip","option_d":"It always settles to 0","correct_option":"B","explanation":"An undefined intermediate level can fan out and be read as 0 by one gate and 1 by another, causing inconsistent state.","difficulty":"medium","is_premium":true,"subject_id":10,"id":268},{"question_text":"To safely pass an 8-bit counter value to a slower domain, the most robust method is:","option_a":"Gray-code the counter and 2-flop synchronize, decoding back if needed","option_b":"Synchronize each bit independently in binary","option_c":"Combinational path","option_d":"Latch all bits","correct_option":"A","explanation":"Gray coding guarantees single-bit change per increment; the synchronized value is always a valid (old or new) count, unlike per-bit binary syncing.","difficulty":"hard","is_premium":true,"subject_id":10,"id":269},{"question_text":"GPUs achieve high throughput primarily through:","option_a":"A few fast cores","option_b":"Massive data parallelism across many simple cores","option_c":"Low clock only","option_d":"Serial execution","correct_option":"B","explanation":"GPUs exploit data parallelism with thousands of lightweight cores.","difficulty":"easy","is_premium":false,"subject_id":12,"id":270},{"question_text":"The SIMT execution model means:","option_a":"Single thread","option_b":"Single Instruction, Multiple Threads (warps/wavefronts)","option_c":"Serial instructions","option_d":"No threads","correct_option":"B","explanation":"SIMT runs many threads in lockstep per instruction (NVIDIA term).","difficulty":"medium","is_premium":false,"subject_id":12,"id":271},{"question_text":"An NVIDIA \u0027warp\u0027 (AMD \u0027wavefront\u0027) is:","option_a":"A single thread","option_b":"A group of threads executed together in lockstep","option_c":"A cache line","option_d":"A clock domain","correct_option":"B","explanation":"A warp/wavefront is the SIMD execution group (32/64 threads).","difficulty":"medium","is_premium":false,"subject_id":12,"id":272},{"question_text":"Warp divergence hurts performance because:","option_a":"It saves power","option_b":"Divergent branches serialize execution of both paths","option_c":"It speeds up","option_d":"It removes threads","correct_option":"B","explanation":"Branch divergence forces serial execution of taken/not-taken paths.","difficulty":"hard","is_premium":false,"subject_id":12,"id":273},{"question_text":"Memory coalescing improves performance by:","option_a":"Random access","option_b":"Combining adjacent thread accesses into fewer wide memory transactions","option_c":"Adding latency","option_d":"Reducing bandwidth","correct_option":"B","explanation":"Coalesced access merges contiguous requests into efficient bursts.","difficulty":"hard","is_premium":false,"subject_id":12,"id":274},{"question_text":"Shared memory (LDS) in a GPU is:","option_a":"Global DRAM","option_b":"Fast on-chip memory shared within a thread block/workgroup","option_c":"Disk","option_d":"A register only","correct_option":"B","explanation":"Shared/local memory is low-latency scratchpad per block.","difficulty":"medium","is_premium":false,"subject_id":12,"id":275},{"question_text":"Bank conflicts in GPU shared memory cause:","option_a":"Faster access","option_b":"Serialized accesses when threads hit the same bank","option_c":"Lower power","option_d":"No effect","correct_option":"B","explanation":"Multiple threads to one bank serialize, reducing throughput.","difficulty":"hard","is_premium":false,"subject_id":12,"id":276},{"question_text":"GPUs hide memory latency mainly via:","option_a":"Large caches only","option_b":"Massive multithreading (switching to ready warps)","option_c":"Lower clocks","option_d":"Serial execution","correct_option":"B","explanation":"Many resident warps let the scheduler hide stalls by switching.","difficulty":"medium","is_premium":false,"subject_id":12,"id":277},{"question_text":"Occupancy in GPU terms refers to:","option_a":"Die area used","option_b":"Ratio of active warps to the maximum supported per SM","option_c":"Clock frequency","option_d":"Power","correct_option":"B","explanation":"Occupancy measures resident warps relative to the hardware max.","difficulty":"medium","is_premium":false,"subject_id":12,"id":278},{"question_text":"High register usage per thread can:","option_a":"Increase occupancy","option_b":"Reduce occupancy by limiting resident warps","option_c":"Have no effect","option_d":"Lower power","correct_option":"B","explanation":"Registers are finite; heavy use limits concurrent warps.","difficulty":"hard","is_premium":false,"subject_id":12,"id":279},{"question_text":"HBM (High Bandwidth Memory) provides:","option_a":"Low bandwidth","option_b":"Very high bandwidth via stacked DRAM and wide buses","option_c":"Disk storage","option_d":"Serial links only","correct_option":"B","explanation":"HBM stacks DRAM with wide interfaces for huge bandwidth.","difficulty":"medium","is_premium":false,"subject_id":12,"id":280},{"question_text":"Tensor/Matrix cores accelerate:","option_a":"Branching","option_b":"Matrix-multiply-accumulate (MAC) for AI workloads","option_c":"Memory copies","option_d":"Reset logic","correct_option":"B","explanation":"Tensor cores do fast MMA operations for deep learning.","difficulty":"medium","is_premium":false,"subject_id":12,"id":281},{"question_text":"A systolic array is efficient for matrix multiply because:","option_a":"It uses one PE","option_b":"Data flows rhythmically through a grid of MAC PEs, maximizing reuse","option_c":"It avoids multiplication","option_d":"It is serial","correct_option":"B","explanation":"Systolic arrays reuse operands across a PE grid for high efficiency.","difficulty":"hard","is_premium":false,"subject_id":12,"id":282},{"question_text":"A pipelined multiplier increases throughput by:","option_a":"Doing all work in one cycle","option_b":"Splitting partial-product/addition stages across registers","option_c":"Removing registers","option_d":"Lowering clock","correct_option":"B","explanation":"Pipelining a multiplier raises clock and throughput.","difficulty":"medium","is_premium":false,"subject_id":12,"id":283},{"question_text":"A Wallace tree is used to:","option_a":"Store data","option_b":"Sum partial products quickly with carry-save adders","option_c":"Divide clock","option_d":"Generate reset","correct_option":"B","explanation":"Wallace trees reduce partial products with CSAs for fast multipliers.","difficulty":"hard","is_premium":false,"subject_id":12,"id":284},{"question_text":"Carry-save addition is fast because:","option_a":"It propagates carry fully","option_b":"It defers carry propagation, summing many operands in parallel","option_c":"It uses latches","option_d":"It is serial","correct_option":"B","explanation":"CSA keeps sum/carry separate, avoiding long carry chains until the end.","difficulty":"hard","is_premium":false,"subject_id":12,"id":285},{"question_text":"Booth encoding reduces multiplier work by:","option_a":"Adding more partial products","option_b":"Reducing the number of partial products via radix encoding","option_c":"Removing the adder","option_d":"Using latches","correct_option":"B","explanation":"Booth (e.g., radix-4) halves partial products, speeding multiplication.","difficulty":"hard","is_premium":false,"subject_id":12,"id":286},{"question_text":"IEEE-754 single precision has how many mantissa bits (stored)?","option_a":"52","option_b":"23 (plus implicit leading 1)","option_c":"8","option_d":"32","correct_option":"B","explanation":"FP32 has 23 stored mantissa bits, 8 exponent, 1 sign.","difficulty":"medium","is_premium":false,"subject_id":12,"id":287},{"question_text":"FP16 vs FP32 in GPUs is used to:","option_a":"Increase precision","option_b":"Boost throughput/save bandwidth for AI at lower precision","option_c":"Add latency","option_d":"Reduce cores","correct_option":"B","explanation":"FP16/BF16 trade precision for speed and memory efficiency in ML.","difficulty":"medium","is_premium":false,"subject_id":12,"id":288},{"question_text":"BF16 differs from FP16 by having:","option_a":"Fewer exponent bits","option_b":"The same 8-bit exponent as FP32 (wider range, less mantissa)","option_c":"More mantissa","option_d":"No sign bit","correct_option":"B","explanation":"BF16 keeps FP32\u0027s exponent range with a smaller mantissa.","difficulty":"hard","is_premium":false,"subject_id":12,"id":289},{"question_text":"A GPU SM (Streaming Multiprocessor)/CU contains:","option_a":"Only DRAM","option_b":"ALUs, schedulers, register file, and shared memory","option_c":"Only a PLL","option_d":"Just a cache","correct_option":"B","explanation":"An SM/CU bundles execution units, schedulers, registers, and shared memory.","difficulty":"medium","is_premium":false,"subject_id":12,"id":290},{"question_text":"Why are GPU caches relatively small per thread?","option_a":"Threads need no data","option_b":"Latency is hidden by multithreading, not large caches","option_c":"Caches are banned","option_d":"To save the clock","correct_option":"B","explanation":"GPUs hide latency via parallelism, so per-thread caches are modest.","difficulty":"hard","is_premium":false,"subject_id":12,"id":291},{"question_text":"An atomic operation in a GPU ensures:","option_a":"Faster division","option_b":"Read-modify-write to a memory location without interference","option_c":"Lower clock","option_d":"No memory access","correct_option":"B","explanation":"Atomics serialize RMW updates to avoid races across threads.","difficulty":"medium","is_premium":false,"subject_id":12,"id":292},{"question_text":"A barrier synchronization in a thread block:","option_a":"Resets the GPU","option_b":"Makes threads wait until all reach the barrier","option_c":"Increases clock","option_d":"Frees memory","correct_option":"B","explanation":"Barriers synchronize all threads in a block at a point.","difficulty":"medium","is_premium":false,"subject_id":12,"id":293},{"question_text":"Roofline analysis helps determine if a kernel is:","option_a":"Reset-bound","option_b":"Compute-bound or memory-bandwidth-bound","option_c":"DRC-bound","option_d":"Power-bound only","correct_option":"B","explanation":"Roofline plots performance vs arithmetic intensity to find the bottleneck.","difficulty":"hard","is_premium":false,"subject_id":12,"id":294},{"question_text":"Arithmetic intensity is:","option_a":"Clock per watt","option_b":"FLOPs per byte of memory traffic","option_c":"Gates per area","option_d":"Threads per warp","correct_option":"B","explanation":"Arithmetic intensity = compute operations divided by bytes moved.","difficulty":"hard","is_premium":false,"subject_id":12,"id":295},{"question_text":"A clock domain crossing FIFO is used between GPU core and memory clock to:","option_a":"Increase power","option_b":"Safely buffer data across asynchronous clocks","option_c":"Remove caches","option_d":"Divide clocks","correct_option":"B","explanation":"Async FIFOs bridge core and memory clock domains.","difficulty":"medium","is_premium":false,"subject_id":12,"id":296},{"question_text":"Why pipeline deeply in a high-frequency GPU datapath?","option_a":"To reduce throughput","option_b":"To shorten critical paths and reach high clock frequency","option_c":"To add latches","option_d":"To remove ALUs","correct_option":"B","explanation":"Deep pipelines enable high clocks by shortening per-stage logic.","difficulty":"medium","is_premium":false,"subject_id":12,"id":297},{"question_text":"A hazard in a pipeline that needs forwarding is a:","option_a":"Structural hazard","option_b":"Data hazard (RAW dependency)","option_c":"Reset hazard","option_d":"Clock hazard","correct_option":"B","explanation":"RAW data hazards are resolved by forwarding/bypassing.","difficulty":"medium","is_premium":false,"subject_id":12,"id":298},{"question_text":"Forwarding (bypassing) in a pipeline:","option_a":"Stalls always","option_b":"Routes a result to a dependent stage before write-back","option_c":"Removes the ALU","option_d":"Resets the pipe","correct_option":"B","explanation":"Forwarding feeds results early to avoid stalls.","difficulty":"hard","is_premium":false,"subject_id":12,"id":299},{"question_text":"A structural hazard occurs when:","option_a":"Data depends on prior result","option_b":"Two instructions need the same hardware resource simultaneously","option_c":"A branch is taken","option_d":"Reset asserts","correct_option":"B","explanation":"Structural hazards arise from resource contention.","difficulty":"medium","is_premium":false,"subject_id":12,"id":300},{"question_text":"Branch prediction reduces penalty of:","option_a":"Data hazards","option_b":"Control hazards by guessing the branch outcome","option_c":"Structural hazards","option_d":"Reset","correct_option":"B","explanation":"Prediction mitigates control-hazard stalls.","difficulty":"medium","is_premium":false,"subject_id":12,"id":301},{"question_text":"Scoreboarding/Tomasulo enable:","option_a":"In-order only","option_b":"Out-of-order execution by tracking dependencies","option_c":"No execution","option_d":"Reset handling","correct_option":"B","explanation":"These schemes dynamically schedule independent instructions.","difficulty":"hard","is_premium":false,"subject_id":12,"id":302},{"question_text":"A register file with many ports is needed in GPUs because:","option_a":"One thread runs","option_b":"Many lanes read/write operands per cycle","option_c":"No registers exist","option_d":"To save area","correct_option":"B","explanation":"Wide SIMD lanes demand high register-file bandwidth.","difficulty":"hard","is_premium":false,"subject_id":12,"id":303},{"question_text":"Why use banked register files instead of a single large multiport RAM?","option_a":"For lower bandwidth","option_b":"Banking provides high bandwidth at lower area/power than full multiport","option_c":"To remove ports","option_d":"For reset","correct_option":"B","explanation":"Banking approximates many ports economically.","difficulty":"hard","is_premium":false,"subject_id":12,"id":304},{"question_text":"Power is often the binding constraint in GPUs because:","option_a":"Area is free","option_b":"Thermal/power budgets limit how many units can switch at once","option_c":"Clock is unlimited","option_d":"No transistors","correct_option":"B","explanation":"Dark-silicon/thermal limits cap simultaneous switching.","difficulty":"medium","is_premium":false,"subject_id":12,"id":305},{"question_text":"Clock gating large idle GPU blocks primarily reduces:","option_a":"Leakage","option_b":"Dynamic (switching) power","option_c":"Area","option_d":"Jitter","correct_option":"B","explanation":"Gating idle clocks cuts dynamic power.","difficulty":"easy","is_premium":false,"subject_id":12,"id":306},{"question_text":"Why are reductions (sum across threads) implemented as trees?","option_a":"To serialize","option_b":"Tree reduction gives O(log n) latency instead of O(n)","option_c":"To save registers","option_d":"To reset","correct_option":"B","explanation":"Tree reductions parallelize the combine in logarithmic depth.","difficulty":"hard","is_premium":false,"subject_id":12,"id":307},{"question_text":"A prefix-sum (scan) is useful in GPUs for:","option_a":"Reset","option_b":"Stream compaction, sorting, and allocation offsets","option_c":"Clock division","option_d":"DRC","correct_option":"B","explanation":"Scan underpins compaction, histograms, and sorting.","difficulty":"hard","is_premium":false,"subject_id":12,"id":308},{"question_text":"ECC on GPU memory protects against:","option_a":"Clock skew","option_b":"Bit errors (e.g., soft errors) via error-correcting codes","option_c":"DRC","option_d":"Leakage","correct_option":"B","explanation":"ECC detects/corrects memory bit errors for reliability.","difficulty":"medium","is_premium":false,"subject_id":12,"id":309},{"question_text":"A crossbar interconnect in a GPU connects:","option_a":"One unit only","option_b":"Many cores to many memory partitions with parallel paths","option_c":"Only clocks","option_d":"Only resets","correct_option":"B","explanation":"Crossbars route many requesters to many memory slices concurrently.","difficulty":"hard","is_premium":false,"subject_id":12,"id":310},{"question_text":"A NoC (Network-on-Chip) is used in large GPUs/SoCs to:","option_a":"Replace transistors","option_b":"Scalably route packets between many on-chip nodes","option_c":"Divide clock","option_d":"Do DRC","correct_option":"B","explanation":"NoCs provide scalable packet-routed on-chip communication.","difficulty":"hard","is_premium":false,"subject_id":12,"id":311},{"question_text":"Deadlock in a NoC can be avoided using:","option_a":"Random routing","option_b":"Virtual channels and deadlock-free routing (e.g., dimension order)","option_c":"No buffers","option_d":"Reset only","correct_option":"B","explanation":"Virtual channels and ordered routing break cyclic dependencies.","difficulty":"hard","is_premium":false,"subject_id":12,"id":312},{"question_text":"Verification of a GPU block heavily uses:","option_a":"Manual waveform only","option_b":"Constrained-random + functional coverage (UVM)","option_c":"DRC","option_d":"Schematic capture","correct_option":"B","explanation":"Constrained-random UVM with coverage scales to complex blocks.","difficulty":"medium","is_premium":false,"subject_id":12,"id":313},{"question_text":"Assertions (SVA) in a GPU pipeline verify:","option_a":"Layout","option_b":"Protocol/handshake and invariant properties during simulation","option_c":"IR drop","option_d":"Antenna","correct_option":"B","explanation":"SVA checks temporal protocol and invariants continuously.","difficulty":"medium","is_premium":false,"subject_id":12,"id":314},{"question_text":"Why is throughput more important than single-thread latency for GPUs?","option_a":"Threads are rare","option_b":"Workloads are massively parallel; aggregate work/sec dominates","option_c":"Latency cannot be hidden","option_d":"Clocks are fixed","correct_option":"B","explanation":"GPUs optimize aggregate throughput across many threads.","difficulty":"medium","is_premium":false,"subject_id":12,"id":315},{"question_text":"A common NVIDIA/AMD RTL ask: design a parameterized N-stage pipelined adder. The key is:","option_a":"One always block, no params","option_b":"Parameterize width/stages with generate and registered stage outputs","option_c":"Use latches","option_d":"Avoid registers","correct_option":"B","explanation":"Parameterization via generate with registered stages is the expected approach.","difficulty":"hard","is_premium":false,"subject_id":12,"id":316},{"question_text":"To compute a running max across a stream with backpressure, you combine:","option_a":"Only a comparator","option_b":"A comparator/register with VALID/READY handshake flow control","option_c":"A PLL","option_d":"A latch only","correct_option":"B","explanation":"A registered max with handshaking handles streaming and stalls.","difficulty":"hard","is_premium":false,"subject_id":12,"id":317},{"question_text":"The strongest GPU-interview answers connect microarchitecture choices to:","option_a":"Only gate count","option_b":"Throughput, latency hiding, memory bandwidth, and power tradeoffs","option_c":"Only DRC","option_d":"Only reset","correct_option":"B","explanation":"Great answers tie design decisions to throughput/bandwidth/power tradeoffs.","difficulty":"medium","is_premium":false,"subject_id":12,"id":318},{"question_text":"A double-buffering (ping-pong) scheme in a GPU datapath is used to:","option_a":"Reset faster","option_b":"Overlap compute on one buffer while loading/storing the other","option_c":"Reduce precision","option_d":"Divide the clock","correct_option":"B","explanation":"Ping-pong buffers hide transfer latency by overlapping load and compute.","difficulty":"hard","is_premium":false,"subject_id":12,"id":319},{"question_text":"In a 5-stage pipeline, a load-use data hazard is best resolved (without stalling) by:","option_a":"Always stalling 2 cycles","option_b":"Forwarding/bypassing the result, plus a 1-cycle stall only for load-use","option_c":"Reordering at runtime in hardware always","option_d":"Flushing the pipeline","correct_option":"B","explanation":"Forwarding handles most ALU dependencies with no stall; a load\u0027s data is available only after MEM, so a single load-use bubble plus forwarding is required.","difficulty":"hard","is_premium":true,"subject_id":12,"id":320},{"question_text":"A skid (elastic) buffer guarantees full throughput in a registered valid/ready pipe by absorbing:","option_a":"Clock skew","option_b":"One in-flight beat when ready de-asserts the same cycle valid is high","option_c":"Metastability","option_d":"Reset","correct_option":"B","explanation":"Registering ready introduces a one-cycle backpressure delay; the skid buffer stores the beat already accepted, preventing loss while keeping 1 beat/cycle.","difficulty":"hard","is_premium":true,"subject_id":12,"id":321},{"question_text":"For an AXI burst, which is illegal?","option_a":"INCR burst of 16 beats","option_b":"A burst that crosses a 4KB address boundary","option_c":"WRAP burst aligned to size","option_d":"Out-of-order completion with different IDs","correct_option":"B","explanation":"AXI forbids a single burst crossing a 4KB boundary so it cannot span two pages/slaves; the master must split it.","difficulty":"medium","is_premium":true,"subject_id":12,"id":322},{"question_text":"AXI allows out-of-order read data return for transactions with:","option_a":"The same ARID","option_b":"Different ARIDs (different transaction IDs)","option_c":"Any transaction","option_d":"Only single beats","correct_option":"B","explanation":"Transactions sharing an ID must stay ordered; different IDs may complete out of order, which enables outstanding/interleaved high-bandwidth access.","difficulty":"hard","is_premium":true,"subject_id":12,"id":323},{"question_text":"A round-robin arbiter is preferred over fixed-priority for shared memory because it:","option_a":"Is faster to build","option_b":"Prevents starvation by rotating grant priority fairly","option_c":"Uses fewer gates","option_d":"Has lower latency always","correct_option":"B","explanation":"Fixed priority can starve low-priority requesters under load. Round-robin rotates priority so every requester eventually gets served.","difficulty":"medium","is_premium":true,"subject_id":12,"id":324},{"question_text":"Little\u0027s Law (N = throughput x latency) implies that to sustain high bandwidth across a long-latency memory you need:","option_a":"A faster clock only","option_b":"Enough outstanding/in-flight requests to cover the latency","option_c":"A wider data bus only","option_d":"Lower latency only","correct_option":"B","explanation":"Throughput = N/latency. To keep a high-latency pipe full at target bandwidth you must issue enough concurrent outstanding requests (N).","difficulty":"hard","is_premium":true,"subject_id":12,"id":325},{"question_text":"A write-back, write-allocate cache on a write miss will:","option_a":"Write only to memory","option_b":"Fetch the line into cache, then write into it, marking it dirty","option_c":"Skip the cache","option_d":"Stall forever","correct_option":"B","explanation":"Write-allocate brings the missed line into the cache; write-back marks it dirty and defers the memory update until eviction.","difficulty":"hard","is_premium":true,"subject_id":12,"id":326},{"question_text":"In a banked/multi-port memory, a bank conflict occurs when:","option_a":"Two accesses target different banks","option_b":"Two simultaneous accesses target the same bank, serializing them","option_c":"The cache is cold","option_d":"Addresses are aligned","correct_option":"B","explanation":"Banks allow parallel access only to distinct banks; concurrent requests to the same bank must serialize, reducing effective bandwidth.","difficulty":"hard","is_premium":true,"subject_id":12,"id":327},{"question_text":"A balanced reduction tree (e.g., adder tree) for summing N inputs has latency proportional to:","option_a":"N","option_b":"log2(N)","option_c":"N^2","option_d":"constant","correct_option":"B","explanation":"A binary tree halves the operand count each stage, giving log2(N) depth versus N for a linear chain, key for high-throughput datapaths.","difficulty":"medium","is_premium":true,"subject_id":12,"id":328},{"question_text":"Carry-save addition is used in multipliers because it:","option_a":"Produces a final sum directly","option_b":"Defers carry propagation, adding many partial products quickly before one final carry-propagate add","option_c":"Removes the need for adders","option_d":"Works only for 2 operands","correct_option":"B","explanation":"CSA keeps sum and carry vectors separate (no long carry chain) until the last stage, accelerating multi-operand addition in multipliers.","difficulty":"hard","is_premium":true,"subject_id":12,"id":329},{"question_text":"Pipelining increases throughput but typically:","option_a":"Reduces latency of a single operation","option_b":"Increases single-operation latency while raising throughput","option_c":"Reduces area","option_d":"Removes hazards","correct_option":"B","explanation":"Each operation now passes through more registered stages (more cycles end-to-end), but a new result completes every cycle, raising throughput.","difficulty":"medium","is_premium":true,"subject_id":12,"id":330},{"question_text":"A control hazard from a taken branch in a deep pipeline is mitigated by:","option_a":"Always stalling until execute","option_b":"Branch prediction with speculative fetch and flush on mispredict","option_c":"Removing branches","option_d":"Lowering frequency","correct_option":"B","explanation":"Predictors let fetch continue speculatively; on a misprediction the wrong-path instructions are flushed. Deeper pipelines raise mispredict penalty.","difficulty":"hard","is_premium":true,"subject_id":12,"id":331},{"question_text":"A FIFO depth to decouple a producer of rate Rp and consumer of rate Rc over a burst of B cycles must hold at least:","option_a":"B beats always","option_b":"(Rp - Rc) x B beats of backlog (when Rp \u003e Rc)","option_c":"Rc x B","option_d":"1 beat","correct_option":"B","explanation":"Backlog accumulates at the rate difference for the burst duration; the FIFO must store (Rp-Rc)*B items to avoid overflow/back-pressure.","difficulty":"hard","is_premium":true,"subject_id":12,"id":332},{"question_text":"In SIMD/GPU execution, branch divergence within a warp hurts performance because:","option_a":"It crashes","option_b":"Both paths are executed serially with lanes masked, wasting throughput","option_c":"It doubles memory","option_d":"It changes clock","correct_option":"B","explanation":"A warp shares one program counter; divergent threads force serialized execution of each path with inactive lanes masked, lowering utilization.","difficulty":"hard","is_premium":true,"subject_id":12,"id":333},{"question_text":"Memory coalescing in GPUs improves bandwidth by:","option_a":"Caching registers","option_b":"Combining per-thread accesses to contiguous addresses into fewer wide memory transactions","option_c":"Adding banks","option_d":"Lowering latency of one access","correct_option":"B","explanation":"When threads in a warp access adjacent addresses, the hardware merges them into one or few wide transactions, maximizing DRAM efficiency.","difficulty":"hard","is_premium":true,"subject_id":12,"id":334},{"question_text":"A credit-based flow control scheme prevents buffer overflow by:","option_a":"Dropping packets","option_b":"Sending only when the sender holds credits reflecting free receiver buffer slots","option_c":"Using a faster clock","option_d":"Backpressure via ready only","correct_option":"B","explanation":"The receiver grants credits equal to free buffer entries; the sender transmits only while it has credits, guaranteeing no overflow across long links.","difficulty":"hard","is_premium":true,"subject_id":12,"id":335},{"question_text":"Gray-to-binary conversion of an N-bit value uses:","option_a":"Bitwise AND","option_b":"A prefix XOR: each binary bit is XOR of all higher Gray bits","option_c":"Addition","option_d":"Shift only","correct_option":"B","explanation":"b[i] = g[i] ^ g[i+1] ^ ... ^ g[N-1], computed as a running XOR from MSB down, the inverse of binary-to-Gray.","difficulty":"medium","is_premium":true,"subject_id":12,"id":336},{"question_text":"Retiming a pipeline (moving registers across logic) is used to:","option_a":"Reduce flop count always","option_b":"Balance stage delays to raise the achievable clock frequency without changing function","option_c":"Remove hazards","option_d":"Lower power only","correct_option":"B","explanation":"Retiming relocates registers to equalize combinational delay between stages, improving Fmax while preserving I/O behavior.","difficulty":"hard","is_premium":true,"subject_id":12,"id":337},{"question_text":"A 2-read 1-write register file with simultaneous read and write to the same address typically needs:","option_a":"Nothing special","option_b":"Write-first bypass (forward the written data to the read port) to avoid reading stale data","option_c":"A second clock","option_d":"A FIFO","correct_option":"B","explanation":"Without bypass, a same-cycle read returns the old value. A write-first/forwarding path supplies the just-written data to the read port.","difficulty":"hard","is_premium":true,"subject_id":12,"id":338},{"question_text":"Throughput of a fully pipelined design is ultimately limited by:","option_a":"Total latency","option_b":"The slowest pipeline stage (longest registered combinational delay)","option_c":"Number of stages","option_d":"Reset time","correct_option":"B","explanation":"The clock period must cover the worst stage delay; that stage sets Fmax and therefore the one-result-per-cycle throughput ceiling.","difficulty":"medium","is_premium":true,"subject_id":12,"id":339},{"question_text":"Qualcomm\u0027s flagship mobile SoC family is branded:","option_a":"Tegra","option_b":"Snapdragon","option_c":"Exynos","option_d":"Apple A-series","correct_option":"B","explanation":"Snapdragon is Qualcomm\u0027s mobile SoC brand.","difficulty":"easy","is_premium":false,"subject_id":11,"id":340},{"question_text":"Low-power design is critical at Qualcomm primarily because targets are:","option_a":"Servers","option_b":"Battery-powered mobile devices","option_c":"Desktops","option_d":"Mainframes","correct_option":"B","explanation":"Mobile SoCs are heavily power/thermal constrained.","difficulty":"easy","is_premium":false,"subject_id":11,"id":341},{"question_text":"Multiple voltage/power domains in a mobile SoC are managed using:","option_a":"A single rail","option_b":"UPF/CPF power intent with level shifters and isolation cells","option_c":"Only clock gating","option_d":"No special cells","correct_option":"B","explanation":"Power intent (UPF) defines domains, isolation, and level shifting.","difficulty":"hard","is_premium":false,"subject_id":11,"id":342},{"question_text":"A level shifter is required when:","option_a":"Two blocks share a rail","option_b":"A signal crosses between different voltage domains","option_c":"Clock is gated","option_d":"Reset asserted","correct_option":"B","explanation":"Level shifters translate logic levels between voltage domains.","difficulty":"medium","is_premium":false,"subject_id":11,"id":343},{"question_text":"An isolation cell is used to:","option_a":"Boost voltage","option_b":"Clamp outputs of a powered-down domain to a known value","option_c":"Add delay","option_d":"Divide the clock","correct_option":"B","explanation":"Isolation cells hold a safe value when a domain powers down.","difficulty":"hard","is_premium":false,"subject_id":11,"id":344},{"question_text":"A retention flop is used during power gating to:","option_a":"Increase speed","option_b":"Preserve state in a low-leakage cell while the main supply is off","option_c":"Add jitter","option_d":"Reset state","correct_option":"B","explanation":"Retention flops keep critical state through power-off via a backup supply.","difficulty":"hard","is_premium":false,"subject_id":11,"id":345},{"question_text":"Snapdragon SoCs integrate a Hexagon block which is a:","option_a":"GPU","option_b":"DSP","option_c":"Modem only","option_d":"Display controller","correct_option":"B","explanation":"Hexagon is Qualcomm\u0027s DSP architecture.","difficulty":"medium","is_premium":false,"subject_id":11,"id":346},{"question_text":"The Adreno block in Snapdragon is the:","option_a":"CPU","option_b":"GPU","option_c":"Modem","option_d":"ISP","correct_option":"B","explanation":"Adreno is Qualcomm\u0027s GPU.","difficulty":"easy","is_premium":false,"subject_id":11,"id":347},{"question_text":"An on-chip modem must handle CDC because:","option_a":"It has one clock","option_b":"RF/baseband and SoC fabric run on different clock domains","option_c":"It never crosses domains","option_d":"It is purely analog","correct_option":"B","explanation":"Modems bridge several clock domains, demanding robust CDC.","difficulty":"medium","is_premium":false,"subject_id":11,"id":348},{"question_text":"Power-aware simulation (UPF-driven) verifies:","option_a":"Only timing","option_b":"Correct behavior across power-down/up with isolation and retention","option_c":"Area","option_d":"DRC","correct_option":"B","explanation":"Power-aware sim checks isolation/retention sequencing functionally.","difficulty":"hard","is_premium":false,"subject_id":11,"id":349},{"question_text":"Why are async FIFOs heavily used in SoC interconnects?","option_a":"To save power","option_b":"To safely transfer data between asynchronous clock domains","option_c":"To increase area","option_d":"To remove resets","correct_option":"B","explanation":"Async FIFOs buffer and synchronize data across clock domains.","difficulty":"medium","is_premium":false,"subject_id":11,"id":350},{"question_text":"In an async FIFO, full/empty are computed by comparing:","option_a":"Binary pointers directly","option_b":"Gray-coded read/write pointers synchronized across domains","option_c":"Clock frequencies","option_d":"Reset signals","correct_option":"B","explanation":"Gray-coded pointers are synchronized and compared for full/empty.","difficulty":"hard","is_premium":false,"subject_id":11,"id":351},{"question_text":"FIFO depth sizing depends on:","option_a":"Only clock frequency","option_b":"Producer/consumer rate difference and burst length","option_c":"Reset polarity","option_d":"Gate count","correct_option":"B","explanation":"Depth covers rate mismatch and burst backpressure without overflow.","difficulty":"hard","is_premium":false,"subject_id":11,"id":352},{"question_text":"An AXI interface is common in Snapdragon because it supports:","option_a":"Only single transfers","option_b":"High-throughput bursts and outstanding transactions","option_c":"No handshakes","option_d":"Analog signals","correct_option":"B","explanation":"AXI\u0027s bursts/outstanding transactions suit high-bandwidth SoC traffic.","difficulty":"medium","is_premium":false,"subject_id":11,"id":353},{"question_text":"Thermal throttling in mobile SoCs is handled by:","option_a":"Increasing voltage","option_b":"DVFS lowering frequency/voltage when temperature rises","option_c":"Disabling reset","option_d":"Adding flops","correct_option":"B","explanation":"DVFS reduces power to manage heat under thermal limits.","difficulty":"medium","is_premium":false,"subject_id":11,"id":354},{"question_text":"Multi-bit flip-flops (MBFF) are used to:","option_a":"Increase leakage","option_b":"Save area and clock power by sharing clock circuitry","option_c":"Add skew","option_d":"Remove reset","correct_option":"B","explanation":"MBFFs merge flops sharing a clock driver, cutting power/area.","difficulty":"hard","is_premium":false,"subject_id":11,"id":355},{"question_text":"An efficient clock-gating cell is the integrated clock gate (ICG) which:","option_a":"Generates clocks","option_b":"Combines a latch and AND to avoid glitches on the gated clock","option_c":"Divides clocks only","option_d":"Adds jitter","correct_option":"B","explanation":"ICG uses a latch-based enable to produce glitch-free gated clocks.","difficulty":"hard","is_premium":false,"subject_id":11,"id":356},{"question_text":"Why prefer fine-grained clock gating in mobile designs?","option_a":"More area","option_b":"Maximizes dynamic power savings by gating small idle regions","option_c":"Less verification","option_d":"Higher leakage","correct_option":"B","explanation":"Fine-grained gating idles small blocks frequently to save power.","difficulty":"medium","is_premium":false,"subject_id":11,"id":357},{"question_text":"Multi-Vt cells let designers trade:","option_a":"Function for area","option_b":"Speed vs leakage (LVT fast/leaky, HVT slow/low-leak)","option_c":"Clock vs reset","option_d":"Skew vs jitter","correct_option":"B","explanation":"Vt selection balances performance against leakage power.","difficulty":"hard","is_premium":false,"subject_id":11,"id":358},{"question_text":"On critical paths, designers tend to use:","option_a":"HVT cells","option_b":"LVT (low-Vt) fast cells, accepting higher leakage","option_c":"Only retention flops","option_d":"No cells","correct_option":"B","explanation":"LVT cells speed up critical paths at the cost of leakage.","difficulty":"medium","is_premium":false,"subject_id":11,"id":359},{"question_text":"On non-critical paths, designers use HVT cells to:","option_a":"Increase speed","option_b":"Reduce leakage power where timing is relaxed","option_c":"Add skew","option_d":"Reset faster","correct_option":"B","explanation":"HVT cells cut leakage on paths with timing margin.","difficulty":"medium","is_premium":false,"subject_id":11,"id":360},{"question_text":"Lint checks in RTL flow catch:","option_a":"Layout DRC","option_b":"Coding issues like latches, width mismatches, unused signals early","option_c":"Electromigration","option_d":"IR drop","correct_option":"B","explanation":"Lint flags RTL structural/coding problems before synthesis.","difficulty":"medium","is_premium":false,"subject_id":11,"id":361},{"question_text":"A CDC verification tool checks for:","option_a":"Power grid","option_b":"Missing synchronizers and reconvergence on clock crossings","option_c":"DRC","option_d":"Antenna effects","correct_option":"B","explanation":"CDC tools find unsynchronized crossings and reconvergence hazards.","difficulty":"hard","is_premium":false,"subject_id":11,"id":362},{"question_text":"Reconvergence in CDC can cause:","option_a":"Lower power","option_b":"Data incoherency if related signals are synchronized separately","option_c":"Faster clock","option_d":"No issue","correct_option":"B","explanation":"Separately synchronized correlated bits can recombine incorrectly.","difficulty":"hard","is_premium":false,"subject_id":11,"id":363},{"question_text":"A handshake-based CDC (req/ack) is preferred when:","option_a":"Data rate is very high","option_b":"Occasional control transfers need guaranteed safe crossing","option_c":"No clocks exist","option_d":"Reset is async","correct_option":"B","explanation":"Req/ack handshakes safely move control/data at lower rates.","difficulty":"medium","is_premium":false,"subject_id":11,"id":364},{"question_text":"MTBF for a synchronizer improves with:","option_a":"Fewer flops","option_b":"More synchronizer stages and higher settling time budget","option_c":"Higher frequency","option_d":"Larger data width","correct_option":"B","explanation":"Additional stages/time exponentially increase MTBF.","difficulty":"hard","is_premium":false,"subject_id":11,"id":365},{"question_text":"DFT scan chains are inserted to:","option_a":"Speed up the design","option_b":"Enable controllability/observability for manufacturing test","option_c":"Save power","option_d":"Fix CDC","correct_option":"B","explanation":"Scan chains make internal flops testable for ATPG.","difficulty":"medium","is_premium":false,"subject_id":11,"id":366},{"question_text":"Stuck-at fault coverage measures:","option_a":"Timing margin","option_b":"Fraction of stuck-at-0/1 faults detectable by test patterns","option_c":"Power","option_d":"Area","correct_option":"B","explanation":"Coverage quantifies detectable stuck-at faults.","difficulty":"medium","is_premium":false,"subject_id":11,"id":367},{"question_text":"MBIST is used to test:","option_a":"Combinational logic","option_b":"On-chip memories with built-in self-test","option_c":"Clock trees","option_d":"Pads","correct_option":"B","explanation":"MBIST tests embedded RAMs on-chip.","difficulty":"medium","is_premium":false,"subject_id":11,"id":368},{"question_text":"A key mobile constraint that shapes microarchitecture is:","option_a":"Unlimited power","option_b":"Energy per operation (performance-per-watt)","option_c":"Infinite area","option_d":"No thermal limit","correct_option":"B","explanation":"Mobile design optimizes performance-per-watt above raw speed.","difficulty":"easy","is_premium":false,"subject_id":11,"id":369},{"question_text":"big.LITTLE / heterogeneous CPU clusters improve efficiency by:","option_a":"Using identical cores","option_b":"Pairing high-performance and high-efficiency cores for workload matching","option_c":"Removing caches","option_d":"Disabling DVFS","correct_option":"B","explanation":"Heterogeneous clusters run light tasks on efficient cores to save energy.","difficulty":"medium","is_premium":false,"subject_id":11,"id":370},{"question_text":"Cache coherency between CPU clusters requires a protocol like:","option_a":"UART","option_b":"MESI/MOESI (or ACE on the bus)","option_c":"I2C","option_d":"SPI","correct_option":"B","explanation":"Coherence protocols (MESI) and ACE keep caches consistent.","difficulty":"hard","is_premium":false,"subject_id":11,"id":371},{"question_text":"In MESI, the \u0027M\u0027 state means a cache line is:","option_a":"Invalid","option_b":"Modified (dirty, exclusively owned)","option_c":"Shared","option_d":"Empty","correct_option":"B","explanation":"Modified = dirty line owned only by this cache.","difficulty":"hard","is_premium":false,"subject_id":11,"id":372},{"question_text":"Why register the boundaries of each IP block in an SoC?","option_a":"To slow it down","option_b":"To ease timing closure and integration at the top level","option_c":"To remove DFT","option_d":"To add leakage","correct_option":"B","explanation":"Registered boundaries simplify SoC-level timing and integration.","difficulty":"medium","is_premium":false,"subject_id":11,"id":373},{"question_text":"An SDC constraint \u0027set_false_path\u0027 is used to:","option_a":"Add a real path","option_b":"Tell STA to ignore a path that is never functionally active","option_c":"Increase clock","option_d":"Fix DRC","correct_option":"B","explanation":"False paths exclude non-functional timing arcs from analysis.","difficulty":"hard","is_premium":false,"subject_id":11,"id":374},{"question_text":"A multicycle path constraint tells STA that:","option_a":"The path is false","option_b":"Data has more than one clock cycle to propagate","option_c":"The clock is gated","option_d":"Reset is async","correct_option":"B","explanation":"Multicycle paths relax timing across multiple clock periods.","difficulty":"hard","is_premium":false,"subject_id":11,"id":375},{"question_text":"Why is glitch-free clock muxing important in SoCs?","option_a":"To save area","option_b":"To switch clock sources without producing runt pulses that corrupt flops","option_c":"To add jitter","option_d":"For DRC","correct_option":"B","explanation":"Glitch-free clock mux avoids runt pulses when switching clocks.","difficulty":"hard","is_premium":false,"subject_id":11,"id":376},{"question_text":"A PLL in an SoC is used to:","option_a":"Store data","option_b":"Generate/multiply clock frequencies from a reference","option_c":"Reset logic","option_d":"Test memory","correct_option":"B","explanation":"PLLs synthesize higher, stable clocks from a reference.","difficulty":"medium","is_premium":false,"subject_id":11,"id":377},{"question_text":"Voltage droop during high di/dt events is mitigated by:","option_a":"Removing decaps","option_b":"On-chip decoupling capacitors","option_c":"Faster clocks","option_d":"More flops","correct_option":"B","explanation":"Decaps supply transient current to limit supply droop.","difficulty":"hard","is_premium":false,"subject_id":11,"id":378},{"question_text":"Why is a 2-flop synchronizer insufficient for a data bus?","option_a":"It is too slow","option_b":"Different bits may resolve in different cycles causing data skew","option_c":"It uses too much power","option_d":"It needs no clock","correct_option":"B","explanation":"Per-bit synchronization can skew bits; use FIFO/Gray for buses.","difficulty":"hard","is_premium":false,"subject_id":11,"id":379},{"question_text":"A common Qualcomm interview ask: design a divide-by-3 with 50% duty needs:","option_a":"1 flop","option_b":"Flops clocked on both edges combined (posedge + negedge counters)","option_c":"A latch only","option_d":"No logic","correct_option":"B","explanation":"50% divide-by-odd uses both clock edges combined.","difficulty":"hard","is_premium":false,"subject_id":11,"id":380},{"question_text":"To debounce a mechanical button in RTL you use:","option_a":"A PLL","option_b":"A counter/timer that ignores transitions for a settle period","option_c":"A FIFO","option_d":"An adder","correct_option":"B","explanation":"A timed counter filters bounce by requiring stable input.","difficulty":"medium","is_premium":false,"subject_id":11,"id":381},{"question_text":"An efficient way to count set bits (popcount) in hardware is:","option_a":"A single flop","option_b":"An adder tree of partial sums","option_c":"A FIFO","option_d":"A PLL","correct_option":"B","explanation":"Popcount uses a tree of adders summing bit groups.","difficulty":"hard","is_premium":false,"subject_id":11,"id":382},{"question_text":"Round-robin arbitration is preferred over fixed-priority to:","option_a":"Save power","option_b":"Provide fairness and avoid starvation among requesters","option_c":"Increase clock","option_d":"Reduce area only","correct_option":"B","explanation":"Round-robin rotates priority to prevent starvation.","difficulty":"medium","is_premium":false,"subject_id":11,"id":383},{"question_text":"A credit-based flow control scheme prevents:","option_a":"Clock skew","option_b":"Buffer overflow by only sending when the receiver has credits","option_c":"Leakage","option_d":"DRC errors","correct_option":"B","explanation":"Credits ensure the sender never overruns the receiver\u0027s buffer.","difficulty":"hard","is_premium":false,"subject_id":11,"id":384},{"question_text":"Why are gate-level simulations with SDF run late in the flow?","option_a":"To check RTL syntax","option_b":"To verify functional+timing behavior on the post-layout netlist","option_c":"To save power","option_d":"To do DRC","correct_option":"B","explanation":"GLS with SDF validates real timing on the final netlist.","difficulty":"hard","is_premium":false,"subject_id":11,"id":385},{"question_text":"X-propagation issues are often caught by:","option_a":"DRC","option_b":"X-pessimism/X-prop aware gate-level simulation","option_c":"LVS","option_d":"Antenna check","correct_option":"B","explanation":"GLS exposes X-propagation that RTL sim may mask.","difficulty":"hard","is_premium":false,"subject_id":11,"id":386},{"question_text":"Reset domain crossing (RDC) is a concern because:","option_a":"Clocks never cross","option_b":"A signal from a reset-asserted domain into a running domain can glitch","option_c":"Power is off","option_d":"DRC fails","correct_option":"B","explanation":"RDC can inject metastability/glitches like CDC; needs analysis.","difficulty":"hard","is_premium":false,"subject_id":11,"id":387},{"question_text":"The best way to answer a Qualcomm low-power question is to discuss:","option_a":"Only frequency","option_b":"Clock/power gating, multi-Vt, DVFS, and verification tradeoffs together","option_c":"Only area","option_d":"Only DRC","correct_option":"B","explanation":"Strong answers weave multiple low-power techniques and their tradeoffs.","difficulty":"medium","is_premium":false,"subject_id":11,"id":388},{"question_text":"A power switch (header/footer) cell in a power-gated design is sized to:","option_a":"Maximize leakage","option_b":"Limit IR drop and rush current when turning a domain on","option_c":"Increase jitter","option_d":"Divide the clock","correct_option":"B","explanation":"Power switches are sized/sequenced to control inrush current and IR drop at wake-up.","difficulty":"hard","is_premium":false,"subject_id":11,"id":389},{"question_text":"In UPF, an isolation cell is required on a signal that:","option_a":"Stays in the same always-on domain","option_b":"Crosses from a power-gated (shut-off) domain into an active domain","option_c":"Is a clock","option_d":"Is a reset only","correct_option":"B","explanation":"When a source domain is powered down its outputs float; isolation cells clamp them to a known value (0/1) for the receiving active domain.","difficulty":"hard","is_premium":true,"subject_id":11,"id":390},{"question_text":"A level shifter is needed when a signal crosses between domains that differ in:","option_a":"Clock frequency","option_b":"Supply voltage","option_c":"Reset polarity","option_d":"Metal layer","correct_option":"B","explanation":"Different VDD levels mean a logic-1 from a low-V domain may not be recognized by a high-V domain; level shifters translate voltage levels.","difficulty":"medium","is_premium":true,"subject_id":11,"id":391},{"question_text":"A retention flop is used during power gating to:","option_a":"Increase speed","option_b":"Preserve state in a small always-on shadow latch while the main logic is powered down","option_c":"Reduce area","option_d":"Filter glitches","correct_option":"B","explanation":"Retention flops save the register value into a low-leakage always-on element so state survives shutdown, enabling fast wake without reloading.","difficulty":"hard","is_premium":true,"subject_id":11,"id":392},{"question_text":"DVFS saves dynamic power most effectively because dynamic power scales as:","option_a":"Linearly with V","option_b":"With V^2 * f (so lowering voltage gives quadratic savings)","option_c":"With 1/f","option_d":"Independent of V","correct_option":"B","explanation":"Dynamic power P = C*V^2*f. Reducing voltage quadratically cuts power; DVFS lowers both V and f when performance demand is low.","difficulty":"medium","is_premium":true,"subject_id":11,"id":393},{"question_text":"The dominant component of static (leakage) power in advanced nodes is:","option_a":"Switching current","option_b":"Subthreshold and gate-oxide leakage","option_c":"Short-circuit current","option_d":"Crowbar only","correct_option":"B","explanation":"At small geometries, subthreshold leakage and gate tunneling dominate static power; power gating and high-Vt cells mitigate it.","difficulty":"medium","is_premium":true,"subject_id":11,"id":394},{"question_text":"Using high-Vt (HVT) cells on non-critical paths is a technique to:","option_a":"Increase speed","option_b":"Reduce leakage at the cost of some delay","option_c":"Reduce area","option_d":"Improve routing","correct_option":"B","explanation":"HVT cells leak less but switch slower. Placing them on paths with timing margin cuts leakage without hurting Fmax; LVT cells go on critical paths.","difficulty":"medium","is_premium":true,"subject_id":11,"id":395},{"question_text":"A glitch-free clock mux is necessary because a naive mux switching clocks can:","option_a":"Only add latency","option_b":"Produce a runt/partial clock pulse that violates min pulse width and corrupts flops","option_c":"Lower voltage","option_d":"Increase skew only","correct_option":"B","explanation":"Switching mid-pulse can chop a clock edge, creating a too-short pulse. The handshake mux only switches when the target clock is low, avoiding runts.","difficulty":"hard","is_premium":true,"subject_id":11,"id":396},{"question_text":"Clock gating reduces dynamic power primarily by:","option_a":"Lowering supply voltage","option_b":"Stopping the clock toggling (and thus flop/clock-tree switching) when logic is idle","option_c":"Reducing capacitance","option_d":"Removing flops","correct_option":"B","explanation":"A large fraction of dynamic power is the clock network and register clocking; gating idle blocks eliminates that switching activity.","difficulty":"medium","is_premium":true,"subject_id":11,"id":397},{"question_text":"In a multi-voltage SoC, the \u0027always-on\u0027 domain typically contains:","option_a":"The main CPU core","option_b":"Power-management controller, isolation/retention control, and wake logic","option_c":"The GPU","option_d":"All memories","correct_option":"B","explanation":"Always-on logic must run while other domains sleep: it controls power switches, isolation enables, retention, and handles wake-up events.","difficulty":"medium","is_premium":true,"subject_id":11,"id":398},{"question_text":"A pulse synchronizer (toggle-based) is preferred over a simple 2-flop synchronizer for a single-cycle pulse when the destination clock is:","option_a":"Faster than source","option_b":"Slower than source (the pulse could be missed)","option_c":"The same","option_d":"Gated off","correct_option":"B","explanation":"A short pulse may fall between slow destination edges and be lost. Converting to a toggle that the destination edge-detects guarantees one captured pulse.","difficulty":"hard","is_premium":true,"subject_id":11,"id":399},{"question_text":"Power switch (header/footer) sizing in power gating trades off:","option_a":"Area vs clock skew","option_b":"IR drop / wake-up rush current vs leakage and area","option_c":"Setup vs hold","option_d":"DRC vs LVS","correct_option":"B","explanation":"Bigger switches lower on-resistance (less IR drop) but cost area/leakage and create larger inrush current at wake; sizing balances these.","difficulty":"hard","is_premium":true,"subject_id":11,"id":400},{"question_text":"Coarse-grain vs fine-grain power gating: coarse-grain means:","option_a":"A switch per standard cell","option_b":"Shared power switches for a whole block/region","option_c":"No switches","option_d":"Always-on cells","correct_option":"B","explanation":"Coarse-grain shares switches across a region (lower area/leakage overhead, simpler), whereas fine-grain per-cell switches add large overhead and are rarely used.","difficulty":"medium","is_premium":true,"subject_id":11,"id":401},{"question_text":"An enable-level (clock-enable) flop reduces power compared to a feedback mux flop because:","option_a":"It has fewer states","option_b":"Modern ICG-based clock gating stops clocking instead of recirculating data every cycle","option_c":"It uses HVT","option_d":"It removes the reset","correct_option":"B","explanation":"Recirculating-mux enable still toggles the clock each cycle. ICG-based gating stops the clock to idle flops, saving clock-tree and flop power.","difficulty":"medium","is_premium":true,"subject_id":11,"id":402},{"question_text":"Voltage scaling lowers maximum frequency because lower V causes:","option_a":"Higher leakage only","option_b":"Increased gate delay (transistors drive less current)","option_c":"More skew","option_d":"Larger area","correct_option":"B","explanation":"Drive current drops with voltage, increasing propagation delay, so the maximum operating frequency must be reduced as voltage drops.","difficulty":"medium","is_premium":true,"subject_id":11,"id":403},{"question_text":"In low-power CDC, an isolation cell value of \u0027clamp to 0\u0027 is chosen when:","option_a":"The receiver expects an active-high inactive level","option_b":"Driving the receiver into a safe inactive state requires logic 0 (e.g., active-high enable)","option_c":"Always","option_d":"Never for enables","correct_option":"B","explanation":"The clamp value must put the receiver in a safe state; for an active-high control, isolating to 0 keeps it inactive while the source domain is off.","difficulty":"hard","is_premium":true,"subject_id":11,"id":404},{"question_text":"Memory low-power retention (light sleep) typically keeps:","option_a":"Full read/write capability","option_b":"Only the array biased to retain data while peripherals/IO are off, at reduced voltage","option_c":"Clocks running","option_d":"All ports active","correct_option":"B","explanation":"Retention mode lowers the array voltage just enough to hold bits while disabling access circuitry, cutting leakage but preventing access until wake.","difficulty":"hard","is_premium":true,"subject_id":11,"id":405},{"question_text":"An ICG (integrated clock gating) cell prevents glitches by latching enable on:","option_a":"The rising edge","option_b":"The low (transparent) phase of the clock","option_c":"Reset","option_d":"Both edges","correct_option":"B","explanation":"The negative-level latch captures enable while the clock is low, so the subsequent AND produces only complete pulses without slivers.","difficulty":"medium","is_premium":true,"subject_id":11,"id":406},{"question_text":"Which reduces both dynamic and leakage power for an idle block most completely?","option_a":"Clock gating","option_b":"Power gating (shutting off the supply)","option_c":"Operand isolation","option_d":"Bus encoding","correct_option":"B","explanation":"Clock gating stops dynamic power but leakage remains. Power gating removes the supply, eliminating both (at cost of state loss / wake latency).","difficulty":"medium","is_premium":true,"subject_id":11,"id":407},{"question_text":"Operand isolation saves power by:","option_a":"Removing the datapath","option_b":"Preventing input toggling into an arithmetic block whose result is unused that cycle","option_c":"Gating the clock","option_d":"Lowering voltage","correct_option":"B","explanation":"If a block\u0027s output is not selected, holding its inputs stable stops unnecessary combinational switching, saving dynamic power.","difficulty":"hard","is_premium":true,"subject_id":11,"id":408},{"question_text":"Wake-up inrush current during power-on is controlled by:","option_a":"Turning all switches at once","option_b":"Sequencing/daisy-chaining power switches so the supply ramps gradually","option_c":"Higher voltage","option_d":"Removing decap","correct_option":"B","explanation":"Enabling all switches simultaneously causes a large current surge and IR droop. Staged switch enabling limits rush current and supply noise.","difficulty":"hard","is_premium":true,"subject_id":11,"id":409},{"question_text":"[Interview] Why is a 2\u0027s complement adder able to subtract without separate subtraction hardware?","option_a":"Because it uses BCD","option_b":"A - B = A + (~B) + 1, so the same adder adds the inverted operand with carry-in 1","option_c":"Because subtraction is illegal in binary","option_d":"It cannot subtract","correct_option":"B","explanation":"Subtraction becomes addition of the 2\u0027s complement, reusing the adder.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Intel, Qualcomm","topic":"Number Systems","subject_id":1,"id":410},{"question_text":"[Interview] Design a circuit to detect if a 4-bit number is divisible by 3. Best approach is:","option_a":"A ripple counter","option_b":"A small FSM/combinational decode over the 16 input values (mod-3 logic)","option_c":"A PLL","option_d":"Impossible","correct_option":"B","explanation":"With 16 values you derive a minimized SOP or a mod-3 FSM.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Nvidia, AMD","topic":"Combinational Design","subject_id":1,"id":411},{"question_text":"[Interview] How many 2:1 muxes are needed to build an 8:1 mux?","option_a":"8","option_b":"7 (a tree of 4 + 2 + 1)","option_c":"3","option_d":"1","correct_option":"B","explanation":"An 8:1 mux tree uses 4+2+1 = 7 two-input muxes.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Apple, Broadcom","topic":"Multiplexers","subject_id":1,"id":412},{"question_text":"[Interview] A glitch on a combinational output before it settles is best handled by:","option_a":"Ignoring it","option_b":"Registering the output so downstream logic samples only the stable value","option_c":"Adding a latch","option_d":"Increasing fan-out","correct_option":"B","explanation":"Registering filters glitches by sampling after settling.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Intel","topic":"Hazards","subject_id":1,"id":413},{"question_text":"[Interview] Convert the gray code 1110 to binary.","option_a":"1011","option_b":"1100","option_c":"1111","option_d":"1001","correct_option":"A","explanation":"MSB copies; each next bit = previous binary bit XOR current gray bit -\u003e 1011.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Qualcomm","topic":"Codes","subject_id":1,"id":414},{"question_text":"[Interview] Minimum flip-flops for a mod-12 counter:","option_a":"12","option_b":"4 (since 2^4=16 \u003e= 12)","option_c":"3","option_d":"6","correct_option":"B","explanation":"Need ceil(log2(12)) = 4 flip-flops.","difficulty":"easy","is_interview":true,"is_premium":true,"company":"Texas Instruments","topic":"Counters","subject_id":1,"id":415},{"question_text":"[Interview] What does this infer: always @(posedge clk) if (en) q \u003c= d; (no else)?","option_a":"A latch","option_b":"An enabled flip-flop that holds its value when en=0 (no latch, it\u0027s clocked)","option_c":"A combinational mux","option_d":"A tri-state","correct_option":"B","explanation":"Inside a clocked block, a missing else holds the reg via the flop, not a latch.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Nvidia, Intel","topic":"Synthesis","subject_id":2,"id":416},{"question_text":"[Interview] In a clocked always block, why use non-blocking \u003c= for q1\u003c=q0; q2\u003c=q1;?","option_a":"It is faster","option_b":"It models parallel register updates so a proper shift register is created","option_c":"It avoids a clock","option_d":"It infers a latch","correct_option":"B","explanation":"Non-blocking schedules updates together, giving correct shift-register behavior.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Qualcomm, AMD","topic":"Blocking vs Non-blocking","subject_id":2,"id":417},{"question_text":"[Interview] Difference between $display and $monitor?","option_a":"They are identical","option_b":"$display prints once when executed; $monitor prints whenever a listed signal changes","option_c":"$monitor is synthesizable","option_d":"$display only works in synthesis","correct_option":"B","explanation":"$monitor is continuous; $display is one-shot.","difficulty":"easy","is_interview":true,"is_premium":true,"company":"Intel","topic":"Simulation","subject_id":2,"id":418},{"question_text":"[Interview] What is the output width of {3{2\u0027b10}}?","option_a":"2 bits","option_b":"6 bits (101010)","option_c":"3 bits","option_d":"8 bits","correct_option":"B","explanation":"Replication {3{2\u0027b10}} repeats the 2-bit pattern three times = 6 bits.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Broadcom","topic":"Operators","subject_id":2,"id":419},{"question_text":"[Interview] Why can casex be dangerous in RTL?","option_a":"It is too slow","option_b":"It treats x/z in the case item as don\u0027t-care, which can mask bugs and mismatch sim vs synthesis","option_c":"It is unsynthesizable","option_d":"It needs a clock","correct_option":"B","explanation":"casex wildcards on x/z can hide real values; casez or explicit cases are safer.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Nvidia","topic":"Case statements","subject_id":2,"id":420},{"question_text":"[Interview] How do you model a synchronous reset vs asynchronous reset?","option_a":"Both use the same sensitivity list","option_b":"Async lists reset in sensitivity (posedge clk or negedge rst_n); sync checks reset only on clk edge","option_c":"Sync reset needs no clock","option_d":"There is no difference","correct_option":"B","explanation":"Async reset appears in the sensitivity list; sync reset is evaluated inside the clocked block.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Apple, Qualcomm","topic":"Reset","subject_id":2,"id":421},{"question_text":"[Interview] Why does slowing the clock NOT fix a hold violation?","option_a":"It does fix it","option_b":"Hold depends on launch/capture at the same edge; clock period does not appear in the hold equation","option_c":"Because hold needs more logic","option_d":"Because hold is a setup problem","correct_option":"B","explanation":"Hold is a min-delay check independent of clock period; fix with delay buffers.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Intel, Nvidia","topic":"Hold timing","subject_id":3,"id":422},{"question_text":"[Interview] What is clock uncertainty used to model in STA?","option_a":"Logic delay","option_b":"Jitter plus design margin (and skew before CTS)","option_c":"Wire length","option_d":"Gate count","correct_option":"B","explanation":"Uncertainty budgets jitter/margin so timing closes with real-world variation.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Qualcomm","topic":"Constraints","subject_id":3,"id":423},{"question_text":"[Interview] When would you legitimately set a multicycle path?","option_a":"Across asynchronous clocks","option_b":"When the design guarantees data has N\u003e1 cycles to propagate (e.g., a slow datapath enabled every 2 cycles)","option_c":"On every path","option_d":"Never","correct_option":"B","explanation":"Multicycle relaxes timing where the protocol allows multiple cycles.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"AMD","topic":"Exceptions","subject_id":3,"id":424},{"question_text":"[Interview] Setup slack is negative by 100ps. Name two fixes.","option_a":"Add hold buffers and slow nothing","option_b":"Reduce logic depth / upsize cells / restructure, or relax the clock period","option_c":"Only change reset","option_d":"Increase fan-out","correct_option":"B","explanation":"Setup fixes reduce path delay or relax the clock.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Intel","topic":"Slack","subject_id":3,"id":425},{"question_text":"[Interview] What does OCV (on-chip variation) derating account for?","option_a":"Only temperature","option_b":"Process/voltage/temperature differences between launch and capture paths within the same die","option_c":"Clock frequency","option_d":"Routing only","correct_option":"B","explanation":"OCV derates paths to model intra-die variation pessimistically.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Nvidia, Qualcomm","topic":"Variation","subject_id":3,"id":426},{"question_text":"[Interview] Why prefer \u0027logic\u0027 over \u0027reg\u0027/\u0027wire\u0027 in SystemVerilog RTL?","option_a":"It is faster in silicon","option_b":"logic is a 4-state type usable in both procedural and continuous contexts (single driver), reducing confusion","option_c":"It removes the need for clocks","option_d":"It is 2-state","correct_option":"B","explanation":"logic unifies reg/wire for single-driver signals with clearer intent.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Intel, Apple","topic":"Types","subject_id":4,"id":427},{"question_text":"[Interview] What does always_comb give you that always @(*) does not?","option_a":"Nothing","option_b":"Tool-checked combinational intent (errors on latch inference / multiple drivers) and correct sensitivity for functions","option_c":"A clock","option_d":"Asynchronous reset","correct_option":"B","explanation":"always_comb adds compile-time checks and broader sensitivity than @(*).","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Nvidia","topic":"Procedural blocks","subject_id":4,"id":428},{"question_text":"[Interview] unique case vs priority case difference?","option_a":"They are identical","option_b":"unique asserts the items are mutually exclusive (parallel); priority implies ordered evaluation","option_c":"unique needs a clock","option_d":"priority is unsynthesizable","correct_option":"B","explanation":"unique = one-hot/parallel intent; priority = first-match ordered intent.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"AMD","topic":"Case","subject_id":4,"id":429},{"question_text":"[Interview] Why use an interface in SystemVerilog?","option_a":"To slow simulation","option_b":"To bundle related signals + modports, reducing port-list errors and easing connectivity","option_c":"To remove clocks","option_d":"To add latches","correct_option":"B","explanation":"Interfaces group signals and define directions via modports.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Qualcomm","topic":"Interfaces","subject_id":4,"id":430},{"question_text":"[Interview] How do you parameterize a reusable N-bit register module?","option_a":"Hardcode the width","option_b":"Use a parameter (e.g., parameter WIDTH=8) and declare ports as [WIDTH-1:0]","option_c":"Use a define only","option_d":"It cannot be parameterized","correct_option":"B","explanation":"Parameters make modules width-configurable and reusable.","difficulty":"easy","is_interview":true,"is_premium":true,"company":"Broadcom","topic":"Parameterization","subject_id":4,"id":431},{"question_text":"[Interview] What is the difference between code coverage and functional coverage?","option_a":"They are the same","option_b":"Code coverage is automatic structural metric; functional coverage is hand-written to map to spec features","option_c":"Functional coverage is automatic","option_d":"Code coverage maps to the spec","correct_option":"B","explanation":"Functional coverage measures spec intent; code coverage measures RTL exercised.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Intel, Nvidia","topic":"Coverage","subject_id":5,"id":432},{"question_text":"[Interview] Why use a mailbox between generator and driver?","option_a":"For clock generation","option_b":"It is a thread-safe FIFO to pass transactions between concurrent processes","option_c":"To reset the DUT","option_d":"To do coverage","correct_option":"B","explanation":"Mailboxes safely hand transactions across SystemVerilog processes.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Qualcomm","topic":"Testbench","subject_id":5,"id":433},{"question_text":"[Interview] What does a \u0027rand\u0027 vs \u0027randc\u0027 variable mean?","option_a":"Nothing","option_b":"rand is uniformly random; randc is random-cyclic (no repeats until all values used)","option_c":"randc is constant","option_d":"rand cannot be constrained","correct_option":"B","explanation":"randc cycles through all values before repeating; rand can repeat.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"AMD","topic":"Randomization","subject_id":5,"id":434},{"question_text":"[Interview] How do constraints solve when two constraints conflict?","option_a":"It always passes","option_b":"randomize() returns 0 (failure); you must detect and handle it","option_c":"It picks one randomly","option_d":"It crashes the tool","correct_option":"B","explanation":"Infeasible constraint sets make randomize() fail (return 0).","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Nvidia","topic":"Constraints","subject_id":5,"id":435},{"question_text":"[Interview] What is the purpose of a virtual interface in a class-based TB?","option_a":"To generate clocks","option_b":"To let dynamic class objects drive/sample static DUT pins through a handle","option_c":"To remove the DUT","option_d":"To do coverage","correct_option":"B","explanation":"Virtual interfaces connect dynamic classes to the static RTL interface.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Apple","topic":"Interfaces","subject_id":5,"id":436},{"question_text":"[Interview] Which UVM phase is time-consuming (a task) and why?","option_a":"build_phase","option_b":"run_phase, because stimulus/checking happen over simulation time","option_c":"connect_phase","option_d":"report_phase","correct_option":"B","explanation":"run_phase is the only task-based phase where time advances.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Intel, Qualcomm","topic":"Phases","subject_id":6,"id":437},{"question_text":"[Interview] How does the UVM factory help reuse?","option_a":"It speeds simulation","option_b":"It lets you override a component/object type with a derived one without changing the env","option_c":"It generates clocks","option_d":"It does coverage","correct_option":"B","explanation":"Factory overrides swap implementations centrally for reuse.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Nvidia","topic":"Factory","subject_id":6,"id":438},{"question_text":"[Interview] What carries config and virtual interfaces down the UVM hierarchy?","option_a":"uvm_event","option_b":"uvm_config_db (set/get)","option_c":"uvm_barrier","option_d":"uvm_printer","correct_option":"B","explanation":"uvm_config_db passes resources (vif, config) by path.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"AMD","topic":"config_db","subject_id":6,"id":439},{"question_text":"[Interview] Difference between uvm_object_utils and uvm_component_utils?","option_a":"None","option_b":"Components are quasi-static and part of the hierarchy; objects (transactions) are transient — different factory registration macros","option_c":"Objects have phases","option_d":"Components are randomized","correct_option":"B","explanation":"Components live in the tree with phases; objects are dynamic data.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Qualcomm","topic":"Components","subject_id":6,"id":440},{"question_text":"[Interview] What is an analysis port used for?","option_a":"Driving pins","option_b":"Broadcasting observed transactions (e.g., monitor -\u003e scoreboard/coverage) to many subscribers","option_c":"Generating clocks","option_d":"Resetting","correct_option":"B","explanation":"uvm_analysis_port broadcasts to all connected subscribers.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Intel","topic":"TLM","subject_id":6,"id":441},{"question_text":"[Interview] What does objection handling (raise/drop) control?","option_a":"Coverage","option_b":"When a phase ends — the phase stays active while objections are raised","option_c":"Clock frequency","option_d":"Factory overrides","correct_option":"B","explanation":"Objections keep run_phase alive until all are dropped.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Nvidia, AMD","topic":"Objections","subject_id":6,"id":442},{"question_text":"[Interview] Difference between |-\u003e and |=\u003e in SVA?","option_a":"None","option_b":"|-\u003e checks the consequent on the same cycle (overlapped); |=\u003e checks it the next cycle (non-overlapped)","option_c":"|=\u003e is unsynthesizable","option_d":"|-\u003e needs no clock","correct_option":"B","explanation":"Overlapped vs non-overlapped implication differ by one cycle.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Intel, Nvidia","topic":"Implication","subject_id":7,"id":443},{"question_text":"[Interview] Why add \u0027disable iff (!rst_n)\u0027 to a property?","option_a":"To speed it up","option_b":"To suppress assertion evaluation during reset so false failures are not reported","option_c":"To create a clock","option_d":"To add coverage","correct_option":"B","explanation":"disable iff voids checks while reset is active.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Qualcomm","topic":"Reset handling","subject_id":7,"id":444},{"question_text":"[Interview] Write a property: grant must follow request within 1-3 cycles.","option_a":"req |-\u003e gnt","option_b":"req |-\u003e ##[1:3] gnt","option_c":"gnt |=\u003e req","option_d":"req and gnt","correct_option":"B","explanation":"##[1:3] specifies a 1 to 3 cycle delay window for gnt.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"AMD","topic":"Sequences","subject_id":7,"id":445},{"question_text":"[Interview] What does $past(sig, 2) return?","option_a":"The next value","option_b":"The value sig held 2 clock cycles ago","option_c":"A reset","option_d":"The current value","correct_option":"B","explanation":"$past(sig, n) samples n cycles earlier.","difficulty":"easy","is_interview":true,"is_premium":true,"company":"Intel","topic":"System functions","subject_id":7,"id":446},{"question_text":"[Interview] Why use \u0027cover property\u0027 alongside \u0027assert property\u0027?","option_a":"To replace assertions","option_b":"To confirm the interesting scenario was actually exercised (avoids vacuous pass)","option_c":"To generate clocks","option_d":"To drive the DUT","correct_option":"B","explanation":"cover proves the antecedent occurred, guarding against vacuous success.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Nvidia","topic":"Coverage","subject_id":7,"id":447},{"question_text":"[Interview] What causes routing congestion and how do you fix it?","option_a":"Too few cells; add more","option_b":"Local over-utilization/high pin density; fix via placement spreading, cell padding, or floorplan changes","option_c":"Slow clock; speed it up","option_d":"Reset polarity","correct_option":"B","explanation":"Congestion comes from too many nets in a region; spread placement/adjust floorplan.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Intel, Nvidia","topic":"Routing","subject_id":8,"id":448},{"question_text":"[Interview] Why is CTS done after placement but before signoff routing?","option_a":"It is done first","option_b":"Cells must be placed to know clock sink locations, then build a balanced tree to minimize skew before final timing","option_c":"CTS removes the clock","option_d":"CTS is optional","correct_option":"B","explanation":"Clock tree needs placed sinks; balancing skew precedes signoff.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Qualcomm","topic":"CTS","subject_id":8,"id":449},{"question_text":"[Interview] How is IR drop reduced in a power-hungry block?","option_a":"Remove power straps","option_b":"Strengthen the power mesh, add straps/vias, and place decaps near high-activity cells","option_c":"Slow the clock only","option_d":"Add more flops","correct_option":"B","explanation":"A stronger grid plus decaps limits supply droop.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"AMD","topic":"Power integrity","subject_id":8,"id":450},{"question_text":"[Interview] What is the antenna effect and a standard fix?","option_a":"RF interference; add shielding","option_b":"Charge accumulation on long metal during fab damaging gate oxide; fix with antenna diodes or metal jumping","option_c":"Crosstalk; add spacing","option_d":"IR drop; add straps","correct_option":"B","explanation":"Antenna diodes/layer jumps discharge accumulated process charge.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Intel","topic":"Manufacturing","subject_id":8,"id":451},{"question_text":"[Interview] What is the difference between setup and hold fixes during PD?","option_a":"Both add buffers everywhere","option_b":"Setup: reduce path delay / restructure; Hold: insert delay buffers on short paths after CTS","option_c":"They are the same","option_d":"Only change reset","correct_option":"B","explanation":"Setup reduces delay; hold adds delay on fast paths.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Nvidia, Qualcomm","topic":"Timing closure","subject_id":8,"id":452},{"question_text":"[Interview] Why are multi-Vt cells used in a final design?","option_a":"To increase leakage","option_b":"LVT on critical paths for speed, HVT elsewhere to cut leakage power","option_c":"To remove clocks","option_d":"For DRC only","correct_option":"B","explanation":"Mixing Vt trades speed and leakage per-path.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Apple","topic":"Low power","subject_id":8,"id":453},{"question_text":"[Interview] In AXI, why must VALID not depend combinationally on READY?","option_a":"For speed","option_b":"To avoid a combinational loop that could deadlock the handshake","option_c":"For burst support","option_d":"For addressing","correct_option":"B","explanation":"A VALID-depends-on-READY loop risks deadlock; protocol forbids it.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Qualcomm, ARM","topic":"AXI handshake","subject_id":9,"id":454},{"question_text":"[Interview] How does AXI support out-of-order responses?","option_a":"By using one channel","option_b":"Transaction IDs (AxID/xID) let responses return and be matched out of order","option_c":"By stalling","option_d":"It does not","correct_option":"B","explanation":"ID tagging enables out-of-order completion in AXI.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Nvidia, ARM","topic":"AXI ordering","subject_id":9,"id":455},{"question_text":"[Interview] Why can an AXI burst not cross a 4KB boundary?","option_a":"Clock limits","option_b":"4KB matches memory page granularity, simplifying address decode and protection","option_c":"Parity","option_d":"Pin count","correct_option":"B","explanation":"The 4KB rule aligns bursts with page boundaries for decode/protection.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Intel, ARM","topic":"AXI bursts","subject_id":9,"id":456},{"question_text":"[Interview] Why is an AXI-to-APB bridge used in an SoC?","option_a":"To speed APB up","option_b":"To adapt high-performance AXI traffic into simple low-bandwidth APB register accesses","option_c":"To add coherence","option_d":"To generate clocks","correct_option":"B","explanation":"Bridges convert fast AXI to simple APB peripheral transfers.","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Qualcomm","topic":"Bridges","subject_id":9,"id":457},{"question_text":"[Interview] Difference between AHB and APB in one line?","option_a":"AHB is for peripherals, APB for memory","option_b":"AHB is a pipelined high-performance bus; APB is a simple low-power non-pipelined peripheral bus","option_c":"They are identical","option_d":"APB supports bursts, AHB does not","correct_option":"B","explanation":"AHB = high performance pipelined; APB = simple peripheral bus.","difficulty":"easy","is_interview":true,"is_premium":true,"company":"ARM, Broadcom","topic":"AMBA","subject_id":9,"id":458},{"question_text":"[Interview] How do you safely cross AXI traffic between two async clock domains?","option_a":"Direct wires","option_b":"An asynchronous FIFO / clock-domain-crossing bridge with Gray-coded pointers","option_c":"A single flop","option_d":"A latch","correct_option":"B","explanation":"Async FIFO/CDC bridge handles different clocks safely.","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Nvidia, Qualcomm","topic":"CDC","subject_id":9,"id":459},{"question_text":"The physical design flow generally starts after which step?","option_a":"RTL coding","option_b":"Logic synthesis (netlist generation)","option_c":"Tape-out","option_d":"Packaging","correct_option":"B","explanation":"PD begins with the synthesized gate-level netlist.","difficulty":"easy","is_premium":false,"subject_id":8,"id":460},{"question_text":"Floorplanning primarily decides:","option_a":"Gate logic","option_b":"Chip dimensions, macro placement, and power grid plan","option_c":"RTL behavior","option_d":"Test vectors","correct_option":"B","explanation":"Floorplanning sets die size, macro/IO locations, and power structure.","difficulty":"easy","is_premium":false,"subject_id":8,"id":461},{"question_text":"Standard cell rows are aligned to:","option_a":"Random positions","option_b":"A fixed row height (site grid)","option_c":"Only the corners","option_d":"The clock tree","correct_option":"B","explanation":"Standard cells fit into rows of a uniform height defined by the library.","difficulty":"medium","is_premium":false,"subject_id":8,"id":462},{"question_text":"Utilization in floorplanning refers to:","option_a":"Power used","option_b":"Fraction of core area occupied by cells","option_c":"Clock frequency","option_d":"Number of pins","correct_option":"B","explanation":"Utilization is the ratio of placed cell area to available core area.","difficulty":"medium","is_premium":false,"subject_id":8,"id":463},{"question_text":"Very high utilization tends to cause:","option_a":"Easy routing","option_b":"Routing congestion and timing closure difficulty","option_c":"Lower power always","option_d":"No effect","correct_option":"B","explanation":"Packing cells too tightly leaves little room for routing.","difficulty":"medium","is_premium":false,"subject_id":8,"id":464},{"question_text":"Placement aims to:","option_a":"Define RTL","option_b":"Assign physical locations to standard cells optimizing timing/congestion/power","option_c":"Generate clocks","option_d":"Create test patterns","correct_option":"B","explanation":"Placement positions cells to optimize PPA and routability.","difficulty":"easy","is_premium":false,"subject_id":8,"id":465},{"question_text":"Global placement vs detailed placement: global placement:","option_a":"Legalizes cells exactly","option_b":"Roughly distributes cells; detailed placement legalizes them on the grid","option_c":"Routes wires","option_d":"Builds the clock tree","correct_option":"B","explanation":"Global placement spreads cells; detailed placement snaps them legally.","difficulty":"medium","is_premium":false,"subject_id":8,"id":466},{"question_text":"Legalization ensures cells:","option_a":"Overlap","option_b":"Are placed on legal sites/rows without overlaps","option_c":"Are routed","option_d":"Are clocked","correct_option":"B","explanation":"Legalization removes overlaps and aligns cells to sites.","difficulty":"medium","is_premium":false,"subject_id":8,"id":467},{"question_text":"Clock Tree Synthesis (CTS) is performed to:","option_a":"Route signals","option_b":"Build a balanced clock distribution minimizing skew and meeting latency","option_c":"Place macros","option_d":"Generate RTL","correct_option":"B","explanation":"CTS constructs the clock network balancing skew/insertion delay.","difficulty":"easy","is_premium":false,"subject_id":8,"id":468},{"question_text":"Before CTS, clocks in STA are treated as:","option_a":"Propagated","option_b":"Ideal (zero skew/latency)","option_c":"Asynchronous","option_d":"Gated","correct_option":"B","explanation":"Pre-CTS uses ideal clocks; post-CTS uses propagated clocks.","difficulty":"medium","is_premium":false,"subject_id":8,"id":469},{"question_text":"Routing connects cell pins using:","option_a":"Only one metal layer","option_b":"Multiple metal layers and vias","option_c":"The substrate only","option_d":"Clock buffers","correct_option":"B","explanation":"Routing uses several metal layers connected by vias.","difficulty":"easy","is_premium":false,"subject_id":8,"id":470},{"question_text":"Global routing vs detailed routing: global routing:","option_a":"Assigns exact tracks","option_b":"Plans routing regions/coarse paths; detailed routing assigns exact tracks/vias","option_c":"Places cells","option_d":"Builds clock tree","correct_option":"B","explanation":"Global routing plans coarse paths; detailed routing finalizes geometry.","difficulty":"medium","is_premium":false,"subject_id":8,"id":471},{"question_text":"A DRC (Design Rule Check) verifies:","option_a":"Logical equivalence","option_b":"Layout meets foundry geometric rules (spacing, width, etc.)","option_c":"Timing","option_d":"Power only","correct_option":"B","explanation":"DRC checks manufacturability rules like spacing and width.","difficulty":"easy","is_premium":false,"subject_id":8,"id":472},{"question_text":"LVS (Layout Versus Schematic) checks:","option_a":"Timing","option_b":"That the layout matches the schematic/netlist connectivity","option_c":"DRC rules","option_d":"Clock skew","correct_option":"B","explanation":"LVS confirms layout connectivity equals the intended netlist.","difficulty":"easy","is_premium":false,"subject_id":8,"id":473},{"question_text":"Antenna effect during fabrication is caused by:","option_a":"Radio antennas","option_b":"Charge accumulation on long metal connected to gates during plasma etch","option_c":"Clock skew","option_d":"High temperature","correct_option":"B","explanation":"Charge build-up on metal can damage thin gate oxides during processing.","difficulty":"hard","is_premium":false,"subject_id":8,"id":474},{"question_text":"Antenna violations are typically fixed by:","option_a":"Adding flops","option_b":"Inserting antenna diodes or layer jumping","option_c":"Increasing the clock","option_d":"Removing buffers","correct_option":"B","explanation":"Diodes provide discharge paths; jogging to higher layers also helps.","difficulty":"hard","is_premium":false,"subject_id":8,"id":475},{"question_text":"Power planning creates:","option_a":"Clock tree","option_b":"Power/ground rings, straps, and rails for current delivery","option_c":"Test patterns","option_d":"RTL","correct_option":"B","explanation":"Power planning builds the PG network (rings, straps, rails).","difficulty":"medium","is_premium":false,"subject_id":8,"id":476},{"question_text":"IR drop refers to:","option_a":"Clock skew","option_b":"Voltage drop across power network resistance under current load","option_c":"Temperature rise","option_d":"A timing arc","correct_option":"B","explanation":"IR drop (V=IR) lowers local supply, degrading timing.","difficulty":"medium","is_premium":false,"subject_id":8,"id":477},{"question_text":"Excessive IR drop causes:","option_a":"Faster cells","option_b":"Slower cells and potential timing/functional failures","option_c":"Lower temperature","option_d":"No effect","correct_option":"B","explanation":"Reduced local voltage increases cell delay, risking failures.","difficulty":"medium","is_premium":false,"subject_id":8,"id":478},{"question_text":"Electromigration (EM) is:","option_a":"Clock movement","option_b":"Gradual metal atom transport under high current density, causing opens/shorts","option_c":"A routing layer","option_d":"A placement step","correct_option":"B","explanation":"EM degrades wires over time due to high current density.","difficulty":"hard","is_premium":false,"subject_id":8,"id":479},{"question_text":"Decoupling capacitors (decaps) are placed to:","option_a":"Increase resistance","option_b":"Provide local charge and stabilize the supply against transient current","option_c":"Generate clocks","option_d":"Route signals","correct_option":"B","explanation":"Decaps reduce dynamic IR drop by supplying transient current locally.","difficulty":"medium","is_premium":false,"subject_id":8,"id":480},{"question_text":"Filler cells are inserted to:","option_a":"Add logic","option_b":"Fill gaps in rows ensuring continuity of power rails and well/implant","option_c":"Build clock tree","option_d":"Generate test","correct_option":"B","explanation":"Fillers maintain rail continuity and DRC-clean spacing.","difficulty":"medium","is_premium":false,"subject_id":8,"id":481},{"question_text":"Tap cells (well taps) are used to:","option_a":"Route clocks","option_b":"Tie wells/substrate to power/ground to prevent latch-up","option_c":"Add flops","option_d":"Reduce skew","correct_option":"B","explanation":"Tap cells bias the wells/substrate, preventing latch-up.","difficulty":"hard","is_premium":false,"subject_id":8,"id":482},{"question_text":"Latch-up is:","option_a":"A timing latch","option_b":"A parasitic low-impedance path between supply and ground that can destroy the chip","option_c":"A clock issue","option_d":"A routing layer","correct_option":"B","explanation":"Latch-up triggers a destructive SCR-like short between rails.","difficulty":"hard","is_premium":false,"subject_id":8,"id":483},{"question_text":"Congestion in routing is indicated by:","option_a":"Low pin density","option_b":"Demand for routing tracks exceeding available supply in regions","option_c":"Low utilization","option_d":"Few vias","correct_option":"B","explanation":"Congestion arises where routing demand exceeds track supply.","difficulty":"medium","is_premium":false,"subject_id":8,"id":484},{"question_text":"Congestion can be reduced by:","option_a":"Increasing utilization","option_b":"Spreading cells, adding routing blockages/keepouts, or restructuring logic","option_c":"Removing power straps","option_d":"Higher clock","correct_option":"B","explanation":"Lowering local density and guiding placement reduces congestion.","difficulty":"medium","is_premium":false,"subject_id":8,"id":485},{"question_text":"Setup timing in PD is often improved by:","option_a":"Adding hold buffers","option_b":"Upsizing cells, restructuring, or useful skew","option_c":"Removing the clock","option_d":"Increasing IR drop","correct_option":"B","explanation":"Faster cells, better placement, and useful skew help setup.","difficulty":"medium","is_premium":false,"subject_id":8,"id":486},{"question_text":"Hold timing in PD is commonly fixed by:","option_a":"Upsizing all cells","option_b":"Inserting delay/hold buffers on short paths","option_c":"Increasing the period","option_d":"Removing flops","correct_option":"B","explanation":"Adding delay on fast paths satisfies hold.","difficulty":"medium","is_premium":false,"subject_id":8,"id":487},{"question_text":"A LEF file describes:","option_a":"Timing","option_b":"Abstract cell/layer physical info (pins, blockages, layers) for PD","option_c":"RTL","option_d":"Test vectors","correct_option":"B","explanation":"LEF gives abstract physical/library data used in place-and-route.","difficulty":"medium","is_premium":false,"subject_id":8,"id":488},{"question_text":"A DEF file contains:","option_a":"Cell timing","option_b":"Design-specific placement/routing/netlist physical data","option_c":"RTL","option_d":"Liberty tables","correct_option":"B","explanation":"DEF stores the design\u0027s physical placement and routing data.","difficulty":"medium","is_premium":false,"subject_id":8,"id":489},{"question_text":"A GDSII (or OASIS) file is:","option_a":"RTL","option_b":"The final mask layout database sent to the foundry","option_c":"A timing report","option_d":"A clock spec","correct_option":"B","explanation":"GDSII/OASIS is the layout handoff format for fabrication.","difficulty":"easy","is_premium":false,"subject_id":8,"id":490},{"question_text":"Macros (e.g., SRAMs) are usually placed:","option_a":"Randomly in the core","option_b":"At the periphery/edges with channels, considering pin access","option_c":"Outside the die","option_d":"On the clock tree","correct_option":"B","explanation":"Macros are placed thoughtfully (often edges) to ease routing and access.","difficulty":"medium","is_premium":false,"subject_id":8,"id":491},{"question_text":"A keep-out/halo region around a macro:","option_a":"Adds logic","option_b":"Reserves space to avoid placing standard cells too close to the macro","option_c":"Routes clocks","option_d":"Increases skew","correct_option":"B","explanation":"Halos prevent cells crowding macro pins, aiding routability.","difficulty":"medium","is_premium":false,"subject_id":8,"id":492},{"question_text":"Pin placement/IO planning affects:","option_a":"Only aesthetics","option_b":"Routability and timing of top-level connections","option_c":"RTL behavior","option_d":"Clock period only","correct_option":"B","explanation":"Good IO placement reduces top-level routing and timing issues.","difficulty":"medium","is_premium":false,"subject_id":8,"id":493},{"question_text":"Multi-Vt cells (HVT/SVT/LVT) trade off:","option_a":"Area only","option_b":"Speed vs leakage power (LVT fast/leaky, HVT slow/low-leak)","option_c":"Routing","option_d":"Clock skew","correct_option":"B","explanation":"Threshold-voltage choice balances performance and leakage.","difficulty":"hard","is_premium":false,"subject_id":8,"id":494},{"question_text":"To reduce leakage on non-critical paths, tools swap to:","option_a":"LVT cells","option_b":"HVT (high-Vt) cells","option_c":"Larger cells","option_d":"Clock buffers","correct_option":"B","explanation":"HVT cells cut leakage where timing slack allows.","difficulty":"medium","is_premium":false,"subject_id":8,"id":495},{"question_text":"Clock gating in PD reduces:","option_a":"Area","option_b":"Dynamic power by stopping the clock to idle logic","option_c":"Leakage only","option_d":"Skew","correct_option":"B","explanation":"Gating idle clocks saves switching (dynamic) power.","difficulty":"medium","is_premium":false,"subject_id":8,"id":496},{"question_text":"Power gating reduces:","option_a":"Dynamic power","option_b":"Leakage by switching off the supply to idle blocks","option_c":"Skew","option_d":"Routing","correct_option":"B","explanation":"Power gating shuts off Vdd to dormant blocks, cutting leakage.","difficulty":"hard","is_premium":false,"subject_id":8,"id":497},{"question_text":"Isolation cells are needed when:","option_a":"Two clocks meet","option_b":"A powered-down block\u0027s outputs must be clamped to a safe value","option_c":"Routing congests","option_d":"DRC fails","correct_option":"B","explanation":"Isolation clamps floating outputs of off domains to known values.","difficulty":"hard","is_premium":false,"subject_id":8,"id":498},{"question_text":"Level shifters are required between:","option_a":"Two same-voltage domains","option_b":"Domains operating at different supply voltages","option_c":"Clock and reset","option_d":"Two flops","correct_option":"B","explanation":"Level shifters translate signals crossing voltage domains.","difficulty":"hard","is_premium":false,"subject_id":8,"id":499},{"question_text":"Retention flops are used in power gating to:","option_a":"Speed clocks","option_b":"Preserve state during power-down via a retained shadow latch","option_c":"Reduce skew","option_d":"Fix DRC","correct_option":"B","explanation":"Retention registers save state through power-down.","difficulty":"hard","is_premium":false,"subject_id":8,"id":500},{"question_text":"A UPF/CPF file specifies:","option_a":"Timing","option_b":"Power intent (domains, isolation, level shifters, retention)","option_c":"RTL logic","option_d":"Test","correct_option":"B","explanation":"UPF/CPF capture multi-voltage power intent for the flow.","difficulty":"hard","is_premium":false,"subject_id":8,"id":501},{"question_text":"Scan chains are inserted for:","option_a":"Power savings","option_b":"Design-for-test (controllability/observability of flops)","option_c":"Clock skew","option_d":"Routing","correct_option":"B","explanation":"Scan stitches flops into shift chains for testability.","difficulty":"medium","is_premium":false,"subject_id":8,"id":502},{"question_text":"Scan chain reordering during PD aims to:","option_a":"Increase wirelength","option_b":"Reduce scan routing wirelength based on physical placement","option_c":"Add logic","option_d":"Raise skew","correct_option":"B","explanation":"Reordering chains by proximity shortens scan routing.","difficulty":"hard","is_premium":false,"subject_id":8,"id":503},{"question_text":"Useful skew is the deliberate adjustment of clock arrival to:","option_a":"Increase power","option_b":"Borrow time between stages to close timing","option_c":"Add DRC","option_d":"Randomize","correct_option":"B","explanation":"Useful skew shifts clock edges to balance slack across stages.","difficulty":"hard","is_premium":false,"subject_id":8,"id":504},{"question_text":"Clock buffers/inverters in a clock tree are sized to:","option_a":"Maximize skew","option_b":"Balance loads and control insertion delay/skew","option_c":"Add logic","option_d":"Fix DRC only","correct_option":"B","explanation":"CTS sizes buffers to balance the tree and meet skew targets.","difficulty":"medium","is_premium":false,"subject_id":8,"id":505},{"question_text":"A clock mesh vs a clock tree generally offers:","option_a":"Higher skew","option_b":"Lower skew at the cost of more power/area","option_c":"No difference","option_d":"Less routing","correct_option":"B","explanation":"Meshes reduce skew but consume more power and area.","difficulty":"hard","is_premium":false,"subject_id":8,"id":506},{"question_text":"Signal integrity crosstalk is worsened by:","option_a":"Short parallel wires","option_b":"Long parallel adjacent nets with fast transitions","option_c":"Wide spacing","option_d":"Shielding","correct_option":"B","explanation":"Long, closely-coupled fast-switching nets increase crosstalk.","difficulty":"hard","is_premium":false,"subject_id":8,"id":507},{"question_text":"Crosstalk is mitigated by:","option_a":"Reducing spacing","option_b":"Increasing spacing, shielding, and limiting parallel run length","option_c":"Removing power","option_d":"Higher clock","correct_option":"B","explanation":"More spacing, shield wires, and shorter runs reduce coupling.","difficulty":"medium","is_premium":false,"subject_id":8,"id":508},{"question_text":"Buffer insertion on long nets is used to:","option_a":"Increase delay","option_b":"Restore signal slew and reduce delay/RC on long interconnect","option_c":"Add skew","option_d":"Fix DRC only","correct_option":"B","explanation":"Buffers break long RC nets, improving slew and delay.","difficulty":"medium","is_premium":false,"subject_id":8,"id":509},{"question_text":"A timing ECO (Engineering Change Order) is:","option_a":"A full re-synthesis","option_b":"A targeted late-stage fix (resize/buffer/reroute) to close timing","option_c":"An RTL rewrite","option_d":"A test change","correct_option":"B","explanation":"ECOs make minimal, localized changes to fix remaining issues.","difficulty":"medium","is_premium":false,"subject_id":8,"id":510},{"question_text":"Metal layer assignment typically routes clocks on:","option_a":"Thin lower layers","option_b":"Thicker/upper layers with lower resistance for low skew","option_c":"Substrate","option_d":"Poly only","correct_option":"B","explanation":"Clocks often use higher, lower-resistance layers to reduce delay/skew.","difficulty":"hard","is_premium":false,"subject_id":8,"id":511},{"question_text":"Double patterning at advanced nodes addresses:","option_a":"Timing","option_b":"Lithography limits by splitting a layer into two masks","option_c":"Power","option_d":"Test","correct_option":"B","explanation":"Double patterning overcomes single-exposure pitch limits.","difficulty":"hard","is_premium":false,"subject_id":8,"id":512},{"question_text":"A coloring (mask) violation in multi-patterning indicates:","option_a":"A timing fail","option_b":"Two features too close cannot be assigned to different masks legally","option_c":"An IR drop","option_d":"A clock skew","correct_option":"B","explanation":"Coloring conflicts mean features can\u0027t be split across masks per rules.","difficulty":"hard","is_premium":false,"subject_id":8,"id":513},{"question_text":"Placement blockages are used to:","option_a":"Add cells","option_b":"Prevent cell placement in specified regions (e.g., over macros)","option_c":"Route clocks","option_d":"Increase skew","correct_option":"B","explanation":"Blockages keep cells out of certain areas.","difficulty":"medium","is_premium":false,"subject_id":8,"id":514},{"question_text":"Routing blockages reserve regions to:","option_a":"Force routing","option_b":"Prevent routing on specified layers/areas (e.g., over sensitive analog)","option_c":"Place cells","option_d":"Add flops","correct_option":"B","explanation":"Routing blockages exclude wiring from designated regions/layers.","difficulty":"medium","is_premium":false,"subject_id":8,"id":515},{"question_text":"A \u0027don\u0027t use\u0027 list in PD specifies:","option_a":"Cells the tool must avoid (e.g., problematic for timing/EM)","option_b":"Cells to always use","option_c":"Clock buffers only","option_d":"Macros","correct_option":"A","explanation":"don\u0027t_use removes certain library cells from optimization choices.","difficulty":"medium","is_premium":false,"subject_id":8,"id":516},{"question_text":"Negotiated congestion routing iteratively:","option_a":"Ignores congestion","option_b":"Rips up and reroutes nets adjusting costs to resolve congestion","option_c":"Places cells","option_d":"Builds clock tree","correct_option":"B","explanation":"Rip-up-and-reroute with cost negotiation resolves contested tracks.","difficulty":"hard","is_premium":false,"subject_id":8,"id":517},{"question_text":"The \u0027core\u0027 area vs \u0027die\u0027 area: the core is:","option_a":"The whole chip including pads","option_b":"The inner region where standard cells/macros are placed","option_c":"The package","option_d":"The clock tree","correct_option":"B","explanation":"Core is the placeable area inside the IO/pad ring.","difficulty":"easy","is_premium":false,"subject_id":8,"id":518},{"question_text":"Aspect ratio in floorplanning is:","option_a":"Power/area","option_b":"Height-to-width ratio of the core/die","option_c":"Clock/data ratio","option_d":"Pin count","correct_option":"B","explanation":"Aspect ratio is the core\u0027s height:width.","difficulty":"easy","is_premium":false,"subject_id":8,"id":519},{"question_text":"Why register/balance macro pins facing the core?","option_a":"For aesthetics","option_b":"To ease pin access and reduce routing detours/congestion","option_c":"To add skew","option_d":"To raise IR drop","correct_option":"B","explanation":"Good macro orientation improves pin access and routability.","difficulty":"medium","is_premium":false,"subject_id":8,"id":520},{"question_text":"An incremental/eco placement after CTS targets:","option_a":"Re-floorplanning","option_b":"Fixing timing/congestion with minimal disruption","option_c":"RTL changes","option_d":"New test","correct_option":"B","explanation":"Incremental placement makes small fixes post-CTS.","difficulty":"medium","is_premium":false,"subject_id":8,"id":521},{"question_text":"Setup violations appearing only post-CTS are often due to:","option_a":"Ideal clocks","option_b":"Real clock insertion delay/skew now modeled","option_c":"RTL bugs","option_d":"Test logic","correct_option":"B","explanation":"Propagated clocks reveal skew/latency effects on timing.","difficulty":"hard","is_premium":false,"subject_id":8,"id":522},{"question_text":"Hold violations frequently increase after CTS because:","option_a":"Clocks are ideal","option_b":"Real skew can shorten the effective hold margin on some paths","option_c":"Routing is done","option_d":"RTL changed","correct_option":"B","explanation":"Clock skew from CTS often exposes/creates hold issues.","difficulty":"hard","is_premium":false,"subject_id":8,"id":523},{"question_text":"A \u0027spare cell\u0027 strategy provides:","option_a":"Power straps","option_b":"Pre-placed unused gates for future metal-only ECOs","option_c":"Clock buffers","option_d":"Test points","correct_option":"B","explanation":"Spare cells enable late metal-only functional fixes.","difficulty":"hard","is_premium":false,"subject_id":8,"id":524},{"question_text":"A metal-only ECO is attractive because it:","option_a":"Requires all masks","option_b":"Reuses base layers, changing only metal/via masks (cheaper, faster)","option_c":"Rewrites RTL","option_d":"Adds flops freely","correct_option":"B","explanation":"Metal-only ECOs avoid expensive base-layer mask changes.","difficulty":"hard","is_premium":false,"subject_id":8,"id":525},{"question_text":"Wire RC parasitics are extracted by:","option_a":"Synthesis","option_b":"A parasitic extraction (RCX) tool producing SPEF","option_c":"DRC","option_d":"CTS","correct_option":"B","explanation":"Extraction produces SPEF capturing wire R and C for STA.","difficulty":"medium","is_premium":false,"subject_id":8,"id":526},{"question_text":"A SPEF file contains:","option_a":"RTL","option_b":"Extracted parasitic resistances/capacitances of nets","option_c":"Cell timing","option_d":"Test vectors","correct_option":"B","explanation":"SPEF holds net parasitics for accurate post-route timing.","difficulty":"medium","is_premium":false,"subject_id":8,"id":527},{"question_text":"Signoff STA differs from in-design STA by:","option_a":"Using ideal clocks","option_b":"Using sign-off-quality extraction, more corners, and golden tools","option_c":"Ignoring parasitics","option_d":"Skipping setup","correct_option":"B","explanation":"Signoff uses accurate parasitics and full corner coverage with golden engines.","difficulty":"hard","is_premium":false,"subject_id":8,"id":528},{"question_text":"MMMC analysis stands for:","option_a":"Multi-Macro Multi-Cell","option_b":"Multi-Mode Multi-Corner","option_c":"Mask-Metal Multi-Channel","option_d":"Multi-Memory Multi-Clock","correct_option":"B","explanation":"MMMC analyzes multiple operating modes across multiple PVT corners.","difficulty":"hard","is_premium":false,"subject_id":8,"id":529},{"question_text":"Why analyze multiple modes (e.g., functional, test, sleep)?","option_a":"For fun","option_b":"Each mode has different constraints/active paths needing closure","option_c":"To increase power","option_d":"No reason","correct_option":"B","explanation":"Different modes activate different paths/constraints to be met.","difficulty":"hard","is_premium":false,"subject_id":8,"id":530},{"question_text":"A timing path group is used to:","option_a":"Generate clocks","option_b":"Categorize paths (reg2reg, in2reg, etc.) for focused optimization/reporting","option_c":"Route nets","option_d":"Add flops","correct_option":"B","explanation":"Path groups organize timing analysis and optimization effort.","difficulty":"medium","is_premium":false,"subject_id":8,"id":531},{"question_text":"A \u0027shielding\u0027 technique for critical nets adds:","option_a":"Extra logic","option_b":"Grounded/power wires adjacent to reduce crosstalk","option_c":"More flops","option_d":"Clock buffers","correct_option":"B","explanation":"Shield wires isolate sensitive nets from aggressors.","difficulty":"hard","is_premium":false,"subject_id":8,"id":532},{"question_text":"Redundant via insertion improves:","option_a":"Timing only","option_b":"Yield/reliability by reducing via failure risk","option_c":"Clock skew","option_d":"Power gating","correct_option":"B","explanation":"Double vias guard against single-via opens, improving yield.","difficulty":"medium","is_premium":false,"subject_id":8,"id":533},{"question_text":"Metal density rules require:","option_a":"Minimum density only","option_b":"Density within min/max windows, often needing metal fill","option_c":"No metal","option_d":"Only clock metal","correct_option":"B","explanation":"CMP planarity needs density in range; fill is added to meet minimums.","difficulty":"hard","is_premium":false,"subject_id":8,"id":534},{"question_text":"Metal fill is added to:","option_a":"Carry signals","option_b":"Meet density rules for planarity (CMP), usually as floating/grounded fill","option_c":"Build the clock tree","option_d":"Add logic","correct_option":"B","explanation":"Fill balances metal density for manufacturing planarity.","difficulty":"medium","is_premium":false,"subject_id":8,"id":535},{"question_text":"CMP stands for:","option_a":"Clock Mesh Planning","option_b":"Chemical Mechanical Polishing/Planarization","option_c":"Core Macro Placement","option_d":"Cell Metal Pitch","correct_option":"B","explanation":"CMP planarizes wafer surfaces between metal layers.","difficulty":"medium","is_premium":false,"subject_id":8,"id":536},{"question_text":"A \u0027placement-aware\u0027 synthesis (physical synthesis) improves accuracy by:","option_a":"Ignoring layout","option_b":"Considering physical location/wireload during synthesis","option_c":"Skipping timing","option_d":"Only logic","correct_option":"B","explanation":"Physical synthesis uses placement info for realistic timing.","difficulty":"hard","is_premium":false,"subject_id":8,"id":537},{"question_text":"Wireload models (older flow) estimate:","option_a":"Power only","option_b":"Net parasitics based on fanout before placement","option_c":"Clock skew","option_d":"Test coverage","correct_option":"B","explanation":"Wireload models statistically estimate pre-layout net delays.","difficulty":"medium","is_premium":false,"subject_id":8,"id":538},{"question_text":"Why are wireload models less accurate at advanced nodes?","option_a":"Wires don\u0027t matter","option_b":"Interconnect-dominated delays vary too much with actual placement","option_c":"They are exact","option_d":"Clocks change","correct_option":"B","explanation":"Real interconnect delay depends on layout, not just fanout.","difficulty":"hard","is_premium":false,"subject_id":8,"id":539},{"question_text":"A \u0027guide\u0027 or region constraint in placement:","option_a":"Forces routing","option_b":"Encourages/forces a group of cells into a specified area","option_c":"Adds clocks","option_d":"Removes flops","correct_option":"B","explanation":"Regions/guides cluster related logic for locality/timing.","difficulty":"medium","is_premium":false,"subject_id":8,"id":540},{"question_text":"Hierarchical (block-level) PD is used for:","option_a":"Tiny designs","option_b":"Large SoCs, enabling parallel block development and reuse","option_c":"Clock gen","option_d":"Test only","correct_option":"B","explanation":"Hierarchy partitions big chips for manageable, parallel implementation.","difficulty":"medium","is_premium":false,"subject_id":8,"id":541},{"question_text":"A timing budget/interface constraint between blocks defines:","option_a":"Power only","option_b":"Allowed delay at block boundaries to close top-level timing","option_c":"RTL","option_d":"Test","correct_option":"B","explanation":"Budgets allocate boundary timing so blocks integrate cleanly.","difficulty":"hard","is_premium":false,"subject_id":8,"id":542},{"question_text":"Feedthrough buffers are inserted to:","option_a":"Add logic","option_b":"Route signals across a block that has no related logic","option_c":"Build clock tree","option_d":"Reduce IR drop","correct_option":"B","explanation":"Feedthroughs pass nets through a block region cleanly.","difficulty":"hard","is_premium":false,"subject_id":8,"id":543},{"question_text":"The main goal of place-and-route is to achieve:","option_a":"Only low power","option_b":"PPA closure (performance, power, area) with DRC/LVS-clean layout","option_c":"Only small area","option_d":"Only high speed","correct_option":"B","explanation":"PD balances PPA while producing a manufacturable, clean layout.","difficulty":"easy","is_premium":false,"subject_id":8,"id":544},{"question_text":"A \u0027pin\u0027 vs \u0027port\u0027 vs \u0027net\u0027 in physical terms: a net is:","option_a":"A cell","option_b":"The electrical connection joining pins/ports","option_c":"A metal layer","option_d":"A clock","correct_option":"B","explanation":"A net connects pins/ports electrically.","difficulty":"easy","is_premium":false,"subject_id":8,"id":545},{"question_text":"The clock \u0027insertion delay\u0027 is:","option_a":"Data path delay","option_b":"Delay from clock source to the flop clock pin","option_c":"Setup time","option_d":"Hold time","correct_option":"B","explanation":"Insertion (latency) delay is source-to-sink clock delay.","difficulty":"medium","is_premium":false,"subject_id":8,"id":546},{"question_text":"Why minimize clock insertion delay?","option_a":"To increase power","option_b":"To reduce jitter accumulation and OCV impact","option_c":"To add skew","option_d":"To fix DRC","correct_option":"B","explanation":"Shorter clock paths reduce variation/jitter sensitivity.","difficulty":"hard","is_premium":false,"subject_id":8,"id":547},{"question_text":"A timing \u0027recovery\u0027/\u0027removal\u0027 check in PD relates to:","option_a":"Data setup/hold","option_b":"Asynchronous reset deassertion timing vs clock","option_c":"Routing","option_d":"Power","correct_option":"B","explanation":"Recovery/removal check async control deassertion timing.","difficulty":"hard","is_premium":false,"subject_id":8,"id":548},{"question_text":"A buffer tree on a high-fanout net (HFN) is built to:","option_a":"Increase load on one cell","option_b":"Distribute drive across many sinks, improving slew/timing","option_c":"Add skew","option_d":"Fix DRC","correct_option":"B","explanation":"HFN buffering balances loading and restores transitions.","difficulty":"medium","is_premium":false,"subject_id":8,"id":549},{"question_text":"A \u0027pulldown\u0027 in IR analysis hotspot indicates:","option_a":"Excess decap","option_b":"A region with high current demand and weak PG, needing more straps/decap","option_c":"Low power","option_d":"No issue","correct_option":"B","explanation":"Hotspots flag insufficient power delivery requiring grid reinforcement.","difficulty":"hard","is_premium":false,"subject_id":8,"id":550},{"question_text":"Why are upper metal layers thicker?","option_a":"For aesthetics","option_b":"Lower resistance for power distribution and long/clock routes","option_c":"To add capacitance","option_d":"For test","correct_option":"B","explanation":"Thick top layers reduce resistance for power and global routing.","difficulty":"medium","is_premium":false,"subject_id":8,"id":551},{"question_text":"A \u0027tie-high/tie-low\u0027 cell is used to:","option_a":"Generate clocks","option_b":"Safely connect logic inputs to constant 1/0 instead of rails directly","option_c":"Add flops","option_d":"Route clocks","correct_option":"B","explanation":"Tie cells provide reliable constant inputs, protecting gates.","difficulty":"medium","is_premium":false,"subject_id":8,"id":552},{"question_text":"Why not connect gate inputs directly to power/ground rails?","option_a":"It is faster","option_b":"Direct rail ties risk antenna/ESD/reliability issues; tie cells are safer","option_c":"No reason","option_d":"It saves clocks","correct_option":"B","explanation":"Tie cells avoid reliability/antenna concerns of direct rail connections.","difficulty":"hard","is_premium":false,"subject_id":8,"id":553},{"question_text":"Congestion vs timing is often a:","option_a":"Non-issue","option_b":"Trade-off requiring balancing during placement/optimization","option_c":"Fixed relationship","option_d":"Power metric","correct_option":"B","explanation":"Optimizing timing can worsen congestion and vice versa; PD balances both.","difficulty":"medium","is_premium":false,"subject_id":8,"id":554},{"question_text":"The final signoff checks before tape-out include:","option_a":"Only RTL sim","option_b":"DRC, LVS, STA, IR/EM, and physical verification clean","option_c":"Only timing","option_d":"Only power","correct_option":"B","explanation":"Tape-out requires DRC/LVS/STA/IR-EM and full physical signoff.","difficulty":"medium","is_premium":false,"subject_id":8,"id":555},{"question_text":"An ERC (Electrical Rule Check) verifies:","option_a":"Timing arcs","option_b":"Electrical issues like floating gates, unconnected pins, shorts","option_c":"RTL","option_d":"Clock period","correct_option":"B","explanation":"ERC catches electrical problems such as floating/unconnected nodes.","difficulty":"hard","is_premium":false,"subject_id":8,"id":556},{"question_text":"The overall objective of good floorplanning is to:","option_a":"Maximize area","option_b":"Set up placement/routing/power for successful timing and DRC closure","option_c":"Add more clocks","option_d":"Increase IR drop","correct_option":"B","explanation":"A good floorplan enables the rest of the flow to converge.","difficulty":"easy","is_premium":false,"subject_id":8,"id":557},{"question_text":"A well-formed power mesh/grid primarily helps to:","option_a":"Increase leakage","option_b":"Minimize IR drop and supply reliable current to all cells","option_c":"Add clock skew","option_d":"Reduce metal layers","correct_option":"B","explanation":"A robust power grid limits IR drop and electromigration risk.","difficulty":"medium","is_premium":false,"subject_id":8,"id":558},{"question_text":"Signal integrity crosstalk between adjacent nets is reduced by:","option_a":"Removing shielding","option_b":"Spacing, shielding, and limiting parallel run length","option_c":"Increasing aggressor strength","option_d":"Adding more vias only","correct_option":"B","explanation":"Spacing/shielding and shorter parallel runs cut capacitive crosstalk.","difficulty":"hard","is_premium":false,"subject_id":8,"id":559},{"question_text":"Static Timing Analysis (STA) verifies timing by:","option_a":"Applying input vectors and simulating","option_b":"Analyzing all timing paths without input vectors","option_c":"Measuring silicon directly","option_d":"Running gate-level random tests","correct_option":"B","explanation":"STA is vectorless; it checks every path against constraints statically.","difficulty":"easy","is_premium":false,"subject_id":3,"id":560},{"question_text":"Setup time is the time data must be stable:","option_a":"After the active clock edge","option_b":"Before the active clock edge","option_c":"During reset","option_d":"At power-up only","correct_option":"B","explanation":"Setup is the required stable interval before the capturing edge.","difficulty":"easy","is_premium":false,"subject_id":3,"id":561},{"question_text":"Hold time is the time data must remain stable:","option_a":"Before the clock edge","option_b":"After the active clock edge","option_c":"During power-down","option_d":"Never","correct_option":"B","explanation":"Hold is the required stable interval after the capturing edge.","difficulty":"easy","is_premium":false,"subject_id":3,"id":562},{"question_text":"A setup violation typically occurs when:","option_a":"Data arrives too early","option_b":"Data arrives too late relative to the capture edge","option_c":"The clock is too slow","option_d":"Reset is asserted","correct_option":"B","explanation":"Late-arriving data fails setup at the capture flop.","difficulty":"easy","is_premium":false,"subject_id":3,"id":563},{"question_text":"A hold violation typically occurs when:","option_a":"Data arrives too late","option_b":"Data changes too soon after the capture edge","option_c":"The clock period is too long","option_d":"The supply is high","correct_option":"B","explanation":"Fast/short data paths can change before hold is satisfied.","difficulty":"easy","is_premium":false,"subject_id":3,"id":564},{"question_text":"Setup slack is defined as:","option_a":"Required time minus arrival time","option_b":"Arrival time minus required time","option_c":"Clock period only","option_d":"Data path delay only","correct_option":"A","explanation":"Setup slack = required arrival time - actual arrival time; positive means timing met.","difficulty":"medium","is_premium":false,"subject_id":3,"id":565},{"question_text":"A negative setup slack means:","option_a":"Timing is met with margin","option_b":"The path fails setup timing","option_c":"Hold is violated","option_d":"The clock stopped","correct_option":"B","explanation":"Negative slack indicates the path does not meet the setup requirement.","difficulty":"easy","is_premium":false,"subject_id":3,"id":566},{"question_text":"Clock skew is the difference in clock arrival times:","option_a":"Between two sequential elements","option_b":"Across two boards","option_c":"Between data and reset","option_d":"Across power domains only","correct_option":"A","explanation":"Skew is the difference in clock arrival at the launch and capture flops.","difficulty":"easy","is_premium":false,"subject_id":3,"id":567},{"question_text":"Clock jitter refers to:","option_a":"Static skew","option_b":"Cycle-to-cycle variation in clock edges","option_c":"Reset bounce","option_d":"Power droop only","correct_option":"B","explanation":"Jitter is the temporal uncertainty/variation of clock edges over time.","difficulty":"medium","is_premium":false,"subject_id":3,"id":568},{"question_text":"Positive (useful) skew toward the capture flop generally:","option_a":"Hurts setup, helps hold","option_b":"Helps setup, hurts hold","option_c":"Has no effect","option_d":"Stops the clock","correct_option":"B","explanation":"Delaying the capture clock relaxes setup but tightens hold.","difficulty":"hard","is_premium":false,"subject_id":3,"id":569},{"question_text":"The basic setup check equation is approximately:","option_a":"Tclk \u003e= Tcq + Tcomb + Tsetup - Tskew","option_b":"Tclk \u003c= Tcq","option_c":"Tcq \u003e= Thold","option_d":"Tclk = 0","correct_option":"A","explanation":"Clock period must cover launch clk-to-q, combinational delay, and setup, adjusted by skew.","difficulty":"medium","is_premium":false,"subject_id":3,"id":570},{"question_text":"The hold check is independent of:","option_a":"Clock-to-Q delay","option_b":"Clock period","option_c":"Data path delay","option_d":"Hold time","correct_option":"B","explanation":"Hold is a same-edge check; it does not depend on the clock period.","difficulty":"medium","is_premium":false,"subject_id":3,"id":571},{"question_text":"A \u0027launch\u0027 flop in a timing path is the flop that:","option_a":"Captures the data","option_b":"Sources/launches the data","option_c":"Generates the reset","option_d":"Divides the clock","correct_option":"B","explanation":"The launch flop drives data into the path; the capture flop samples it.","difficulty":"easy","is_premium":false,"subject_id":3,"id":572},{"question_text":"Which SDC command defines the clock period?","option_a":"set_input_delay","option_b":"create_clock","option_c":"set_false_path","option_d":"set_load","correct_option":"B","explanation":"create_clock defines a clock and its period/waveform.","difficulty":"easy","is_premium":false,"subject_id":3,"id":573},{"question_text":"set_input_delay specifies:","option_a":"Internal flop delay","option_b":"Delay of external logic before the input port relative to a clock","option_c":"Clock skew","option_d":"Cell library delay","correct_option":"B","explanation":"It models the off-chip path delay arriving at an input port.","difficulty":"medium","is_premium":false,"subject_id":3,"id":574},{"question_text":"set_output_delay specifies:","option_a":"The delay of external logic after an output port relative to a clock","option_b":"Internal combinational delay","option_c":"Reset timing","option_d":"Power","correct_option":"A","explanation":"It models the external setup/path requirement after the output port.","difficulty":"medium","is_premium":false,"subject_id":3,"id":575},{"question_text":"A false path is a timing path that:","option_a":"Is the critical path","option_b":"Cannot be logically/functionally activated and is excluded from analysis","option_c":"Has zero delay","option_d":"Is the clock path","correct_option":"B","explanation":"False paths are functionally impossible and are excluded via set_false_path.","difficulty":"medium","is_premium":false,"subject_id":3,"id":576},{"question_text":"A multicycle path constraint is used when:","option_a":"Data must settle within one cycle","option_b":"Data is allowed multiple clock cycles to propagate","option_c":"There is no clock","option_d":"The path is asynchronous","correct_option":"B","explanation":"set_multicycle_path relaxes the capture edge to allow more than one cycle.","difficulty":"medium","is_premium":false,"subject_id":3,"id":577},{"question_text":"The critical path of a design is:","option_a":"The shortest path","option_b":"The path with the worst (least) setup slack","option_c":"The clock path","option_d":"Any reset path","correct_option":"B","explanation":"The critical path limits maximum frequency; it has the worst setup slack.","difficulty":"easy","is_premium":false,"subject_id":3,"id":578},{"question_text":"Maximum operating frequency is limited primarily by:","option_a":"Hold timing","option_b":"The worst setup path","option_c":"Reset recovery","option_d":"Leakage power","correct_option":"B","explanation":"Setup determines the minimum clock period and hence max frequency.","difficulty":"easy","is_premium":false,"subject_id":3,"id":579},{"question_text":"Hold violations are usually fixed by:","option_a":"Speeding up the clock","option_b":"Adding delay (buffers) on the short data path","option_c":"Removing flops","option_d":"Increasing the clock period","correct_option":"B","explanation":"Inserting delay on fast paths satisfies hold; period changes don\u0027t help hold.","difficulty":"medium","is_premium":false,"subject_id":3,"id":580},{"question_text":"Setup violations can be fixed by:","option_a":"Adding buffers to the data path","option_b":"Reducing logic depth, upsizing cells, or relaxing the clock","option_c":"Removing the clock","option_d":"Increasing hold time","correct_option":"B","explanation":"Faster logic, fewer levels, or a longer period improve setup.","difficulty":"medium","is_premium":false,"subject_id":3,"id":581},{"question_text":"An operating corner (PVT) stands for:","option_a":"Power, Voltage, Timing","option_b":"Process, Voltage, Temperature","option_c":"Path, Vector, Test","option_d":"Pin, Via, Trace","correct_option":"B","explanation":"PVT corners capture process, voltage, and temperature variation.","difficulty":"easy","is_premium":false,"subject_id":3,"id":582},{"question_text":"Which corner is typically worst for setup timing?","option_a":"Fast process, high V, low T","option_b":"Slow process, low V, high T (SS corner)","option_c":"Typical corner","option_d":"No corner matters","correct_option":"B","explanation":"Slow-slow (low V, high T) gives the largest delays, stressing setup.","difficulty":"medium","is_premium":false,"subject_id":3,"id":583},{"question_text":"Which corner is typically worst for hold timing?","option_a":"Slow process","option_b":"Fast process (FF), high V, low T","option_c":"Typical","option_d":"No corner","correct_option":"B","explanation":"Fast-fast minimizes delays, stressing hold on short paths.","difficulty":"medium","is_premium":false,"subject_id":3,"id":584},{"question_text":"On-Chip Variation (OCV) modeling accounts for:","option_a":"Identical delays everywhere","option_b":"Local delay variation between launch and capture paths","option_c":"Only temperature","option_d":"Only voltage","correct_option":"B","explanation":"OCV derates paths to model local variation in delays across the die.","difficulty":"hard","is_premium":false,"subject_id":3,"id":585},{"question_text":"Clock latency is:","option_a":"Data path delay","option_b":"The delay from clock source to the clock pin of a flop","option_c":"Setup time","option_d":"Reset delay","correct_option":"B","explanation":"Latency is the insertion delay from clock source to the register clock pin.","difficulty":"medium","is_premium":false,"subject_id":3,"id":586},{"question_text":"Source latency vs network latency: source latency is:","option_a":"On-chip clock tree delay","option_b":"Delay external to the chip before the clock definition point","option_c":"Data delay","option_d":"Hold time","correct_option":"B","explanation":"Source latency is off-chip/pre-clock-port; network latency is on-chip tree delay.","difficulty":"hard","is_premium":false,"subject_id":3,"id":587},{"question_text":"An ideal clock in STA assumes:","option_a":"Real clock tree delays","option_b":"Zero skew and zero insertion delay","option_c":"Infinite jitter","option_d":"No period","correct_option":"B","explanation":"Pre-CTS ideal clocks assume no tree delay or skew.","difficulty":"medium","is_premium":false,"subject_id":3,"id":588},{"question_text":"After Clock Tree Synthesis (CTS), STA uses:","option_a":"Ideal clocks","option_b":"Propagated (real) clock latencies and skew","option_c":"No clocks","option_d":"Only setup","correct_option":"B","explanation":"Post-CTS analysis uses propagated clocks with real insertion delay and skew.","difficulty":"medium","is_premium":false,"subject_id":3,"id":589},{"question_text":"Recovery time relates to:","option_a":"Data setup","option_b":"Async reset deassertion before the clock edge","option_c":"Hold of data","option_d":"Clock period","correct_option":"B","explanation":"Recovery is the setup-like requirement for reset deassertion vs the clock edge.","difficulty":"hard","is_premium":false,"subject_id":3,"id":590},{"question_text":"Removal time relates to:","option_a":"Async reset deassertion held after the clock edge","option_b":"Data setup","option_c":"Clock skew","option_d":"Jitter","correct_option":"A","explanation":"Removal is the hold-like requirement for reset deassertion after the clock edge.","difficulty":"hard","is_premium":false,"subject_id":3,"id":591},{"question_text":"A timing arc describes:","option_a":"A wire","option_b":"A delay/timing relationship between two pins of a cell","option_c":"A power rail","option_d":"A clock domain","correct_option":"B","explanation":"Timing arcs (cell/net) capture delay between pins.","difficulty":"medium","is_premium":false,"subject_id":3,"id":592},{"question_text":"Transition (slew) time at a pin affects:","option_a":"Nothing","option_b":"Cell delay and downstream timing","option_c":"Only power","option_d":"Reset","correct_option":"B","explanation":"Slower transitions increase cell delays and degrade timing.","difficulty":"medium","is_premium":false,"subject_id":3,"id":593},{"question_text":"A .lib (Liberty) file provides:","option_a":"Layout geometry","option_b":"Cell timing, power, and constraint data","option_c":"RTL code","option_d":"Test vectors","correct_option":"B","explanation":"Liberty models cell delay/power tables and pin constraints.","difficulty":"easy","is_premium":false,"subject_id":3,"id":594},{"question_text":"An SDF file is used to:","option_a":"Define RTL","option_b":"Back-annotate delays for gate-level simulation/STA","option_c":"Store layout","option_d":"Define clocks only","correct_option":"B","explanation":"Standard Delay Format carries delays for back-annotation.","difficulty":"medium","is_premium":false,"subject_id":3,"id":595},{"question_text":"Which analysis checks both fast and slow paths simultaneously using min/max delays?","option_a":"Single-corner only","option_b":"Min-max (on-chip variation) analysis","option_c":"Functional sim","option_d":"DRC","correct_option":"B","explanation":"Min/max analysis uses min delays for hold and max for setup.","difficulty":"medium","is_premium":false,"subject_id":3,"id":596},{"question_text":"Setup uses which delays for the data path?","option_a":"Min (fastest)","option_b":"Max (slowest) data path, min clock path to capture","option_c":"Typical only","option_d":"Zero","correct_option":"B","explanation":"Worst-case setup uses max data delay and the earliest capture clock.","difficulty":"hard","is_premium":false,"subject_id":3,"id":597},{"question_text":"Hold uses which delays for the data path?","option_a":"Max (slowest)","option_b":"Min (fastest) data path, max clock to capture","option_c":"Typical","option_d":"Zero","correct_option":"B","explanation":"Worst-case hold uses min data delay and the latest capture clock.","difficulty":"hard","is_premium":false,"subject_id":3,"id":598},{"question_text":"Clock gating affects timing because:","option_a":"It removes flops","option_b":"The enable must meet setup/hold to the gating cell to avoid glitches","option_c":"It speeds the clock","option_d":"It has no timing impact","correct_option":"B","explanation":"Gating enable timing must be met to prevent clock glitches.","difficulty":"hard","is_premium":false,"subject_id":3,"id":599},{"question_text":"A reg-to-reg path is bounded by:","option_a":"Input/output delays","option_b":"Launch and capture flip-flops","option_c":"Only primary inputs","option_d":"The reset tree","correct_option":"B","explanation":"Internal paths run from one flop to another.","difficulty":"easy","is_premium":false,"subject_id":3,"id":600},{"question_text":"An input-to-reg path uses which constraint to model arrival?","option_a":"set_output_delay","option_b":"set_input_delay","option_c":"create_generated_clock","option_d":"set_false_path","correct_option":"B","explanation":"set_input_delay models external arrival at input ports.","difficulty":"easy","is_premium":false,"subject_id":3,"id":601},{"question_text":"A generated clock is created with:","option_a":"create_clock","option_b":"create_generated_clock","option_c":"set_clock_groups","option_d":"set_load","correct_option":"B","explanation":"Divided/derived clocks use create_generated_clock referencing a master.","difficulty":"medium","is_premium":false,"subject_id":3,"id":602},{"question_text":"set_clock_groups -asynchronous is used to:","option_a":"Make clocks synchronous","option_b":"Tell STA two clock domains are unrelated (no real timing between them)","option_c":"Define a clock period","option_d":"Add jitter","correct_option":"B","explanation":"It declares clocks asynchronous so cross-domain paths aren\u0027t timed.","difficulty":"hard","is_premium":false,"subject_id":3,"id":603},{"question_text":"Why must asynchronous clock-domain-crossing paths use synchronizers rather than STA timing?","option_a":"STA is too slow","option_b":"Phase relationship is unknown, so static timing is meaningless; synchronizers manage metastability","option_c":"They have no delay","option_d":"Synthesis requires it","correct_option":"B","explanation":"Unknown phase makes setup/hold undefined; synchronizers mitigate metastability.","difficulty":"hard","is_premium":false,"subject_id":3,"id":604},{"question_text":"Data Required Time at a capture flop for setup equals approximately:","option_a":"Capture clock arrival - setup time","option_b":"Launch clock + Tcq","option_c":"Data arrival + hold","option_d":"Zero","correct_option":"A","explanation":"Required time = capture edge - setup (adjusted for skew/uncertainty).","difficulty":"medium","is_premium":false,"subject_id":3,"id":605},{"question_text":"Clock uncertainty in SDC typically models:","option_a":"Data delay","option_b":"Jitter and skew margin reserved in the setup/hold checks","option_c":"Leakage","option_d":"Reset","correct_option":"B","explanation":"set_clock_uncertainty reserves margin for jitter/skew.","difficulty":"medium","is_premium":false,"subject_id":3,"id":606},{"question_text":"A path with large fanout/load tends to have:","option_a":"Lower delay","option_b":"Higher delay due to increased capacitance","option_c":"No delay change","option_d":"Negative delay","correct_option":"B","explanation":"Greater load capacitance increases transition and cell delay.","difficulty":"easy","is_premium":false,"subject_id":3,"id":607},{"question_text":"Wire (interconnect) delay becomes more significant:","option_a":"At older, larger nodes","option_b":"At advanced nodes where RC interconnect dominates","option_c":"Never","option_d":"Only in testbenches","correct_option":"B","explanation":"At smaller geometries, interconnect RC delay grows relative to gate delay.","difficulty":"medium","is_premium":false,"subject_id":3,"id":608},{"question_text":"TNS (Total Negative Slack) represents:","option_a":"The single worst path","option_b":"The sum of all negative slacks across endpoints","option_c":"Clock period","option_d":"Power","correct_option":"B","explanation":"TNS aggregates all failing endpoints; WNS is the single worst.","difficulty":"medium","is_premium":false,"subject_id":3,"id":609},{"question_text":"WNS stands for:","option_a":"Weighted Net Slack","option_b":"Worst Negative Slack (the most critical endpoint)","option_c":"Wire Net Sum","option_d":"Wide Noise Source","correct_option":"B","explanation":"WNS is the worst negative slack among all paths.","difficulty":"easy","is_premium":false,"subject_id":3,"id":610},{"question_text":"A latch-based (level-sensitive) design enables which technique not available to flops?","option_a":"Clock gating","option_b":"Time borrowing across phases","option_c":"Reset","option_d":"Scan","correct_option":"B","explanation":"Transparent latches permit time/cycle borrowing between phases.","difficulty":"hard","is_premium":false,"subject_id":3,"id":611},{"question_text":"Increasing drive strength of a cell on a slow path generally:","option_a":"Increases delay","option_b":"Decreases delay but increases area/power","option_c":"Has no effect","option_d":"Adds a flop","correct_option":"B","explanation":"Upsizing reduces delay at the cost of area and power.","difficulty":"medium","is_premium":false,"subject_id":3,"id":612},{"question_text":"A \u0027min\u0027 delay corner is most relevant to checking:","option_a":"Setup","option_b":"Hold","option_c":"Power","option_d":"Area","correct_option":"B","explanation":"Fast/min delays stress hold timing.","difficulty":"medium","is_premium":false,"subject_id":3,"id":613},{"question_text":"The clock-to-Q delay (Tcq) is:","option_a":"Time from data change to output","option_b":"Time from the active clock edge to the flop output updating","option_c":"Setup time","option_d":"Hold time","correct_option":"B","explanation":"Tcq is the propagation delay from clock edge to Q.","difficulty":"easy","is_premium":false,"subject_id":3,"id":614},{"question_text":"If clock period is 2 ns, Tcq=0.2 ns, setup=0.1 ns, what is the max allowed combinational delay (zero skew)?","option_a":"2.3 ns","option_b":"1.7 ns","option_c":"2.0 ns","option_d":"0.3 ns","correct_option":"B","explanation":"Tcomb \u003c= Tclk - Tcq - Tsetup = 2 - 0.2 - 0.1 = 1.7 ns.","difficulty":"medium","is_premium":false,"subject_id":3,"id":615},{"question_text":"Adding pipeline stages to a long combinational path:","option_a":"Worsens setup","option_b":"Improves setup/throughput at the cost of latency","option_c":"Removes the clock","option_d":"Increases hold violations only","correct_option":"B","explanation":"Pipelining shortens per-stage logic, improving frequency while adding latency.","difficulty":"medium","is_premium":false,"subject_id":3,"id":616},{"question_text":"A balanced clock tree aims to:","option_a":"Maximize skew","option_b":"Minimize skew across all sink flops","option_c":"Remove the clock","option_d":"Increase jitter","correct_option":"B","explanation":"CTS balances insertion delays to minimize skew.","difficulty":"easy","is_premium":false,"subject_id":3,"id":617},{"question_text":"A negative setup slack of -50 ps means the clock period must increase by at least:","option_a":"0 ps","option_b":"50 ps (or the path sped up by 50 ps)","option_c":"100 ps","option_d":"1 ns","correct_option":"B","explanation":"Closing -50 ps requires 50 ps more period or 50 ps less path delay.","difficulty":"medium","is_premium":false,"subject_id":3,"id":618},{"question_text":"Crosstalk (signal integrity) can affect STA by:","option_a":"Reducing all delays","option_b":"Adding delay/noise that worsens setup or hold depending on aggressor switching","option_c":"Removing skew","option_d":"Only affecting power","correct_option":"B","explanation":"Coupling can speed up or slow down victims, impacting both setup and hold.","difficulty":"hard","is_premium":false,"subject_id":3,"id":619},{"question_text":"A \u0027don\u0027t_touch\u0027 or set_disable_timing is sometimes used to:","option_a":"Speed the clock","option_b":"Break/disable specific timing arcs that are not real","option_c":"Add buffers","option_d":"Define a clock","correct_option":"B","explanation":"Disabling arcs removes invalid timing relationships from analysis.","difficulty":"hard","is_premium":false,"subject_id":3,"id":620},{"question_text":"For a half-cycle (negedge capture) path, the setup capture edge is at:","option_a":"Full period","option_b":"Half the clock period","option_c":"Zero","option_d":"Two periods","correct_option":"B","explanation":"Posedge launch to negedge capture gives a half-period setup window.","difficulty":"hard","is_premium":false,"subject_id":3,"id":621},{"question_text":"Reducing logic levels on a path primarily improves:","option_a":"Hold","option_b":"Setup","option_c":"Leakage","option_d":"Skew","correct_option":"B","explanation":"Fewer logic levels reduce data delay, improving setup.","difficulty":"easy","is_premium":false,"subject_id":3,"id":622},{"question_text":"A timing exception that limits the maximum delay regardless of clock is:","option_a":"set_false_path","option_b":"set_max_delay","option_c":"create_clock","option_d":"set_load","correct_option":"B","explanation":"set_max_delay constrains the path delay directly.","difficulty":"medium","is_premium":false,"subject_id":3,"id":623},{"question_text":"set_min_delay is typically used to address:","option_a":"Setup","option_b":"Hold/short-path requirements","option_c":"Clock definition","option_d":"Area","correct_option":"B","explanation":"set_min_delay enforces a minimum path delay, relevant to hold.","difficulty":"medium","is_premium":false,"subject_id":3,"id":624},{"question_text":"Glitch power and timing hazards are reduced by:","option_a":"Adding more combinational depth","option_b":"Registering signals and balancing path delays","option_c":"Removing the clock","option_d":"Increasing fanout","correct_option":"B","explanation":"Registering outputs and balancing delays reduce glitching.","difficulty":"medium","is_premium":false,"subject_id":3,"id":625},{"question_text":"A multicycle path of 2 means the capture edge for setup moves to:","option_a":"The same cycle","option_b":"Two cycles later (more time for data)","option_c":"Half a cycle","option_d":"Zero","correct_option":"B","explanation":"MCP of 2 gives the data two cycles to settle for setup.","difficulty":"hard","is_premium":false,"subject_id":3,"id":626},{"question_text":"Which is NOT a typical STA output report?","option_a":"Setup/hold slack","option_b":"Functional pass/fail vectors","option_c":"Critical path list","option_d":"Clock skew","correct_option":"B","explanation":"STA is vectorless; functional pass/fail comes from simulation, not STA.","difficulty":"medium","is_premium":false,"subject_id":3,"id":627},{"question_text":"The primary benefit of STA over dynamic timing simulation is:","option_a":"It needs test vectors","option_b":"Exhaustive path coverage without vectors and much faster runtime","option_c":"It measures power","option_d":"It replaces synthesis","correct_option":"B","explanation":"STA checks all paths quickly without needing input stimulus.","difficulty":"easy","is_premium":false,"subject_id":3,"id":628},{"question_text":"On-chip variation (OCV) derating in STA accounts for:","option_a":"Only clock frequency","option_b":"Process/voltage/temperature variation by derating launch vs capture paths","option_c":"Gate count","option_d":"Reset polarity","correct_option":"B","explanation":"OCV applies derates so that worst-case variation between launch and capture paths is modeled.","difficulty":"hard","is_premium":false,"subject_id":3,"id":629},{"question_text":"Which SystemVerilog type is a 4-state type?","option_a":"bit","option_b":"logic","option_c":"byte","option_d":"int","correct_option":"B","explanation":"logic is 4-state (0,1,x,z); bit/byte/int are 2-state.","difficulty":"easy","is_premium":false,"subject_id":4,"id":630},{"question_text":"Which SystemVerilog type is 2-state?","option_a":"logic","option_b":"reg","option_c":"bit","option_d":"wire","correct_option":"C","explanation":"bit holds only 0/1 (2-state).","difficulty":"easy","is_premium":false,"subject_id":4,"id":631},{"question_text":"always_comb improves on always @(*) by:","option_a":"Adding clock","option_b":"Statically checking for combinational intent and inferring sensitivity","option_c":"Inferring latches","option_d":"Slowing simulation","correct_option":"B","explanation":"always_comb enforces combinational semantics and auto-sensitivity.","difficulty":"easy","is_premium":false,"subject_id":4,"id":632},{"question_text":"always_ff is used to model:","option_a":"Combinational logic","option_b":"Sequential (clocked) logic","option_c":"Latches","option_d":"Testbench tasks","correct_option":"B","explanation":"always_ff documents and checks flip-flop (clocked) intent.","difficulty":"easy","is_premium":false,"subject_id":4,"id":633},{"question_text":"always_latch is used to model:","option_a":"Flip-flops","option_b":"Intentional level-sensitive latches","option_c":"Combinational logic","option_d":"Clocks","correct_option":"B","explanation":"always_latch declares intentional latch behavior and is checked by tools.","difficulty":"easy","is_premium":false,"subject_id":4,"id":634},{"question_text":"What does the SystemVerilog \u0027logic\u0027 type allow that Verilog \u0027reg\u0027 restricted?","option_a":"Nothing new","option_b":"It can be driven by continuous assign or a single procedural driver","option_c":"Multiple drivers always","option_d":"Only clock use","correct_option":"B","explanation":"logic can be driven by assign or one procedural block, unifying reg/wire usage.","difficulty":"medium","is_premium":false,"subject_id":4,"id":635},{"question_text":"An enum in SystemVerilog is used to:","option_a":"Generate clocks","option_b":"Define named symbolic values, e.g., FSM states","option_c":"Replace modules","option_d":"Force nets","correct_option":"B","explanation":"enum provides readable named constants, ideal for FSM states.","difficulty":"easy","is_premium":false,"subject_id":4,"id":636},{"question_text":"A typedef is used to:","option_a":"Create a clock","option_b":"Define a user type alias","option_c":"Drive a net","option_d":"Add delay","correct_option":"B","explanation":"typedef names a (possibly complex) type for reuse.","difficulty":"easy","is_premium":false,"subject_id":4,"id":637},{"question_text":"A packed struct is:","option_a":"Stored as separate variables","option_b":"Laid out as a contiguous bit vector and can be used in arithmetic","option_c":"Only for testbenches","option_d":"Unsynthesizable","correct_option":"B","explanation":"packed structs map to a contiguous bit-vector usable like a vector.","difficulty":"medium","is_premium":false,"subject_id":4,"id":638},{"question_text":"An unpacked array differs from packed in that unpacked:","option_a":"Is a single bit vector","option_b":"Stores elements separately, not as a contiguous vector","option_c":"Cannot hold logic","option_d":"Is always 2-state","correct_option":"B","explanation":"Unpacked dimensions store independent elements; packed are contiguous bits.","difficulty":"medium","is_premium":false,"subject_id":4,"id":639},{"question_text":"Which casting reinterprets a value to a new type in SystemVerilog?","option_a":"type\u0027(value)","option_b":"cast value","option_c":"convert(value)","option_d":"force value","correct_option":"A","explanation":"The static cast syntax is type\u0027(expression).","difficulty":"medium","is_premium":false,"subject_id":4,"id":640},{"question_text":"The \u0027unique case\u0027 statement asserts at runtime that:","option_a":"No case matches","option_b":"Exactly one branch matches (else a violation is reported)","option_c":"All branches match","option_d":"The case is combinational","correct_option":"B","explanation":"unique requires one and only one matching branch, flagging overlaps/missing.","difficulty":"medium","is_premium":false,"subject_id":4,"id":641},{"question_text":"The \u0027priority case\u0027 statement asserts that:","option_a":"Branches are unordered","option_b":"At least one branch matches and earlier items take priority","option_c":"No branch matches","option_d":"It is asynchronous","correct_option":"B","explanation":"priority guarantees a match and evaluates in listed order.","difficulty":"medium","is_premium":false,"subject_id":4,"id":642},{"question_text":"An interface in SystemVerilog primarily:","option_a":"Adds delay","option_b":"Bundles related signals and can contain modports/methods","option_c":"Replaces always blocks","option_d":"Defines a clock","correct_option":"B","explanation":"Interfaces group signals and may define modports and tasks for cleaner connections.","difficulty":"medium","is_premium":false,"subject_id":4,"id":643},{"question_text":"A modport in an interface defines:","option_a":"Clock period","option_b":"Direction/access view of interface signals for a connected module","option_c":"Reset polarity","option_d":"A typedef","correct_option":"B","explanation":"modports specify signal directions for each side of the interface.","difficulty":"medium","is_premium":false,"subject_id":4,"id":644},{"question_text":"Which loop variable declaration is local to a for loop in SystemVerilog?","option_a":"for (int i=0; ...)","option_b":"integer i; for (i=0; ...)","option_c":"genvar i","option_d":"wire i","correct_option":"A","explanation":"Declaring \u0027int i\u0027 inside the for header scopes it to the loop.","difficulty":"easy","is_premium":false,"subject_id":4,"id":645},{"question_text":"The ++ operator in SystemVerilog:","option_a":"Is illegal","option_b":"Increments a variable (i++)","option_c":"Concatenates","option_d":"Is a reduction","correct_option":"B","explanation":"SystemVerilog adds increment/decrement operators like i++.","difficulty":"easy","is_premium":false,"subject_id":4,"id":646},{"question_text":"A \u0027do...while\u0027 loop in SystemVerilog executes the body:","option_a":"Zero or more times","option_b":"At least once","option_c":"Never","option_d":"Only at elaboration","correct_option":"B","explanation":"do...while runs the body before testing the condition, so at least once.","difficulty":"easy","is_premium":false,"subject_id":4,"id":647},{"question_text":"What is the benefit of using enum for FSM states over plain parameters?","option_a":"Faster clock","option_b":"Type safety and readable waveforms/debug","option_c":"Less area always","option_d":"No benefit","correct_option":"B","explanation":"Enums give named, type-checked states and show names in tools.","difficulty":"medium","is_premium":false,"subject_id":4,"id":648},{"question_text":"A two-always-block FSM separates:","option_a":"Clock and reset","option_b":"Next-state combinational logic from state register update","option_c":"Inputs and outputs only","option_d":"Two clocks","correct_option":"B","explanation":"One block computes next state combinationally; the other registers it.","difficulty":"medium","is_premium":false,"subject_id":4,"id":649},{"question_text":"Using \u0027logic\u0027 for an FSM state and assigning in always_ff infers:","option_a":"A latch","option_b":"A state register (flip-flops)","option_c":"Combinational logic","option_d":"A ROM","correct_option":"B","explanation":"Clocked assignment of state in always_ff creates the state register.","difficulty":"easy","is_premium":false,"subject_id":4,"id":650},{"question_text":"The default keyword in an enum assigns values starting at:","option_a":"1","option_b":"0 and increments","option_c":"Random","option_d":"-1","correct_option":"B","explanation":"Unspecified enum members start at 0 and increment by one.","difficulty":"easy","is_premium":false,"subject_id":4,"id":651},{"question_text":"A \u0027union\u0027 (packed) in SystemVerilog:","option_a":"Stores members in separate memory","option_b":"Overlays members in the same bits","option_c":"Is a clock type","option_d":"Cannot be packed","correct_option":"B","explanation":"A packed union maps all members onto the same bit storage.","difficulty":"hard","is_premium":false,"subject_id":4,"id":652},{"question_text":"Which is true about always_comb sensitivity?","option_a":"You must list signals manually","option_b":"It is automatically sensitive to all signals read, including in called functions","option_c":"It is clocked","option_d":"It ignores function reads","correct_option":"B","explanation":"always_comb infers sensitivity to everything read, even through functions.","difficulty":"medium","is_premium":false,"subject_id":4,"id":653},{"question_text":"What does $bits(expr) return?","option_a":"The value","option_b":"The number of bits in the type/expression","option_c":"The address","option_d":"The delay","correct_option":"B","explanation":"$bits gives the bit-width of a type or expression.","difficulty":"medium","is_premium":false,"subject_id":4,"id":654},{"question_text":"Which operator set is added by SystemVerilog over Verilog for assignment?","option_a":"Only =","option_b":"+=, -=, *=, etc. compound assignments","option_c":"None","option_d":"Only \u003c=","correct_option":"B","explanation":"SystemVerilog adds compound assignment operators.","difficulty":"easy","is_premium":false,"subject_id":4,"id":655},{"question_text":"The \u0027inside\u0027 operator is used to:","option_a":"Index arrays","option_b":"Test set/range membership, e.g., x inside {[0:7]}","option_c":"Concatenate","option_d":"Define a clock","correct_option":"B","explanation":"inside checks membership in a value set or range.","difficulty":"medium","is_premium":false,"subject_id":4,"id":656},{"question_text":"A packed array [3:0][7:0] data declares:","option_a":"Four 8-bit elements as one contiguous 32-bit vector","option_b":"An unpacked array","option_c":"A single bit","option_d":"A real number","correct_option":"A","explanation":"Two packed dimensions form a 32-bit contiguous vector viewed as 4x8.","difficulty":"medium","is_premium":false,"subject_id":4,"id":657},{"question_text":"Default port direction in an interface modport for a master driving data is usually:","option_a":"input","option_b":"output for driven signals, input for sampled","option_c":"inout always","option_d":"ref","correct_option":"B","explanation":"Modport directions match how the side uses each signal.","difficulty":"medium","is_premium":false,"subject_id":4,"id":658},{"question_text":"What is a benefit of parameterized types (type parameters) in SystemVerilog?","option_a":"Faster clock","option_b":"Generic, reusable modules over different data types","option_c":"No benefit","option_d":"Latch inference","correct_option":"B","explanation":"Type parameters allow generic RTL/verification components.","difficulty":"hard","is_premium":false,"subject_id":4,"id":659},{"question_text":"An always_ff block should use which reset style for sync reset?","option_a":"@(posedge clk or posedge rst)","option_b":"@(posedge clk) with if(rst) inside","option_c":"@(*)","option_d":"always_comb","correct_option":"B","explanation":"Synchronous reset samples rst only at the clock edge.","difficulty":"medium","is_premium":false,"subject_id":4,"id":660},{"question_text":"Which avoids inferred latches in always_comb?","option_a":"Partial assignment","option_b":"Assigning every output in all paths or using defaults at the top","option_c":"Using \u003c=","option_d":"Omitting default","correct_option":"B","explanation":"Default assignments or full coverage prevent latch inference.","difficulty":"medium","is_premium":false,"subject_id":4,"id":661},{"question_text":"What does the \u0027const\u0027 qualifier do?","option_a":"Makes a clock","option_b":"Declares a variable that cannot be reassigned after initialization","option_c":"Forces a net","option_d":"Adds delay","correct_option":"B","explanation":"const variables are read-only after initialization.","difficulty":"easy","is_premium":false,"subject_id":4,"id":662},{"question_text":"A \u0027for\u0027 loop with a non-constant bound in RTL is:","option_a":"Always synthesizable","option_b":"Generally not synthesizable (must be statically bounded)","option_c":"A clock","option_d":"A latch","correct_option":"B","explanation":"Synthesis requires statically determinable loop bounds.","difficulty":"medium","is_premium":false,"subject_id":4,"id":663},{"question_text":"What is the width of \u0027int\u0027 in SystemVerilog?","option_a":"16 bits","option_b":"32 bits (2-state, signed)","option_c":"64 bits","option_d":"8 bits","correct_option":"B","explanation":"int is a 32-bit 2-state signed type.","difficulty":"easy","is_premium":false,"subject_id":4,"id":664},{"question_text":"What is the width of \u0027byte\u0027?","option_a":"4 bits","option_b":"8 bits (signed, 2-state)","option_c":"16 bits","option_d":"1 bit","correct_option":"B","explanation":"byte is an 8-bit signed 2-state type.","difficulty":"easy","is_premium":false,"subject_id":4,"id":665},{"question_text":"\u0027longint\u0027 in SystemVerilog is:","option_a":"16 bits","option_b":"64-bit signed 2-state","option_c":"32 bits","option_d":"128 bits","correct_option":"B","explanation":"longint is a 64-bit 2-state signed type.","difficulty":"easy","is_premium":false,"subject_id":4,"id":666},{"question_text":"Why prefer 2-state types in some testbench computations?","option_a":"They are 4-state","option_b":"Lower memory and faster, but cannot represent x/z","option_c":"They infer latches","option_d":"They are slower","correct_option":"B","explanation":"2-state types are efficient but cannot show unknowns.","difficulty":"medium","is_premium":false,"subject_id":4,"id":667},{"question_text":"An enum\u0027s .name() method returns:","option_a":"The integer value","option_b":"The string name of the current enum value","option_c":"The next value","option_d":"The bit width","correct_option":"B","explanation":".name() yields the symbolic name as a string.","difficulty":"medium","is_premium":false,"subject_id":4,"id":668},{"question_text":"The .next() and .prev() enum methods:","option_a":"Change the clock","option_b":"Return the following/preceding enumerated value","option_c":"Are illegal","option_d":"Return strings","correct_option":"B","explanation":"next/prev iterate enumerated values.","difficulty":"medium","is_premium":false,"subject_id":4,"id":669},{"question_text":"A combinational function used in always_comb must:","option_a":"Contain @ or #","option_b":"Be free of timing controls and return in zero time","option_c":"Use non-blocking","option_d":"Drive nets","correct_option":"B","explanation":"Functions are zero-time and cannot contain timing controls.","difficulty":"medium","is_premium":false,"subject_id":4,"id":670},{"question_text":"Which keyword groups statements that must execute together as a block returning a name scope?","option_a":"begin...end","option_b":"fork...join","option_c":"module","option_d":"interface","correct_option":"A","explanation":"begin...end groups sequential statements (named blocks optional).","difficulty":"easy","is_premium":false,"subject_id":4,"id":671},{"question_text":"A registered FSM output (Moore, registered) adds:","option_a":"Glitches","option_b":"One cycle latency but glitch-free outputs","option_c":"Asynchronous behavior","option_d":"No change","correct_option":"B","explanation":"Registering Moore outputs removes glitches at a one-cycle latency cost.","difficulty":"medium","is_premium":false,"subject_id":4,"id":672},{"question_text":"Which describes a one-hot FSM advantage in FPGAs?","option_a":"Minimal flops","option_b":"Simple next-state logic and fast decode using abundant flops","option_c":"No flops","option_d":"Lower frequency","correct_option":"B","explanation":"One-hot trades flops for simpler, faster combinational decode, suiting FPGAs.","difficulty":"hard","is_premium":false,"subject_id":4,"id":673},{"question_text":"Binary state encoding minimizes:","option_a":"Combinational logic","option_b":"The number of state flip-flops","option_c":"Clock frequency","option_d":"Fanout","correct_option":"B","explanation":"Binary uses ceil(log2 N) flops, the fewest registers.","difficulty":"medium","is_premium":false,"subject_id":4,"id":674},{"question_text":"What is the risk of reading and writing the same variable with blocking assignments across two always_ff blocks?","option_a":"Nothing","option_b":"Race conditions / nondeterministic behavior","option_c":"Lower power","option_d":"Latch inference","correct_option":"B","explanation":"Sharing variables via blocking assigns across clocked blocks risks races.","difficulty":"hard","is_premium":false,"subject_id":4,"id":675},{"question_text":"A \u0027ref\u0027 argument to a function/task passes:","option_a":"A copy","option_b":"A reference, so changes are visible to the caller","option_c":"A clock","option_d":"A constant","correct_option":"B","explanation":"ref passes by reference (pass-through), avoiding copies.","difficulty":"medium","is_premium":false,"subject_id":4,"id":676},{"question_text":"An automatic variable in a function:","option_a":"Persists across calls (static)","option_b":"Is allocated per call, enabling re-entrancy/recursion","option_c":"Is a net","option_d":"Is a clock","correct_option":"B","explanation":"automatic storage is per-invocation, supporting recursion.","difficulty":"hard","is_premium":false,"subject_id":4,"id":677},{"question_text":"A static variable in a module/function:","option_a":"Is reallocated each call","option_b":"Retains its value across calls (single instance)","option_c":"Cannot be read","option_d":"Is a clock","correct_option":"B","explanation":"static storage keeps one shared instance across calls.","difficulty":"medium","is_premium":false,"subject_id":4,"id":678},{"question_text":"Which improves readability and reuse of multi-signal connections between modules?","option_a":"Many individual ports","option_b":"A SystemVerilog interface","option_c":"Global variables","option_d":"More clocks","correct_option":"B","explanation":"Interfaces bundle related signals, reducing port clutter.","difficulty":"easy","is_premium":false,"subject_id":4,"id":679},{"question_text":"What does \u0027logic [WIDTH-1:0]\u0027 with WIDTH as a parameter enable?","option_a":"Runtime resizing","option_b":"Parameterized bus width at elaboration","option_c":"Asynchronous logic","option_d":"Nothing","correct_option":"B","explanation":"Parameterized widths allow reusable, scalable RTL.","difficulty":"easy","is_premium":false,"subject_id":4,"id":680},{"question_text":"Which statement about \u0027always_comb\u0027 and shared variables is correct?","option_a":"It can be triggered by another always_comb writing a shared var","option_b":"Two always_comb blocks writing the same variable cause a multiple-driver error","option_c":"It needs a clock","option_d":"It infers a flop","correct_option":"B","explanation":"A variable written by two always_comb blocks is a multiple-driver conflict.","difficulty":"hard","is_premium":false,"subject_id":4,"id":681},{"question_text":"A \u0027package\u0027 in SystemVerilog is used to:","option_a":"Generate clocks","option_b":"Share typedefs, parameters, and functions across files","option_c":"Replace modules","option_d":"Define ports","correct_option":"B","explanation":"Packages encapsulate reusable declarations imported elsewhere.","difficulty":"medium","is_premium":false,"subject_id":4,"id":682},{"question_text":"How are package items brought into scope?","option_a":"include only","option_b":"import pkg::* or pkg::item","option_c":"assign","option_d":"force","correct_option":"B","explanation":"import makes package contents visible.","difficulty":"easy","is_premium":false,"subject_id":4,"id":683},{"question_text":"Which is a synthesizable use of a struct?","option_a":"Dynamic class","option_b":"Packed struct as a bundled bus register","option_c":"Mailbox","option_d":"Semaphore","correct_option":"B","explanation":"Packed structs map to hardware registers/buses.","difficulty":"medium","is_premium":false,"subject_id":4,"id":684},{"question_text":"Dynamic arrays, queues, and associative arrays in SystemVerilog are:","option_a":"Synthesizable to RTL","option_b":"Primarily for testbench/verification, not synthesis","option_c":"Clock types","option_d":"Always 1 bit","correct_option":"B","explanation":"These dynamic data structures are verification constructs, not RTL.","difficulty":"medium","is_premium":false,"subject_id":4,"id":685},{"question_text":"Which is a valid way to declare a 2D memory in RTL?","option_a":"logic mem [0:255][7:0] (unpacked addr, packed data)","option_b":"real mem","option_c":"event mem","option_d":"string mem","correct_option":"A","explanation":"An unpacked address dimension with packed data models a memory array.","difficulty":"medium","is_premium":false,"subject_id":4,"id":686},{"question_text":"A registered RAM read (synchronous read) means:","option_a":"Data appears combinationally","option_b":"Read data is available one clock after the address is applied","option_c":"No clock needed","option_d":"It is asynchronous","correct_option":"B","explanation":"Synchronous read registers the output, adding a cycle of latency.","difficulty":"medium","is_premium":false,"subject_id":4,"id":687},{"question_text":"Write-first vs read-first RAM behavior describes:","option_a":"Clock polarity","option_b":"Whether a simultaneous read returns new or old data on a write","option_c":"Reset type","option_d":"Address width","correct_option":"B","explanation":"Collision behavior defines if the read sees freshly written or previous data.","difficulty":"hard","is_premium":false,"subject_id":4,"id":688},{"question_text":"Which is the cleanest way to default all FSM outputs each cycle?","option_a":"Assign nothing","option_b":"Set defaults at the top of always_comb, then override per state","option_c":"Use non-blocking","option_d":"Use initial","correct_option":"B","explanation":"Top-of-block defaults avoid latches and reduce verbose else branches.","difficulty":"medium","is_premium":false,"subject_id":4,"id":689},{"question_text":"Which sequential element does always_ff with only posedge clk infer for assigned signals?","option_a":"Latches","option_b":"Edge-triggered flip-flops","option_c":"Combinational gates","option_d":"Tri-states","correct_option":"B","explanation":"Posedge-clocked always_ff infers flip-flops.","difficulty":"easy","is_premium":false,"subject_id":4,"id":690},{"question_text":"What does the \u0027void\u0027 return type indicate for a function?","option_a":"It returns an int","option_b":"It returns no value (like a task callable in expressions limited)","option_c":"It is a clock","option_d":"It is illegal","correct_option":"B","explanation":"void functions perform actions without returning a value.","difficulty":"medium","is_premium":false,"subject_id":4,"id":691},{"question_text":"A common cause of X-propagation in RTL simulation is:","option_a":"Fully reset registers","option_b":"Uninitialized state or reading before reset","option_c":"Using enums","option_d":"Using parameters","correct_option":"B","explanation":"Uninitialized 4-state signals start at x and propagate.","difficulty":"medium","is_premium":false,"subject_id":4,"id":692},{"question_text":"Which helps debug X-propagation issues?","option_a":"Ignoring x","option_b":"Proper reset of all state and X-checking assertions","option_c":"More clocks","option_d":"Removing resets","correct_option":"B","explanation":"Resetting state and asserting on x catches propagation early.","difficulty":"medium","is_premium":false,"subject_id":4,"id":693},{"question_text":"A combinational always_comb that reads an output it also writes can cause:","option_a":"A clean flop","option_b":"A combinational feedback loop / latch-like behavior","option_c":"Lower power","option_d":"A clock","correct_option":"B","explanation":"Self-referential combinational writes create feedback loops.","difficulty":"hard","is_premium":false,"subject_id":4,"id":694},{"question_text":"What is the effect of declaring an FSM state variable as enum logic [1:0]?","option_a":"It is 2-state","option_b":"It is a 2-bit 4-state enumerated type","option_c":"It is a real","option_d":"It is a clock","correct_option":"B","explanation":"enum logic [1:0] gives a 2-bit 4-state enumerated state.","difficulty":"medium","is_premium":false,"subject_id":4,"id":695},{"question_text":"A safe FSM should handle illegal states by:","option_a":"Ignoring them","option_b":"Providing a default that returns to a known/reset state","option_c":"Removing the clock","option_d":"Adding latches","correct_option":"B","explanation":"A default branch recovers from illegal states (important for safety).","difficulty":"hard","is_premium":false,"subject_id":4,"id":696},{"question_text":"Which describes \u0027fork...join_none\u0027?","option_a":"Wait for all","option_b":"Spawn parallel processes and continue without waiting","option_c":"Wait for one","option_d":"Sequential","correct_option":"B","explanation":"join_none launches threads and proceeds immediately (testbench use).","difficulty":"hard","is_premium":false,"subject_id":4,"id":697},{"question_text":"Which is true about \u0027logic\u0027 being driven by two continuous assigns?","option_a":"Allowed","option_b":"Multiple-driver conflict / not allowed for a single-driver variable","option_c":"Creates a flop","option_d":"Speeds simulation","correct_option":"B","explanation":"A variable driven by multiple continuous assigns is a conflict.","difficulty":"hard","is_premium":false,"subject_id":4,"id":698},{"question_text":"The \u0027wildcard\u0027 equality operator ==? treats x/z in the operand as:","option_a":"Exact match required","option_b":"Don\u0027t-care for masked positions","option_c":"Always false","option_d":"A clock","correct_option":"B","explanation":"==? performs a masked comparison treating x/z as wildcards on the RHS literal.","difficulty":"hard","is_premium":false,"subject_id":4,"id":699},{"question_text":"Which SystemVerilog feature improves connecting a bus across hierarchy without listing each signal?","option_a":"Wildcard .* port connections","option_b":"More parameters","option_c":"force","option_d":"initial blocks","correct_option":"A","explanation":".* auto-connects ports with matching names, reducing boilerplate.","difficulty":"medium","is_premium":false,"subject_id":4,"id":700},{"question_text":"Implicit .name port connection (.clk) means:","option_a":"Connect port clk to a net of the same name clk","option_b":"Leave unconnected","option_c":"Tie to 0","option_d":"Tie to 1","correct_option":"A","explanation":".name connects the port to a same-named signal in scope.","difficulty":"medium","is_premium":false,"subject_id":4,"id":701},{"question_text":"A pipelined datapath improves throughput by:","option_a":"Reducing latency","option_b":"Allowing a new operation each cycle after fill","option_c":"Removing registers","option_d":"Lowering frequency","correct_option":"B","explanation":"Pipelining yields one result per cycle once full, raising throughput.","difficulty":"medium","is_premium":false,"subject_id":4,"id":702},{"question_text":"Valid/ready handshaking ensures:","option_a":"No flow control","option_b":"Data transfers only when both producer valid and consumer ready are high","option_c":"Always transfer","option_d":"Clock gating","correct_option":"B","explanation":"A transfer happens on the cycle valid \u0026\u0026 ready are both asserted.","difficulty":"medium","is_premium":false,"subject_id":4,"id":703},{"question_text":"A skid buffer is used to:","option_a":"Generate clocks","option_b":"Pipeline a ready/valid interface without losing data on backpressure","option_c":"Reset the design","option_d":"Reduce flops","correct_option":"B","explanation":"Skid buffers register valid/ready paths while preserving data under backpressure.","difficulty":"hard","is_premium":false,"subject_id":4,"id":704},{"question_text":"What does $countones(vector) return?","option_a":"Number of bits","option_b":"Count of bits set to 1","option_c":"Count of zeros","option_d":"The MSB","correct_option":"B","explanation":"$countones counts the number of 1 bits.","difficulty":"medium","is_premium":false,"subject_id":4,"id":705},{"question_text":"$onehot(vector) returns true when:","option_a":"All bits are 1","option_b":"Exactly one bit is 1","option_c":"No bits are 1","option_d":"Two bits are 1","correct_option":"B","explanation":"$onehot is true if precisely one bit is set.","difficulty":"medium","is_premium":false,"subject_id":4,"id":706},{"question_text":"$onehot0(vector) is true when:","option_a":"Exactly one bit is set","option_b":"Zero or one bit is set","option_c":"All bits set","option_d":"Never","correct_option":"B","explanation":"$onehot0 allows zero or one set bit.","difficulty":"hard","is_premium":false,"subject_id":4,"id":707},{"question_text":"Which is a good practice for reset in always_ff?","option_a":"Reset only some registers","option_b":"Reset all state needed for known startup behavior","option_c":"Avoid reset","option_d":"Use blocking assignments","correct_option":"B","explanation":"Resetting required state ensures deterministic startup.","difficulty":"medium","is_premium":false,"subject_id":4,"id":708},{"question_text":"Which describes \u0027unique0 case\u0027?","option_a":"Exactly one branch must match","option_b":"At most one branch matches (zero allowed)","option_c":"All match","option_d":"None can match","correct_option":"B","explanation":"unique0 allows zero or one match without a violation.","difficulty":"hard","is_premium":false,"subject_id":4,"id":709},{"question_text":"A combinational multiplier inferred from \u0027*\u0027 on wide operands tends to:","option_a":"Be a flip-flop","option_b":"Create a large, slow combinational path needing pipelining for speed","option_c":"Use no logic","option_d":"Be asynchronous","correct_option":"B","explanation":"Wide multipliers are large and may need pipelining to meet timing.","difficulty":"medium","is_premium":false,"subject_id":4,"id":710},{"question_text":"Which is true about default enum base type?","option_a":"It is real","option_b":"It defaults to int unless specified","option_c":"It is a string","option_d":"It is 1 bit","correct_option":"B","explanation":"Unspecified enums use int as the base type.","difficulty":"medium","is_premium":false,"subject_id":4,"id":711},{"question_text":"A \u0027generate if\u0027 block selects hardware based on:","option_a":"Runtime signals","option_b":"Compile-time parameter/constant conditions","option_c":"Clock edges","option_d":"Reset","correct_option":"B","explanation":"generate if conditionally elaborates hardware using constants.","difficulty":"medium","is_premium":false,"subject_id":4,"id":712},{"question_text":"What is a benefit of registering module inputs?","option_a":"Removes flops","option_b":"Isolates inter-module timing paths and eases timing closure","option_c":"Adds combinational loops","option_d":"Lowers frequency","correct_option":"B","explanation":"Registered I/O breaks long cross-module paths, helping timing.","difficulty":"medium","is_premium":false,"subject_id":4,"id":713},{"question_text":"A \u0027logic signed [7:0]\u0027 value of 8\u0027hFF equals:","option_a":"255","option_b":"-1","option_c":"1","option_d":"127","correct_option":"B","explanation":"As signed 8-bit, 0xFF is -1 (two\u0027s complement).","difficulty":"medium","is_premium":false,"subject_id":4,"id":714},{"question_text":"Which avoids sign-extension bugs when mixing signed and unsigned?","option_a":"Ignore signedness","option_b":"Explicit casts ($signed/$unsigned) and matched widths","option_c":"Use real","option_d":"Add delay","correct_option":"B","explanation":"Explicit signed/unsigned casts prevent unintended extension.","difficulty":"hard","is_premium":false,"subject_id":4,"id":715},{"question_text":"Which is the recommended FSM coding for safety-critical designs?","option_a":"Implicit states","option_b":"Enumerated states with default recovery and possibly safe one-hot encoding","option_c":"No reset","option_d":"Latches","correct_option":"B","explanation":"Enumerated, fully-specified FSMs with recovery are safest.","difficulty":"hard","is_premium":false,"subject_id":4,"id":716},{"question_text":"What does \u0027assign #2 y = a;\u0027 do in synthesis?","option_a":"Adds a 2 ns gate","option_b":"The delay is ignored; y = a is synthesized","option_c":"Creates a flop","option_d":"Errors out","correct_option":"B","explanation":"Synthesis ignores delays; only the logic is realized.","difficulty":"medium","is_premium":false,"subject_id":4,"id":717},{"question_text":"An interface clocking relationship is often captured using:","option_a":"A clocking block (mainly for verification)","option_b":"A parameter","option_c":"An enum","option_d":"A force","correct_option":"A","explanation":"Clocking blocks define sample/drive timing, mostly in testbenches.","difficulty":"hard","is_premium":false,"subject_id":4,"id":718},{"question_text":"Which is true about default net type in SystemVerilog modules using \u0027logic\u0027 ports?","option_a":"Ports must be wire","option_b":"logic ports are allowed and commonly used","option_c":"Only reg allowed","option_d":"No ports allowed","correct_option":"B","explanation":"SystemVerilog permits logic-typed ports directly.","difficulty":"easy","is_premium":false,"subject_id":4,"id":719},{"question_text":"What does \u0027parameter type T = logic [7:0]\u0027 allow?","option_a":"Runtime type change","option_b":"Type to be specified per instance at elaboration","option_c":"Clock change","option_d":"Nothing","correct_option":"B","explanation":"Type parameters let each instance choose the data type.","difficulty":"hard","is_premium":false,"subject_id":4,"id":720},{"question_text":"Why register the output of a wide combinational adder/comparator?","option_a":"To add latches","option_b":"To meet timing by breaking the long combinational path","option_c":"To remove the clock","option_d":"To lower frequency","correct_option":"B","explanation":"Registering shortens the path seen by downstream logic, aiding timing.","difficulty":"medium","is_premium":false,"subject_id":4,"id":721},{"question_text":"A FIFO depth must usually be:","option_a":"Any value","option_b":"Often a power of two for simple Gray-pointer wrap logic","option_c":"Prime","option_d":"Odd","correct_option":"B","explanation":"Power-of-two depths simplify pointer/Gray-code wrap-around.","difficulty":"medium","is_premium":false,"subject_id":4,"id":722},{"question_text":"Almost-full/almost-empty flags in a FIFO are used to:","option_a":"Reset","option_b":"Provide early warning for flow control before truly full/empty","option_c":"Change clock","option_d":"Reduce area","correct_option":"B","explanation":"Programmable thresholds give margin to react before overflow/underflow.","difficulty":"medium","is_premium":false,"subject_id":4,"id":723},{"question_text":"Which is the correct reset value syntax for a packed vector in always_ff?","option_a":"q \u003c= \u0027x;","option_b":"q \u003c= \u00270;","option_c":"q \u003c= 0.0;","option_d":"q \u003c= z;","correct_option":"B","explanation":"\u00270 fills all bits with zero regardless of width.","difficulty":"easy","is_premium":false,"subject_id":4,"id":724},{"question_text":"Which is a synthesizable description of a saturating counter?","option_a":"Wrap on overflow","option_b":"Hold at max value when at the top instead of wrapping","option_c":"Random","option_d":"Asynchronous","correct_option":"B","explanation":"A saturating counter clamps at max/min instead of rolling over.","difficulty":"medium","is_premium":false,"subject_id":4,"id":725},{"question_text":"Clock domain crossing of a multi-bit bus is best handled by:","option_a":"A single synchronizer flop","option_b":"Async FIFO or handshake with Gray-coded pointers","option_c":"Combinational logic","option_d":"A latch","correct_option":"B","explanation":"Multi-bit CDC needs FIFOs/handshakes, not naive per-bit synchronizers.","difficulty":"hard","is_premium":false,"subject_id":4,"id":726},{"question_text":"Why is a single two-flop synchronizer insufficient for a multi-bit bus?","option_a":"It is too fast","option_b":"Bits may be sampled in different cycles causing data incoherency","option_c":"It uses too much power","option_d":"It needs no clock","correct_option":"B","explanation":"Independent bit metastability can split a multi-bit value across cycles.","difficulty":"hard","is_premium":false,"subject_id":4,"id":727},{"question_text":"A \u0027localparam\u0027 computed from a \u0027parameter\u0027 is useful to:","option_a":"Override externally","option_b":"Derive internal constants that should not be overridden","option_c":"Create clocks","option_d":"Drive nets","correct_option":"B","explanation":"localparams derive fixed internal values from parameters.","difficulty":"medium","is_premium":false,"subject_id":4,"id":728},{"question_text":"Which best models a synchronous up/down counter with load?","option_a":"always_comb","option_b":"always_ff with priority: load \u003e up/down, all in clocked if/else","option_c":"assign only","option_d":"initial","correct_option":"B","explanation":"Clocked if/else priority encodes load and direction controls.","difficulty":"medium","is_premium":false,"subject_id":4,"id":729},{"question_text":"Which is the cleanest way to express a constant-width replication of zeros?","option_a":"{N{1\u0027b0}} or \u00270","option_b":"0","option_c":"z","option_d":"x","correct_option":"A","explanation":"{N{1\u0027b0}} or the width-agnostic \u00270 both yield all zeros.","difficulty":"easy","is_premium":false,"subject_id":4,"id":730},{"question_text":"A SystemVerilog class is an example of which kind of type?","option_a":"Static, packed","option_b":"Dynamic, reference (handle) type","option_c":"A net","option_d":"A clock","correct_option":"B","explanation":"Class objects are dynamically allocated and accessed via handles.","difficulty":"easy","is_premium":false,"subject_id":5,"id":731},{"question_text":"What does the \u0027new()\u0027 method do for a class?","option_a":"Frees memory","option_b":"Constructs (allocates) a new object instance","option_c":"Generates a clock","option_d":"Copies a handle only","correct_option":"B","explanation":"new() is the constructor allocating an object.","difficulty":"easy","is_premium":false,"subject_id":5,"id":732},{"question_text":"Assigning one class handle to another (h2 = h1) results in:","option_a":"A deep copy","option_b":"Both handles referencing the same object","option_c":"A new object","option_d":"A compile error","correct_option":"B","explanation":"Handle assignment copies the reference, not the object.","difficulty":"medium","is_premium":false,"subject_id":5,"id":733},{"question_text":"A shallow copy (copy()) duplicates:","option_a":"All nested objects recursively","option_b":"Only the top-level object; nested handles are shared","option_c":"Nothing","option_d":"Only clocks","correct_option":"B","explanation":"Shallow copy duplicates members but nested object handles still point to originals.","difficulty":"medium","is_premium":false,"subject_id":5,"id":734},{"question_text":"The \u0027rand\u0027 keyword on a class field enables:","option_a":"Clock generation","option_b":"Randomization of that field via randomize()","option_c":"A constant","option_d":"A net","correct_option":"B","explanation":"rand marks fields for randomization.","difficulty":"easy","is_premium":false,"subject_id":5,"id":735},{"question_text":"The difference between \u0027rand\u0027 and \u0027randc\u0027 is:","option_a":"randc is constant","option_b":"randc is cyclic (no repeat until all values used)","option_c":"rand is cyclic","option_d":"No difference","correct_option":"B","explanation":"randc cycles through all values before repeating.","difficulty":"medium","is_premium":false,"subject_id":5,"id":736},{"question_text":"A constraint block restricts:","option_a":"Clock frequency","option_b":"Legal values a randomize() call can produce","option_c":"Module ports","option_d":"Reset polarity","correct_option":"B","explanation":"Constraints define the legal solution space for randomization.","difficulty":"easy","is_premium":false,"subject_id":5,"id":737},{"question_text":"randomize() returns:","option_a":"The random value","option_b":"1 on success, 0 if constraints cannot be satisfied","option_c":"A handle","option_d":"Void","correct_option":"B","explanation":"randomize() returns success/failure status.","difficulty":"medium","is_premium":false,"subject_id":5,"id":738},{"question_text":"The \u0027inside\u0027 constraint \u0027x inside {[1:10]}\u0027 restricts x to:","option_a":"Exactly 1","option_b":"The range 1 to 10 inclusive","option_c":"Outside 1-10","option_d":"Any value","correct_option":"B","explanation":"inside with a range constrains membership to that interval.","difficulty":"easy","is_premium":false,"subject_id":5,"id":739},{"question_text":"An implication constraint \u0027a -\u003e b\u0027 means:","option_a":"b implies a","option_b":"If a is true then b must hold","option_c":"a equals b","option_d":"Always b","correct_option":"B","explanation":"The -\u003e operator conditions b on a being true.","difficulty":"medium","is_premium":false,"subject_id":5,"id":740},{"question_text":"A \u0027solve...before\u0027 constraint controls:","option_a":"Clocking","option_b":"The ordering/distribution bias of random variable solving","option_c":"Reset","option_d":"Port direction","correct_option":"B","explanation":"solve...before influences the solver order to shape distributions.","difficulty":"hard","is_premium":false,"subject_id":5,"id":741},{"question_text":"The \u0027dist\u0027 operator in constraints sets:","option_a":"Equal probability always","option_b":"Weighted probability distribution of values","option_c":"A clock","option_d":"A reset","correct_option":"B","explanation":"dist assigns weights to value ranges for biased randomization.","difficulty":"medium","is_premium":false,"subject_id":5,"id":742},{"question_text":"randomize() with {...} is used to:","option_a":"Disable randomization","option_b":"Add inline (in-line) constraints for a single call","option_c":"Free memory","option_d":"Generate a clock","correct_option":"B","explanation":"The with clause adds temporary constraints to one randomize call.","difficulty":"medium","is_premium":false,"subject_id":5,"id":743},{"question_text":"rand_mode(0) on a variable:","option_a":"Enables randomization","option_b":"Disables randomization of that variable","option_c":"Deletes it","option_d":"Makes it a clock","correct_option":"B","explanation":"rand_mode(0) turns off randomization for the field.","difficulty":"medium","is_premium":false,"subject_id":5,"id":744},{"question_text":"constraint_mode(0) on a constraint block:","option_a":"Enables it","option_b":"Disables that constraint","option_c":"Adds a clock","option_d":"Copies it","correct_option":"B","explanation":"constraint_mode(0) turns off a named constraint block.","difficulty":"medium","is_premium":false,"subject_id":5,"id":745},{"question_text":"A mailbox in SystemVerilog is used for:","option_a":"Clock generation","option_b":"Passing data between concurrent processes (producer/consumer)","option_c":"Resetting","option_d":"Defining ports","correct_option":"B","explanation":"Mailboxes are FIFO channels for inter-process communication.","difficulty":"medium","is_premium":false,"subject_id":5,"id":746},{"question_text":"A semaphore is used to:","option_a":"Store data","option_b":"Control access to a shared resource via keys","option_c":"Generate clocks","option_d":"Randomize","correct_option":"B","explanation":"Semaphores manage mutual exclusion using a key count.","difficulty":"medium","is_premium":false,"subject_id":5,"id":747},{"question_text":"An \u0027event\u0027 in SystemVerilog is used to:","option_a":"Store many values","option_b":"Synchronize processes via -\u003e/@ triggering and waiting","option_c":"Define ports","option_d":"Randomize","correct_option":"B","explanation":"Events synchronize threads: -\u003e triggers, @ waits.","difficulty":"medium","is_premium":false,"subject_id":5,"id":748},{"question_text":"fork...join waits for:","option_a":"The first thread","option_b":"All spawned threads to complete","option_c":"No threads","option_d":"A clock","correct_option":"B","explanation":"join blocks until every forked process finishes.","difficulty":"medium","is_premium":false,"subject_id":5,"id":749},{"question_text":"fork...join_any continues when:","option_a":"All complete","option_b":"Any one thread completes","option_c":"None complete","option_d":"Reset","correct_option":"B","explanation":"join_any resumes after the first thread finishes.","difficulty":"medium","is_premium":false,"subject_id":5,"id":750},{"question_text":"A dynamic array is sized:","option_a":"At compile time only","option_b":"At runtime using new[n]","option_c":"Never","option_d":"By a clock","correct_option":"B","explanation":"Dynamic arrays are allocated at runtime with new[size].","difficulty":"easy","is_premium":false,"subject_id":5,"id":751},{"question_text":"A queue in SystemVerilog supports:","option_a":"Fixed size only","option_b":"push_back/push_front/pop and variable size","option_c":"Clock generation","option_d":"No indexing","correct_option":"B","explanation":"Queues are variable-length with push/pop methods.","difficulty":"easy","is_premium":false,"subject_id":5,"id":752},{"question_text":"An associative array is best for:","option_a":"Dense, contiguous indices","option_b":"Sparse data indexed by arbitrary keys","option_c":"Clock generation","option_d":"Fixed small vectors","correct_option":"B","explanation":"Associative arrays efficiently store sparse, key-indexed data.","difficulty":"medium","is_premium":false,"subject_id":5,"id":753},{"question_text":"The array method \u0027sum()\u0027 returns:","option_a":"Array size","option_b":"The sum of array elements","option_c":"Max element","option_d":"First element","correct_option":"B","explanation":"sum() is a reduction method returning the total.","difficulty":"easy","is_premium":false,"subject_id":5,"id":754},{"question_text":"The array locator method \u0027find with (item \u003e 5)\u0027 returns:","option_a":"A single int","option_b":"A queue of matching elements","option_c":"A clock","option_d":"The size","correct_option":"B","explanation":"find returns all elements satisfying the predicate as a queue.","difficulty":"medium","is_premium":false,"subject_id":5,"id":755},{"question_text":"A virtual method enables:","option_a":"Faster clocks","option_b":"Polymorphism (runtime dispatch to the derived override)","option_c":"Static binding only","option_d":"Randomization","correct_option":"B","explanation":"virtual methods dispatch based on the actual object type at runtime.","difficulty":"medium","is_premium":false,"subject_id":5,"id":756},{"question_text":"Inheritance is expressed with which keyword?","option_a":"implements","option_b":"extends","option_c":"inherits","option_d":"derives","correct_option":"B","explanation":"A subclass uses \u0027extends\u0027 to inherit from a base class.","difficulty":"easy","is_premium":false,"subject_id":5,"id":757},{"question_text":"The \u0027super\u0027 keyword refers to:","option_a":"The current object","option_b":"The parent (base) class members/constructor","option_c":"A clock","option_d":"The top module","correct_option":"B","explanation":"super accesses the base class, e.g., super.new().","difficulty":"medium","is_premium":false,"subject_id":5,"id":758},{"question_text":"An abstract (virtual) class:","option_a":"Can be instantiated directly","option_b":"Cannot be instantiated; serves as a base for derived classes","option_c":"Is a net","option_d":"Generates clocks","correct_option":"B","explanation":"virtual (abstract) classes define interfaces but cannot be directly created.","difficulty":"medium","is_premium":false,"subject_id":5,"id":759},{"question_text":"A pure virtual method:","option_a":"Has a body in the base","option_b":"Has no body and must be overridden by derived classes","option_c":"Is static","option_d":"Is a constraint","correct_option":"B","explanation":"pure virtual methods declare an interface with no implementation.","difficulty":"hard","is_premium":false,"subject_id":5,"id":760},{"question_text":"A static class member is:","option_a":"Per-object","option_b":"Shared by all instances of the class","option_c":"A clock","option_d":"Randomized","correct_option":"B","explanation":"static members exist once for the whole class.","difficulty":"medium","is_premium":false,"subject_id":5,"id":761},{"question_text":"What does $cast(dst, src) do?","option_a":"Generates a clock","option_b":"Performs a checked dynamic downcast between class handles","option_c":"Adds delay","option_d":"Randomizes","correct_option":"B","explanation":"$cast safely downcasts and reports success/failure.","difficulty":"hard","is_premium":false,"subject_id":5,"id":762},{"question_text":"A clocking block in a testbench is used to:","option_a":"Generate RTL","option_b":"Define sampling and driving timing relative to a clock to avoid races","option_c":"Reset DUT","option_d":"Randomize","correct_option":"B","explanation":"Clocking blocks specify input sampling and output driving skews.","difficulty":"hard","is_premium":false,"subject_id":5,"id":763},{"question_text":"A \u0027program\u0027 block was introduced to:","option_a":"Add clocks","option_b":"Separate testbench code in the reactive region to reduce races","option_c":"Define RTL","option_d":"Generate resets","correct_option":"B","explanation":"program blocks schedule TB code in the reactive region, reducing DUT/TB races.","difficulty":"hard","is_premium":false,"subject_id":5,"id":764},{"question_text":"Functional coverage measures:","option_a":"Lines of code executed","option_b":"Whether intended functional scenarios/values were exercised","option_c":"Power","option_d":"Area","correct_option":"B","explanation":"Functional coverage tracks user-defined scenarios via covergroups.","difficulty":"medium","is_premium":false,"subject_id":5,"id":765},{"question_text":"A covergroup contains:","option_a":"Constraints","option_b":"Coverpoints and cross coverage that sample values","option_c":"Clocks","option_d":"Ports","correct_option":"B","explanation":"Covergroups define coverpoints (and crosses) to record value coverage.","difficulty":"medium","is_premium":false,"subject_id":5,"id":766},{"question_text":"A coverpoint \u0027bins\u0027 definition specifies:","option_a":"Clock edges","option_b":"Value buckets to be hit for coverage","option_c":"Constraints","option_d":"Reset","correct_option":"B","explanation":"bins categorize the values that must be observed.","difficulty":"medium","is_premium":false,"subject_id":5,"id":767},{"question_text":"Cross coverage measures:","option_a":"Single variable values","option_b":"Combinations of two or more coverpoints occurring together","option_c":"Clock skew","option_d":"Power","correct_option":"B","explanation":"Cross coverage tracks the cartesian combinations of coverpoints.","difficulty":"medium","is_premium":false,"subject_id":5,"id":768},{"question_text":"When is a covergroup sampled by default?","option_a":"Continuously","option_b":"On its sample() call or a specified clocking event","option_c":"At reset only","option_d":"Never","correct_option":"B","explanation":"Sampling occurs on sample() or the covergroup\u0027s trigger event.","difficulty":"medium","is_premium":false,"subject_id":5,"id":769},{"question_text":"Code coverage differs from functional coverage in that code coverage:","option_a":"Is user-defined intent","option_b":"Is automatically derived from RTL structure (lines, toggles, branches)","option_c":"Measures power","option_d":"Requires constraints","correct_option":"B","explanation":"Code coverage is structural/automatic; functional coverage is intent-based.","difficulty":"medium","is_premium":false,"subject_id":5,"id":770},{"question_text":"100% code coverage but low functional coverage indicates:","option_a":"Verification is complete","option_b":"Structure exercised but intended scenarios may be missed","option_c":"A clock bug","option_d":"A reset bug","correct_option":"B","explanation":"Both coverages matter; code coverage alone doesn\u0027t prove functional intent.","difficulty":"hard","is_premium":false,"subject_id":5,"id":771},{"question_text":"Constrained-random verification\u0027s main advantage over directed tests is:","option_a":"Less setup","option_b":"Broad scenario exploration that can hit unforeseen corner cases","option_c":"No checkers needed","option_d":"Faster compile","correct_option":"B","explanation":"Randomization explores a wide space, finding unexpected bugs.","difficulty":"medium","is_premium":false,"subject_id":5,"id":772},{"question_text":"A scoreboard in a testbench is responsible for:","option_a":"Driving stimulus","option_b":"Checking DUT outputs against a reference/expected model","option_c":"Generating clocks","option_d":"Coverage only","correct_option":"B","explanation":"Scoreboards compare actual vs expected results.","difficulty":"medium","is_premium":false,"subject_id":5,"id":773},{"question_text":"A driver component:","option_a":"Checks results","option_b":"Converts transactions into pin-level activity on the interface","option_c":"Collects coverage","option_d":"Generates random seeds","correct_option":"B","explanation":"The driver translates transactions to signal-level stimulus.","difficulty":"medium","is_premium":false,"subject_id":5,"id":774},{"question_text":"A monitor component:","option_a":"Drives stimulus","option_b":"Observes interface signals and reconstructs transactions","option_c":"Resets DUT","option_d":"Allocates memory","correct_option":"B","explanation":"Monitors passively sample signals and form transactions for checking/coverage.","difficulty":"medium","is_premium":false,"subject_id":5,"id":775},{"question_text":"A generator/sequencer produces:","option_a":"Clocks","option_b":"Stimulus transactions to feed the driver","option_c":"Coverage","option_d":"Resets only","correct_option":"B","explanation":"The generator/sequencer creates transactions for the driver.","difficulty":"medium","is_premium":false,"subject_id":5,"id":776},{"question_text":"Why use a virtual interface in class-based testbenches?","option_a":"To generate clocks","option_b":"To let dynamic class objects access static interface signals","option_c":"To randomize","option_d":"To reset","correct_option":"B","explanation":"virtual interfaces bridge dynamic classes to static DUT interfaces.","difficulty":"hard","is_premium":false,"subject_id":5,"id":777},{"question_text":"An assertion \u0027assert property\u0027 that fails will by default:","option_a":"Do nothing","option_b":"Report an error (with optional action block)","option_c":"Stop the clock","option_d":"Randomize","correct_option":"B","explanation":"A failing assertion triggers the fail action, by default an error.","difficulty":"medium","is_premium":false,"subject_id":5,"id":778},{"question_text":"An immediate assertion is evaluated:","option_a":"Over multiple clocks","option_b":"At the point it is reached, like a procedural if","option_c":"Only at reset","option_d":"Never","correct_option":"B","explanation":"Immediate assertions evaluate procedurally when executed.","difficulty":"medium","is_premium":false,"subject_id":5,"id":779},{"question_text":"A concurrent assertion is evaluated:","option_a":"Procedurally once","option_b":"On a clock, checking temporal sequences","option_c":"At compile time","option_d":"Only in functions","correct_option":"B","explanation":"Concurrent assertions sample on a clock and check sequences over time.","difficulty":"medium","is_premium":false,"subject_id":5,"id":780},{"question_text":"The randomize \u0027pre_randomize\u0027 callback runs:","option_a":"After randomization","option_b":"Before the solver runs","option_c":"Never","option_d":"On reset","correct_option":"B","explanation":"pre_randomize executes before constraint solving.","difficulty":"hard","is_premium":false,"subject_id":5,"id":781},{"question_text":"The \u0027post_randomize\u0027 callback runs:","option_a":"Before solving","option_b":"After values are assigned, useful for derived computation","option_c":"Never","option_d":"On clock","correct_option":"B","explanation":"post_randomize runs after solving to finalize/derive fields.","difficulty":"hard","is_premium":false,"subject_id":5,"id":782},{"question_text":"A \u0027foreach\u0027 constraint is used to:","option_a":"Loop in RTL","option_b":"Apply constraints to each element of an array","option_c":"Generate clocks","option_d":"Reset","correct_option":"B","explanation":"foreach constrains array elements individually.","difficulty":"medium","is_premium":false,"subject_id":5,"id":783},{"question_text":"Why seed control matters in constrained-random testing:","option_a":"It changes the DUT","option_b":"It enables reproducible random stimulus across runs","option_c":"It generates clocks","option_d":"It removes coverage","correct_option":"B","explanation":"Fixed seeds reproduce failing scenarios for debug.","difficulty":"medium","is_premium":false,"subject_id":5,"id":784},{"question_text":"A transaction (sequence item) typically contains:","option_a":"Clock trees","option_b":"Randomizable fields describing one unit of stimulus/response","option_c":"RTL gates","option_d":"Power data","correct_option":"B","explanation":"Transactions model abstract operations with random fields.","difficulty":"easy","is_premium":false,"subject_id":5,"id":785},{"question_text":"What is \u0027reactive\u0027 vs \u0027active\u0027 region significance in TB?","option_a":"None","option_b":"Scheduling TB sampling/driving in proper regions avoids races with DUT","option_c":"It sets clock period","option_d":"It randomizes","correct_option":"B","explanation":"Correct region usage (clocking blocks/program) prevents TB-DUT races.","difficulty":"hard","is_premium":false,"subject_id":5,"id":786},{"question_text":"A \u0027wait fork\u0027 statement:","option_a":"Spawns threads","option_b":"Blocks until all child processes of the current thread finish","option_c":"Generates a clock","option_d":"Resets","correct_option":"B","explanation":"wait fork waits for all forked children to complete.","difficulty":"hard","is_premium":false,"subject_id":5,"id":787},{"question_text":"A \u0027disable fork\u0027 statement:","option_a":"Starts threads","option_b":"Terminates all active child processes","option_c":"Resets DUT","option_d":"Randomizes","correct_option":"B","explanation":"disable fork kills outstanding forked processes.","difficulty":"hard","is_premium":false,"subject_id":5,"id":788},{"question_text":"Why prefer mailboxes over shared variables between generator and driver?","option_a":"Faster clocks","option_b":"Built-in synchronization and blocking semantics avoid races","option_c":"Less code only","option_d":"No reason","correct_option":"B","explanation":"Mailboxes provide safe, blocking producer/consumer communication.","difficulty":"medium","is_premium":false,"subject_id":5,"id":789},{"question_text":"A parameterized class is declared as:","option_a":"class C; ... endclass","option_b":"class C #(type T = int); ... endclass","option_c":"module C","option_d":"interface C","correct_option":"B","explanation":"Classes can take type/value parameters via #().","difficulty":"medium","is_premium":false,"subject_id":5,"id":790},{"question_text":"What does the \u0027local\u0027 access qualifier do in a class?","option_a":"Makes a member global","option_b":"Restricts member access to the class itself","option_c":"Makes a clock","option_d":"Randomizes","correct_option":"B","explanation":"local limits visibility to the declaring class.","difficulty":"medium","is_premium":false,"subject_id":5,"id":791},{"question_text":"The \u0027protected\u0027 qualifier allows access by:","option_a":"Anyone","option_b":"The class and its derived classes","option_c":"Only modules","option_d":"No one","correct_option":"B","explanation":"protected members are visible to the class and subclasses.","difficulty":"medium","is_premium":false,"subject_id":5,"id":792},{"question_text":"A \u0027string\u0027 method .len() returns:","option_a":"ASCII value","option_b":"Number of characters","option_c":"A clock","option_d":"The first char","correct_option":"B","explanation":"len() gives the string length.","difficulty":"easy","is_premium":false,"subject_id":5,"id":793},{"question_text":"$sformatf is used to:","option_a":"Print directly","option_b":"Return a formatted string","option_c":"Generate a clock","option_d":"Randomize","correct_option":"B","explanation":"$sformatf builds a formatted string for later use.","difficulty":"easy","is_premium":false,"subject_id":5,"id":794},{"question_text":"Why is randomization failure (randomize()==0) important to check?","option_a":"It never happens","option_b":"Over-constraint can make the solution space empty, silently skipping stimulus","option_c":"It generates clocks","option_d":"It resets DUT","correct_option":"B","explanation":"Conflicting constraints yield no solution; unchecked, tests do nothing.","difficulty":"hard","is_premium":false,"subject_id":5,"id":795},{"question_text":"An assertion \u0027assume property\u0027 in formal is used to:","option_a":"Check DUT","option_b":"Constrain the environment/inputs for the formal tool","option_c":"Generate clocks","option_d":"Collect coverage","correct_option":"B","explanation":"assume restricts legal inputs in formal verification.","difficulty":"hard","is_premium":false,"subject_id":5,"id":796},{"question_text":"A \u0027cover property\u0027 statement is used to:","option_a":"Force a failure","option_b":"Check that a temporal scenario was exercised at least once","option_c":"Reset DUT","option_d":"Drive stimulus","correct_option":"B","explanation":"cover verifies a sequence happened, contributing to coverage.","difficulty":"medium","is_premium":false,"subject_id":5,"id":797},{"question_text":"Why register/queue handles in a factory pattern?","option_a":"Faster clocks","option_b":"To enable type/instance overrides without editing the testbench","option_c":"To reduce area","option_d":"No reason","correct_option":"B","explanation":"Factory overrides let tests substitute component types flexibly.","difficulty":"hard","is_premium":false,"subject_id":5,"id":798},{"question_text":"A constraint with both range and dist that conflict will:","option_a":"Pick one silently","option_b":"Cause randomize() to fail if unsatisfiable","option_c":"Generate a clock","option_d":"Crash compile always","correct_option":"B","explanation":"Unsatisfiable combined constraints make randomize() return 0.","difficulty":"hard","is_premium":false,"subject_id":5,"id":799},{"question_text":"What does \u0027std::randomize()\u0027 (scope randomize) allow?","option_a":"Only class fields","option_b":"Randomizing standalone variables not in a class","option_c":"Clock generation","option_d":"Reset","correct_option":"B","explanation":"std::randomize randomizes local variables with inline constraints.","difficulty":"hard","is_premium":false,"subject_id":5,"id":800},{"question_text":"A weighted \u0027dist\u0027 like x dist {0:=10, [1:3]:/90} means:","option_a":"Equal weights","option_b":"0 weight 10; the range 1-3 shares weight 90 (/= divides)","option_c":"Only 0 allowed","option_d":"Invalid","correct_option":"B","explanation":":= assigns weight per value; :/ divides weight across the range.","difficulty":"hard","is_premium":false,"subject_id":5,"id":801},{"question_text":"A self-checking testbench means:","option_a":"Manual waveform review","option_b":"Automatic pass/fail decision via scoreboards/assertions","option_c":"No checking","option_d":"Only coverage","correct_option":"B","explanation":"Self-checking TBs automatically validate behavior without manual inspection.","difficulty":"easy","is_premium":false,"subject_id":5,"id":802},{"question_text":"Why is a reference (golden) model used?","option_a":"To generate clocks","option_b":"To predict expected DUT behavior for comparison","option_c":"To reset","option_d":"To randomize","correct_option":"B","explanation":"A reference model computes expected outputs for the scoreboard.","difficulty":"medium","is_premium":false,"subject_id":5,"id":803},{"question_text":"Coverage closure refers to:","option_a":"Closing files","option_b":"Reaching coverage goals, indicating verification completeness","option_c":"Closing clocks","option_d":"Resetting","correct_option":"B","explanation":"Coverage closure is meeting defined coverage targets.","difficulty":"medium","is_premium":false,"subject_id":5,"id":804},{"question_text":"A regression suite is:","option_a":"A single test","option_b":"A collection of tests run repeatedly to catch new bugs","option_c":"A clock","option_d":"A constraint","correct_option":"B","explanation":"Regressions re-run many tests to detect regressions over time.","difficulty":"easy","is_premium":false,"subject_id":5,"id":805},{"question_text":"Bug rate flattening over time typically indicates:","option_a":"More bugs incoming","option_b":"Verification maturity approaching closure","option_c":"Clock failure","option_d":"Reset failure","correct_option":"B","explanation":"A flattening discovery curve suggests the DUT is maturing.","difficulty":"medium","is_premium":false,"subject_id":5,"id":806},{"question_text":"A \u0027queue[$]\u0027 declaration creates:","option_a":"A fixed array","option_b":"An unbounded queue","option_c":"A clock","option_d":"An associative array","correct_option":"B","explanation":"type q[$] is an unbounded queue.","difficulty":"easy","is_premium":false,"subject_id":5,"id":807},{"question_text":"What does the array method \u0027shuffle()\u0027 do?","option_a":"Sorts ascending","option_b":"Randomly reorders elements","option_c":"Removes duplicates","option_d":"Sums","correct_option":"B","explanation":"shuffle() randomizes element order.","difficulty":"easy","is_premium":false,"subject_id":5,"id":808},{"question_text":"Constraint randomization respects active constraints unless:","option_a":"Always ignored","option_b":"They are disabled via constraint_mode or rand_mode","option_c":"A clock ticks","option_d":"Reset asserts","correct_option":"B","explanation":"Disabling modes removes constraints/variables from solving.","difficulty":"medium","is_premium":false,"subject_id":5,"id":809},{"question_text":"Why use \u0027protected virtual\u0027 methods in a base verification component?","option_a":"Faster clocks","option_b":"Allow controlled overriding by subclasses while hiding from outside","option_c":"Randomize","option_d":"Reset DUT","correct_option":"B","explanation":"protected virtual exposes override points only to subclasses.","difficulty":"hard","is_premium":false,"subject_id":5,"id":810},{"question_text":"A directed test is most useful for:","option_a":"Broad random exploration","option_b":"Targeting a specific known scenario or corner case deterministically","option_c":"Coverage only","option_d":"Clock generation","correct_option":"B","explanation":"Directed tests deterministically hit specific scenarios.","difficulty":"easy","is_premium":false,"subject_id":5,"id":811},{"question_text":"Combining directed and constrained-random testing is beneficial because:","option_a":"It wastes time","option_b":"Directed covers known corners; random finds the unexpected","option_c":"It removes checkers","option_d":"It needs no coverage","correct_option":"B","explanation":"The two approaches complement each other for thorough verification.","difficulty":"medium","is_premium":false,"subject_id":5,"id":812},{"question_text":"A \u0027rand bit [3:0] addr; constraint c { addr != 0; }\u0027 guarantees:","option_a":"addr is always 0","option_b":"addr is randomized to any value except 0","option_c":"addr is constant","option_d":"addr is a clock","correct_option":"B","explanation":"The constraint excludes 0 from the legal set.","difficulty":"easy","is_premium":false,"subject_id":5,"id":813},{"question_text":"Which is true about randc cycling?","option_a":"It can repeat immediately","option_b":"It exhausts all values once before repeating any","option_c":"It is the same as rand","option_d":"It is constant","correct_option":"B","explanation":"randc walks the full value set before repeats.","difficulty":"medium","is_premium":false,"subject_id":5,"id":814},{"question_text":"A handle that is null and is dereferenced causes:","option_a":"Nothing","option_b":"A null-handle runtime error","option_c":"A clock","option_d":"Randomization","correct_option":"B","explanation":"Dereferencing a null handle is a runtime error.","difficulty":"medium","is_premium":false,"subject_id":5,"id":815},{"question_text":"Garbage collection of class objects occurs when:","option_a":"Manually freed","option_b":"No handles reference the object anymore","option_c":"On clock edge","option_d":"Never","correct_option":"B","explanation":"SystemVerilog auto-reclaims objects with no remaining references.","difficulty":"medium","is_premium":false,"subject_id":5,"id":816},{"question_text":"Why prefer \u0027virtual\u0027 methods in TB base classes (e.g., run_phase)?","option_a":"To prevent overrides","option_b":"To allow derived tests to customize behavior via polymorphism","option_c":"Faster clocks","option_d":"Less memory","correct_option":"B","explanation":"virtual enables subclasses to override and extend behavior.","difficulty":"medium","is_premium":false,"subject_id":5,"id":817},{"question_text":"A constraint \u0027len inside {[1:8]}; payload.size() == len;\u0027 ties:","option_a":"Nothing","option_b":"The array size to a randomized length variable","option_c":"A clock","option_d":"Reset","correct_option":"B","explanation":"Constraining size() to len couples the dynamic array length to randomization.","difficulty":"hard","is_premium":false,"subject_id":5,"id":818},{"question_text":"The main purpose of a transaction-level model (TLM) is:","option_a":"Pin-accurate timing","option_b":"Faster, abstract communication between components via function calls","option_c":"Clock generation","option_d":"Layout","correct_option":"B","explanation":"TLM abstracts communication to transactions for speed and reuse.","difficulty":"medium","is_premium":false,"subject_id":5,"id":819},{"question_text":"Why is randomization seeding tied to the simulator and test name?","option_a":"For clocks","option_b":"To create varied but reproducible stimulus per test","option_c":"To reset","option_d":"No reason","correct_option":"B","explanation":"Seeding schemes balance variation with reproducibility.","difficulty":"hard","is_premium":false,"subject_id":5,"id":820},{"question_text":"A weighted coverage goal might exclude some bins via:","option_a":"ignore_bins","option_b":"rand_mode","option_c":"clocking","option_d":"fork","correct_option":"A","explanation":"ignore_bins removes specified values from coverage consideration.","difficulty":"hard","is_premium":false,"subject_id":5,"id":821},{"question_text":"illegal_bins in a covergroup:","option_a":"Count toward coverage","option_b":"Flag an error if the value is ever sampled","option_c":"Generate clocks","option_d":"Are ignored","correct_option":"B","explanation":"illegal_bins assert that certain values must never occur.","difficulty":"hard","is_premium":false,"subject_id":5,"id":822},{"question_text":"Why separate stimulus generation from the driver?","option_a":"Faster clocks","option_b":"Reuse and layering: abstract generation independent of pin protocol","option_c":"Less memory","option_d":"No reason","correct_option":"B","explanation":"Decoupling improves reuse and lets the protocol change independently.","difficulty":"medium","is_premium":false,"subject_id":5,"id":823},{"question_text":"A \u0027bit [7:0] data []\u0027 declares:","option_a":"A fixed 8-element array","option_b":"A dynamic array of 8-bit elements","option_c":"A queue","option_d":"An associative array","correct_option":"B","explanation":"[] empty dimension declares a dynamic array.","difficulty":"easy","is_premium":false,"subject_id":5,"id":824},{"question_text":"What does \u0027data = new[10]\u0027 do for a dynamic array?","option_a":"Frees it","option_b":"Allocates 10 elements","option_c":"Sorts it","option_d":"Randomizes it","correct_option":"B","explanation":"new[10] sizes the dynamic array to 10 elements.","difficulty":"easy","is_premium":false,"subject_id":5,"id":825},{"question_text":"A test that always passes regardless of DUT behavior likely has:","option_a":"Good checkers","option_b":"Missing/weak checking (no real verification value)","option_c":"High coverage","option_d":"A clock bug","correct_option":"B","explanation":"Always-passing tests indicate absent or ineffective checking.","difficulty":"medium","is_premium":false,"subject_id":5,"id":826},{"question_text":"Which SystemVerilog construct lets two processes synchronize by passing transactions safely between them?","option_a":"fork...join_none","option_b":"mailbox","option_c":"always_comb","option_d":"wait fork","correct_option":"B","explanation":"A mailbox is a built-in FIFO used to pass data between concurrent processes (e.g., generator to driver) without race conditions.","difficulty":"easy","is_premium":false,"subject_id":5,"id":827},{"question_text":"A reference (golden) model in verification provides:","option_a":"Random noise","option_b":"Expected behavior to compare the DUT against","option_c":"Clock generation","option_d":"Pin wiggling","correct_option":"B","explanation":"The reference model predicts expected results for checking.","difficulty":"medium","is_premium":false,"subject_id":5,"id":828},{"question_text":"Coverage-driven verification uses coverage to:","option_a":"Replace checkers","option_b":"Guide stimulus toward unexercised scenarios and measure completeness","option_c":"Generate clocks","option_d":"Reset the DUT","correct_option":"B","explanation":"CDV closes coverage holes by steering randomized stimulus.","difficulty":"medium","is_premium":false,"subject_id":5,"id":829},{"question_text":"A self-checking testbench is preferred because it:","option_a":"Needs manual waveform review","option_b":"Automatically flags pass/fail, enabling large automated regressions","option_c":"Runs slower","option_d":"Removes coverage","correct_option":"B","explanation":"Self-checking enables scalable, automated regression without manual inspection.","difficulty":"easy","is_premium":false,"subject_id":5,"id":830},{"question_text":"SVA stands for:","option_a":"Synthesis Verification Array","option_b":"SystemVerilog Assertions","option_c":"Static Vector Analysis","option_d":"Signal Value Assertion","correct_option":"B","explanation":"SVA = SystemVerilog Assertions, for specifying temporal properties.","difficulty":"easy","is_premium":false,"subject_id":7,"id":831},{"question_text":"An immediate assertion is written as:","option_a":"assert property (...)","option_b":"assert (expr) ... else ...;","option_c":"cover property (...)","option_d":"sequence ...","correct_option":"B","explanation":"Immediate assertions use assert(expr) procedurally.","difficulty":"easy","is_premium":false,"subject_id":7,"id":832},{"question_text":"A concurrent assertion is written using:","option_a":"assert (expr);","option_b":"assert property (...);","option_c":"if (expr)","option_d":"case","correct_option":"B","explanation":"Concurrent assertions use assert property with a clocking event.","difficulty":"easy","is_premium":false,"subject_id":7,"id":833},{"question_text":"Concurrent assertions sample signals in which region?","option_a":"Active region","option_b":"Preponed region (just before the clock edge)","option_c":"Postponed region","option_d":"NBA region","correct_option":"B","explanation":"Sampled values are taken in the preponed region to avoid races.","difficulty":"hard","is_premium":false,"subject_id":7,"id":834},{"question_text":"The overlapping implication operator is:","option_a":"|-\u003e","option_b":"|=\u003e","option_c":"-\u003e","option_d":"=\u003e","correct_option":"A","explanation":"|-\u003e checks the consequent in the same cycle the antecedent matches.","difficulty":"medium","is_premium":false,"subject_id":7,"id":835},{"question_text":"The non-overlapping implication operator is:","option_a":"|-\u003e","option_b":"|=\u003e","option_c":"##1","option_d":"and","correct_option":"B","explanation":"|=\u003e checks the consequent starting the next cycle.","difficulty":"medium","is_premium":false,"subject_id":7,"id":836},{"question_text":"##2 in a sequence means:","option_a":"2 events","option_b":"A delay of exactly 2 clock cycles","option_c":"2 signals","option_d":"2 properties","correct_option":"B","explanation":"##N specifies a fixed cycle delay of N.","difficulty":"easy","is_premium":false,"subject_id":7,"id":837},{"question_text":"##[1:3] specifies:","option_a":"Exactly 3 cycles","option_b":"A variable delay between 1 and 3 cycles","option_c":"An infinite delay","option_d":"No delay","correct_option":"B","explanation":"##[m:n] is a range delay from m to n cycles.","difficulty":"medium","is_premium":false,"subject_id":7,"id":838},{"question_text":"The consecutive repetition a[*3] means:","option_a":"a true once","option_b":"a true on 3 consecutive cycles","option_c":"a true 3 times non-consecutively","option_d":"a never true","correct_option":"B","explanation":"[*n] is consecutive repetition n times.","difficulty":"medium","is_premium":false,"subject_id":7,"id":839},{"question_text":"The goto repetition a[-\u003e3] means:","option_a":"a true 3 consecutive cycles","option_b":"a true on the 3rd occurrence (not necessarily consecutive), ending at that match","option_c":"a false 3 times","option_d":"a never true","correct_option":"B","explanation":"[-\u003en] matches at the nth true occurrence of a.","difficulty":"hard","is_premium":false,"subject_id":7,"id":840},{"question_text":"The non-consecutive repetition a[=2] means:","option_a":"a true twice consecutively","option_b":"a true exactly twice, with possible gaps, not requiring match to end at the last","option_c":"a false twice","option_d":"a true once","correct_option":"B","explanation":"[=n] is non-consecutive repetition of n occurrences.","difficulty":"hard","is_premium":false,"subject_id":7,"id":841},{"question_text":"A sequence is a building block that describes:","option_a":"A single boolean","option_b":"A temporal pattern over multiple cycles","option_c":"A clock","option_d":"A reset","correct_option":"B","explanation":"Sequences express multi-cycle temporal behavior.","difficulty":"easy","is_premium":false,"subject_id":7,"id":842},{"question_text":"A property differs from a sequence in that a property:","option_a":"Cannot be asserted","option_b":"Can include implications and is the unit asserted/covered","option_c":"Has no clock","option_d":"Is always immediate","correct_option":"B","explanation":"Properties combine sequences with operators like implication and are asserted.","difficulty":"medium","is_premium":false,"subject_id":7,"id":843},{"question_text":"What does $rose(sig) detect?","option_a":"sig is high","option_b":"A 0-to-1 transition of sig at the sampling edge","option_c":"A 1-to-0 transition","option_d":"sig unchanged","correct_option":"B","explanation":"$rose is true when the sampled value rose from 0 to 1.","difficulty":"medium","is_premium":false,"subject_id":7,"id":844},{"question_text":"What does $fell(sig) detect?","option_a":"0-to-1","option_b":"1-to-0 transition","option_c":"sig high","option_d":"no change","correct_option":"B","explanation":"$fell is true on a falling (1-\u003e0) transition.","difficulty":"medium","is_premium":false,"subject_id":7,"id":845},{"question_text":"$stable(sig) is true when:","option_a":"sig changed","option_b":"sig has the same sampled value as the previous cycle","option_c":"sig is 1","option_d":"sig is x","correct_option":"B","explanation":"$stable indicates no change between consecutive samples.","difficulty":"medium","is_premium":false,"subject_id":7,"id":846},{"question_text":"$past(sig, 2) returns:","option_a":"sig now","option_b":"sig\u0027s sampled value 2 cycles ago","option_c":"sig next cycle","option_d":"Always 0","correct_option":"B","explanation":"$past(sig, n) gives the value n cycles earlier.","difficulty":"medium","is_premium":false,"subject_id":7,"id":847},{"question_text":"A disable iff (rst) clause is used to:","option_a":"Enable the assertion only on reset","option_b":"Asynchronously abort assertion evaluation during reset","option_c":"Generate a clock","option_d":"Add delay","correct_option":"B","explanation":"disable iff aborts the property when the condition (e.g., reset) is true.","difficulty":"medium","is_premium":false,"subject_id":7,"id":848},{"question_text":"Which clause specifies the clock for a concurrent assertion?","option_a":"@(posedge clk)","option_b":"#5","option_c":"wait","option_d":"initial","correct_option":"A","explanation":"A clocking event like @(posedge clk) drives sampling.","difficulty":"easy","is_premium":false,"subject_id":7,"id":849},{"question_text":"A \u0027cover property\u0027 is used to:","option_a":"Force failure","option_b":"Confirm a temporal scenario occurred (functional coverage)","option_c":"Reset","option_d":"Drive stimulus","correct_option":"B","explanation":"cover checks that a property/sequence was exercised.","difficulty":"easy","is_premium":false,"subject_id":7,"id":850},{"question_text":"An \u0027assume property\u0027 in formal verification:","option_a":"Checks the DUT","option_b":"Constrains legal inputs for the formal tool","option_c":"Generates clocks","option_d":"Collects coverage","correct_option":"B","explanation":"assume restricts the input space in formal proofs.","difficulty":"hard","is_premium":false,"subject_id":7,"id":851},{"question_text":"The \u0027and\u0027 operator between two sequences requires:","option_a":"Either to match","option_b":"Both to match (they may end at different times)","option_c":"Neither","option_d":"A clock","correct_option":"B","explanation":"seq1 and seq2 succeeds if both match (end times may differ).","difficulty":"hard","is_premium":false,"subject_id":7,"id":852},{"question_text":"The \u0027intersect\u0027 operator between sequences requires:","option_a":"Both match and end at the same time (same length)","option_b":"Either match","option_c":"Neither","option_d":"Different lengths","correct_option":"A","explanation":"intersect requires both to match with identical start and end.","difficulty":"hard","is_premium":false,"subject_id":7,"id":853},{"question_text":"The \u0027or\u0027 operator between sequences matches when:","option_a":"Both match","option_b":"Either sequence matches","option_c":"Neither matches","option_d":"They are equal length","correct_option":"B","explanation":"seq1 or seq2 matches if at least one matches.","difficulty":"medium","is_premium":false,"subject_id":7,"id":854},{"question_text":"The \u0027throughout\u0027 operator (cond throughout seq) requires:","option_a":"cond true only at the end","option_b":"cond to hold for the entire duration of seq","option_c":"cond never true","option_d":"A clock change","correct_option":"B","explanation":"throughout enforces a condition across the whole sequence match.","difficulty":"hard","is_premium":false,"subject_id":7,"id":855},{"question_text":"The \u0027within\u0027 operator (seq1 within seq2) means:","option_a":"seq1 occurs entirely inside seq2\u0027s span","option_b":"seq2 inside seq1","option_c":"They never overlap","option_d":"Same as or","correct_option":"A","explanation":"within requires seq1 to be contained in seq2\u0027s match window.","difficulty":"hard","is_premium":false,"subject_id":7,"id":856},{"question_text":"first_match(seq) is used to:","option_a":"Match all occurrences","option_b":"Take only the earliest match, discarding later overlapping matches","option_c":"Never match","option_d":"Generate clocks","correct_option":"B","explanation":"first_match selects the first successful match of a sequence.","difficulty":"hard","is_premium":false,"subject_id":7,"id":857},{"question_text":"A common request-grant property \u0027req |-\u003e ##[1:3] gnt\u0027 checks:","option_a":"gnt before req","option_b":"After req, gnt occurs within 1 to 3 cycles","option_c":"req and gnt simultaneously always","option_d":"Nothing","correct_option":"B","explanation":"It asserts a grant follows a request within a bounded window.","difficulty":"medium","is_premium":false,"subject_id":7,"id":858},{"question_text":"A liveness property typically asserts:","option_a":"Something bad never happens","option_b":"Something good eventually happens","option_c":"A clock toggles","option_d":"Reset asserts","correct_option":"B","explanation":"Liveness: eventually something must occur (often unbounded).","difficulty":"hard","is_premium":false,"subject_id":7,"id":859},{"question_text":"A safety property typically asserts:","option_a":"Eventually good happens","option_b":"A bad condition never occurs","option_c":"A clock toggles","option_d":"Reset","correct_option":"B","explanation":"Safety: a bad state is never reached (bounded violation).","difficulty":"hard","is_premium":false,"subject_id":7,"id":860},{"question_text":"The s_eventually operator expresses:","option_a":"A safety property","option_b":"A strong liveness: the property must eventually hold","option_c":"A reset","option_d":"An immediate check","correct_option":"B","explanation":"s_eventually is a strong liveness operator.","difficulty":"hard","is_premium":false,"subject_id":7,"id":861},{"question_text":"Where can concurrent assertions be placed?","option_a":"Only in modules","option_b":"In modules, interfaces, programs, and as standalone via assert directives","option_c":"Only in functions","option_d":"Only in testbenches","correct_option":"B","explanation":"Concurrent assertions can appear in modules, interfaces, and programs.","difficulty":"medium","is_premium":false,"subject_id":7,"id":862},{"question_text":"Binding assertions to a DUT without editing RTL uses:","option_a":"force","option_b":"the bind construct","option_c":"config_db","option_d":"a clock","correct_option":"B","explanation":"bind attaches an assertion/checker module to the DUT non-intrusively.","difficulty":"hard","is_premium":false,"subject_id":7,"id":863},{"question_text":"A property with a failing antecedent (e.g., req false) results in:","option_a":"A failure","option_b":"A vacuous (trivial) pass","option_c":"A fatal error","option_d":"A clock glitch","correct_option":"B","explanation":"If the antecedent never matches, the implication passes vacuously.","difficulty":"hard","is_premium":false,"subject_id":7,"id":864},{"question_text":"Why is vacuous success a concern in coverage?","option_a":"It is impossible","option_b":"Properties may \u0027pass\u0027 without the meaningful scenario ever happening","option_c":"It speeds clocks","option_d":"It resets DUT","correct_option":"B","explanation":"Vacuous passes don\u0027t prove the intended behavior; cover the antecedent too.","difficulty":"hard","is_premium":false,"subject_id":7,"id":865},{"question_text":"To ensure the antecedent is exercised, you can add:","option_a":"A disable iff","option_b":"A cover property on the antecedent sequence","option_c":"A clock","option_d":"A reset","correct_option":"B","explanation":"Covering the antecedent confirms the meaningful case occurred.","difficulty":"hard","is_premium":false,"subject_id":7,"id":866},{"question_text":"An immediate assertion\u0027s \u0027else\u0027 block is used to:","option_a":"Generate clocks","option_b":"Specify the action (e.g., $error) on failure","option_c":"Pass the assertion","option_d":"Add delay","correct_option":"B","explanation":"The else clause runs on failure, often reporting an error.","difficulty":"medium","is_premium":false,"subject_id":7,"id":867},{"question_text":"Default severity of a failing assertion action is:","option_a":"$info","option_b":"$error","option_c":"$fatal","option_d":"$warning","correct_option":"B","explanation":"Without an else, a failing assertion issues an error by default.","difficulty":"medium","is_premium":false,"subject_id":7,"id":868},{"question_text":"A sequence with local variables can:","option_a":"Not store anything","option_b":"Capture and later compare values across cycles","option_c":"Generate clocks","option_d":"Reset","correct_option":"B","explanation":"Local variables in sequences capture data for later comparison.","difficulty":"hard","is_premium":false,"subject_id":7,"id":869},{"question_text":"A data-integrity property like \u0027wr |-\u003e ##2 (rd_data == $past(wr_data,2))\u0027 checks:","option_a":"Clock toggling","option_b":"Data written equals data read after a known latency","option_c":"Reset","option_d":"Nothing","correct_option":"B","explanation":"It verifies pipeline data integrity using $past.","difficulty":"hard","is_premium":false,"subject_id":7,"id":870},{"question_text":"Which is true about sampling in concurrent assertions?","option_a":"Uses current (not sampled) values","option_b":"Uses preponed sampled values, so glitches within the cycle are ignored","option_c":"Uses postponed values","option_d":"Ignores the clock","correct_option":"B","explanation":"Preponed sampling uses stable values from just before the edge.","difficulty":"hard","is_premium":false,"subject_id":7,"id":871},{"question_text":"An assertion \u0027a |-\u003e b\u0027 where a and b are booleans checks:","option_a":"Over many cycles","option_b":"In the same cycle: whenever a is true, b must be true","option_c":"b before a","option_d":"Nothing","correct_option":"B","explanation":"Overlapping implication of booleans is a same-cycle check.","difficulty":"easy","is_premium":false,"subject_id":7,"id":872},{"question_text":"A multi-clock assertion (different clocks across ##) is:","option_a":"Illegal always","option_b":"Allowed using clock flow with clocking event changes","option_c":"Only immediate","option_d":"A reset","correct_option":"B","explanation":"SVA supports multi-clocked sequences with explicit clock changes.","difficulty":"hard","is_premium":false,"subject_id":7,"id":873},{"question_text":"Which detects that a one-hot bus stays one-hot?","option_a":"assert property (@(posedge clk) $onehot(bus));","option_b":"assert property (bus == 0);","option_c":"cover (clk);","option_d":"assume (rst);","correct_option":"A","explanation":"$onehot in a property checks the one-hot invariant each cycle.","difficulty":"medium","is_premium":false,"subject_id":7,"id":874},{"question_text":"A \u0027no two grants simultaneously\u0027 arbiter property uses:","option_a":"$onehot0(grant)","option_b":"$rose(grant)","option_c":"$past(grant)","option_d":"##2 grant","correct_option":"A","explanation":"$onehot0 allows zero or one grant, forbidding simultaneous grants.","difficulty":"hard","is_premium":false,"subject_id":7,"id":875},{"question_text":"Why use disable iff (!rst_n) on most assertions?","option_a":"To speed clocks","option_b":"To avoid false failures while the DUT is in reset","option_c":"To randomize","option_d":"To add coverage","correct_option":"B","explanation":"Disabling during reset prevents spurious failures from unknown states.","difficulty":"medium","is_premium":false,"subject_id":7,"id":876},{"question_text":"Binding a checker module with \u0027bind dut checker u_chk(.*);\u0027 connects:","option_a":"Nothing","option_b":"Same-named signals of the checker to the DUT","option_c":"Only clocks","option_d":"Only reset","correct_option":"B","explanation":".* connects matching-named ports between checker and DUT.","difficulty":"hard","is_premium":false,"subject_id":7,"id":877},{"question_text":"Which is true about immediate assertions and clocks?","option_a":"They need a clock","option_b":"They evaluate when reached procedurally, no clock required","option_c":"They are temporal","option_d":"They sample in preponed","correct_option":"B","explanation":"Immediate assertions are procedural and not clock-sampled.","difficulty":"medium","is_premium":false,"subject_id":7,"id":878},{"question_text":"A property to check \u0027gnt only after req\u0027 could be:","option_a":"gnt |-\u003e req","option_b":"gnt |-\u003e $past(req)","option_c":"req |=\u003e gnt always","option_d":"gnt and req","correct_option":"B","explanation":"Checking $past(req) ensures a request preceded the grant.","difficulty":"hard","is_premium":false,"subject_id":7,"id":879},{"question_text":"Which expresses \u0027busy must deassert within 8 cycles of asserting\u0027?","option_a":"$rose(busy) |-\u003e ##[1:8] !busy","option_b":"busy |-\u003e busy","option_c":"!busy |-\u003e busy","option_d":"busy and !busy","correct_option":"A","explanation":"On busy rising, it must fall within 1 to 8 cycles.","difficulty":"medium","is_premium":false,"subject_id":7,"id":880},{"question_text":"A bounded liveness property differs from unbounded in that it:","option_a":"Never completes","option_b":"Requires the event within a finite cycle window","option_c":"Uses no clock","option_d":"Is immediate","correct_option":"B","explanation":"Bounded liveness sets a finite deadline, simpler for simulation/formal.","difficulty":"hard","is_premium":false,"subject_id":7,"id":881},{"question_text":"Why are unbounded liveness properties hard in simulation?","option_a":"They are illegal","option_b":"Simulation is finite, so \u0027eventually\u0027 may never be confirmed","option_c":"They need no clock","option_d":"They reset DUT","correct_option":"B","explanation":"Finite sims can\u0027t prove unbounded eventualities; formal handles them better.","difficulty":"hard","is_premium":false,"subject_id":7,"id":882},{"question_text":"A sequence \u0027a ##1 b ##1 c\u0027 matches when:","option_a":"a, b, c all in one cycle","option_b":"a now, b next cycle, c the cycle after","option_c":"c first","option_d":"Never","correct_option":"B","explanation":"##1 separators sequence a, b, c on successive cycles.","difficulty":"easy","is_premium":false,"subject_id":7,"id":883},{"question_text":"Which operator binds an antecedent sequence to a consequent property?","option_a":"##","option_b":"implication (|-\u003e or |=\u003e)","option_c":"and","option_d":"or","correct_option":"B","explanation":"Implication links antecedent match to a required consequent.","difficulty":"easy","is_premium":false,"subject_id":7,"id":884},{"question_text":"What does \u0027a[*1:$]\u0027 mean?","option_a":"a once","option_b":"a repeated one or more times (unbounded)","option_c":"a never","option_d":"a exactly $","correct_option":"B","explanation":"[*1:$] is one-or-more consecutive repetitions ($ = unbounded).","difficulty":"hard","is_premium":false,"subject_id":7,"id":885},{"question_text":"A property can be named and reused with which keyword?","option_a":"sequence","option_b":"property ... endproperty","option_c":"function","option_d":"task","correct_option":"B","explanation":"Named properties are declared with property...endproperty.","difficulty":"easy","is_premium":false,"subject_id":7,"id":886},{"question_text":"Parameterizing a property/sequence enables:","option_a":"Clock generation","option_b":"Reuse across signals/latencies (e.g., variable delay bounds)","option_c":"Reset","option_d":"Nothing","correct_option":"B","explanation":"Parameters make properties reusable for different signals/timing.","difficulty":"medium","is_premium":false,"subject_id":7,"id":887},{"question_text":"An assertion failure typically reports:","option_a":"Only the time","option_b":"Time, assertion name, and the failing condition for debug","option_c":"Coverage","option_d":"The seed","correct_option":"B","explanation":"Failures include time and context to aid debugging.","difficulty":"easy","is_premium":false,"subject_id":7,"id":888},{"question_text":"Which is best for checking FIFO never overflows?","option_a":"cover property","option_b":"assert property (@(posedge clk) disable iff(!rst_n) !(full \u0026\u0026 wr \u0026\u0026 !rd));","option_c":"assume property","option_d":"$rose only","correct_option":"B","explanation":"An assertion forbidding write when full without read catches overflow.","difficulty":"hard","is_premium":false,"subject_id":7,"id":889},{"question_text":"Which is best for checking FIFO never underflows?","option_a":"assert property (!(empty \u0026\u0026 rd \u0026\u0026 !wr));","option_b":"cover (empty)","option_c":"assume (full)","option_d":"$fell(clk)","correct_option":"A","explanation":"Forbidding read when empty without write catches underflow.","difficulty":"hard","is_premium":false,"subject_id":7,"id":890},{"question_text":"What is the benefit of assertions over manual waveform inspection?","option_a":"Slower debug","option_b":"Automatic, continuous checking that pinpoints violations in time","option_c":"No benefit","option_d":"They generate clocks","correct_option":"B","explanation":"Assertions continuously check and localize failures automatically.","difficulty":"easy","is_premium":false,"subject_id":7,"id":891},{"question_text":"Embedding assertions in RTL/interfaces is called:","option_a":"Black-box testing","option_b":"White-box / assertion-based verification (ABV)","option_c":"Gate-level sim","option_d":"DRC","correct_option":"B","explanation":"ABV embeds checks close to the logic for early bug detection.","difficulty":"medium","is_premium":false,"subject_id":7,"id":892},{"question_text":"A property \u0027req |-\u003e ##1 ack\u0027 fails if:","option_a":"ack is high with req","option_b":"After req, ack is not high exactly one cycle later","option_c":"req is low","option_d":"Clock toggles","correct_option":"B","explanation":"The consequent requires ack precisely one cycle after req.","difficulty":"medium","is_premium":false,"subject_id":7,"id":893},{"question_text":"Which captures \u0027every read must have been preceded by a valid address\u0027?","option_a":"rd |-\u003e $past(addr_valid)","option_b":"addr_valid |-\u003e rd","option_c":"rd and addr_valid","option_d":"##2 rd","correct_option":"A","explanation":"Checking $past(addr_valid) on read enforces ordering.","difficulty":"hard","is_premium":false,"subject_id":7,"id":894},{"question_text":"Local variable assignment within a sequence uses:","option_a":"= inside a (expr, var=expr) action","option_b":"\u003c= only","option_c":"assign","option_d":"force","correct_option":"A","explanation":"Sequence match actions can assign local variables, e.g., (a, v=data).","difficulty":"hard","is_premium":false,"subject_id":7,"id":895},{"question_text":"Which is an example of a structural (combinational) assertion?","option_a":"Multi-cycle handshake","option_b":"assert property (@(posedge clk) one_hot_invariant);","option_c":"Liveness","option_d":"$past chain","correct_option":"B","explanation":"Same-cycle invariants (like one-hot) are essentially structural checks.","difficulty":"medium","is_premium":false,"subject_id":7,"id":896},{"question_text":"What does \u0027reject_on\u0027/\u0027accept_on\u0027 do (SVA abort)?","option_a":"Nothing","option_b":"Abort property evaluation on a condition (reject = fail, accept = pass)","option_c":"Generate clocks","option_d":"Reset","correct_option":"B","explanation":"These abort operators terminate evaluation with pass/fail on a condition.","difficulty":"hard","is_premium":false,"subject_id":7,"id":897},{"question_text":"Which sampling function helps detect a pulse exactly one cycle wide?","option_a":"$rose(sig) ##1 $fell(sig)","option_b":"$stable(sig)","option_c":"$past(sig,5)","option_d":"$onehot(sig)","correct_option":"A","explanation":"Rise then fall the next cycle indicates a single-cycle pulse.","difficulty":"hard","is_premium":false,"subject_id":7,"id":898},{"question_text":"Why prefer concurrent assertions for protocol checking?","option_a":"They are immediate","option_b":"They naturally express temporal/multi-cycle relationships with clean sampling","option_c":"They need no clock","option_d":"They are faster to type","correct_option":"B","explanation":"Concurrent assertions are designed for temporal protocol properties.","difficulty":"medium","is_premium":false,"subject_id":7,"id":899},{"question_text":"An assertion\u0027s clock can be inferred from:","option_a":"Nothing","option_b":"A default clocking block in the scope","option_c":"The reset","option_d":"The seed","correct_option":"B","explanation":"A default clocking provides the sampling clock if not specified.","difficulty":"hard","is_premium":false,"subject_id":7,"id":900},{"question_text":"A property \u0027a |=\u003e b[*2]\u0027 requires:","option_a":"b true once next cycle","option_b":"Starting next cycle, b true for two consecutive cycles","option_c":"a true twice","option_d":"Nothing","correct_option":"B","explanation":"|=\u003e then b[*2] means b holds two consecutive cycles after a.","difficulty":"hard","is_premium":false,"subject_id":7,"id":901},{"question_text":"What is the role of \u0027expect\u0027 statement?","option_a":"Same as cover","option_b":"A procedural blocking check that waits for a property to succeed","option_c":"Generate clocks","option_d":"Reset","correct_option":"B","explanation":"expect blocks the process until the property completes (pass/fail).","difficulty":"hard","is_premium":false,"subject_id":7,"id":902},{"question_text":"Which is true about assertion severity $fatal in a check?","option_a":"Continues simulation","option_b":"Stops the simulation immediately","option_c":"Just warns","option_d":"Adds coverage","correct_option":"B","explanation":"$fatal terminates the simulation.","difficulty":"easy","is_premium":false,"subject_id":7,"id":903},{"question_text":"Why qualify assertions with valid/enable conditions?","option_a":"To slow sim","option_b":"To avoid checking during invalid/idle phases (reducing false fails)","option_c":"To generate clocks","option_d":"To reset","correct_option":"B","explanation":"Guarding with enables prevents spurious failures when checks don\u0027t apply.","difficulty":"medium","is_premium":false,"subject_id":7,"id":904},{"question_text":"A sequence used as a boolean trigger in procedural code can use:","option_a":"assign","option_b":"the sequence event in @(seq) or .triggered","option_c":"force","option_d":"initial","correct_option":"B","explanation":"Sequences expose .triggered and can be waited on as events.","difficulty":"hard","is_premium":false,"subject_id":7,"id":905},{"question_text":"Which best checks \u0027stable data while valid is asserted until ready\u0027?","option_a":"$stable(data) throughout (valid[*1:$] ##0 ready)","option_b":"$rose(data)","option_c":"$past(ready)","option_d":"##2 data","correct_option":"A","explanation":"throughout enforces data stability across the valid-until-ready window.","difficulty":"hard","is_premium":false,"subject_id":7,"id":906},{"question_text":"What does a \u0027cover property\u0027 report at the end of sim?","option_a":"Pass/fail","option_b":"How many times the covered scenario occurred","option_c":"Clock count","option_d":"Reset count","correct_option":"B","explanation":"cover reports the number of matches (occurrences).","difficulty":"easy","is_premium":false,"subject_id":7,"id":907},{"question_text":"Assertions placed in an interface benefit from:","option_a":"No reuse","option_b":"Reuse across all DUTs that use that interface","option_c":"Slower checks","option_d":"No clock","correct_option":"B","explanation":"Interface assertions travel with the interface, aiding reuse.","difficulty":"medium","is_premium":false,"subject_id":7,"id":908},{"question_text":"A glitch on a combinational signal mid-cycle is ignored by concurrent assertions because:","option_a":"They sample postponed","option_b":"They use preponed sampled values, stable before the edge","option_c":"They have no clock","option_d":"They are immediate","correct_option":"B","explanation":"Preponed sampling captures stable values, ignoring intra-cycle glitches.","difficulty":"hard","is_premium":false,"subject_id":7,"id":909},{"question_text":"Why might an assertion never fire (no pass/fail)?","option_a":"It is too fast","option_b":"The antecedent is never satisfied (no meaningful evaluation)","option_c":"The clock is too slow","option_d":"Reset is low","correct_option":"B","explanation":"If the antecedent never matches, the property only passes vacuously.","difficulty":"medium","is_premium":false,"subject_id":7,"id":910},{"question_text":"A good practice is to pair each protocol assertion with:","option_a":"A clock divider","option_b":"A cover to confirm the scenario is actually hit","option_c":"A reset","option_d":"A constraint","correct_option":"B","explanation":"Covers ensure the asserted scenario was genuinely exercised.","difficulty":"medium","is_premium":false,"subject_id":7,"id":911},{"question_text":"Which expresses mutual exclusion of two signals a and b?","option_a":"assert property (!(a \u0026\u0026 b));","option_b":"assert property (a || b);","option_c":"cover (a);","option_d":"assume (b);","correct_option":"A","explanation":"!(a \u0026\u0026 b) forbids both being high together.","difficulty":"medium","is_premium":false,"subject_id":7,"id":912},{"question_text":"Formal tools prove an assertion by:","option_a":"Running random stimulus","option_b":"Exhaustively exploring reachable states for a counterexample","option_c":"Inspecting waveforms","option_d":"Generating clocks","correct_option":"B","explanation":"Formal exhaustively searches for any violating trace.","difficulty":"hard","is_premium":false,"subject_id":7,"id":913},{"question_text":"A counterexample (CEX) from a formal tool is:","option_a":"A passing trace","option_b":"A waveform showing how the property can be violated","option_c":"A clock","option_d":"A constraint","correct_option":"B","explanation":"A CEX demonstrates a concrete property violation.","difficulty":"hard","is_premium":false,"subject_id":7,"id":914},{"question_text":"Over-constraining inputs in formal can cause:","option_a":"More bugs found","option_b":"Missed bugs because real input scenarios are excluded","option_c":"Faster clocks","option_d":"Reset","correct_option":"B","explanation":"Excessive assumptions can hide legitimate failure scenarios.","difficulty":"hard","is_premium":false,"subject_id":7,"id":915},{"question_text":"Which is true about assertion \u0027assert property\u0027 default pass action?","option_a":"Prints a message","option_b":"By default does nothing visible on pass","option_c":"Stops sim","option_d":"Generates a clock","correct_option":"B","explanation":"Pass actions are usually silent unless specified.","difficulty":"medium","is_premium":false,"subject_id":7,"id":916},{"question_text":"A reusable assertion checker module commonly takes which as inputs?","option_a":"Only a seed","option_b":"Clock, reset, and the protocol signals to monitor","option_c":"Only coverage","option_d":"Only constraints","correct_option":"B","explanation":"Checker modules receive clock/reset and the signals under check.","difficulty":"medium","is_premium":false,"subject_id":7,"id":917},{"question_text":"Which captures \u0027no back-to-back grants without a request between\u0027?","option_a":"$rose(gnt) |-\u003e $past(req)","option_b":"gnt |=\u003e !gnt until req","option_c":"gnt and req","option_d":"##2 gnt","correct_option":"B","explanation":"It requires deassertion of gnt until a new request, preventing back-to-back grants.","difficulty":"hard","is_premium":false,"subject_id":7,"id":918},{"question_text":"The \u0027until\u0027 operator (a until b) holds when:","option_a":"a holds until b becomes true","option_b":"b always true","option_c":"a never true","option_d":"Same as and","correct_option":"A","explanation":"until requires a to hold every cycle until b occurs.","difficulty":"hard","is_premium":false,"subject_id":7,"id":919},{"question_text":"The strong vs weak distinction (e.g., until vs s_until) concerns:","option_a":"Clock speed","option_b":"Whether the terminating condition must eventually occur (strong) or not (weak)","option_c":"Reset","option_d":"Coverage","correct_option":"B","explanation":"Strong operators require the terminating event to occur; weak don\u0027t.","difficulty":"hard","is_premium":false,"subject_id":7,"id":920},{"question_text":"Which is the safest way to add assertions to a third-party IP?","option_a":"Edit its RTL","option_b":"Use bind to attach a checker without modifying the IP","option_c":"Force signals","option_d":"Change the clock","correct_option":"B","explanation":"bind keeps the IP untouched while adding checks.","difficulty":"medium","is_premium":false,"subject_id":7,"id":921},{"question_text":"An assertion clock different from the design clock is useful for:","option_a":"Nothing","option_b":"Checking signals in a different clock domain at the proper sampling","option_c":"Resetting","option_d":"Randomizing","correct_option":"B","explanation":"Domain-specific assertion clocks sample signals correctly per domain.","difficulty":"hard","is_premium":false,"subject_id":7,"id":922},{"question_text":"What does \u0027assert property (@(posedge clk) p);\u0027 with p a boolean check?","option_a":"Over many cycles","option_b":"That p holds every clock cycle (an invariant)","option_c":"p once","option_d":"Nothing","correct_option":"B","explanation":"A clocked boolean property checks the invariant each cycle.","difficulty":"easy","is_premium":false,"subject_id":7,"id":923},{"question_text":"Why might you write a cover for \u0027req ##[1:3] gnt\u0027?","option_a":"To force failure","option_b":"To confirm grants at each latency (1,2,3) actually occur in testing","option_c":"To reset","option_d":"To generate clocks","correct_option":"B","explanation":"Covering the range confirms the timing scenarios were exercised.","difficulty":"medium","is_premium":false,"subject_id":7,"id":924},{"question_text":"A property failing only after reset deassertion suggests:","option_a":"Nothing to fix","option_b":"Missing disable iff or an actual post-reset bug to investigate","option_c":"A clock issue only","option_d":"A seed issue","correct_option":"B","explanation":"Check whether reset gating is needed or a real bug exists post-reset.","difficulty":"hard","is_premium":false,"subject_id":7,"id":925},{"question_text":"The main value of assertion-based verification in regressions is:","option_a":"Slower runs","option_b":"Continuous self-checking that catches violations across many tests","option_c":"No checking","option_d":"Manual review","correct_option":"B","explanation":"Assertions provide always-on checks across the whole regression.","difficulty":"easy","is_premium":false,"subject_id":7,"id":926},{"question_text":"The SVA operator \u0027throughout\u0027 is used to require:","option_a":"A one-time event","option_b":"A condition to hold for the entire duration of a sequence","option_c":"A reset","option_d":"A clock edge","correct_option":"B","explanation":"expr throughout seq requires expr true across the whole sequence match.","difficulty":"hard","is_premium":false,"subject_id":7,"id":927},{"question_text":"The SVA \u0027within\u0027 operator checks that:","option_a":"One sequence occurs entirely inside the span of another","option_b":"Two clocks match","option_c":"Reset is async","option_d":"A signal is high once","correct_option":"A","explanation":"seq1 within seq2 requires seq1 to occur within the match of seq2.","difficulty":"hard","is_premium":false,"subject_id":7,"id":928},{"question_text":"Using $past in an assertion lets you reference:","option_a":"A future value","option_b":"A signal\u0027s value from previous clock cycle(s)","option_c":"The reset vector","option_d":"Another clock domain","correct_option":"B","explanation":"$past(sig, n) returns the value sig had n cycles earlier.","difficulty":"medium","is_premium":false,"subject_id":7,"id":929},{"question_text":"A \u0027cover\u0027 directive on a sequence is used to:","option_a":"Force a failure","option_b":"Confirm that an interesting scenario actually occurred in simulation","option_c":"Generate the clock","option_d":"Reset the DUT","correct_option":"B","explanation":"cover property checks that a scenario was exercised, aiding functional coverage.","difficulty":"medium","is_premium":false,"subject_id":7,"id":930},{"question_text":"UVM stands for:","option_a":"Unified Verification Method","option_b":"Universal Verification Methodology","option_c":"Universal Vector Model","option_d":"Unified VHDL Model","correct_option":"B","explanation":"UVM is the Universal Verification Methodology, an Accellera standard.","difficulty":"easy","is_premium":false,"subject_id":6,"id":931},{"question_text":"UVM is built on top of which language?","option_a":"VHDL","option_b":"SystemVerilog","option_c":"C++","option_d":"Python","correct_option":"B","explanation":"UVM is a SystemVerilog class library.","difficulty":"easy","is_premium":false,"subject_id":6,"id":932},{"question_text":"The base class for all UVM components is:","option_a":"uvm_object","option_b":"uvm_component","option_c":"uvm_sequence","option_d":"uvm_test","correct_option":"B","explanation":"uvm_component is the base for hierarchical, phased components.","difficulty":"easy","is_premium":false,"subject_id":6,"id":933},{"question_text":"The base class for transient data objects (transactions) is:","option_a":"uvm_component","option_b":"uvm_object","option_c":"uvm_driver","option_d":"uvm_env","correct_option":"B","explanation":"uvm_object is the base for data/sequence items.","difficulty":"easy","is_premium":false,"subject_id":6,"id":934},{"question_text":"Which UVM component converts sequence items into pin-level activity?","option_a":"Monitor","option_b":"Driver","option_c":"Scoreboard","option_d":"Subscriber","correct_option":"B","explanation":"The uvm_driver drives transactions onto the interface.","difficulty":"easy","is_premium":false,"subject_id":6,"id":935},{"question_text":"Which UVM component observes the DUT interface and broadcasts transactions?","option_a":"Driver","option_b":"Monitor","option_c":"Sequencer","option_d":"Test","correct_option":"B","explanation":"The uvm_monitor samples signals and publishes transactions via analysis ports.","difficulty":"easy","is_premium":false,"subject_id":6,"id":936},{"question_text":"The component that arbitrates and routes sequence items to the driver is the:","option_a":"Monitor","option_b":"Sequencer","option_c":"Scoreboard","option_d":"Env","correct_option":"B","explanation":"The uvm_sequencer manages sequences and feeds the driver.","difficulty":"easy","is_premium":false,"subject_id":6,"id":937},{"question_text":"A UVM agent typically encapsulates:","option_a":"Only a scoreboard","option_b":"A sequencer, driver, and monitor for one interface","option_c":"The DUT","option_d":"The clock generator","correct_option":"B","explanation":"An agent bundles sequencer+driver+monitor for a protocol/interface.","difficulty":"medium","is_premium":false,"subject_id":6,"id":938},{"question_text":"An agent configured as PASSIVE omits:","option_a":"The monitor","option_b":"The driver and sequencer (monitor only)","option_c":"Everything","option_d":"The scoreboard","correct_option":"B","explanation":"Passive agents only monitor; no stimulus driving.","difficulty":"medium","is_premium":false,"subject_id":6,"id":939},{"question_text":"The UVM environment (uvm_env) contains:","option_a":"Only the DUT","option_b":"Agents, scoreboards, and other sub-environments","option_c":"Only clocks","option_d":"Only sequences","correct_option":"B","explanation":"uvm_env composes agents, scoreboards, and config.","difficulty":"easy","is_premium":false,"subject_id":6,"id":940},{"question_text":"The top-level container that builds the env and starts sequences is the:","option_a":"uvm_monitor","option_b":"uvm_test","option_c":"uvm_driver","option_d":"uvm_object","correct_option":"B","explanation":"uvm_test instantiates the env and orchestrates stimulus.","difficulty":"easy","is_premium":false,"subject_id":6,"id":941},{"question_text":"Which function starts the UVM phasing and runs the selected test?","option_a":"run()","option_b":"run_test()","option_c":"main()","option_d":"build()","correct_option":"B","explanation":"run_test() in the top module launches UVM.","difficulty":"easy","is_premium":false,"subject_id":6,"id":942},{"question_text":"Which UVM phase is used to construct the component hierarchy?","option_a":"run_phase","option_b":"build_phase","option_c":"report_phase","option_d":"final_phase","correct_option":"B","explanation":"build_phase creates child components top-down.","difficulty":"easy","is_premium":false,"subject_id":6,"id":943},{"question_text":"build_phase executes in which order through the hierarchy?","option_a":"Bottom-up","option_b":"Top-down","option_c":"Random","option_d":"Leaf only","correct_option":"B","explanation":"build_phase runs top-down so parents create children first.","difficulty":"medium","is_premium":false,"subject_id":6,"id":944},{"question_text":"connect_phase executes in which order?","option_a":"Top-down","option_b":"Bottom-up","option_c":"Random","option_d":"Never","correct_option":"B","explanation":"connect_phase runs bottom-up after components exist.","difficulty":"medium","is_premium":false,"subject_id":6,"id":945},{"question_text":"Which is the only time-consuming (task) phase among these?","option_a":"build_phase","option_b":"run_phase","option_c":"connect_phase","option_d":"end_of_elaboration_phase","correct_option":"B","explanation":"run_phase is a task that consumes simulation time.","difficulty":"medium","is_premium":false,"subject_id":6,"id":946},{"question_text":"Which mechanism keeps the run_phase alive until stimulus is done?","option_a":"Clocking blocks","option_b":"Objections (raise/drop)","option_c":"Constraints","option_d":"Config DB only","correct_option":"B","explanation":"Objections prevent phase end until all are dropped.","difficulty":"medium","is_premium":false,"subject_id":6,"id":947},{"question_text":"Forgetting to drop an objection causes:","option_a":"Immediate end","option_b":"The phase (and sim) to hang until timeout","option_c":"A compile error","option_d":"A clock glitch","correct_option":"B","explanation":"Unbalanced objections stall the phase until the drain/timeout.","difficulty":"medium","is_premium":false,"subject_id":6,"id":948},{"question_text":"The UVM factory enables:","option_a":"Faster clocks","option_b":"Creating and overriding component/object types at runtime","option_c":"Reset","option_d":"Coverage only","correct_option":"B","explanation":"The factory creates objects by type and supports overrides.","difficulty":"medium","is_premium":false,"subject_id":6,"id":949},{"question_text":"Which macro registers a component with the factory?","option_a":"`uvm_object_utils","option_b":"`uvm_component_utils","option_c":"`uvm_info","option_d":"`uvm_do","correct_option":"B","explanation":"`uvm_component_utils registers component classes.","difficulty":"easy","is_premium":false,"subject_id":6,"id":950},{"question_text":"Which macro registers a transaction/object with the factory?","option_a":"`uvm_component_utils","option_b":"`uvm_object_utils","option_c":"`uvm_error","option_d":"`uvm_phase","correct_option":"B","explanation":"`uvm_object_utils registers uvm_object-derived classes.","difficulty":"easy","is_premium":false,"subject_id":6,"id":951},{"question_text":"To create a component via the factory you call:","option_a":"new()","option_b":"type::type_id::create(name, parent)","option_c":"build()","option_d":"connect()","correct_option":"B","explanation":"create() via type_id lets the factory honor overrides.","difficulty":"medium","is_premium":false,"subject_id":6,"id":952},{"question_text":"A factory type override replaces:","option_a":"A clock","option_b":"All creations of a base type with a derived type","option_c":"The DUT","option_d":"A constraint","correct_option":"B","explanation":"set_type_override swaps every creation of the base for the derived type.","difficulty":"medium","is_premium":false,"subject_id":6,"id":953},{"question_text":"An instance override differs from a type override in that it:","option_a":"Affects all instances","option_b":"Affects only a specific hierarchical instance path","option_c":"Generates clocks","option_d":"Disables the factory","correct_option":"B","explanation":"Instance overrides target a specific path, not the whole type.","difficulty":"hard","is_premium":false,"subject_id":6,"id":954},{"question_text":"The uvm_config_db is used to:","option_a":"Store waveforms","option_b":"Pass configuration/handles down the hierarchy","option_c":"Generate clocks","option_d":"Randomize","correct_option":"B","explanation":"config_db sets/gets configuration across the hierarchy.","difficulty":"medium","is_premium":false,"subject_id":6,"id":955},{"question_text":"A virtual interface is commonly passed to the driver/monitor via:","option_a":"Constraints","option_b":"uvm_config_db","option_c":"Clocking blocks","option_d":"Macros","correct_option":"B","explanation":"The TB sets the vif in config_db; components get it in build_phase.","difficulty":"medium","is_premium":false,"subject_id":6,"id":956},{"question_text":"TLM analysis ports are used to:","option_a":"Drive pins","option_b":"Broadcast transactions one-to-many (e.g., monitor to scoreboard/coverage)","option_c":"Generate clocks","option_d":"Reset","correct_option":"B","explanation":"uvm_analysis_port publishes transactions to multiple subscribers.","difficulty":"medium","is_premium":false,"subject_id":6,"id":957},{"question_text":"A uvm_analysis_imp implements which method to receive transactions?","option_a":"run()","option_b":"write()","option_c":"build()","option_d":"get()","correct_option":"B","explanation":"Subscribers implement write(t) to receive analysis transactions.","difficulty":"medium","is_premium":false,"subject_id":6,"id":958},{"question_text":"The driver gets the next item from the sequencer using:","option_a":"get_next_item()/try_next_item()","option_b":"write()","option_c":"raise_objection()","option_d":"create()","correct_option":"A","explanation":"The driver pulls items via get_next_item and signals item_done.","difficulty":"medium","is_premium":false,"subject_id":6,"id":959},{"question_text":"After processing an item, the driver calls:","option_a":"raise_objection","option_b":"item_done()","option_c":"connect()","option_d":"report()","correct_option":"B","explanation":"item_done() tells the sequencer the item is complete.","difficulty":"medium","is_premium":false,"subject_id":6,"id":960},{"question_text":"A uvm_sequence runs on:","option_a":"The driver","option_b":"A sequencer (via start())","option_c":"The monitor","option_d":"The scoreboard","correct_option":"B","explanation":"Sequences execute on a sequencer using start().","difficulty":"medium","is_premium":false,"subject_id":6,"id":961},{"question_text":"The `uvm_do macro:","option_a":"Creates a clock","option_b":"Creates, randomizes, and sends a sequence item","option_c":"Resets the DUT","option_d":"Connects ports","correct_option":"B","explanation":"`uvm_do automates create/start_item/randomize/finish_item.","difficulty":"medium","is_premium":false,"subject_id":6,"id":962},{"question_text":"Inside a sequence body, the proper item handshake is:","option_a":"get_next_item/item_done","option_b":"start_item(req)/finish_item(req)","option_c":"raise/drop objection","option_d":"build/connect","correct_option":"B","explanation":"Sequences use start_item/finish_item around randomization.","difficulty":"hard","is_premium":false,"subject_id":6,"id":963},{"question_text":"uvm_sequence is derived from:","option_a":"uvm_component","option_b":"uvm_object (uvm_sequence_item lineage)","option_c":"uvm_driver","option_d":"uvm_env","correct_option":"B","explanation":"Sequences and items are uvm_object-based (transient), not components.","difficulty":"medium","is_premium":false,"subject_id":6,"id":964},{"question_text":"Which reporting macro logs informational messages with verbosity?","option_a":"`uvm_error","option_b":"`uvm_info","option_c":"`uvm_fatal","option_d":"`uvm_do","correct_option":"B","explanation":"`uvm_info(ID, msg, verbosity) prints info messages.","difficulty":"easy","is_premium":false,"subject_id":6,"id":965},{"question_text":"`uvm_fatal causes:","option_a":"A warning","option_b":"Immediate simulation termination","option_c":"An info message","option_d":"A clock","correct_option":"B","explanation":"`uvm_fatal ends the simulation immediately.","difficulty":"easy","is_premium":false,"subject_id":6,"id":966},{"question_text":"UVM verbosity levels include UVM_LOW, UVM_MEDIUM, UVM_HIGH. A message prints when:","option_a":"Its verbosity \u003e threshold","option_b":"Its verbosity \u003c= the configured threshold","option_c":"Always","option_d":"Never","correct_option":"B","explanation":"Messages at or below the threshold verbosity are displayed.","difficulty":"medium","is_premium":false,"subject_id":6,"id":967},{"question_text":"The field automation macros (`uvm_field_*) provide:","option_a":"Clock generation","option_b":"Automatic copy, compare, print, pack for object fields","option_c":"Reset","option_d":"Coverage","correct_option":"B","explanation":"Field macros auto-implement do_copy/compare/print etc.","difficulty":"medium","is_premium":false,"subject_id":6,"id":968},{"question_text":"Which method deep-copies a uvm_object?","option_a":"clone()/copy()","option_b":"new() only","option_c":"build()","option_d":"connect()","correct_option":"A","explanation":"clone() creates and copies; copy() copies into an existing object.","difficulty":"medium","is_premium":false,"subject_id":6,"id":969},{"question_text":"A uvm_subscriber is typically used for:","option_a":"Driving stimulus","option_b":"Receiving analysis transactions (e.g., for coverage)","option_c":"Clock generation","option_d":"Reset","correct_option":"B","explanation":"uvm_subscriber provides an analysis_export and write() for coverage/checks.","difficulty":"medium","is_premium":false,"subject_id":6,"id":970},{"question_text":"A scoreboard usually connects to monitors via:","option_a":"Virtual interfaces","option_b":"Analysis ports/exports (TLM)","option_c":"Clocking blocks","option_d":"Constraints","correct_option":"B","explanation":"Monitors publish to the scoreboard through analysis connections.","difficulty":"medium","is_premium":false,"subject_id":6,"id":971},{"question_text":"The uvm_test is selected at runtime using:","option_a":"A constraint","option_b":"+UVM_TESTNAME=\u003ctest\u003e plusarg","option_c":"A clock","option_d":"config_db only","correct_option":"B","explanation":"run_test reads +UVM_TESTNAME to pick the test.","difficulty":"medium","is_premium":false,"subject_id":6,"id":972},{"question_text":"Which phase is appropriate to check final pass/fail and print summaries?","option_a":"build_phase","option_b":"report_phase","option_c":"connect_phase","option_d":"run_phase","correct_option":"B","explanation":"report_phase summarizes results at the end.","difficulty":"medium","is_premium":false,"subject_id":6,"id":973},{"question_text":"The 12 run-time sub-phases (reset, configure, main, shutdown, etc.) enable:","option_a":"Faster clocks","option_b":"Fine-grained, synchronized scheduling of stimulus across components","option_c":"Reset only","option_d":"Coverage","correct_option":"B","explanation":"Run-time phases coordinate ordered stimulus (reset-\u003emain-\u003eshutdown).","difficulty":"hard","is_premium":false,"subject_id":6,"id":974},{"question_text":"A virtual sequence is used to:","option_a":"Drive a single interface","option_b":"Coordinate multiple sequencers/agents from one place","option_c":"Generate clocks","option_d":"Reset","correct_option":"B","explanation":"Virtual sequences orchestrate stimulus across several sequencers.","difficulty":"hard","is_premium":false,"subject_id":6,"id":975},{"question_text":"A virtual sequencer typically holds:","option_a":"DUT logic","option_b":"Handles to sub-sequencers for coordination","option_c":"Clock trees","option_d":"Coverage bins","correct_option":"B","explanation":"The virtual sequencer references real sequencers to direct them.","difficulty":"hard","is_premium":false,"subject_id":6,"id":976},{"question_text":"Sequence arbitration on a sequencer can be controlled by:","option_a":"Clock period","option_b":"Priority and arbitration mode (e.g., SEQ_ARB_FIFO)","option_c":"Reset","option_d":"Config_db only","correct_option":"B","explanation":"Sequencers arbitrate among sequences by priority/mode.","difficulty":"hard","is_premium":false,"subject_id":6,"id":977},{"question_text":"p_sequencer is:","option_a":"A clock","option_b":"A typed handle to the sequencer running the sequence","option_c":"A constraint","option_d":"A monitor","correct_option":"B","explanation":"`uvm_declare_p_sequencer gives a typed sequencer handle for access.","difficulty":"hard","is_premium":false,"subject_id":6,"id":978},{"question_text":"uvm_config_db::set is typically called in which phase by the test/env?","option_a":"run_phase","option_b":"build_phase (before children build)","option_c":"report_phase","option_d":"final_phase","correct_option":"B","explanation":"Set config in build_phase so children retrieve it during their build.","difficulty":"medium","is_premium":false,"subject_id":6,"id":979},{"question_text":"If a config_db::get fails to find a value, good practice is to:","option_a":"Ignore silently","option_b":"Issue `uvm_fatal/error to catch misconfiguration","option_c":"Generate a clock","option_d":"Randomize","correct_option":"B","explanation":"Failing loudly on missing required config prevents silent bugs.","difficulty":"medium","is_premium":false,"subject_id":6,"id":980},{"question_text":"The \u0027objection\u0027 drain time is used to:","option_a":"Speed the clock","option_b":"Allow in-flight activity to settle before ending the phase","option_c":"Reset DUT","option_d":"Randomize","correct_option":"B","explanation":"Drain time provides a settling window after objections drop.","difficulty":"hard","is_premium":false,"subject_id":6,"id":981},{"question_text":"A uvm_reg model is used for:","option_a":"Clock generation","option_b":"Abstract register/memory access and checking (RAL)","option_c":"Driving pins directly","option_d":"Coverage only","correct_option":"B","explanation":"The register abstraction layer (RAL) models DUT registers.","difficulty":"hard","is_premium":false,"subject_id":6,"id":982},{"question_text":"In RAL, a frontdoor access goes through:","option_a":"Direct backdoor poke","option_b":"The actual bus protocol via an adapter","option_c":"A clock","option_d":"A constraint","correct_option":"B","explanation":"Frontdoor uses the real bus (adapter+sequencer); backdoor pokes signals directly.","difficulty":"hard","is_premium":false,"subject_id":6,"id":983},{"question_text":"A backdoor register access:","option_a":"Uses the bus protocol","option_b":"Reads/writes DUT storage directly via hierarchical paths (zero time)","option_c":"Needs a sequencer","option_d":"Generates clocks","correct_option":"B","explanation":"Backdoor bypasses the bus, accessing registers via HDL paths.","difficulty":"hard","is_premium":false,"subject_id":6,"id":984},{"question_text":"A reg adapter converts:","option_a":"Clocks to data","option_b":"Between uvm_reg bus operations and protocol sequence items","option_c":"Coverage to bins","option_d":"Reset to clock","correct_option":"B","explanation":"The adapter translates RAL reg2bus/bus2reg with the protocol.","difficulty":"hard","is_premium":false,"subject_id":6,"id":985},{"question_text":"Which class is the base for stimulus data items in UVM?","option_a":"uvm_sequence_item","option_b":"uvm_driver","option_c":"uvm_env","option_d":"uvm_test","correct_option":"A","explanation":"uvm_sequence_item is the base transaction class.","difficulty":"easy","is_premium":false,"subject_id":6,"id":986},{"question_text":"Why use the factory create() instead of new() for components?","option_a":"Faster simulation","option_b":"To allow type/instance overrides without changing source","option_c":"Less memory","option_d":"It generates clocks","correct_option":"B","explanation":"create() routes through the factory so overrides take effect.","difficulty":"medium","is_premium":false,"subject_id":6,"id":987},{"question_text":"An end_of_elaboration_phase is commonly used to:","option_a":"Construct components","option_b":"Print the topology or do final connection checks","option_c":"Drive stimulus","option_d":"Reset","correct_option":"B","explanation":"It runs after connect, good for topology checks/printing.","difficulty":"medium","is_premium":false,"subject_id":6,"id":988},{"question_text":"Which is true about uvm_component hierarchy?","option_a":"Components are transient","option_b":"Components are persistent and form a static tree by parent name","option_c":"They are randomized","option_d":"They have no parent","correct_option":"B","explanation":"Components persist and form a named hierarchy via their parent.","difficulty":"medium","is_premium":false,"subject_id":6,"id":989},{"question_text":"What does get_full_name() return for a component?","option_a":"Its type","option_b":"Its hierarchical instance path","option_c":"A random id","option_d":"The clock","correct_option":"B","explanation":"get_full_name yields the dotted hierarchical path.","difficulty":"easy","is_premium":false,"subject_id":6,"id":990},{"question_text":"The recommended way to start a sequence from a test is:","option_a":"seq.body()","option_b":"seq.start(sequencer)","option_c":"seq.run()","option_d":"seq.connect()","correct_option":"B","explanation":"start(sequencer) properly launches the sequence with phasing hooks.","difficulty":"medium","is_premium":false,"subject_id":6,"id":991},{"question_text":"Raising an objection in a sequence\u0027s pre_body/post_body is used to:","option_a":"Speed clocks","option_b":"Keep the run phase alive while the sequence runs","option_c":"Reset","option_d":"Randomize","correct_option":"B","explanation":"Sequences can raise/drop objections to control phase duration.","difficulty":"hard","is_premium":false,"subject_id":6,"id":992},{"question_text":"Which best describes uvm_event vs SystemVerilog event?","option_a":"Identical","option_b":"uvm_event adds data passing, callbacks, and is reusable across components","option_c":"uvm_event is slower only","option_d":"uvm_event is a clock","correct_option":"B","explanation":"uvm_event extends events with data, waiters, and callbacks.","difficulty":"hard","is_premium":false,"subject_id":6,"id":993},{"question_text":"A uvm_barrier is used to:","option_a":"Reset DUT","option_b":"Synchronize multiple processes to reach a point before proceeding","option_c":"Generate clocks","option_d":"Randomize","correct_option":"B","explanation":"uvm_barrier blocks processes until a threshold count arrives.","difficulty":"hard","is_premium":false,"subject_id":6,"id":994},{"question_text":"The print() method on a uvm_object uses:","option_a":"A clock","option_b":"The configured printer/field automation to display fields","option_c":"Constraints","option_d":"The factory","correct_option":"B","explanation":"print uses field automation and a printer policy.","difficulty":"medium","is_premium":false,"subject_id":6,"id":995},{"question_text":"compare() on two uvm_objects returns:","option_a":"A handle","option_b":"1 if equal, 0 if different (using field automation/comparer)","option_c":"A clock","option_d":"The size","correct_option":"B","explanation":"compare reports equality via the comparer policy.","difficulty":"medium","is_premium":false,"subject_id":6,"id":996},{"question_text":"A uvm_pool/uvm_queue is used to:","option_a":"Drive pins","option_b":"Store collections of objects/handles","option_c":"Generate clocks","option_d":"Reset","correct_option":"B","explanation":"uvm_pool and uvm_queue are container utilities.","difficulty":"medium","is_premium":false,"subject_id":6,"id":997},{"question_text":"Why is the monitor usually independent of the driver?","option_a":"For faster clocks","option_b":"So checking/coverage reflect actual bus activity, not intended stimulus","option_c":"To save memory","option_d":"No reason","correct_option":"B","explanation":"An independent monitor observes real DUT behavior for unbiased checking.","difficulty":"medium","is_premium":false,"subject_id":6,"id":998},{"question_text":"The recommended verbosity for routine progress messages is:","option_a":"UVM_NONE","option_b":"UVM_MEDIUM/UVM_HIGH so they can be filtered","option_c":"UVM_FATAL","option_d":"UVM_ERROR","correct_option":"B","explanation":"Routine logs use higher verbosity so they can be suppressed.","difficulty":"medium","is_premium":false,"subject_id":6,"id":999},{"question_text":"Set verbosity at runtime using:","option_a":"A constraint","option_b":"+UVM_VERBOSITY=\u003clevel\u003e plusarg","option_c":"A clock","option_d":"build_phase only","correct_option":"B","explanation":"+UVM_VERBOSITY controls default message verbosity.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1000},{"question_text":"A sequence\u0027s body() task is where:","option_a":"Components are built","option_b":"Stimulus items are generated and sent","option_c":"Ports are connected","option_d":"Clocks are made","correct_option":"B","explanation":"body() contains the stimulus generation logic.","difficulty":"easy","is_premium":false,"subject_id":6,"id":1001},{"question_text":"uvm_component\u0027s run_phase for a driver typically contains:","option_a":"build of children","option_b":"A forever loop pulling and driving items","option_c":"report printing","option_d":"connect calls","correct_option":"B","explanation":"Drivers loop forever fetching items and driving the bus.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1002},{"question_text":"Which is true about objection mechanism scope?","option_a":"Per component only","option_b":"Phase-wide; the phase ends when the total objection count reaches zero","option_c":"Per clock","option_d":"Per constraint","correct_option":"B","explanation":"The phase ends only when all raised objections are dropped.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1003},{"question_text":"The recommended way to pass a virtual interface from top to env is:","option_a":"Global variable","option_b":"uvm_config_db#(virtual if)::set in the top module","option_c":"A constraint","option_d":"A clock","correct_option":"B","explanation":"Top sets the vif in config_db; components get it.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1004},{"question_text":"A layered sequence approach means:","option_a":"One flat sequence","option_b":"Higher-level sequences translate into lower-level protocol sequences","option_c":"No sequences","option_d":"Only directed tests","correct_option":"B","explanation":"Layering abstracts complex stimulus into protocol-level items.","difficulty":"hard","is_premium":false,"subject_id":6,"id":1005},{"question_text":"Which UVM class provides reporting services (verbosity, ids, actions)?","option_a":"uvm_factory","option_b":"uvm_report_object/uvm_report_handler","option_c":"uvm_sequence","option_d":"uvm_driver","correct_option":"B","explanation":"The report object/handler manage message filtering and actions.","difficulty":"hard","is_premium":false,"subject_id":6,"id":1006},{"question_text":"set_report_severity_action can, for example:","option_a":"Generate clocks","option_b":"Make a UVM_WARNING also count as an error or stop sim","option_c":"Randomize","option_d":"Reset","correct_option":"B","explanation":"You can change actions per severity (e.g., escalate warnings).","difficulty":"hard","is_premium":false,"subject_id":6,"id":1007},{"question_text":"Why is the scoreboard usually passive regarding stimulus?","option_a":"It drives the DUT","option_b":"It only observes and checks, keeping checking independent of driving","option_c":"It generates clocks","option_d":"It randomizes","correct_option":"B","explanation":"Independent checking avoids biasing results with stimulus logic.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1008},{"question_text":"A reusable verification component (VIP) typically packages:","option_a":"Just a clock","option_b":"An agent, sequences, coverage, and config for a protocol","option_c":"Only the DUT","option_d":"Only constraints","correct_option":"B","explanation":"A VIP bundles everything to verify a standard protocol reusably.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1009},{"question_text":"uvm_top is:","option_a":"The DUT","option_b":"The implicit root of the UVM component hierarchy","option_c":"A clock","option_d":"A sequence","correct_option":"B","explanation":"uvm_top (uvm_root) is the singleton root parent of all components.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1010},{"question_text":"Which is the correct order: build, connect, run?","option_a":"run, build, connect","option_b":"build, connect, run","option_c":"connect, build, run","option_d":"build, run, connect","correct_option":"B","explanation":"Components build, then connect, then the run phase executes.","difficulty":"easy","is_premium":false,"subject_id":6,"id":1011},{"question_text":"A monitor publishing to two subscribers requires:","option_a":"Two analysis ports","option_b":"One analysis_port connected to two analysis_exports (fan-out supported)","option_c":"A clock per subscriber","option_d":"Two drivers","correct_option":"B","explanation":"A single analysis_port can broadcast to multiple subscribers.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1012},{"question_text":"What does `uvm_info(get_type_name(), ...) commonly use as the ID?","option_a":"A random number","option_b":"The component/object type name string","option_c":"The clock","option_d":"The seed","correct_option":"B","explanation":"Using the type name as the message ID aids filtering.","difficulty":"easy","is_premium":false,"subject_id":6,"id":1013},{"question_text":"Which mechanism allows changing a sequence item\u0027s class for a specific agent only?","option_a":"Type override globally","option_b":"Instance override targeting that agent\u0027s sequencer path","option_c":"A clock","option_d":"A constraint","correct_option":"B","explanation":"Instance overrides scope the substitution to a path.","difficulty":"hard","is_premium":false,"subject_id":6,"id":1014},{"question_text":"Why call super.build_phase(phase) in an overridden build_phase?","option_a":"It is forbidden","option_b":"To preserve base-class build behavior (e.g., field automation config)","option_c":"To generate clocks","option_d":"To reset","correct_option":"B","explanation":"Calling super ensures base setup runs as intended.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1015},{"question_text":"A heartbeat monitor in UVM detects:","option_a":"Clock frequency","option_b":"Hung/inactive components by tracking expected activity","option_c":"Coverage","option_d":"Reset","correct_option":"B","explanation":"uvm_heartbeat flags lack of expected component activity (deadlock).","difficulty":"hard","is_premium":false,"subject_id":6,"id":1016},{"question_text":"What is the role of the \u0027response\u0027 path (rsp) from driver to sequence?","option_a":"Drive pins","option_b":"Return DUT response/status back to the originating sequence","option_c":"Generate clocks","option_d":"Reset","correct_option":"B","explanation":"Drivers can send responses back via put_response/get_response.","difficulty":"hard","is_premium":false,"subject_id":6,"id":1017},{"question_text":"Why randomize transactions inside the sequence rather than the driver?","option_a":"Faster clocks","option_b":"Keeps the driver protocol-only and stimulus generation in sequences","option_c":"Less memory","option_d":"No reason","correct_option":"B","explanation":"Separating concerns: sequences create stimulus, drivers handle protocol.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1018},{"question_text":"The uvm_phase \u0027objection\u0027 for run_phase is dropped typically:","option_a":"In build_phase","option_b":"After the test\u0027s stimulus completes","option_c":"Never","option_d":"At time zero","correct_option":"B","explanation":"Tests drop objections once stimulus finishes to end run_phase.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1019},{"question_text":"Which best describes UVM\u0027s goal?","option_a":"Speed up RTL","option_b":"Provide a reusable, scalable, interoperable verification framework","option_c":"Replace synthesis","option_d":"Generate clocks","correct_option":"B","explanation":"UVM standardizes reusable, interoperable testbench architecture.","difficulty":"easy","is_premium":false,"subject_id":6,"id":1020},{"question_text":"A common cause of \u0027factory create returns base type\u0027 bug is:","option_a":"Too many clocks","option_b":"Using new() instead of type_id::create(), bypassing overrides","option_c":"Missing reset","option_d":"Wrong verbosity","correct_option":"B","explanation":"new() ignores factory overrides; always use create().","difficulty":"hard","is_premium":false,"subject_id":6,"id":1021},{"question_text":"Which connects a monitor\u0027s analysis_port to a scoreboard\u0027s export?","option_a":"build_phase","option_b":"connect_phase using .connect()","option_c":"run_phase","option_d":"report_phase","correct_option":"B","explanation":"TLM connections are made in connect_phase via connect().","difficulty":"medium","is_premium":false,"subject_id":6,"id":1022},{"question_text":"uvm_sequence_item\u0027s get_transaction_id is used for:","option_a":"Clocking","option_b":"Matching requests with responses","option_c":"Coverage","option_d":"Reset","correct_option":"B","explanation":"Transaction ids correlate requests and their responses.","difficulty":"hard","is_premium":false,"subject_id":6,"id":1023},{"question_text":"Why prefer config objects over many individual config_db entries?","option_a":"Faster clocks","option_b":"Group related settings, improving maintainability and clarity","option_c":"Less simulation time","option_d":"No reason","correct_option":"B","explanation":"A single config object bundles related parameters cleanly.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1024},{"question_text":"The recommended place to retrieve config and build sub-components is:","option_a":"run_phase","option_b":"build_phase","option_c":"report_phase","option_d":"final_phase","correct_option":"B","explanation":"build_phase reads config and constructs children.","difficulty":"easy","is_premium":false,"subject_id":6,"id":1025},{"question_text":"A sequence library is used to:","option_a":"Store clocks","option_b":"Randomly select among a registered set of sequences","option_c":"Reset DUT","option_d":"Hold coverage","correct_option":"B","explanation":"uvm_sequence_library randomly runs registered sequences.","difficulty":"hard","is_premium":false,"subject_id":6,"id":1026},{"question_text":"Which is essential for a self-checking UVM environment?","option_a":"Only a driver","option_b":"A scoreboard/checker plus coverage and a reference model","option_c":"Only clocks","option_d":"Only sequences","correct_option":"B","explanation":"Checking + coverage + reference model make the env self-checking and measurable.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1027},{"question_text":"Calling start_item then randomizing then finish_item ensures:","option_a":"Randomization before arbitration grant is wasted","option_b":"The item is randomized after the sequencer grants, reflecting late config","option_c":"Clocks are generated","option_d":"Reset occurs","correct_option":"B","explanation":"Randomizing between start_item and finish_item uses up-to-date constraints/config after arbitration.","difficulty":"hard","is_premium":false,"subject_id":6,"id":1028},{"question_text":"A UVM heartbeat is used to:","option_a":"Generate the clock","option_b":"Detect a hung simulation when components stop showing activity","option_c":"Reset the DUT","option_d":"Drive stimulus","correct_option":"B","explanation":"uvm_heartbeat monitors component activity to flag stalled/hung tests.","difficulty":"hard","is_premium":false,"subject_id":6,"id":1029},{"question_text":"uvm_event differs from a SystemVerilog event by providing:","option_a":"Nothing extra","option_b":"Persistent triggered state, data passing, and callbacks","option_c":"Only edge detection","option_d":"Clock generation","correct_option":"B","explanation":"uvm_event adds triggered-state, data, and callback features over plain events.","difficulty":"medium","is_premium":false,"subject_id":6,"id":1030},{"question_text":"In Verilog, which data type can hold a value driven by procedural assignment inside an always block?","option_a":"wire","option_b":"reg","option_c":"tri","option_d":"supply0","correct_option":"B","explanation":"reg variables hold values assigned in procedural (always/initial) blocks.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1031},{"question_text":"Which assignment should be used to model combinational logic in an always @(*) block?","option_a":"Non-blocking (\u003c=)","option_b":"Blocking (=)","option_c":"assign","option_d":"force","correct_option":"B","explanation":"Blocking assignments model combinational logic correctly within always @(*).","difficulty":"easy","is_premium":false,"subject_id":2,"id":1032},{"question_text":"Which assignment should be used to model sequential logic in a clocked always block?","option_a":"Blocking (=)","option_b":"Non-blocking (\u003c=)","option_c":"assign","option_d":"deassign","correct_option":"B","explanation":"Non-blocking assignments avoid race conditions in clocked logic.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1033},{"question_text":"What does the $clog2 system function return?","option_a":"Natural log","option_b":"Ceiling of log base 2","option_c":"Floor of log base 10","option_d":"Square root","correct_option":"B","explanation":"$clog2(N) gives the number of bits needed to represent N values.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1034},{"question_text":"How many bits does the literal 4\u0027b1010 represent?","option_a":"2","option_b":"4","option_c":"8","option_d":"10","correct_option":"B","explanation":"The prefix 4\u0027b declares a 4-bit binary literal.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1035},{"question_text":"The continuous assignment \u0027assign y = a \u0026 b;\u0027 drives which type of net?","option_a":"reg","option_b":"wire","option_c":"integer","option_d":"real","correct_option":"B","explanation":"Continuous assignments drive nets (wire).","difficulty":"easy","is_premium":false,"subject_id":2,"id":1036},{"question_text":"Which operator performs a reduction OR on a vector?","option_a":"||","option_b":"|","option_c":"\u0026","option_d":"^~","correct_option":"B","explanation":"A unary | applied to a vector ORs all its bits together.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1037},{"question_text":"What is the result of the concatenation {2{1\u0027b1}}?","option_a":"1\u0027b1","option_b":"2\u0027b11","option_c":"2\u0027b10","option_d":"4\u0027b1111","correct_option":"B","explanation":"Replication {2{1\u0027b1}} produces 2\u0027b11.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1038},{"question_text":"Which construct executes once at time zero for initialization in simulation?","option_a":"always","option_b":"initial","option_c":"assign","option_d":"generate","correct_option":"B","explanation":"initial blocks run once at the start of simulation.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1039},{"question_text":"A latch is inferred in a combinational always block when:","option_a":"All outputs are assigned in every branch","option_b":"An output is not assigned in some branch","option_c":"Non-blocking assignments are used","option_d":"The block is clocked","correct_option":"B","explanation":"Incomplete assignment forces the tool to retain the previous value, inferring a latch.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1040},{"question_text":"Which sensitivity list correctly models a positive-edge clocked flop with async active-low reset?","option_a":"@(clk)","option_b":"@(posedge clk or negedge rst_n)","option_c":"@(*)","option_d":"@(posedge rst_n)","correct_option":"B","explanation":"Both clock edge and async reset edge must be in the list.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1041},{"question_text":"The casez statement treats which value as a don\u0027t-care in case items?","option_a":"0","option_b":"1","option_c":"z (and ?)","option_d":"x only","correct_option":"C","explanation":"casez treats z and ? as don\u0027t-cares.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1042},{"question_text":"What width does the expression a + b have if a and b are both 4 bits and the result is assigned to a 5-bit reg?","option_a":"4 bits, carry lost","option_b":"5 bits, carry preserved","option_c":"8 bits","option_d":"1 bit","correct_option":"B","explanation":"The 5-bit target preserves the carry-out of a 4-bit addition.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1043},{"question_text":"Which statement about blocking assignments in a clocked block across multiple statements is true?","option_a":"They always behave like non-blocking","option_b":"They can create unintended sequential dependencies/races","option_c":"They are illegal in always blocks","option_d":"They infer latches","correct_option":"B","explanation":"Blocking assignments execute in order and can cause races for sequential logic.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1044},{"question_text":"A parameter in Verilog is best described as:","option_a":"A runtime variable","option_b":"A compile-time constant overridable at instantiation","option_c":"A wire","option_d":"A task argument","correct_option":"B","explanation":"Parameters are constants that can be overridden per instance.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1045},{"question_text":"Which keyword overrides a parameter value during module instantiation?","option_a":"defparam or #()","option_b":"assign","option_c":"force","option_d":"localparam","correct_option":"A","explanation":"Parameters are overridden via #() at instantiation or the older defparam.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1046},{"question_text":"localparam differs from parameter in that localparam:","option_a":"Can be overridden at instantiation","option_b":"Cannot be overridden from outside the module","option_c":"Is a net type","option_d":"Is only for testbenches","correct_option":"B","explanation":"localparam values are fixed and cannot be externally overridden.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1047},{"question_text":"A generate-for loop is primarily used to:","option_a":"Run code at simulation time","option_b":"Instantiate repeated hardware structurally at elaboration","option_c":"Replace always blocks","option_d":"Define tasks","correct_option":"B","explanation":"generate loops replicate hardware at elaboration time.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1048},{"question_text":"Which of these is a four-valued logic value in Verilog?","option_a":"Only 0 and 1","option_b":"0, 1, x, z","option_c":"0, 1, 2, 3","option_d":"True and False","correct_option":"B","explanation":"Verilog nets/regs use the 4-state values 0, 1, x, z.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1049},{"question_text":"The value \u0027z\u0027 in Verilog represents:","option_a":"Logic 0","option_b":"High impedance","option_c":"Unknown","option_d":"Don\u0027t care","correct_option":"B","explanation":"z denotes a high-impedance (floating/tri-stated) node.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1050},{"question_text":"The value \u0027x\u0027 in Verilog simulation represents:","option_a":"High impedance","option_b":"An unknown/uninitialized value","option_c":"Logic 1","option_d":"A delay","correct_option":"B","explanation":"x is an unknown or conflicting value.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1051},{"question_text":"A tri-state output is modeled by assigning which value when disabled?","option_a":"0","option_b":"1","option_c":"1\u0027bz","option_d":"1\u0027bx","correct_option":"C","explanation":"Driving 1\u0027bz models a high-impedance (disabled) output.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1052},{"question_text":"Which always block style avoids simulation/synthesis mismatch for combinational logic?","option_a":"always @(a)","option_b":"always @(*)","option_c":"always @(posedge clk)","option_d":"always #5","correct_option":"B","explanation":"always @(*) automatically includes all read signals, preventing missing-signal mismatches.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1053},{"question_text":"What does the bitwise XOR operator ^ produce for inputs 1 and 1?","option_a":"1","option_b":"0","option_c":"x","option_d":"z","correct_option":"B","explanation":"1 XOR 1 = 0.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1054},{"question_text":"A signed arithmetic right shift in Verilog uses which operator?","option_a":"\u003e\u003e","option_b":"\u003e\u003e\u003e","option_c":"\u003c\u003c","option_d":"\u003c\u003c\u003c","correct_option":"B","explanation":"\u003e\u003e\u003e is the arithmetic right shift that preserves the sign bit for signed operands.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1055},{"question_text":"Which directive defines a text macro in Verilog?","option_a":"`include","option_b":"`define","option_c":"`timescale","option_d":"`ifdef","correct_option":"B","explanation":"`define creates a compiler text macro.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1056},{"question_text":"The `timescale 1ns/1ps directive sets:","option_a":"Clock frequency","option_b":"Time unit and time precision","option_c":"Reset polarity","option_d":"Bus width","correct_option":"B","explanation":"It sets the simulation time unit (1ns) and precision (1ps).","difficulty":"easy","is_premium":false,"subject_id":2,"id":1057},{"question_text":"A function in Verilog must:","option_a":"Contain timing controls (#, @)","option_b":"Return a value and execute in zero time","option_c":"Drive nets directly","option_d":"Use non-blocking assignments","correct_option":"B","explanation":"Functions return a value, take zero simulation time, and cannot contain timing controls.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1058},{"question_text":"A task differs from a function in that a task:","option_a":"Cannot have inputs","option_b":"Can contain timing controls and have multiple outputs","option_c":"Must return one value","option_d":"Runs only at elaboration","correct_option":"B","explanation":"Tasks may consume time and have multiple input/output arguments.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1059},{"question_text":"Which is a synthesizable way to describe a ROM?","option_a":"An initial block with $random","option_b":"A case statement mapping address to data","option_c":"A real variable array","option_d":"A force statement","correct_option":"B","explanation":"A case (or constant array) mapping address to data synthesizes to a ROM.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1060},{"question_text":"The full_case/parallel_case synthesis pragmas can cause sim/synth mismatch because:","option_a":"They are ignored by simulation but honored by synthesis","option_b":"They speed up simulation","option_c":"They infer latches","option_d":"They change clock polarity","correct_option":"A","explanation":"Simulators may not honor the pragmas, so behavior can differ from synthesis.","difficulty":"hard","is_premium":false,"subject_id":2,"id":1061},{"question_text":"Which describes a blocking assignment ordering hazard in two always blocks?","option_a":"Determinism is guaranteed","option_b":"Read/write order between blocks is nondeterministic","option_c":"It always synthesizes a latch","option_d":"It is a compile error","correct_option":"B","explanation":"Using blocking assignments shared across always blocks leaves evaluation order undefined.","difficulty":"hard","is_premium":false,"subject_id":2,"id":1062},{"question_text":"What does an unconnected input port default to in synthesis?","option_a":"Logic 1","option_b":"Logic 0 or tool-defined (often high-Z/undriven)","option_c":"The clock","option_d":"Random","correct_option":"B","explanation":"Unconnected inputs are typically undriven; behavior is tool-defined and usually a warning.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1063},{"question_text":"Which loop is synthesizable when its bounds are static constants?","option_a":"while with dynamic condition","option_b":"for loop with constant bounds","option_c":"forever","option_d":"repeat with variable count","correct_option":"B","explanation":"Static-bound for loops unroll into hardware during synthesis.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1064},{"question_text":"The expression (a == 1\u0027bx) in Verilog evaluates to:","option_a":"1 if a is x","option_b":"Always x (unknown) for == comparison","option_c":"Always 0","option_d":"A compile error","correct_option":"B","explanation":"The == operator returns x when any operand bit is x/z; use === for exact match.","difficulty":"hard","is_premium":false,"subject_id":2,"id":1065},{"question_text":"The case-equality operator === differs from == in that ===:","option_a":"Ignores x and z","option_b":"Compares x and z bits exactly, returning 0 or 1","option_c":"Only works on signed values","option_d":"Is non-synthesizable always","correct_option":"B","explanation":"=== matches x and z literally and never returns x.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1066},{"question_text":"A Verilog module port declared \u0027inout\u0027 is used for:","option_a":"Clock only","option_b":"Bidirectional signals such as shared buses","option_c":"Reset only","option_d":"Parameters","correct_option":"B","explanation":"inout ports model bidirectional connections like tri-state buses.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1067},{"question_text":"Which is the correct way to instantiate a module with named port connections?","option_a":".clk(clk), .d(d)","option_b":"clk, d (positional only)","option_c":"assign clk = d","option_d":"@(clk, d)","correct_option":"A","explanation":"Named connection uses .port_name(signal) syntax.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1068},{"question_text":"Why are non-blocking assignments preferred for inter-flop data in pipelines?","option_a":"They are faster to simulate","option_b":"They schedule updates after all RHS are evaluated, preserving flop semantics","option_c":"They infer combinational logic","option_d":"They use less area","correct_option":"B","explanation":"Non-blocking updates occur in the NBA region after all RHS sampling, modeling registers correctly.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1069},{"question_text":"A shift register that shifts MSB-first is described by:","option_a":"q \u003c= {q[6:0], d}","option_b":"q \u003c= {d, q[7:1]}","option_c":"q \u003c= q + 1","option_d":"q \u003c= q ^ d","correct_option":"A","explanation":"Shifting in at the LSB and out at the MSB: {q[6:0], d}.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1070},{"question_text":"What is the purpose of the \u0027default\u0027 branch in a case statement for synthesis?","option_a":"Improves speed","option_b":"Avoids unintended latch inference by covering all cases","option_c":"Adds a clock","option_d":"Reduces area always","correct_option":"B","explanation":"A default ensures every case is assigned, preventing latch inference.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1071},{"question_text":"The reduction operator \u0026a on a 4-bit a returns 1 only when:","option_a":"Any bit is 1","option_b":"All bits are 1","option_c":"No bits are 1","option_d":"An even number of bits are 1","correct_option":"B","explanation":"Reduction AND yields 1 only if every bit is 1.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1072},{"question_text":"Which is true about \u0027wire\u0027 vs \u0027reg\u0027 in Verilog?","option_a":"reg always becomes a flip-flop","option_b":"reg is a variable that may model combinational or sequential logic","option_c":"wire can be assigned in always blocks","option_d":"They are identical","correct_option":"B","explanation":"reg is a storage variable; it becomes a flop only if assigned in clocked logic.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1073},{"question_text":"An integer type in Verilog is typically how many bits?","option_a":"8","option_b":"16","option_c":"32 (signed)","option_d":"64","correct_option":"C","explanation":"Verilog integer is a 32-bit signed variable.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1074},{"question_text":"What does $display do in a testbench?","option_a":"Ends simulation","option_b":"Prints formatted text to the console","option_c":"Forces a net","option_d":"Creates a clock","correct_option":"B","explanation":"$display prints formatted messages during simulation.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1075},{"question_text":"What does $finish do?","option_a":"Pauses simulation","option_b":"Terminates the simulation","option_c":"Prints values","option_d":"Resets the DUT","correct_option":"B","explanation":"$finish ends the simulation run.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1076},{"question_text":"A clock can be generated in a testbench using:","option_a":"assign clk = ~clk;","option_b":"always #5 clk = ~clk;","option_c":"initial clk = 1;","option_d":"wire clk = 0;","correct_option":"B","explanation":"always #5 clk = ~clk toggles the clock every 5 time units.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1077},{"question_text":"Which best avoids a race when sampling DUT outputs in a testbench?","option_a":"Sample at posedge with blocking assignment","option_b":"Sample slightly after the edge or use non-blocking","option_c":"Use force","option_d":"Use $random","correct_option":"B","explanation":"Sampling after the active edge (or via NBA) avoids read/write races with the DUT.","difficulty":"hard","is_premium":false,"subject_id":2,"id":1078},{"question_text":"The Verilog event scheduling region where non-blocking assignment updates occur is the:","option_a":"Active region","option_b":"NBA (non-blocking assign) region","option_c":"Postponed region","option_d":"Inactive region","correct_option":"B","explanation":"Non-blocking RHS are evaluated in active and updated in the NBA region.","difficulty":"hard","is_premium":false,"subject_id":2,"id":1079},{"question_text":"What is the result width of {4\u0027d5, 4\u0027d3}?","option_a":"4 bits","option_b":"8 bits","option_c":"16 bits","option_d":"2 bits","correct_option":"B","explanation":"Concatenation of two 4-bit values yields an 8-bit value.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1080},{"question_text":"Which statement about \u0027assign\u0027 on a reg is correct?","option_a":"Legal and common","option_b":"Illegal; continuous assign targets nets, not reg variables","option_c":"Creates a flop","option_d":"Required for clocks","correct_option":"B","explanation":"Continuous assignment cannot drive a reg; it drives nets.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1081},{"question_text":"An asynchronous reset is characterized by:","option_a":"Acting only on a clock edge","option_b":"Taking effect immediately regardless of the clock","option_c":"Requiring two clocks","option_d":"Being non-synthesizable","correct_option":"B","explanation":"Async reset affects the flop immediately, independent of the clock.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1082},{"question_text":"A synchronous reset differs from async in that it:","option_a":"Is sampled on the active clock edge","option_b":"Ignores the clock","option_c":"Cannot be coded in Verilog","option_d":"Uses negedge only","correct_option":"A","explanation":"Synchronous reset only takes effect at the clock edge.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1083},{"question_text":"Which is a downside of asynchronous reset in deep designs?","option_a":"Higher area always","option_b":"Reset-removal recovery/removal timing must be met to avoid metastability","option_c":"It cannot reset flops","option_d":"It needs no synthesis","correct_option":"B","explanation":"Async reset deassertion must meet recovery/removal timing, often requiring reset synchronizers.","difficulty":"hard","is_premium":false,"subject_id":2,"id":1084},{"question_text":"A 3-to-8 decoder output for input 3\u0027b101 (active-high) asserts which output?","option_a":"out[3]","option_b":"out[5]","option_c":"out[1]","option_d":"out[8]","correct_option":"B","explanation":"Binary 101 = 5, so out[5] is asserted.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1085},{"question_text":"Which describes correct behavior of $monitor?","option_a":"Prints once","option_b":"Prints whenever a listed variable changes","option_c":"Generates a clock","option_d":"Forces a value","correct_option":"B","explanation":"$monitor continuously displays values when any argument changes.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1086},{"question_text":"A Gray-code counter is preferred over binary for asynchronous FIFOs because:","option_a":"It counts faster","option_b":"Only one bit changes per step, easing safe synchronization","option_c":"It uses fewer flops","option_d":"It needs no clock","correct_option":"B","explanation":"Single-bit transitions prevent multi-bit sampling errors across clock domains.","difficulty":"hard","is_premium":false,"subject_id":2,"id":1087},{"question_text":"What does the \u0027#\u0027 symbol introduce in \u0027a = #5 b;\u0027?","option_a":"A parameter","option_b":"An intra-assignment delay","option_c":"A macro","option_d":"A comment","correct_option":"B","explanation":"#5 is a delay; here an intra-assignment delay (non-synthesizable).","difficulty":"medium","is_premium":false,"subject_id":2,"id":1088},{"question_text":"Delays such as #5 in RTL are:","option_a":"Synthesizable to hardware","option_b":"Ignored by synthesis (simulation-only)","option_c":"Converted to flops","option_d":"Used to set clock frequency in silicon","correct_option":"B","explanation":"Synthesis ignores delays; they are for simulation timing only.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1089},{"question_text":"The keyword \u0027genvar\u0027 is used with:","option_a":"always blocks","option_b":"generate-for loops","option_c":"tasks","option_d":"initial blocks","correct_option":"B","explanation":"genvar declares the loop index used in generate-for constructs.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1090},{"question_text":"Which is true about an empty sensitivity list \u0027always @*\u0027 vs \u0027always @(a or b)\u0027?","option_a":"They differ; @* auto-adds all RHS signals","option_b":"They are always identical","option_c":"@* infers a flop","option_d":"@(a or b) is illegal","correct_option":"A","explanation":"@* automatically includes every signal read, reducing missing-signal bugs.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1091},{"question_text":"A registered output adds:","option_a":"Combinational delay only","option_b":"One clock cycle of latency but cleaner timing","option_c":"No latency change","option_d":"Asynchronous behavior","correct_option":"B","explanation":"Registering an output adds a cycle of latency and isolates timing paths.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1092},{"question_text":"What does $signed() do?","option_a":"Truncates to 1 bit","option_b":"Reinterprets an expression as a signed value","option_c":"Generates a clock","option_d":"Adds delay","correct_option":"B","explanation":"$signed casts the operand to signed for arithmetic/comparison.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1093},{"question_text":"A combinational loop in RTL (e.g., assign a = a ^ b;) typically results in:","option_a":"A flip-flop","option_b":"An unstable/oscillating or unsynthesizable construct","option_c":"A clean counter","option_d":"A ROM","correct_option":"B","explanation":"Feedback without a register creates a combinational loop, which is illegal/unstable.","difficulty":"hard","is_premium":false,"subject_id":2,"id":1094},{"question_text":"To register a vector bus on each clock with enable, the code is:","option_a":"if (en) q \u003c= d;","option_b":"assign q = en ? d : q;","option_c":"q = d;","option_d":"always @* q \u003c= d;","correct_option":"A","explanation":"Clocked \u0027if (en) q \u003c= d;\u0027 implements an enabled register.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1095},{"question_text":"Which best models a one-hot to binary encoder for known one-hot inputs?","option_a":"Priority casez","option_b":"A case on the one-hot vector","option_c":"An adder","option_d":"A latch","correct_option":"B","explanation":"A case mapping each one-hot pattern to its index encodes it to binary.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1096},{"question_text":"In simulation, reading a reg before it is assigned yields:","option_a":"0","option_b":"x (unknown)","option_c":"1","option_d":"z","correct_option":"B","explanation":"Uninitialized reg variables start at x in simulation.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1097},{"question_text":"Which avoids width-mismatch truncation warnings?","option_a":"Ignoring widths","option_b":"Matching operand and target bit-widths explicitly","option_c":"Using real types","option_d":"Adding delays","correct_option":"B","explanation":"Explicit, consistent widths prevent unintended truncation/extension.","difficulty":"medium","is_premium":false,"subject_id":2,"id":1098},{"question_text":"A two-stage flip-flop synchronizer is used to:","option_a":"Increase clock speed","option_b":"Reduce the probability of metastability when crossing clock domains","option_c":"Save area","option_d":"Generate resets","correct_option":"B","explanation":"Two cascaded flops give the first stage time to resolve metastability before use.","difficulty":"hard","is_premium":false,"subject_id":2,"id":1099},{"question_text":"What does parameterizing a module with #(parameter WIDTH=8) enable?","option_a":"Runtime resizing","option_b":"Compile-time reuse at different bit widths","option_c":"Asynchronous resets","option_d":"Faster simulation only","correct_option":"B","explanation":"Parameters allow the same RTL to be instantiated at various widths at elaboration.","difficulty":"easy","is_premium":false,"subject_id":2,"id":1100},{"question_text":"A \u0027wire [7:0] bus;\u0027 with multiple continuous drivers of conflicting values resolves to:","option_a":"The last driver wins","option_b":"x on conflicting bits","option_c":"0","option_d":"High-Z always","correct_option":"B","explanation":"Multiple conflicting strong drivers on a wire produce x.","difficulty":"hard","is_premium":false,"subject_id":2,"id":1101}],"tutorials":[{"topic":"Number Systems","title":"Number Systems and Codes","order_index":1,"reading_minutes":8,"content_markdown":"## Number Systems\n\nDigital systems represent information in **binary** (base-2). Key bases:\n\n| Base | Name | Digits |\n|---|---|---|\n| 2 | Binary | 0,1 |\n| 8 | Octal | 0-7 |\n| 10 | Decimal | 0-9 |\n| 16 | Hexadecimal | 0-9, A-F |\n\n### Conversions\n- **Decimal -\u003e Binary:** repeatedly divide by 2, read remainders bottom-up.\n- **Binary -\u003e Decimal:** sum each bit times its positional weight (2^n).\n- **Binary \u003c-\u003e Hex:** group bits in nibbles of 4.\n\n### Signed numbers\n- **Sign-magnitude**, **1\u0027s complement**, and **2\u0027s complement**. Modern hardware uses **2\u0027s complement** because it has a single representation of zero and addition/subtraction use the same adder.\n- 2\u0027s complement of a number = invert all bits + 1.\n\n### Common codes\n- **Gray code:** only one bit changes between consecutive values, used for encoders and CDC FIFO pointers.\n- **BCD:** each decimal digit stored as 4 bits.\n- **ASCII:** character encoding.\n\n\u003e Tip: In interviews you are often asked to convert and to explain why 2\u0027s complement is preferred.","subject_id":1,"id":1},{"topic":"Combinational Logic","title":"Logic Gates, Boolean Algebra and Karnaugh Maps","order_index":2,"reading_minutes":10,"content_markdown":"## Logic Gates\n\nBasic gates: **AND, OR, NOT, NAND, NOR, XOR, XNOR**. NAND and NOR are *universal* — any function can be built from them alone.\n\n## Boolean Algebra\nKey laws used to simplify expressions:\n- Identity: A+0=A, A*1=A\n- Null: A+1=1, A*0=0\n- Idempotent: A+A=A, A*A=A\n- Complement: A+A\u0027=1, A*A\u0027=0\n- **De Morgan:** (A*B)\u0027 = A\u0027+B\u0027 and (A+B)\u0027 = A\u0027*B\u0027\n\n## Canonical Forms\n- **SOP** (sum of products) from the 1-minterms.\n- **POS** (product of sums) from the 0-maxterms.\n\n## Karnaugh Maps (K-map)\nA K-map is a visual method to minimize Boolean functions:\n1. Place outputs in a grid arranged in Gray-code order.\n2. Group adjacent 1s in powers of two (1,2,4,8...).\n3. Larger groups = fewer literals.\n4. Use **don\u0027t-cares (X)** to make bigger groups.\n\n### Example\nF(A,B,C) = sum of minterms (1,3,5,7) simplifies to F = C.\n\n\u003e Combinational logic has **no memory**: output depends only on current inputs.","subject_id":1,"id":2},{"topic":"Sequential Logic","title":"Latches, Flip-Flops and Finite State Machines","order_index":3,"reading_minutes":10,"content_markdown":"## Sequential Logic\n\nUnlike combinational logic, sequential logic has **memory** — output depends on inputs *and* stored state.\n\n### Latches vs Flip-Flops\n- **Latch:** level-sensitive (transparent while enable is active).\n- **Flip-flop:** edge-triggered (samples on clock edge). Preferred for synchronous design.\n- Types: SR, D, JK, T. The **D flip-flop** is the workhorse of RTL.\n\n### Timing\n- **Setup time:** data stable *before* the clock edge.\n- **Hold time:** data stable *after* the clock edge.\n- Violations cause **metastability**.\n\n### Finite State Machines (FSM)\n- **Moore:** outputs depend only on state.\n- **Mealy:** outputs depend on state + inputs (fewer states, but outputs can glitch).\n\nDesign steps: state diagram -\u003e state table -\u003e state encoding (binary / one-hot) -\u003e next-state and output logic.\n\n### Counters \u0026 Registers\n- Ripple vs synchronous counters.\n- Shift registers (SISO, SIPO, PISO, PIPO).\n\n\u003e Interview favourite: design a sequence detector (e.g., detect 1011) as a Moore/Mealy FSM.","subject_id":1,"id":3},{"topic":"Verilog Basics","title":"Verilog Fundamentals: Modules, Data Types and Operators","order_index":1,"reading_minutes":9,"content_markdown":"## What is Verilog?\nVerilog is a **Hardware Description Language (HDL)** used to model digital circuits for simulation and synthesis.\n\n## Modules\nThe basic building block:\n```verilog\nmodule adder(input  [3:0] a, b,\n             output [4:0] sum);\n  assign sum = a + b;\nendmodule\n```\n\n## Data Types\n- **wire / net:** continuous connection, driven by `assign` or a port.\n- **reg:** holds a value, assigned inside `always`/`initial`.\n- **integer, parameter, localparam**.\n- 4-state values: `0, 1, x (unknown), z (high-impedance)`.\n\n## Operators\n- Arithmetic (+ - * / %), bitwise (\u0026 | ^ ~), logical (\u0026\u0026 || !), relational, shift (\u003c\u003c \u003e\u003e), concatenation `{a,b}`, replication `{4{1\u0027b0}}`, ternary `sel ? a : b`.\n\n## Modeling Styles\n1. **Gate-level** (primitives).\n2. **Dataflow** (`assign`).\n3. **Behavioral** (`always` blocks).\n\n\u003e Rule of thumb: use `assign`/blocking (=) for combinational, non-blocking (\u003c=) for sequential.","subject_id":2,"id":4},{"topic":"Procedural Blocks","title":"always Blocks, Blocking vs Non-Blocking and Synthesis","order_index":2,"reading_minutes":9,"content_markdown":"## Procedural Blocks\n\n### Combinational\n```verilog\nalways @(*) begin\n  y = a \u0026 b;      // blocking \u0027=\u0027\nend\n```\nUse a full sensitivity list `@(*)` and assign every output on every path to avoid **inferred latches**.\n\n### Sequential\n```verilog\nalways @(posedge clk or negedge rst_n) begin\n  if (!rst_n) q \u003c= 1\u0027b0;   // non-blocking \u0027\u003c=\u0027\n  else        q \u003c= d;\nend\n```\n\n## Blocking (=) vs Non-Blocking (\u003c=)\n- **Blocking** executes immediately, in order -\u003e model combinational logic.\n- **Non-blocking** schedules the update for end of the time step -\u003e model registers, avoids race conditions between flops.\n\n## Common synthesis pitfalls\n- Incomplete `if`/`case` -\u003e latch.\n- Mixing blocking and non-blocking in one block.\n- Using `#delays` for synthesis (ignored by synthesizer).\n\n\u003e Golden rule (Cummings): separate combinational and sequential logic and never mix = and \u003c= in the same always block.","subject_id":2,"id":5},{"topic":"Timing Fundamentals","title":"Setup, Hold, Slack and the Timing Path","order_index":1,"reading_minutes":10,"content_markdown":"## Static Timing Analysis (STA)\nSTA verifies timing **without simulation vectors** by analyzing every path between sequential elements across all conditions.\n\n## A Timing Path\nlaunch flop -\u003e combinational logic -\u003e capture flop. Characterized by:\n- **Tcq:** clock-to-Q delay of launch flop.\n- **Tlogic:** combinational delay.\n- **Tsetup / Thold:** capture flop requirements.\n- **Tskew:** clock arrival difference.\n\n## Setup check (max delay)\n```\nTclk + Tskew \u003e= Tcq + Tlogic + Tsetup\n```\nFix setup violations by reducing logic depth, upsizing cells, or relaxing the clock.\n\n## Hold check (min delay)\n```\nTcq + Tlogic \u003e= Thold + Tskew\n```\nFix hold violations by **adding delay** (buffers) on short paths.\n\n## Slack\n`Slack = Required time - Arrival time`. Positive slack = met; negative = violation (the WNS, worst negative slack, is reported).\n\n\u003e Setup is a frequency problem (slow clock helps); hold is a fixed problem (slowing the clock does NOT help).","subject_id":3,"id":6},{"topic":"Constraints","title":"Clocks, False Paths and Multicycle Paths (SDC)","order_index":2,"reading_minutes":8,"content_markdown":"## SDC Constraints\nSTA is driven by an **SDC** (Synopsys Design Constraints) file.\n\n### Defining clocks\n```tcl\ncreate_clock -name clk -period 2.0 [get_ports clk]\n```\n\n### Input/Output delays\n`set_input_delay` and `set_output_delay` model the timing of logic outside the block relative to the clock.\n\n### Exceptions\n- **False path** (`set_false_path`): a path that is never functionally active (e.g., across asynchronous domains or static config) — excluded from analysis.\n- **Multicycle path** (`set_multicycle_path`): data legitimately has more than one clock cycle to propagate.\n\n### Clock attributes\n- **Latency** (insertion delay), **uncertainty** (jitter + margin), **skew**.\n- **OCV / derating** models on-chip process variation between launch and capture paths.\n\n\u003e Misapplied false/multicycle paths are a top cause of silicon timing bugs — use them deliberately.","subject_id":3,"id":7},{"topic":"SystemVerilog for Design","title":"SystemVerilog RTL Enhancements over Verilog","order_index":1,"reading_minutes":9,"content_markdown":"## Why SystemVerilog for RTL?\nSystemVerilog adds productivity and safety features on top of Verilog.\n\n### Better types\n- `logic`: 4-state type that replaces both `wire` and `reg` in most places (single-driver).\n- `bit`: 2-state.\n- `enum`, `struct`, `union`, `typedef` for readable, structured code.\n\n### Procedural blocks with intent\n- `always_comb` — combinational, auto sensitivity, flags latches.\n- `always_ff @(posedge clk)` — sequential, tool checks it infers flops.\n- `always_latch` — explicit latch.\n\n```systemverilog\nalways_ff @(posedge clk or negedge rst_n)\n  if (!rst_n) count \u003c= \u00270;\n  else        count \u003c= count + 1\u0027b1;\n```\n\n### Other features\n- `unique`/`priority` case for parallel/priority intent.\n- Packed vs unpacked arrays.\n- Interfaces to bundle related signals.\n\n\u003e Using `always_comb` / `always_ff` makes design intent explicit and lets the tool catch mistakes early.","subject_id":4,"id":8},{"topic":"Verification Basics","title":"Testbench Architecture and Constrained Random","order_index":1,"reading_minutes":10,"content_markdown":"## Functional Verification\nGoal: prove the design does what the spec says, across as many scenarios as possible.\n\n## Layered Testbench\n- **Generator** creates stimulus (transactions).\n- **Driver** converts transactions to pin wiggles.\n- **Monitor** observes the DUT and reconstructs transactions.\n- **Scoreboard** compares DUT output against a reference model.\n- **Coverage** measures what has been exercised.\n\n## Constrained-Random Verification (CRV)\nInstead of hand-writing every vector, randomize within legal constraints:\n```systemverilog\nclass packet;\n  rand bit [7:0] len;\n  constraint c_len { len inside {[1:64]}; }\nendclass\n```\n\n## OOP features used\n- Classes, inheritance, virtual methods, `randomize()`, mailboxes, semaphores.\n\n## Coverage\n- **Code coverage** (line, toggle, FSM) — automatic.\n- **Functional coverage** (covergroups) — written to match the spec.\n\n\u003e A passing test with no checking proves nothing — always have a scoreboard or assertions.","subject_id":5,"id":9},{"topic":"UVM Basics","title":"UVM Components, Phases and the Factory","order_index":1,"reading_minutes":11,"content_markdown":"## What is UVM?\nThe **Universal Verification Methodology** is a standardized SystemVerilog class library for building reusable testbenches.\n\n## Core Components\n- **uvm_sequence_item** — a transaction.\n- **uvm_sequence / sequencer** — generates and arbitrates transactions.\n- **uvm_driver** — drives the DUT interface.\n- **uvm_monitor** — samples the interface.\n- **uvm_agent** — bundles driver + monitor + sequencer.\n- **uvm_scoreboard**, **uvm_env**, **uvm_test**.\n\n## Phases\nRun in order: `build` -\u003e `connect` -\u003e `end_of_elaboration` -\u003e `start_of_simulation` -\u003e `run` (with reset/configure/main/shutdown sub-phases) -\u003e `extract` -\u003e `check` -\u003e `report`. `run_phase` is the only **time-consuming** phase (a task).\n\n## The Factory\nRegister with `uvm_component_utils` / `uvm_object_utils`, then use **overrides** to swap implementations without editing the testbench:\n```systemverilog\nset_type_override_by_type(base::get_type(), derived::get_type());\n```\n\n## TLM \u0026 config_db\n- **TLM ports/exports/analysis ports** connect components.\n- **uvm_config_db** passes configuration/virtual interfaces down the hierarchy.\n\n\u003e The factory + config_db are what make UVM testbenches reusable and configurable.","subject_id":6,"id":10},{"topic":"Assertions","title":"SystemVerilog Assertions: Immediate and Concurrent","order_index":1,"reading_minutes":9,"content_markdown":"## Why Assertions?\nAssertions are executable specifications that continuously check design behavior and pinpoint *where* and *when* a bug occurs.\n\n## Two kinds\n- **Immediate** (`assert`): inside procedural code, evaluated like an if.\n- **Concurrent** (`assert property`): clocked, checks temporal behavior.\n\n## Building blocks\n- **Boolean expressions** over signals.\n- **Sequences** describe events over time using delay `##n` and repetition `[*n]`, `[-\u003en]`.\n- **Properties** combine sequences with implication.\n\n### Implication operators\n```systemverilog\n// overlapped: consequent checked on the same cycle\nassert property (@(posedge clk) req |-\u003e gnt);\n// non-overlapped: consequent checked next cycle\nassert property (@(posedge clk) req |=\u003e gnt);\n```\n\n## Useful constructs\n- `$rose`, `$fell`, `$stable`, `$past(sig, n)`.\n- `throughout`, `within`, `disable iff (rst)` to ignore during reset.\n- `cover property` to confirm a scenario actually occurred.\n\n\u003e Assertions act as always-on checks across the entire regression — invaluable for protocol checking.","subject_id":7,"id":11},{"topic":"PD Flow","title":"The Physical Design Flow: Floorplan to Signoff","order_index":1,"reading_minutes":11,"content_markdown":"## Physical Design (PD)\nPD turns a synthesized gate-level netlist into a manufacturable layout (GDSII).\n\n## Major steps\n1. **Floorplanning** — die/core area, macro placement, IO ring, power planning.\n2. **Power planning** — rings, straps, and a power mesh to limit IR drop.\n3. **Placement** — standard cells placed to optimize timing, congestion, and area.\n4. **CTS (Clock Tree Synthesis)** — build a balanced clock tree to minimize skew.\n5. **Routing** — global + detailed routing of all nets.\n6. **Signoff** — STA, DRC, LVS, EM/IR, antenna checks.\n\n## Key concerns\n- **Congestion** — too many wires in a region; fixed by spreading cells.\n- **IR drop** — supply voltage sag; fixed by strengthening the power grid.\n- **Electromigration (EM)** — metal wear from high current density.\n- **Crosstalk** — coupling between adjacent nets; reduce with spacing/shielding.\n\n## Verification\n- **DRC:** geometric foundry rules.\n- **LVS:** layout connectivity matches schematic.\n\n\u003e A good floorplan is the single biggest factor in whether the rest of the flow converges.","subject_id":8,"id":12},{"topic":"AMBA","title":"AMBA Bus Family: AXI, AHB and APB","order_index":1,"reading_minutes":10,"content_markdown":"## AMBA\nARM\u0027s **AMBA** defines on-chip interconnect protocols. The three you must know:\n\n| Protocol | Use | Key trait |\n|---|---|---|\n| **APB** | Low-speed peripherals | Simple, 2-phase, non-pipelined |\n| **AHB** | High-performance bus | Pipelined address/data |\n| **AXI** | High-bandwidth SoC | 5 channels, bursts, outstanding |\n\n## AXI essentials\nFive independent channels: **AW** (write addr), **W** (write data), **B** (write resp), **AR** (read addr), **R** (read data). Each uses a **VALID/READY** handshake — data transfers only when *both* are high.\n\nKey features:\n- **Bursts:** INCR, WRAP, FIXED; `AxLEN = beats - 1`.\n- **Outstanding \u0026 out-of-order** via transaction **IDs**.\n- A burst must not cross a **4KB boundary**.\n- Rule: VALID must not depend on READY (prevents deadlock).\n\n## APB\nSetup phase -\u003e access phase (`PSEL`, then `PENABLE`), with optional `PREADY` wait states and `PSLVERR`.\n\n\u003e Pick the lightest protocol that meets bandwidth: APB for registers, AXI for DMA/memory.","subject_id":9,"id":13},{"topic":"Combinational Logic","title":"Combinational Building Blocks: Mux, Decoder, Encoder, Comparator","order_index":4,"reading_minutes":9,"content_markdown":"## Multiplexer (MUX)\nA MUX selects **one of many inputs** onto a single output using select lines. A 2^n-to-1 MUX needs **n** select lines.\n- 2:1 MUX: `Y = S\u0027 .I0 + S.I1`.\n- A MUX is a **universal** building block: any Boolean function of n variables can be built with a 2^n:1 MUX.\n\n## Demultiplexer (DEMUX)\nReverse of a MUX: routes one input to **one of 2^n outputs**. Same structure as a decoder with an enable acting as data.\n\n## Decoder\nConverts an n-bit code into **one active line out of 2^n**. A 3:8 decoder activates exactly one of 8 outputs. With an enable, decoders build memory address selection and can implement SOP functions directly.\n\n## Encoder\nOpposite of a decoder: 2^n inputs -\u003e n-bit code. A **priority encoder** resolves the case when multiple inputs are active by encoding the highest-priority one (fixes the ambiguity of a plain encoder).\n\n## Comparator\nProduces A\u003eB, A=B, A\u003cB. Equality uses XNOR per bit ANDed together; magnitude compares from the MSB down.\n\n\u003e Interview tip: be ready to implement a full adder or any 3-variable function using only an 8:1 MUX.","subject_id":1,"id":14},{"topic":"Arithmetic Circuits","title":"Adders, Subtractors and Multipliers","order_index":5,"reading_minutes":9,"content_markdown":"## Half and Full Adder\n- **Half adder:** `Sum = A xor B`, `Carry = A.B`.\n- **Full adder:** adds A, B and carry-in. `Sum = A xor B xor Cin`, `Cout = A.B + Cin.(A xor B)`.\n\n## Ripple-Carry Adder (RCA)\nChain full adders; carry ripples from LSB to MSB. Simple but **slow** — delay grows linearly with width (worst-case carry propagation).\n\n## Carry-Lookahead Adder (CLA)\nSpeeds up by computing carries in parallel using **generate** `Gi = Ai.Bi` and **propagate** `Pi = Ai xor Bi`:\n`C(i+1) = Gi + Pi.Ci`. Trades area for much lower delay — the classic speed/area tradeoff.\n\n## Subtraction\nUse **2\u0027s complement**: `A - B = A + (~B) + 1`. The same adder hardware does add and subtract by inverting B and setting carry-in = 1.\n\n## Multipliers\n- **Array multiplier:** grid of AND gates + adders, regular but large.\n- **Booth\u0027s algorithm:** reduces partial products for signed multiplication.\n\n\u003e Adders are the most-asked combinational interview topic — know the full-adder equations cold.","subject_id":1,"id":15},{"topic":"Sequential Logic","title":"Flip-Flops in Depth: Types, Conversions and Timing","order_index":6,"reading_minutes":9,"content_markdown":"## Flip-Flop Types\n| FF | Behavior |\n|---|---|\n| **D** | Q follows D on the clock edge (the RTL workhorse) |\n| **T** | Toggles Q when T=1 (good for counters) |\n| **JK** | Like SR but J=K=1 toggles (no invalid state) |\n| **SR** | Set/Reset; S=R=1 is invalid |\n\n## Characteristic Equations\n- D: `Q+ = D`\n- T: `Q+ = T xor Q`\n- JK: `Q+ = J.Q\u0027 + K\u0027.Q`\n\n## FF Conversions\nTo convert one FF to another: write the required FF\u0027s excitation table, then design logic to drive the available FF\u0027s inputs (e.g., JK -\u003e D uses `D = J.Q\u0027 + K\u0027.Q`).\n\n## Timing Parameters\n- **Setup (Tsu):** data must be stable *before* the edge.\n- **Hold (Th):** data must be stable *after* the edge.\n- **Tcq:** clock-to-Q propagation delay.\n- Violating setup/hold can drive the FF into **metastability**.\n\n\u003e A latch is level-sensitive (transparent); a flip-flop is edge-triggered. Synchronous design uses edge-triggered flops.","subject_id":1,"id":16},{"topic":"Sequential Logic","title":"Counters and Shift Registers","order_index":7,"reading_minutes":8,"content_markdown":"## Counters\n- **Asynchronous (ripple) counter:** each FF clocked by the previous output. Simple but accumulates delay and can glitch.\n- **Synchronous counter:** all FFs share the clock; faster and glitch-free. Preferred in design.\n- **Mod-N counter:** counts 0..N-1 then wraps; decode the terminal count to reset.\n\n## Special Counters\n- **Ring counter:** circulates a single 1 through n FFs -\u003e n valid states.\n- **Johnson (twisted-ring) counter:** feeds back the inverted last output -\u003e 2n states.\n\n## Shift Registers\nMove data one bit per clock. Configurations: **SISO, SIPO, PISO, PIPO**.\nUses: serial\u003c-\u003eparallel conversion, delay lines, and **LFSRs** (linear-feedback shift registers) for pseudo-random sequences and CRC.\n\n\u003e Know why a synchronous counter is preferred over a ripple counter: no cumulative clock-to-Q skew between stages.","subject_id":1,"id":17},{"topic":"Memories","title":"Memories, PLDs and Logic Hazards","order_index":8,"reading_minutes":8,"content_markdown":"## Memory Types\n- **SRAM:** fast, 6 transistors/bit, no refresh, used for caches.\n- **DRAM:** dense, 1T+1C/bit, needs periodic **refresh**, used for main memory.\n- **ROM/PROM/EPROM/EEPROM/Flash:** non-volatile, varying re-programmability.\n\n## Programmable Logic Devices\n- **PROM:** fixed AND, programmable OR.\n- **PAL:** programmable AND, fixed OR.\n- **PLA:** programmable AND and OR (most flexible).\n- **FPGA:** LUT-based, fully reconfigurable.\n\n## Hazards\nUnwanted transient glitches in combinational logic from unequal path delays.\n- **Static-1 hazard:** output should stay 1 but glitches to 0.\n- **Static-0 hazard:** should stay 0 but glitches to 1.\n- **Fix:** add redundant (consensus) terms / overlapping K-map groups.\n\n\u003e Hazards matter for asynchronous logic and level-sensitive inputs; synchronous registers re-sample and usually mask them.","subject_id":1,"id":18},{"topic":"Verification","title":"Writing Testbenches and Simulating Verilog","order_index":3,"reading_minutes":9,"content_markdown":"## Testbench Basics\nA testbench instantiates the **DUT** (design under test), generates a clock and reset, drives stimulus, and checks outputs. It has **no ports**.\n\n```verilog\nmodule tb;\n  reg clk = 0, rst_n = 0, d;\n  wire q;\n  dff u_dff(.clk(clk), .rst_n(rst_n), .d(d), .q(q));\n  always #5 clk = ~clk;        // 100 MHz clock\n  initial begin\n    rst_n = 0; d = 0; #12 rst_n = 1;\n    d = 1; @(posedge clk);\n    if (q !== 1\u0027b1) $error(\"q mismatch\");\n    #20 $finish;\n  end\nendmodule\n```\n\n## Useful Constructs\n- **Stimulus:** `initial`, `#delay`, `@(posedge clk)`, `repeat`, `forever`.\n- **Display:** `$display`, `$monitor`, `$strobe`.\n- **Control:** `$finish`, `$stop`, `$time`.\n- **Files/waves:** `$dumpfile`, `$dumpvars` for VCD waveform dumping.\n\n## Self-Checking\nCompare DUT output to an expected value and print pass/fail automatically — never eyeball waveforms for a regression.\n\n\u003e Use `!==`/`===` (4-state compare) in testbenches so X and Z mismatches are caught.","subject_id":2,"id":19},{"topic":"RTL Design","title":"Coding Finite State Machines in Verilog","order_index":4,"reading_minutes":9,"content_markdown":"## FSM Coding Styles\nThe recommended style separates **state register**, **next-state logic**, and **output logic**.\n\n```verilog\nmodule fsm(input clk, rst_n, in, output reg out);\n  localparam S0=2\u0027d0, S1=2\u0027d1, S2=2\u0027d2;\n  reg [1:0] state, next;\n  // 1) state register (sequential)\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) state \u003c= S0; else state \u003c= next;\n  // 2) next-state logic (combinational)\n  always @(*) begin\n    next = state;\n    case (state)\n      S0: if (in) next = S1;\n      S1: if (in) next = S2;\n      S2: next = S0;\n    endcase\n  end\n  // 3) output logic\n  always @(*) out = (state == S2);\nendmodule\n```\n\n## Moore vs Mealy\n- **Moore:** output depends only on state (registered, glitch-free, one cycle later).\n- **Mealy:** output depends on state + input (fewer states, can glitch).\n\n## Encoding\n- **Binary:** fewest flops.\n- **One-hot:** one FF per state, fast next-state decode — common in FPGAs.\n\n\u003e Always assign `next = state;` as a default to avoid accidental latches.","subject_id":2,"id":20},{"topic":"Advanced","title":"Tasks, Functions, Parameters and Generate","order_index":5,"reading_minutes":8,"content_markdown":"## Functions vs Tasks\n- **Function:** returns one value, executes in **zero** simulation time, no timing controls, at least one input. Use for combinational computation.\n- **Task:** can have multiple inputs/outputs, **can consume time** (`#`, `@`), used for stimulus/procedures.\n\n## Parameters\nMake modules reusable:\n```verilog\nmodule reg_file #(parameter WIDTH=8, DEPTH=16) ( ... );\n```\nOverride at instantiation: `reg_file #(.WIDTH(32)) u_rf(...);`. Use **localparam** for constants you do not want overridden (e.g., FSM state encodings).\n\n## Generate\nBuild repetitive or conditional hardware at elaboration:\n```verilog\ngenvar i;\ngenerate\n  for (i = 0; i \u003c WIDTH; i = i + 1) begin : bit_slice\n    full_adder fa(.a(a[i]), .b(b[i]), .cin(c[i]), .sum(s[i]), .cout(c[i+1]));\n  end\nendgenerate\n```\n\n\u003e `generate-for` needs a `genvar`; it unrolls structural hardware, unlike a procedural for-loop.","subject_id":2,"id":21},{"topic":"Advanced Timing","title":"Clock Domain Crossing (CDC) and Metastability","order_index":3,"reading_minutes":9,"content_markdown":"## Metastability\nWhen a flip-flop samples data that violates setup/hold, its output can hang between 0 and 1 for an unbounded time before resolving. This is **metastability**, characterized by **MTBF** (mean time between failures).\n\n## Clock Domain Crossing\nWhenever a signal moves between **asynchronous clocks**, you must synchronize it or risk metastability propagating.\n\n### Single-bit CDC\nUse a **2-flop synchronizer** (sometimes 3) in the destination clock domain to let metastability settle.\n\n### Multi-bit CDC\nNever sync a multi-bit bus bit-by-bit (bits can resolve in different cycles). Instead:\n- **Gray code** the value (only one bit changes at a time) — used for FIFO pointers.\n- **Handshake** (req/ack) to safely pass a stable bus.\n- **Async FIFO** for streaming data between clocks.\n\n## STA treatment\nCDC paths are declared **false paths** (`set_false_path`) or analyzed with special constraints, because they are not meant to meet single-cycle timing.\n\n\u003e CDC bugs are intermittent and brutal to debug — design synchronizers correctly the first time.","subject_id":3,"id":22},{"topic":"Clocking","title":"Clock Tree: Skew, Jitter, Latency and OCV","order_index":4,"reading_minutes":8,"content_markdown":"## Clock Latency\nTime for the clock to travel from its source to a flop.\n- **Source latency:** source to clock-definition point.\n- **Network latency:** definition point to the flop\u0027s clock pin.\n\n## Skew\nDifference in clock arrival time between two flops.\n- **Positive skew** (capture clock later) helps **setup**, hurts **hold**.\n- **Negative skew** does the opposite.\n\n## Jitter\nCycle-to-cycle variation in clock edges (from the PLL/supply noise). Modeled as **clock uncertainty**, which eats into the available period.\n\n## Setup/Hold with Uncertainty\n- Setup: `Tclk - Tuncertainty \u003e= Tcq + Tlogic + Tsu - Tskew`\n- Hold: `Tcq + Tlogic \u003e= Th + Tskew + Tuncertainty`\n\n## OCV / Derating\n**On-Chip Variation** derates launch vs capture paths to account for process/voltage/temperature differences across the die. Advanced flows use **AOCV/POCV**.\n\n\u003e Hold violations cannot be fixed by slowing the clock — they are independent of the period.","subject_id":3,"id":23},{"topic":"SV Types","title":"SystemVerilog Data Types: logic, enum, struct, arrays","order_index":2,"reading_minutes":9,"content_markdown":"## 2-State vs 4-State\n- **4-state:** `logic`, `integer` (values 0,1,X,Z).\n- **2-state:** `bit`, `int`, `byte`, `longint` (only 0,1 — faster sim, no X).\n\n## logic\n`logic` replaces both `wire` and `reg` for single-driver signals. Use a `wire` only when you truly need multiple drivers.\n\n## enum\nReadable state/encoding names with type safety:\n```systemverilog\ntypedef enum logic [1:0] {IDLE, RUN, DONE} state_t;\nstate_t state;\n```\n\n## struct and union\nGroup related fields:\n```systemverilog\ntypedef struct packed { logic [7:0] addr; logic [31:0] data; } bus_t;\n```\n**packed** structs map to a contiguous bit-vector (synthesizable); **unpacked** are for testbenches.\n\n## Arrays\n- **Packed** `[7:0]` — a vector.\n- **Unpacked** `mem [0:255]` — memory-like.\n- **Dynamic** `int q[]`, **associative** `int a[string]`, **queues** `int q[$]` — verification only.\n\n\u003e Prefer `int`/`bit` for loop counters and 2-state TB code; use `logic` for RTL signals.","subject_id":4,"id":24},{"topic":"SV Design","title":"Interfaces, Modports and Clocking","order_index":3,"reading_minutes":8,"content_markdown":"## Interfaces\nAn **interface** bundles related signals into one named connection, cutting port-list clutter and wiring mistakes.\n```systemverilog\ninterface axi_if(input logic clk);\n  logic        valid, ready;\n  logic [31:0] data;\n  modport master (output valid, data, input ready);\n  modport slave  (input  valid, data, output ready);\nendinterface\n```\n\n## Modports\nDefine signal **directions** per role (master/slave), so each side only sees the correct in/out view.\n\n## Why interfaces help\n- One connection instead of dozens of ports.\n- Add a signal in one place.\n- Carry **tasks/functions** and assertions with the bus.\n- In verification, the testbench drives the DUT through a **virtual interface**.\n\n\u003e Interfaces are heavily used to connect UVM testbenches to the DUT via `uvm_config_db`-passed virtual interfaces.","subject_id":4,"id":25},{"topic":"SV Design","title":"Parameterized RTL and FSMs in SystemVerilog","order_index":4,"reading_minutes":8,"content_markdown":"## always_ff / always_comb\nSystemVerilog makes intent explicit and lets the tool catch mistakes:\n```systemverilog\ntypedef enum logic [1:0] {IDLE, LOAD, RUN} st_t;\nst_t state, next;\nalways_ff @(posedge clk or negedge rst_n)\n  if (!rst_n) state \u003c= IDLE; else state \u003c= next;\nalways_comb begin\n  next = state;\n  unique case (state)\n    IDLE: if (start) next = LOAD;\n    LOAD: next = RUN;\n    RUN:  if (done)  next = IDLE;\n  endcase\nend\n```\n`always_comb` flags accidental latches; `unique`/`priority` express case intent.\n\n## Parameterization\n```systemverilog\nmodule fifo #(parameter int WIDTH=8, DEPTH=16) ( ... );\n  localparam int AW = $clog2(DEPTH);\nendmodule\n```\n`$clog2` sizes address widths automatically.\n\n\u003e Use enums for states so waveforms show `RUN` instead of `2\u0027b10`.","subject_id":4,"id":26},{"topic":"CRV","title":"Randomization and Constraints","order_index":2,"reading_minutes":9,"content_markdown":"## Constrained-Random Verification\nRandomize within legal bounds to hit corner cases you would never write by hand.\n```systemverilog\nclass packet;\n  rand bit [7:0] len;\n  rand bit [3:0] kind;\n  constraint c_len  { len inside {[1:64]}; }\n  constraint c_dist { kind dist {0:=50, [1:3]:/50}; }\nendclass\n\npacket p = new();\nif (!p.randomize()) $error(\"randomize failed\");\n```\n\n## Constraint Features\n- `inside`, `dist` (weighted), implication `-\u003e`, `if/else`.\n- **Soft constraints** can be overridden by tests.\n- `randomize() with { ... }` adds inline constraints per call.\n- `rand` (full random) vs `randc` (random-cyclic, no repeat until all values used).\n\n## Control\n- `pre_randomize()` / `post_randomize()` hooks.\n- `rand_mode()` and `constraint_mode()` enable/disable at runtime.\n\n\u003e Always check the return value of `randomize()` — a failed solve silently leaves stale values otherwise.","subject_id":5,"id":27},{"topic":"Coverage","title":"Functional Coverage with Covergroups","order_index":3,"reading_minutes":8,"content_markdown":"## Why Functional Coverage\nCode coverage proves lines toggled; **functional coverage** proves the *intended scenarios* from the spec actually occurred.\n\n## Covergroups and Coverpoints\n```systemverilog\ncovergroup cg @(posedge clk);\n  cp_kind : coverpoint pkt.kind { bins rd = {0}; bins wr = {1}; }\n  cp_len  : coverpoint pkt.len  { bins small = {[1:16]}; bins big = {[17:64]}; }\n  cross cp_kind, cp_len;   // did we see every kind x length combo?\nendgroup\ncg cov = new();\n```\n\n## Key Ideas\n- **bins** group values; auto-bins exist but explicit bins are clearer.\n- **cross** coverage checks combinations of coverpoints.\n- **ignore_bins / illegal_bins** exclude or flag values.\n- Coverage **closure** = reaching your coverage goal; drives when to stop testing.\n\n\u003e A passing test with low functional coverage means you simply have not exercised the design enough.","subject_id":5,"id":28},{"topic":"Concurrency","title":"Processes, Mailboxes, Semaphores and Events","order_index":4,"reading_minutes":8,"content_markdown":"## Spawning Processes\n```systemverilog\nfork\n  drive_a();\n  drive_b();\njoin       // join (all), join_any, join_none\n```\n`wait fork` waits for spawned children; `disable fork` kills them.\n\n## Mailbox\nA thread-safe FIFO to pass transactions between processes (e.g., generator -\u003e driver):\n```systemverilog\nmailbox #(packet) mbx = new();\nmbx.put(p);      // blocking\nmbx.get(p);      // blocking until available\n```\n\n## Semaphore\nControls access to a shared resource with keys:\n```systemverilog\nsemaphore sem = new(1);\nsem.get(1); /* critical section */ sem.put(1);\n```\n\n## Events\n`event e;` with `-\u003e e;` to trigger and `@e` / `wait(e.triggered)` to sync.\n\n\u003e Mailboxes decouple producers and consumers — the backbone of layered testbenches.","subject_id":5,"id":29},{"topic":"Stimulus","title":"UVM Sequences, Sequence Items and the Sequencer","order_index":2,"reading_minutes":9,"content_markdown":"## The Stimulus Path\n**Sequence** generates **sequence_items** (transactions) and sends them through the **sequencer** to the **driver**.\n\n```systemverilog\nclass my_item extends uvm_sequence_item;\n  rand bit [31:0] addr, data;\n  `uvm_object_utils(my_item)\nendclass\n\nclass my_seq extends uvm_sequence #(my_item);\n  `uvm_object_utils(my_seq)\n  task body();\n    my_item it = my_item::type_id::create(\"it\");\n    start_item(it);\n    assert(it.randomize());\n    finish_item(it);\n  endtask\nendclass\n```\n\n## Driver Handshake\nThe driver pulls items with `seq_item_port.get_next_item(req)` and signals completion with `item_done()`.\n\n## Running a Sequence\n`seq.start(env.agent.sequencer);` from the test\u0027s run_phase.\n\n\u003e `start_item`/`finish_item` implement the sequencer\u003c-\u003edriver handshake; the driver controls the pace via `get_next_item`/`item_done`.","subject_id":6,"id":30},{"topic":"Infrastructure","title":"config_db, TLM Ports and Analysis","order_index":3,"reading_minutes":8,"content_markdown":"## uvm_config_db\nPasses configuration and **virtual interfaces** down the hierarchy without hard wiring:\n```systemverilog\n// top\nuvm_config_db#(virtual my_if)::set(null, \"*\", \"vif\", vif);\n// driver build_phase\nif (!uvm_config_db#(virtual my_if)::get(this, \"\", \"vif\", vif))\n  `uvm_fatal(\"NOVIF\", \"vif not set\")\n```\n\n## TLM Communication\nComponents talk through **transaction-level** ports, not pins:\n- `uvm_put_port` / `uvm_get_port` for point-to-point.\n- **analysis ports** (`uvm_analysis_port`) broadcast to many subscribers (monitor -\u003e scoreboard + coverage).\n\n```systemverilog\nuvm_analysis_port #(my_item) ap;\nap.write(item);   // monitor publishes\n```\n\n\u003e The monitor\u0027s analysis port feeding the scoreboard and the coverage collector is the canonical UVM connection.","subject_id":6,"id":31},{"topic":"Flow Control","title":"UVM Phases, Objections and Reporting","order_index":4,"reading_minutes":8,"content_markdown":"## Phase Order\n`build` (top-down) -\u003e `connect` (bottom-up) -\u003e `end_of_elaboration` -\u003e `start_of_simulation` -\u003e **`run`** -\u003e `extract` -\u003e `check` -\u003e `report` -\u003e `final`.\nOnly `run_phase` consumes time (it is a `task`); the rest are functions.\n\n## Run Sub-phases\n`reset -\u003e configure -\u003e main -\u003e shutdown` (with pre/post variants) let components align timing.\n\n## Objections\nKeep the test alive while work is pending:\n```systemverilog\nphase.raise_objection(this);\n// ... drive sequences ...\nphase.drop_objection(this);\n```\nThe run phase ends when **all** objections are dropped.\n\n## Reporting\n`` `uvm_info(ID, msg, UVM_MEDIUM) ``, `` `uvm_warning ``, `` `uvm_error ``, `` `uvm_fatal ``. Verbosity is filterable with `+UVM_VERBOSITY`.\n\n\u003e Forgetting to drop an objection makes a test hang until timeout — a very common UVM mistake.","subject_id":6,"id":32},{"topic":"Temporal Logic","title":"SVA Sequences, Operators and Implication","order_index":2,"reading_minutes":8,"content_markdown":"## Sequences\nDescribe events over time:\n- `##n` — delay n cycles; `##[1:3]` — range.\n- `[*n]` — consecutive repetition; `[-\u003en]` — goto (non-consecutive) repetition; `[=n]` — non-consecutive.\n\n```systemverilog\nsequence s_req_gnt; req ##[1:3] gnt; endsequence\n```\n\n## Implication\n- **Overlapped** `|-\u003e` : consequent checked on the **same** cycle the antecedent matches.\n- **Non-overlapped** `|=\u003e` : consequent checked on the **next** cycle.\n\n```systemverilog\nassert property (@(posedge clk) req |=\u003e gnt);\n```\n\n## Combining\n`and`, `or`, `intersect`, `within`, `throughout` build complex temporal checks.\n\n\u003e Use `cover property` to confirm a scenario actually happens, not just that it never fails vacuously.","subject_id":7,"id":33},{"topic":"Practical SVA","title":"Sampled Functions and disable iff","order_index":3,"reading_minutes":7,"content_markdown":"## Sampled-Value Functions\nEvaluate signals relative to the clock:\n- `$rose(sig)` — 0 -\u003e 1 this cycle.\n- `$fell(sig)` — 1 -\u003e 0 this cycle.\n- `$stable(sig)` — unchanged.\n- `$past(sig, n)` — value n cycles ago.\n\n```systemverilog\nassert property (@(posedge clk) $rose(start) |=\u003e busy);\n```\n\n## Reset Handling\nIgnore checks during reset with **disable iff**:\n```systemverilog\nassert property (@(posedge clk) disable iff (!rst_n)\n  req |-\u003e ##[1:5] ack);\n```\n\n## Immediate vs Concurrent\n- **Immediate** (`assert(expr);`) inside procedural code, no clock.\n- **Concurrent** (`assert property`) clocked, temporal.\n\n\u003e `disable iff` prevents false failures while the DUT is held in reset — almost every real property needs it.","subject_id":7,"id":34},{"topic":"Frontend PD","title":"Floorplanning and Power Planning","order_index":2,"reading_minutes":9,"content_markdown":"## Floorplanning\nThe most impactful PD step. Decisions:\n- **Die/core size** and **aspect ratio**.\n- **Utilization** (cell area / core area) — too high causes congestion.\n- **Macro placement:** push memories to edges/corners, keep channels for routing, align with dataflow.\n- **IO/pad ring** and pin placement.\n- **Halos/blockages** around macros to keep std cells away.\n\n## Power Planning\nBuild a robust supply network to limit **IR drop**:\n- **Rings** around core/macros, **straps** across, and a **mesh** on upper metals.\n- Connect down to standard-cell **rails** (VDD/VSS).\n- Add **decap** cells to handle switching current and **tie cells** for constants.\n\n## Why it matters\n- Bad macro placement -\u003e congestion + timing failure later.\n- Weak grid -\u003e IR drop -\u003e cells slow down -\u003e timing/functional failures.\n\n\u003e \u0027A good floorplan is 80% of PD success\u0027 — most downstream problems trace back to floorplan/power planning.","subject_id":8,"id":35},{"topic":"Backend PD","title":"Placement, CTS and Routing","order_index":3,"reading_minutes":9,"content_markdown":"## Placement\nLegalize standard cells into rows optimizing **timing, congestion, and area**.\n- **Global placement** -\u003e **detailed/legalization**.\n- Add buffers for long nets; run placement-based optimization to fix early timing.\n\n## Clock Tree Synthesis (CTS)\nBuild a balanced clock distribution **after placement**:\n- Goals: minimize **skew** and **insertion delay**, control jitter.\n- Structures: **H-tree**, clustered trees, or a **clock mesh** for low skew.\n- Insert clock buffers/inverters; the clock was ideal before CTS, real after.\n\n## Routing\n- **Global routing** plans regions; **detailed routing** lays exact metal/vias.\n- Resolve **DRC** violations, **crosstalk**, and **antenna** effects.\n- Post-route optimization closes remaining timing.\n\n\u003e Order matters: place -\u003e CTS -\u003e route. Building the clock tree before placement is meaningless.","subject_id":8,"id":36},{"topic":"Signoff","title":"Signoff: STA, DRC, LVS, IR and EM","order_index":4,"reading_minutes":8,"content_markdown":"## Timing Signoff\nMulti-corner multi-mode (**MCMM**) STA across PVT corners with **OCV** derating; close **setup** and **hold** at every corner.\n\n## Physical Verification\n- **DRC:** geometric foundry rules (spacing, width, density).\n- **LVS:** layout devices/connectivity match the schematic netlist.\n- **Antenna:** limit charge on long metal during fabrication (add diodes/jogs).\n\n## Electrical Signoff\n- **IR drop:** static + dynamic supply-voltage sag; fix by strengthening the grid/decap.\n- **EM (Electromigration):** limit current density so metal does not wear out over time.\n- **Crosstalk/noise:** spacing, shielding, buffering.\n\n## Final Output\nClean **GDSII** plus signoff reports — ready for **tape-out**.\n\n\u003e Signoff = proving the chip will be manufacturable, functional, and reliable across all conditions.","subject_id":8,"id":37},{"topic":"AXI","title":"AXI Deep Dive: Channels, Handshake and Bursts","order_index":2,"reading_minutes":9,"content_markdown":"## Five Channels\n| Channel | Direction | Purpose |\n|---|---|---|\n| **AW** | master-\u003eslave | write address |\n| **W**  | master-\u003eslave | write data (+`WSTRB`, `WLAST`) |\n| **B**  | slave-\u003emaster | write response |\n| **AR** | master-\u003eslave | read address |\n| **R**  | slave-\u003emaster | read data (+`RRESP`, `RLAST`) |\n\nRead and write paths are fully **independent**.\n\n## VALID/READY Handshake\nTransfer happens only when **both** VALID and READY are high on a clock edge.\n- The source asserts VALID when data is ready and **must not** wait for READY to assert VALID (prevents deadlock).\n- Either side may stall by deasserting its signal.\n\n## Bursts\n- Types: **INCR** (incrementing), **WRAP** (cache lines), **FIXED** (same address, e.g. FIFO).\n- `AxLEN = beats - 1`; `AxSIZE` = bytes per beat.\n- A burst **must not cross a 4KB boundary**.\n\n## Ordering\nTransactions with the same **ID** stay ordered; different IDs may complete out of order, enabling **outstanding** transactions.\n\n\u003e `WSTRB` byte-strobes enable partial writes; `xLAST` marks the final beat of a burst.","subject_id":9,"id":38},{"topic":"AHB/APB","title":"AHB and APB in Detail","order_index":3,"reading_minutes":8,"content_markdown":"## AHB (Advanced High-performance Bus)\nA **pipelined**, single-clock bus with overlapping **address** and **data** phases.\n- Signals: `HADDR`, `HWRITE`, `HSIZE`, `HBURST`, `HTRANS` (IDLE/BUSY/NONSEQ/SEQ), `HWDATA`, `HRDATA`, `HREADY`, `HRESP`.\n- A slave inserts wait states by holding `HREADY` low.\n- One active master at a time via the **arbiter**; an address decoder selects the slave.\n\n## APB (Advanced Peripheral Bus)\nThe simplest AMBA bus for **low-bandwidth registers/peripherals**.\n- **Two phases:** SETUP (`PSEL=1`, `PENABLE=0`) then ACCESS (`PENABLE=1`).\n- Signals: `PADDR`, `PWRITE`, `PWDATA`, `PRDATA`, `PREADY` (wait states), `PSLVERR` (error).\n- Non-pipelined, no bursts — minimal logic, easy to integrate.\n\n## Choosing\n- **APB:** control/status registers.\n- **AHB:** moderate-bandwidth, pipelined transfers.\n- **AXI:** high-bandwidth, bursts, outstanding/out-of-order.\n\n\u003e Many SoCs bridge AXI -\u003e APB so a fast interconnect can reach slow peripheral registers.","subject_id":9,"id":39}],"notes":[{"topic":"Combinational Logic","title":"K-Map Reduction Workflow","content_markdown":"1. Mark minterms/maxterms.\n2. Form largest power-of-two groups.\n3. Prefer overlap only when it reduces literals.\n4. Validate with truth table spot checks.","subject_id":1,"id":1},{"topic":"Sequential Logic","title":"FSM Design Checklist","content_markdown":"Define states, transitions, reset behavior, and output coding style (Moore/Mealy). Verify unreachable states and default branches.","subject_id":1,"id":2},{"topic":"Synthesizable RTL","title":"Combinational vs Sequential Blocks","content_markdown":"Use `always @(*)` or `always_comb` for combinational logic and `always @(posedge clk ...)` / `always_ff` for sequential logic.","subject_id":2,"id":3},{"topic":"Coding Hygiene","title":"Latch Avoidance","content_markdown":"Initialize outputs and cover all branches in combinational blocks to avoid unintended latch inference.","subject_id":2,"id":4},{"topic":"Timing Paths","title":"Setup/Hold Intuition","content_markdown":"Setup is max-delay check; hold is min-delay check. Fix setup with faster data path or slower capture clock, fix hold with delay insertion.","subject_id":3,"id":5},{"topic":"Constraints","title":"Essential SDC Commands","content_markdown":"Start with `create_clock`, input/output delays, false/multicycle paths, and clock uncertainty before deep optimization.","subject_id":3,"id":6},{"topic":"Language Constructs","title":"always_ff/always_comb Best Practices","content_markdown":"These constructs add tool checks for intent and reduce class of simulation-synthesis mismatches.","subject_id":4,"id":7},{"topic":"Data Types","title":"Packed vs Unpacked","content_markdown":"Packed is bit-level contiguous representation; unpacked is array-of-elements representation.","subject_id":4,"id":8},{"topic":"TB Architecture","title":"Generator-Driver-Monitor-Scoreboard","content_markdown":"This decomposition gives separation of concerns and easier debug when coverage or checks fail.","subject_id":5,"id":9},{"topic":"Randomization","title":"Constraint Debugging","content_markdown":"When randomization fails, reduce constraint set, inspect conflicting ranges, and incrementally restore intent.","subject_id":5,"id":10},{"topic":"UVM Components","title":"Agent Anatomy","content_markdown":"An active agent includes sequencer, driver, and monitor. Passive agent typically contains only monitor.","subject_id":6,"id":11},{"topic":"Phasing","title":"Run Phase Objections","content_markdown":"Raise objection before traffic starts and drop when done to control test end cleanly.","subject_id":6,"id":12},{"topic":"Assertion Basics","title":"Implication Operators","content_markdown":"Use `|-\u003e` for overlapped and `|=\u003e` for non-overlapped implication depending on cycle alignment intent.","subject_id":7,"id":13},{"topic":"Protocol Checking","title":"Handshake Assertions","content_markdown":"Convert spec timing to temporal properties with clear reset disable and bounded delays where possible.","subject_id":7,"id":14},{"topic":"Flow Stages","title":"From Floorplan to Route","content_markdown":"Typical order: floorplan -\u003e power plan -\u003e placement -\u003e CTS -\u003e route -\u003e signoff checks and ECO.","subject_id":8,"id":15},{"topic":"Congestion","title":"Early Congestion Prevention","content_markdown":"Use macro spacing, blockages, balanced utilization targets, and buffering strategy to avoid late-stage congestion crises.","subject_id":8,"id":16},{"topic":"AXI","title":"Independent Channels","content_markdown":"AW, W, B, AR, R channels are independently handshaked, enabling pipelining and higher throughput.","subject_id":9,"id":17},{"topic":"APB/AHB","title":"When to Use APB vs AHB","content_markdown":"APB for simple low-bandwidth peripherals; AHB for higher-performance memory-mapped backbone segments.","subject_id":9,"id":18},{"topic":"Interview Strategy","title":"How to Answer Design Debug Questions","content_markdown":"Structure answers as: symptom -\u003e hypothesis -\u003e experiment -\u003e observation -\u003e fix -\u003e prevention.","subject_id":10,"id":19},{"topic":"Company Practice","title":"Performance and Power Tradeoff Cases","content_markdown":"Prepare examples on clock gating, DVFS assumptions, and protocol bottleneck debugging with measurable metrics.","subject_id":11,"id":20},{"topic":"Company Practice","title":"High-Throughput Pipeline Discussion","content_markdown":"Expect questions on hazard control, occupancy, buffering, and latency-hiding patterns in compute-heavy pipelines.","subject_id":12,"id":21}],"coding":[{"title":"Parameterized Counter","prompt":"Create an always_ff based up-counter with parameter WIDTH and synchronous clear.","constraints":"Use logic type and parameterized width.","expected_output":"Count increments on each clock and clears when clr is high.","starter_code":"module up_counter #(parameter int WIDTH=8) (input logic clk, input logic rst_n, input logic clr, output logic [WIDTH-1:0] cnt);\n  // TODO\nendmodule","solution_code":"module up_counter #(parameter int WIDTH=8) (input logic clk, input logic rst_n, input logic clr, output logic [WIDTH-1:0] cnt);\n  always_ff @(posedge clk or negedge rst_n) begin\n    if (!rst_n) cnt \u003c= \u00270;\n    else if (clr) cnt \u003c= \u00270;\n    else cnt \u003c= cnt + 1\u0027b1;\n  end\nendmodule","subject_id":4,"id":1},{"title":"Priority Encoder","prompt":"Implement a 4-to-2 priority encoder with valid signal using always_comb.","constraints":"Highest bit has highest priority.","expected_output":"enc outputs highest asserted input index and valid indicates any active input.","starter_code":"module prio_enc4(input logic [3:0] req, output logic [1:0] enc, output logic valid);\n  // TODO\nendmodule","solution_code":"module prio_enc4(input logic [3:0] req, output logic [1:0] enc, output logic valid);\n  always_comb begin\n    valid = 1\u0027b1;\n    unique casez (req)\n      4\u0027b1???: enc = 2\u0027d3;\n      4\u0027b01??: enc = 2\u0027d2;\n      4\u0027b001?: enc = 2\u0027d1;\n      4\u0027b0001: enc = 2\u0027d0;\n      default: begin valid = 1\u0027b0; enc = 2\u0027d0; end\n    endcase\n  end\nendmodule","subject_id":4,"id":2},{"title":"Mailbox Producer-Consumer TB","prompt":"Create basic testbench classes to send integer transactions through mailbox.","constraints":"Use one producer and one consumer class.","expected_output":"Consumer prints values generated by producer.","starter_code":"class producer;\n  // TODO\nendclass\nclass consumer;\n  // TODO\nendclass","solution_code":"class producer;\n  mailbox mbx;\n  function new(mailbox mbx); this.mbx = mbx; endfunction\n  task run(); repeat (5) mbx.put($urandom_range(0,15)); endtask\nendclass\nclass consumer;\n  mailbox mbx; int v;\n  function new(mailbox mbx); this.mbx = mbx; endfunction\n  task run(); repeat (5) begin mbx.get(v); $display(\"rx=%0d\", v); end endtask\nendclass","subject_id":5,"id":3},{"title":"Constrained Random Packet","prompt":"Define packet class with constrained length and payload values.","constraints":"len in [1:8], payload size equals len.","expected_output":"Randomized packet instances satisfy constraints.","starter_code":"class packet;\n  // TODO\nendclass","solution_code":"class packet;\n  rand int len;\n  rand byte payload[];\n  constraint c_len { len inside {[1:8]}; }\n  constraint c_size { payload.size() == len; }\nendclass","subject_id":5,"id":4},{"title":"Minimal UVM Sequence","prompt":"Write a UVM sequence that sends 10 transactions.","constraints":"Use `uvm_do_with or start_item/finish_item flow.","expected_output":"Sequence creates and randomizes 10 items.","starter_code":"class basic_seq extends uvm_sequence #(my_item);\n  // TODO\nendclass","solution_code":"class basic_seq extends uvm_sequence #(my_item);\n  `uvm_object_utils(basic_seq)\n  function new(string name=\"basic_seq\"); super.new(name); endfunction\n  task body();\n    repeat (10) begin\n      my_item it = my_item::type_id::create(\"it\");\n      start_item(it);\n      assert(it.randomize());\n      finish_item(it);\n    end\n  endtask\nendclass","subject_id":6,"id":5},{"title":"Simple Scoreboard Compare","prompt":"Build a scoreboard method that compares expected and observed queue elements.","constraints":"Print mismatch index and value.","expected_output":"Scoreboard reports pass/fail with mismatch detail.","starter_code":"class my_scoreboard extends uvm_component;\n  // TODO\nendclass","solution_code":"class my_scoreboard extends uvm_component;\n  int exp_q[$], act_q[$];\n  function void compare_all();\n    int n = (exp_q.size() \u003c act_q.size()) ? exp_q.size() : act_q.size();\n    for (int i=0; i\u003cn; i++) begin\n      if (exp_q[i] != act_q[i]) `uvm_error(\"SB\", $sformatf(\"Mismatch @%0d exp=%0d act=%0d\", i, exp_q[i], act_q[i]))\n    end\n  endfunction\nendclass","subject_id":6,"id":6},{"title":"Handshake Assertion","prompt":"Write assertion: once req rises, gnt must come within 3 cycles.","constraints":"Use disable iff reset.","expected_output":"Assertion fails if grant latency exceeds 3 cycles.","starter_code":"// TODO: assert property","solution_code":"property req_to_gnt; @(posedge clk) disable iff(!rst_n) req |-\u003e ##[1:3] gnt; endproperty\nassert property(req_to_gnt);","subject_id":7,"id":7},{"title":"No X on Output Assertion","prompt":"Ensure output bus y has no unknown value after reset deassertion.","constraints":"Use $isunknown in assertion.","expected_output":"Assertion flags any X/Z on y during active operation.","starter_code":"// TODO: assert property","solution_code":"property no_x_y; @(posedge clk) disable iff(!rst_n) !$isunknown(y); endproperty\nassert property(no_x_y);","subject_id":7,"id":8},{"title":"APB Write Task","prompt":"Create an APB master task for single write transfer.","constraints":"Follow setup and enable phases.","expected_output":"PSEL asserted in setup, PENABLE in next cycle, then deassert.","starter_code":"task apb_write(input logic [31:0] addr, input logic [31:0] data);\n  // TODO\nendtask","solution_code":"task apb_write(input logic [31:0] addr, input logic [31:0] data);\n  @(posedge pclk); psel\u003c=1; penable\u003c=0; pwrite\u003c=1; paddr\u003c=addr; pwdata\u003c=data;\n  @(posedge pclk); penable\u003c=1;\n  wait (pready);\n  @(posedge pclk); psel\u003c=0; penable\u003c=0;\nendtask","subject_id":9,"id":9},{"title":"AXI Ready/Valid Monitor","prompt":"Write monitor logic to count successful AXI write address handshakes.","constraints":"Increment counter on AWVALID \u0026\u0026 AWREADY.","expected_output":"Counter tracks accepted AW channel beats.","starter_code":"always @(posedge aclk) begin\n  // TODO\nend","solution_code":"always @(posedge aclk or negedge aresetn) begin\n  if (!aresetn) aw_hs_cnt \u003c= 0;\n  else if (awvalid \u0026\u0026 awready) aw_hs_cnt \u003c= aw_hs_cnt + 1;\nend","subject_id":9,"id":10},{"title":"CDC Synchronizer RTL","prompt":"Implement a 2-flop synchronizer module for single-bit control signal.","constraints":"Destination clock domain only.","expected_output":"s_out is metastability-hardened version of s_in.","starter_code":"module sync2(input wire clk_d, input wire rst_n, input wire s_in, output reg s_out);\n  // TODO\nendmodule","solution_code":"module sync2(input wire clk_d, input wire rst_n, input wire s_in, output reg s_out);\n  reg ff1;\n  always @(posedge clk_d or negedge rst_n) begin\n    if (!rst_n) begin ff1 \u003c= 1\u0027b0; s_out \u003c= 1\u0027b0; end\n    else begin ff1 \u003c= s_in; s_out \u003c= ff1; end\n  end\nendmodule","subject_id":10,"id":11},{"title":"Rate Limiter FSM","prompt":"Design FSM that allows one request grant every N cycles.","constraints":"Parameterized cooldown counter.","expected_output":"Grant pulses only when cooldown expires and request is high.","starter_code":"module rate_limiter #(parameter int N=4) (...);\n  // TODO\nendmodule","solution_code":"module rate_limiter #(parameter int N=4) (input wire clk, input wire rst_n, input wire req, output reg gnt);\n  reg [$clog2(N+1)-1:0] cd;\n  always @(posedge clk or negedge rst_n) begin\n    if (!rst_n) begin cd \u003c= 0; gnt \u003c= 0; end\n    else if (cd != 0) begin cd \u003c= cd - 1\u0027b1; gnt \u003c= 0; end\n    else if (req) begin gnt \u003c= 1; cd \u003c= N-1; end\n    else gnt \u003c= 0;\n  end\nendmodule","subject_id":11,"id":12},{"title":"Pipeline Valid Propagation","prompt":"Implement 3-stage valid pipeline for datapath synchronization.","constraints":"Use sequential logic with reset.","expected_output":"valid_out asserts three cycles after valid_in.","starter_code":"module vpipe3(input wire clk, input wire rst_n, input wire valid_in, output reg valid_out);\n  // TODO\nendmodule","solution_code":"module vpipe3(input wire clk, input wire rst_n, input wire valid_in, output reg valid_out);\n  reg v1, v2;\n  always @(posedge clk or negedge rst_n) begin\n    if (!rst_n) begin v1\u003c=0; v2\u003c=0; valid_out\u003c=0; end\n    else begin v1\u003c=valid_in; v2\u003c=v1; valid_out\u003c=v2; end\n  end\nendmodule","subject_id":12,"id":13},{"title":"Basic Gates: AND, OR, NOT","prompt":"Build a module that outputs the AND, OR and NOT of two 1-bit inputs a and b.","constraints":"Module name: top. Inputs: a, b. Outputs: y_and, y_or, y_not (NOT of a).","expected_output":"y_and = a \u0026 b; y_or = a | b; y_not = ~a.","starter_code":"module top(input a, input b, output y_and, output y_or, output y_not);\n  // Write code here\nendmodule","solution_code":"module top(input a, input b, output y_and, output y_or, output y_not);\n  assign y_and = a \u0026 b;\n  assign y_or  = a | b;\n  assign y_not = ~a;\nendmodule","subject_id":1,"id":14},{"title":"Universal Gates: NAND, NOR, XOR, XNOR","prompt":"Produce NAND, NOR, XOR and XNOR of two 1-bit inputs.","constraints":"Module name: top. Inputs: a, b. Outputs: y_nand, y_nor, y_xor, y_xnor.","expected_output":"Standard truth tables for each gate.","starter_code":"module top(input a, input b, output y_nand, output y_nor, output y_xor, output y_xnor);\n  // Write code here\nendmodule","solution_code":"module top(input a, input b, output y_nand, output y_nor, output y_xor, output y_xnor);\n  assign y_nand = ~(a \u0026 b);\n  assign y_nor  = ~(a | b);\n  assign y_xor  = a ^ b;\n  assign y_xnor = ~(a ^ b);\nendmodule","subject_id":1,"id":15},{"title":"2:1 Multiplexer","prompt":"Select input i0 when sel=0 and i1 when sel=1.","constraints":"Module name: top. Inputs: i0, i1, sel. Output: y.","expected_output":"y = sel ? i1 : i0.","starter_code":"module top(input i0, input i1, input sel, output y);\n  // Write code here\nendmodule","solution_code":"module top(input i0, input i1, input sel, output y);\n  assign y = sel ? i1 : i0;\nendmodule","subject_id":1,"id":16},{"title":"4:1 Multiplexer","prompt":"Route one of four 1-bit inputs to the output based on a 2-bit select.","constraints":"Module name: top. Inputs: i[3:0], sel[1:0]. Output: y.","expected_output":"y = i[sel].","starter_code":"module top(input [3:0] i, input [1:0] sel, output reg y);\n  // Write code here\nendmodule","solution_code":"module top(input [3:0] i, input [1:0] sel, output reg y);\n  always @(*) begin\n    case (sel)\n      2\u0027d0: y = i[0];\n      2\u0027d1: y = i[1];\n      2\u0027d2: y = i[2];\n      default: y = i[3];\n    endcase\n  end\nendmodule","subject_id":1,"id":17},{"title":"2-to-4 Decoder with Enable","prompt":"Activate exactly one of four outputs based on a 2-bit input when enable is high; all zero when disabled.","constraints":"Module name: top. Inputs: a[1:0], en. Output: y[3:0] (one-hot).","expected_output":"en=1 -\u003e y = 1\u003c\u003ca; en=0 -\u003e y = 0000.","starter_code":"module top(input [1:0] a, input en, output reg [3:0] y);\n  // Write code here\nendmodule","solution_code":"module top(input [1:0] a, input en, output reg [3:0] y);\n  always @(*) begin\n    y = 4\u0027b0000;\n    if (en) y[a] = 1\u0027b1;\n  end\nendmodule","subject_id":1,"id":18},{"title":"4-to-2 Priority Encoder","prompt":"Encode the index of the highest set bit; assert valid if any input is high.","constraints":"Module name: top. Input: in[3:0]. Outputs: y[1:0], valid. Bit 3 has highest priority.","expected_output":"valid=0 when in=0; else y = index of MSB that is 1.","starter_code":"module top(input [3:0] in, output reg [1:0] y, output reg valid);\n  // Write code here\nendmodule","solution_code":"module top(input [3:0] in, output reg [1:0] y, output reg valid);\n  always @(*) begin\n    valid = 1\u0027b1;\n    casez (in)\n      4\u0027b1???: y = 2\u0027d3;\n      4\u0027b01??: y = 2\u0027d2;\n      4\u0027b001?: y = 2\u0027d1;\n      4\u0027b0001: y = 2\u0027d0;\n      default: begin y = 2\u0027d0; valid = 1\u0027b0; end\n    endcase\n  end\nendmodule","subject_id":1,"id":19},{"title":"Half Adder","prompt":"Add two 1-bit numbers producing sum and carry.","constraints":"Module name: top. Inputs: a, b. Outputs: sum, cout.","expected_output":"sum = a ^ b; cout = a \u0026 b.","starter_code":"module top(input a, input b, output sum, output cout);\n  // Write code here\nendmodule","solution_code":"module top(input a, input b, output sum, output cout);\n  assign sum  = a ^ b;\n  assign cout = a \u0026 b;\nendmodule","subject_id":1,"id":20},{"title":"Full Adder","prompt":"Add three 1-bit values (a, b, cin) producing sum and carry-out.","constraints":"Module name: top. Inputs: a, b, cin. Outputs: sum, cout.","expected_output":"sum = a^b^cin; cout = (a\u0026b)|(cin\u0026(a^b)).","starter_code":"module top(input a, input b, input cin, output sum, output cout);\n  // Write code here\nendmodule","solution_code":"module top(input a, input b, input cin, output sum, output cout);\n  assign sum  = a ^ b ^ cin;\n  assign cout = (a \u0026 b) | (cin \u0026 (a ^ b));\nendmodule","subject_id":1,"id":21},{"title":"4-bit Ripple Carry Adder","prompt":"Add two 4-bit numbers with carry-in, producing a 4-bit sum and carry-out.","constraints":"Module name: top. Inputs: a[3:0], b[3:0], cin. Outputs: sum[3:0], cout.","expected_output":"{cout, sum} = a + b + cin.","starter_code":"module top(input [3:0] a, input [3:0] b, input cin, output [3:0] sum, output cout);\n  // Write code here\nendmodule","solution_code":"module top(input [3:0] a, input [3:0] b, input cin, output [3:0] sum, output cout);\n  assign {cout, sum} = a + b + cin;\nendmodule","subject_id":1,"id":22},{"title":"4-bit Magnitude Comparator","prompt":"Compare two 4-bit numbers and assert gt, eq, lt.","constraints":"Module name: top. Inputs: a[3:0], b[3:0]. Outputs: gt, eq, lt.","expected_output":"gt=a\u003eb, eq=a==b, lt=a\u003cb (exactly one high).","starter_code":"module top(input [3:0] a, input [3:0] b, output gt, output eq, output lt);\n  // Write code here\nendmodule","solution_code":"module top(input [3:0] a, input [3:0] b, output gt, output eq, output lt);\n  assign gt = (a \u003e b);\n  assign eq = (a == b);\n  assign lt = (a \u003c b);\nendmodule","subject_id":1,"id":23},{"title":"D Latch (Level Sensitive)","prompt":"Build a transparent D latch: when enable is high q follows d; when low q holds.","constraints":"Module name: top. Inputs: en, d. Output: q. Use always @(*).","expected_output":"en=1 -\u003e q=d; en=0 -\u003e q unchanged.","starter_code":"module top(input en, input d, output reg q);\n  // Write code here\nendmodule","solution_code":"module top(input en, input d, output reg q);\n  always @(*)\n    if (en) q = d;\nendmodule","subject_id":1,"id":24},{"title":"D Flip-Flop with Async Reset","prompt":"Capture d on the rising clock edge; clear q to 0 asynchronously when rst_n is low.","constraints":"Module name: top. Inputs: clk, rst_n, d. Output: q. Use non-blocking.","expected_output":"On posedge clk, q\u003c=d; rst_n=0 forces q=0.","starter_code":"module top(input clk, input rst_n, input d, output reg q);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input d, output reg q);\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) q \u003c= 1\u0027b0;\n    else        q \u003c= d;\nendmodule","subject_id":1,"id":25},{"title":"JK Flip-Flop","prompt":"Implement a JK flip-flop: 00 hold, 01 reset, 10 set, 11 toggle.","constraints":"Module name: top. Inputs: clk, rst_n, j, k. Output: q.","expected_output":"q+ = j\u0026~q | ~k\u0026q.","starter_code":"module top(input clk, input rst_n, input j, input k, output reg q);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input j, input k, output reg q);\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) q \u003c= 1\u0027b0;\n    else        q \u003c= (j \u0026 ~q) | (~k \u0026 q);\nendmodule","subject_id":1,"id":26},{"title":"T Flip-Flop","prompt":"Toggle q on each clock edge when t=1, hold when t=0.","constraints":"Module name: top. Inputs: clk, rst_n, t. Output: q.","expected_output":"q+ = t ^ q.","starter_code":"module top(input clk, input rst_n, input t, output reg q);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input t, output reg q);\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) q \u003c= 1\u0027b0;\n    else        q \u003c= t ^ q;\nendmodule","subject_id":1,"id":27},{"title":"4-bit Shift Register (SISO)","prompt":"Shift serial input in by one position each clock; serial output is the last bit.","constraints":"Module name: top. Inputs: clk, rst_n, sin. Output: sout. 4-bit internal register, shift left.","expected_output":"Data appears at sout after 4 clocks.","starter_code":"module top(input clk, input rst_n, input sin, output sout);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input sin, output sout);\n  reg [3:0] sr;\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) sr \u003c= 4\u0027b0;\n    else        sr \u003c= {sr[2:0], sin};\n  assign sout = sr[3];\nendmodule","subject_id":1,"id":28},{"title":"4-bit Synchronous Up Counter","prompt":"Count 0..15 and wrap, with synchronous active-high clear.","constraints":"Module name: top. Inputs: clk, rst_n, clr. Output: cnt[3:0].","expected_output":"Increments each clock; clr forces 0.","starter_code":"module top(input clk, input rst_n, input clr, output reg [3:0] cnt);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input clr, output reg [3:0] cnt);\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n)   cnt \u003c= 4\u0027d0;\n    else if (clr) cnt \u003c= 4\u0027d0;\n    else          cnt \u003c= cnt + 4\u0027d1;\nendmodule","subject_id":1,"id":29},{"title":"Mod-10 (BCD) Counter","prompt":"Count 0..9 then wrap to 0, asserting tc on the count of 9.","constraints":"Module name: top. Inputs: clk, rst_n. Outputs: cnt[3:0], tc.","expected_output":"Sequence 0,1,...,9,0,...; tc=1 when cnt==9.","starter_code":"module top(input clk, input rst_n, output reg [3:0] cnt, output tc);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, output reg [3:0] cnt, output tc);\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n)        cnt \u003c= 4\u0027d0;\n    else if (cnt == 4\u0027d9) cnt \u003c= 4\u0027d0;\n    else               cnt \u003c= cnt + 4\u0027d1;\n  assign tc = (cnt == 4\u0027d9);\nendmodule","subject_id":1,"id":30},{"title":"4-bit Ring Counter","prompt":"Circulate a single 1 through a 4-bit register (one-hot), reset state 0001.","constraints":"Module name: top. Inputs: clk, rst_n. Output: q[3:0].","expected_output":"0001 -\u003e 0010 -\u003e 0100 -\u003e 1000 -\u003e 0001 ...","starter_code":"module top(input clk, input rst_n, output reg [3:0] q);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, output reg [3:0] q);\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) q \u003c= 4\u0027b0001;\n    else        q \u003c= {q[2:0], q[3]};\nendmodule","subject_id":1,"id":31},{"title":"Sequence Detector FSM (detect 1011)","prompt":"Assert detected for one cycle whenever the serial input bit stream contains the pattern 1011 (overlapping).","constraints":"Module name: top. Inputs: clk, rst_n, in. Output: detected. Mealy or Moore allowed.","expected_output":"detected pulses high when ...1011 is seen.","starter_code":"module top(input clk, input rst_n, input in, output reg detected);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input in, output reg detected);\n  localparam S0=2\u0027d0, S1=2\u0027d1, S10=2\u0027d2, S101=2\u0027d3;\n  reg [1:0] st, nx;\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) st \u003c= S0; else st \u003c= nx;\n  always @(*) begin\n    nx = st; detected = 1\u0027b0;\n    case (st)\n      S0:   nx = in ? S1   : S0;\n      S1:   nx = in ? S1   : S10;\n      S10:  nx = in ? S101 : S0;\n      S101: begin nx = in ? S1 : S10; detected = in; end\n    endcase\n  end\nendmodule","subject_id":1,"id":32},{"title":"Binary to Gray Code","prompt":"Convert a 4-bit binary number to Gray code.","constraints":"Module name: top. Input: bin[3:0]. Output: gray[3:0].","expected_output":"gray = bin ^ (bin \u003e\u003e 1).","starter_code":"module top(input [3:0] bin, output [3:0] gray);\n  // Write code here\nendmodule","solution_code":"module top(input [3:0] bin, output [3:0] gray);\n  assign gray = bin ^ (bin \u003e\u003e 1);\nendmodule","subject_id":2,"id":33},{"title":"Gray to Binary Code","prompt":"Convert a 4-bit Gray code value back to binary.","constraints":"Module name: top. Input: gray[3:0]. Output: bin[3:0].","expected_output":"Each binary bit is XOR of all higher Gray bits.","starter_code":"module top(input [3:0] gray, output [3:0] bin);\n  // Write code here\nendmodule","solution_code":"module top(input [3:0] gray, output [3:0] bin);\n  assign bin[3] = gray[3];\n  assign bin[2] = bin[3] ^ gray[2];\n  assign bin[1] = bin[2] ^ gray[1];\n  assign bin[0] = bin[1] ^ gray[0];\nendmodule","subject_id":2,"id":34},{"title":"Even Parity Generator","prompt":"Generate an even-parity bit for an 8-bit input.","constraints":"Module name: top. Input: data[7:0]. Output: parity.","expected_output":"parity = XOR of all 8 bits (1 if odd number of ones).","starter_code":"module top(input [7:0] data, output parity);\n  // Write code here\nendmodule","solution_code":"module top(input [7:0] data, output parity);\n  assign parity = ^data;\nendmodule","subject_id":2,"id":35},{"title":"Rising Edge Detector","prompt":"Output a one-cycle pulse when the input signal goes from 0 to 1.","constraints":"Module name: top. Inputs: clk, rst_n, sig. Output: pulse.","expected_output":"pulse high for one clock on each 0-\u003e1 transition of sig.","starter_code":"module top(input clk, input rst_n, input sig, output pulse);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input sig, output pulse);\n  reg sig_d;\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) sig_d \u003c= 1\u0027b0;\n    else        sig_d \u003c= sig;\n  assign pulse = sig \u0026 ~sig_d;\nendmodule","subject_id":2,"id":36},{"title":"Clock Divider by 2","prompt":"Generate an output clock at half the input frequency.","constraints":"Module name: top. Inputs: clk, rst_n. Output: clk_div2.","expected_output":"clk_div2 toggles once per input clock period (50% duty, f/2).","starter_code":"module top(input clk, input rst_n, output reg clk_div2);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, output reg clk_div2);\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) clk_div2 \u003c= 1\u0027b0;\n    else        clk_div2 \u003c= ~clk_div2;\nendmodule","subject_id":2,"id":37},{"title":"Parameterized N-bit Mux 2:1","prompt":"Implement a width-parameterized 2:1 multiplexer.","constraints":"Module name: top. Param WIDTH (default 8). Inputs: a[WIDTH-1:0], b[WIDTH-1:0], sel. Output: y[WIDTH-1:0].","expected_output":"y = sel ? b : a.","starter_code":"module top #(parameter WIDTH=8) (input [WIDTH-1:0] a, input [WIDTH-1:0] b, input sel, output [WIDTH-1:0] y);\n  // Write code here\nendmodule","solution_code":"module top #(parameter WIDTH=8) (input [WIDTH-1:0] a, input [WIDTH-1:0] b, input sel, output [WIDTH-1:0] y);\n  assign y = sel ? b : a;\nendmodule","subject_id":2,"id":38},{"title":"Traffic Light FSM","prompt":"Cycle a light through GREEN, YELLOW, RED, advancing one state per clock.","constraints":"Module name: top. Inputs: clk, rst_n. Output: light[1:0] (0=GREEN,1=YELLOW,2=RED).","expected_output":"GREEN -\u003e YELLOW -\u003e RED -\u003e GREEN ...","starter_code":"module top(input clk, input rst_n, output reg [1:0] light);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, output reg [1:0] light);\n  localparam GREEN=2\u0027d0, YELLOW=2\u0027d1, RED=2\u0027d2;\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) light \u003c= GREEN;\n    else case (light)\n      GREEN:  light \u003c= YELLOW;\n      YELLOW: light \u003c= RED;\n      RED:    light \u003c= GREEN;\n      default: light \u003c= GREEN;\n    endcase\nendmodule","subject_id":2,"id":39},{"title":"8-bit Barrel Shifter (Logical Left)","prompt":"Logically shift an 8-bit value left by a 3-bit amount.","constraints":"Module name: top. Inputs: din[7:0], shamt[2:0]. Output: dout[7:0].","expected_output":"dout = din \u003c\u003c shamt (zeros fill from the right).","starter_code":"module top(input [7:0] din, input [2:0] shamt, output [7:0] dout);\n  // Write code here\nendmodule","solution_code":"module top(input [7:0] din, input [2:0] shamt, output [7:0] dout);\n  assign dout = din \u003c\u003c shamt;\nendmodule","subject_id":2,"id":40},{"title":"Synchronous FIFO","prompt":"Design a synchronous FIFO with full/empty flags using always_ff.","constraints":"Module name: top. Params WIDTH, DEPTH (power of 2). Inputs: clk, rst_n, wr, rd, din. Outputs: dout, full, empty.","expected_output":"Writes when !full, reads when !empty; flags track occupancy.","starter_code":"module top #(parameter WIDTH=8, DEPTH=8) (input logic clk, rst_n, wr, rd, input logic [WIDTH-1:0] din, output logic [WIDTH-1:0] dout, output logic full, empty);\n  // Write code here\nendmodule","solution_code":"module top #(parameter WIDTH=8, DEPTH=8) (input logic clk, rst_n, wr, rd, input logic [WIDTH-1:0] din, output logic [WIDTH-1:0] dout, output logic full, empty);\n  localparam AW = $clog2(DEPTH);\n  logic [WIDTH-1:0] mem [0:DEPTH-1];\n  logic [AW:0] wptr, rptr;\n  assign empty = (wptr == rptr);\n  assign full  = (wptr[AW] != rptr[AW]) \u0026\u0026 (wptr[AW-1:0] == rptr[AW-1:0]);\n  assign dout  = mem[rptr[AW-1:0]];\n  always_ff @(posedge clk or negedge rst_n) begin\n    if (!rst_n) begin wptr \u003c= \u00270; rptr \u003c= \u00270; end\n    else begin\n      if (wr \u0026\u0026 !full) begin mem[wptr[AW-1:0]] \u003c= din; wptr \u003c= wptr + 1\u0027b1; end\n      if (rd \u0026\u0026 !empty) rptr \u003c= rptr + 1\u0027b1;\n    end\n  end\nendmodule","subject_id":4,"id":41},{"title":"Round-Robin Arbiter (4 requesters)","prompt":"Grant one of four requests in round-robin order, advancing priority after each grant.","constraints":"Module name: top. Inputs: clk, rst_n, req[3:0]. Output: gnt[3:0] (one-hot).","expected_output":"Exactly one grant; fairness rotates among active requesters.","starter_code":"module top(input logic clk, rst_n, input logic [3:0] req, output logic [3:0] gnt);\n  // Write code here\nendmodule","solution_code":"module top(input logic clk, rst_n, input logic [3:0] req, output logic [3:0] gnt);\n  logic [1:0] ptr;\n  always_ff @(posedge clk or negedge rst_n)\n    if (!rst_n) ptr \u003c= 2\u0027d0;\n    else if (|gnt) begin\n      casez (gnt)\n        4\u0027b0001: ptr \u003c= 2\u0027d1;\n        4\u0027b0010: ptr \u003c= 2\u0027d2;\n        4\u0027b0100: ptr \u003c= 2\u0027d3;\n        default: ptr \u003c= 2\u0027d0;\n      endcase\n    end\n  always_comb begin\n    gnt = 4\u0027b0000;\n    for (int i = 0; i \u003c 4; i++) begin\n      automatic int idx = (ptr + i) \u0026 2\u0027b11;\n      if (req[idx]) begin gnt[idx] = 1\u0027b1; break; end\n    end\n  end\nendmodule","subject_id":4,"id":42},{"title":"One-Hot FSM: Pulse Generator","prompt":"Using one-hot encoding, output a single-cycle pulse every 3rd clock.","constraints":"Module name: top. Inputs: clk, rst_n. Output: pulse. Use one-hot states.","expected_output":"pulse high once every three clocks.","starter_code":"module top(input logic clk, rst_n, output logic pulse);\n  // Write code here\nendmodule","solution_code":"module top(input logic clk, rst_n, output logic pulse);\n  typedef enum logic [2:0] {S0=3\u0027b001, S1=3\u0027b010, S2=3\u0027b100} st_t;\n  st_t st;\n  always_ff @(posedge clk or negedge rst_n)\n    if (!rst_n) st \u003c= S0;\n    else unique case (st)\n      S0: st \u003c= S1;\n      S1: st \u003c= S2;\n      S2: st \u003c= S0;\n      default: st \u003c= S0;\n    endcase\n  assign pulse = (st == S2);\nendmodule","subject_id":4,"id":43},{"title":"Assertion: Request Followed by Acknowledge","prompt":"Write a concurrent assertion that every req is acknowledged by ack within 1 to 4 cycles.","constraints":"Module name: top. Inputs: clk, rst_n, req, ack. Bind the property; disable during reset.","expected_output":"Property passes when ack arrives within 4 cycles of req.","starter_code":"module top(input clk, input rst_n, input req, input ack);\n  // Write an assert property here\nendmodule","solution_code":"module top(input clk, input rst_n, input req, input ack);\n  property p_req_ack;\n    @(posedge clk) disable iff (!rst_n)\n      req |-\u003e ##[1:4] ack;\n  endproperty\n  a_req_ack: assert property (p_req_ack);\nendmodule","subject_id":7,"id":44},{"title":"Assertion: One-Hot Check","prompt":"Assert that a 4-bit state vector is always exactly one-hot.","constraints":"Module name: top. Inputs: clk, rst_n, state[3:0]. Use $onehot.","expected_output":"Fails if zero or more than one bit is set.","starter_code":"module top(input clk, input rst_n, input [3:0] state);\n  // Write an assert property here\nendmodule","solution_code":"module top(input clk, input rst_n, input [3:0] state);\n  a_onehot: assert property (\n    @(posedge clk) disable iff (!rst_n) $onehot(state)\n  );\nendmodule","subject_id":7,"id":45},{"title":"Constrained Random Packet Class","prompt":"Create a transaction class with a random 8-bit length constrained to 1..64 and a 2-bit kind, and a method to print it.","constraints":"Class name: packet. Fields: rand len[7:0], rand kind[1:0]. Constraint len inside [1:64].","expected_output":"randomize() always yields 1\u003c=len\u003c=64.","starter_code":"class packet;\n  // declare fields, constraint, and a print() function\nendclass","solution_code":"class packet;\n  rand bit [7:0] len;\n  rand bit [1:0] kind;\n  constraint c_len { len inside {[1:64]}; }\n  function void print();\n    $display(\"packet kind=%0d len=%0d\", kind, len);\n  endfunction\nendclass","subject_id":5,"id":46},{"title":"UVM Sequence Body","prompt":"Write the body() of a uvm_sequence that creates, randomizes and sends 10 items.","constraints":"Sequence class my_seq #(my_item). Use start_item/finish_item and a loop of 10.","expected_output":"Ten randomized items are sent to the driver via the sequencer.","starter_code":"class my_seq extends uvm_sequence #(my_item);\n  `uvm_object_utils(my_seq)\n  function new(string name=\"my_seq\"); super.new(name); endfunction\n  task body();\n    // Write code here\n  endtask\nendclass","solution_code":"class my_seq extends uvm_sequence #(my_item);\n  `uvm_object_utils(my_seq)\n  function new(string name=\"my_seq\"); super.new(name); endfunction\n  task body();\n    repeat (10) begin\n      my_item it = my_item::type_id::create(\"it\");\n      start_item(it);\n      if (!it.randomize()) `uvm_error(\"SEQ\", \"randomize failed\")\n      finish_item(it);\n    end\n  endtask\nendclass","subject_id":6,"id":47},{"title":"APB Slave Read/Write","prompt":"Implement a simple APB slave with a single 32-bit register, supporting read and write with PREADY always high.","constraints":"Module name: top. APB inputs: pclk, presetn, psel, penable, pwrite, paddr, pwdata. Outputs: prdata, pready.","expected_output":"Write in access phase updates reg; read returns reg; pready=1.","starter_code":"module top(input pclk, input presetn, input psel, input penable, input pwrite, input [31:0] paddr, input [31:0] pwdata, output reg [31:0] prdata, output pready);\n  // Write code here\nendmodule","solution_code":"module top(input pclk, input presetn, input psel, input penable, input pwrite, input [31:0] paddr, input [31:0] pwdata, output reg [31:0] prdata, output pready);\n  reg [31:0] datareg;\n  assign pready = 1\u0027b1;\n  always @(posedge pclk or negedge presetn) begin\n    if (!presetn) datareg \u003c= 32\u0027d0;\n    else if (psel \u0026\u0026 penable \u0026\u0026 pwrite) datareg \u003c= pwdata;\n  end\n  always @(*) prdata = (psel \u0026\u0026 !pwrite) ? datareg : 32\u0027d0;\nendmodule","subject_id":9,"id":48},{"title":"Write Basic SDC Constraints","prompt":"Write the SDC commands to create a 100 MHz clock on port clk and set input/output delays of 2 ns relative to it.","constraints":"Use create_clock, set_input_delay, set_output_delay. Clock period 10 ns.","expected_output":"A 10 ns clock named clk with 2 ns IO delays on all inputs/outputs.","starter_code":"# Write your SDC constraints here\n# clock port: clk, all inputs: [all_inputs], all outputs: [all_outputs]","solution_code":"create_clock -name clk -period 10.0 [get_ports clk]\nset_input_delay  -clock clk 2.0 [all_inputs]\nset_output_delay -clock clk 2.0 [all_outputs]\nset_clock_uncertainty 0.2 [get_clocks clk]","subject_id":3,"id":49},{"title":"Wire (Pass-Through)","prompt":"Create a module with one input and one output that behaves like a wire.","constraints":"Use a continuous assignment.","expected_output":"out always equals in.","starter_code":"module top_module(input in, output out);\n  // TODO\nendmodule","solution_code":"module top_module(input in, output out);\n  assign out = in;\nendmodule","difficulty":"easy","is_premium":false,"subject_id":2,"id":50},{"title":"Constant Outputs","prompt":"Drive output zero to constant 0 and output one to constant 1.","constraints":"Use continuous assignments.","expected_output":"zero=0 and one=1 at all times.","starter_code":"module top_module(output zero, output one);\n  // TODO\nendmodule","solution_code":"module top_module(output zero, output one);\n  assign zero = 1\u0027b0;\n  assign one = 1\u0027b1;\nendmodule","difficulty":"easy","is_premium":false,"subject_id":2,"id":51},{"title":"NOT Gate","prompt":"Implement an inverter.","constraints":"Single continuous assignment.","expected_output":"out = NOT in.","starter_code":"module top_module(input in, output out);\n  // TODO\nendmodule","solution_code":"module top_module(input in, output out);\n  assign out = ~in;\nendmodule","difficulty":"easy","is_premium":false,"subject_id":2,"id":52},{"title":"2:1 Mux","prompt":"Build a 2:1 multiplexer selecting a or b based on sel.","constraints":"Use the conditional operator.","expected_output":"y = a when sel=0 else b.","starter_code":"module top_module(input a, input b, input sel, output y);\n  // TODO\nendmodule","solution_code":"module top_module(input a, input b, input sel, output y);\n  assign y = sel ? b : a;\nendmodule","difficulty":"easy","is_premium":false,"subject_id":2,"id":53},{"title":"4-bit AND","prompt":"Bitwise AND two 4-bit inputs.","constraints":"Vectors of width 4.","expected_output":"y[i] = a[i] \u0026 b[i].","starter_code":"module top_module(input [3:0] a, input [3:0] b, output [3:0] y);\n  // TODO\nendmodule","solution_code":"module top_module(input [3:0] a, input [3:0] b, output [3:0] y);\n  assign y = a \u0026 b;\nendmodule","difficulty":"easy","is_premium":false,"subject_id":2,"id":54},{"title":"Half Adder","prompt":"Create a half adder producing sum and carry.","constraints":"Use XOR and AND.","expected_output":"sum = a^b, cout = a\u0026b.","starter_code":"module top_module(input a, input b, output sum, output cout);\n  // TODO\nendmodule","solution_code":"module top_module(input a, input b, output sum, output cout);\n  assign sum = a ^ b;\n  assign cout = a \u0026 b;\nendmodule","difficulty":"easy","is_premium":false,"subject_id":2,"id":55},{"title":"Full Adder","prompt":"Create a full adder with carry-in.","constraints":"Use bitwise operators only.","expected_output":"sum = a^b^cin, cout = majority(a,b,cin).","starter_code":"module top_module(input a, input b, input cin, output sum, output cout);\n  // TODO\nendmodule","solution_code":"module top_module(input a, input b, input cin, output sum, output cout);\n  assign sum = a ^ b ^ cin;\n  assign cout = (a \u0026 b) | (b \u0026 cin) | (a \u0026 cin);\nendmodule","difficulty":"medium","is_premium":false,"subject_id":2,"id":56},{"title":"4-bit Ripple Adder","prompt":"Add two 4-bit numbers with carry out.","constraints":"You may use the + operator.","expected_output":"{cout,sum} = a + b + cin.","starter_code":"module top_module(input [3:0] a, input [3:0] b, input cin, output [3:0] sum, output cout);\n  // TODO\nendmodule","solution_code":"module top_module(input [3:0] a, input [3:0] b, input cin, output [3:0] sum, output cout);\n  assign {cout, sum} = a + b + cin;\nendmodule","difficulty":"medium","is_premium":false,"subject_id":2,"id":57},{"title":"D Flip-Flop With Async Reset","prompt":"Positive-edge DFF with active-low async reset.","constraints":"Non-blocking assignment in sequential block.","expected_output":"q\u003c=0 on reset else q\u003c=d at posedge clk.","starter_code":"module top_module(input clk, input rst_n, input d, output reg q);\n  // TODO\nendmodule","solution_code":"module top_module(input clk, input rst_n, input d, output reg q);\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) q \u003c= 1\u0027b0; else q \u003c= d;\nendmodule","difficulty":"medium","is_premium":false,"subject_id":2,"id":58},{"title":"Mod-10 Counter","prompt":"Design a synchronous decade counter (0-9) with sync reset.","constraints":"Wrap from 9 back to 0.","expected_output":"count cycles 0..9 then repeats.","starter_code":"module top_module(input clk, input reset, output reg [3:0] count);\n  // TODO\nendmodule","solution_code":"module top_module(input clk, input reset, output reg [3:0] count);\n  always @(posedge clk)\n    if (reset || count==4\u0027d9) count \u003c= 4\u0027d0; else count \u003c= count + 4\u0027d1;\nendmodule","difficulty":"medium","is_premium":false,"subject_id":2,"id":59},{"title":"4-to-1 Mux (Vectorized)","prompt":"Select one of four 8-bit inputs using a 2-bit select.","constraints":"Use a case statement.","expected_output":"out equals chosen input.","starter_code":"module top_module(input [1:0] sel, input [7:0] a, input [7:0] b, input [7:0] c, input [7:0] d, output reg [7:0] out);\n  // TODO\nendmodule","solution_code":"module top_module(input [1:0] sel, input [7:0] a, input [7:0] b, input [7:0] c, input [7:0] d, output reg [7:0] out);\n  always @(*) case(sel) 2\u0027d0:out=a; 2\u0027d1:out=b; 2\u0027d2:out=c; default:out=d; endcase\nendmodule","difficulty":"medium","is_premium":false,"subject_id":2,"id":60},{"title":"Sequence Detector 1011 (Overlapping)","prompt":"Detect the overlapping pattern 1011 on serial input using a Moore FSM.","constraints":"Assert detected for one cycle when pattern completes.","expected_output":"detected pulses when 1011 seen, overlap allowed.","starter_code":"module top_module(input clk, input rst_n, input din, output detected);\n  // TODO\nendmodule","solution_code":"module top_module(input clk, input rst_n, input din, output detected);\n  localparam S0=0,S1=1,S10=2,S101=3,S1011=4;\n  reg [2:0] st;\n  always @(posedge clk or negedge rst_n) begin\n    if(!rst_n) st\u003c=S0; else case(st)\n      S0: st \u003c= din?S1:S0;\n      S1: st \u003c= din?S1:S10;\n      S10: st \u003c= din?S101:S0;\n      S101: st \u003c= din?S1011:S10;\n      S1011: st \u003c= din?S1:S10;\n      default: st\u003c=S0;\n    endcase\n  end\n  assign detected = (st==S1011);\nendmodule","difficulty":"hard","is_premium":true,"subject_id":2,"id":61},{"title":"Parameterized Barrel Shifter","prompt":"Implement a combinational left rotate by a variable amount for WIDTH-bit data.","constraints":"Rotate (not shift); WIDTH is a power of two.","expected_output":"out = data rotated left by amt.","starter_code":"module top_module #(parameter WIDTH=8)(input [WIDTH-1:0] data, input [$clog2(WIDTH)-1:0] amt, output [WIDTH-1:0] out);\n  // TODO\nendmodule","solution_code":"module top_module #(parameter WIDTH=8)(input [WIDTH-1:0] data, input [$clog2(WIDTH)-1:0] amt, output [WIDTH-1:0] out);\n  assign out = (data \u003c\u003c amt) | (data \u003e\u003e (WIDTH-amt));\nendmodule","difficulty":"hard","is_premium":true,"subject_id":2,"id":62},{"title":"Synchronous FIFO Pointer Logic","prompt":"Implement full/empty generation for a synchronous FIFO of DEPTH using read/write pointers with an extra wrap bit.","constraints":"DEPTH is a power of two.","expected_output":"full and empty flags computed correctly.","starter_code":"module top_module #(parameter AW=4)(input clk, input rst_n, input wr, input rd, output full, output empty);\n  // TODO\nendmodule","solution_code":"module top_module #(parameter AW=4)(input clk, input rst_n, input wr, input rd, output full, output empty);\n  reg [AW:0] wptr, rptr;\n  always @(posedge clk or negedge rst_n) begin\n    if(!rst_n) begin wptr\u003c=0; rptr\u003c=0; end\n    else begin\n      if(wr \u0026\u0026 !full) wptr\u003c=wptr+1\u0027b1;\n      if(rd \u0026\u0026 !empty) rptr\u003c=rptr+1\u0027b1;\n    end\n  end\n  assign empty = (wptr==rptr);\n  assign full = (wptr[AW]!=rptr[AW]) \u0026\u0026 (wptr[AW-1:0]==rptr[AW-1:0]);\nendmodule","difficulty":"hard","is_premium":true,"subject_id":2,"id":63},{"title":"[Interview] 4-bit Carry-Lookahead Adder","prompt":"Design a 4-bit carry-lookahead adder using generate (G=a\u0026b) and propagate (P=a^b) terms. Compute all carries in parallel.","constraints":"No ripple carry; carries must be combinational from G/P.","expected_output":"sum[3:0] and cout match a+b+cin for all inputs.","starter_code":"module cla4(input [3:0] a,b, input cin, output [3:0] sum, output cout);\n  // your code\nendmodule","solution_code":"module cla4(input [3:0] a,b, input cin, output [3:0] sum, output cout);\n  wire [3:0] g = a \u0026 b;\n  wire [3:0] p = a ^ b;\n  wire [4:0] c;\n  assign c[0]=cin;\n  assign c[1]=g[0]|(p[0]\u0026c[0]);\n  assign c[2]=g[1]|(p[1]\u0026c[1]);\n  assign c[3]=g[2]|(p[2]\u0026c[2]);\n  assign c[4]=g[3]|(p[3]\u0026c[3]);\n  assign sum=p^c[3:0];\n  assign cout=c[4];\nendmodule","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Intel, Nvidia","topic":"Adders","test_cases":[{"name":"zero","input":"a=0,b=0,cin=0","expected":"sum=0,cout=0"},{"name":"simple","input":"a=3,b=4,cin=0","expected":"sum=7,cout=0"},{"name":"carry","input":"a=15,b=1,cin=0","expected":"sum=0,cout=1"},{"name":"cin","input":"a=15,b=0,cin=1","expected":"sum=0,cout=1"}],"subject_id":1,"id":64},{"title":"[Interview] Synchronous FIFO (depth 8)","prompt":"Implement a synchronous FIFO with full/empty flags, width 8, depth 8.","constraints":"Single clock; no overflow/underflow; use a read and write pointer with a count.","expected_output":"Data read out in the same order written; full at 8 entries, empty at 0.","starter_code":"module fifo8(input clk, rst_n, wr, rd, input [7:0] din,\n             output reg [7:0] dout, output full, empty);\n  // your code\nendmodule","solution_code":"module fifo8(input clk, rst_n, wr, rd, input [7:0] din, output reg [7:0] dout, output full, empty);\n  reg [7:0] mem [0:7]; reg [3:0] cnt; reg [2:0] wp, rp;\n  assign full = (cnt==8); assign empty=(cnt==0);\n  always @(posedge clk or negedge rst_n) begin\n    if(!rst_n) begin cnt\u003c=0; wp\u003c=0; rp\u003c=0; end\n    else begin\n      if(wr\u0026\u0026!full) begin mem[wp]\u003c=din; wp\u003c=wp+1; end\n      if(rd\u0026\u0026!empty) begin dout\u003c=mem[rp]; rp\u003c=rp+1; end\n      case({wr\u0026\u0026!full, rd\u0026\u0026!empty})\n        2\u0027b10: cnt\u003c=cnt+1; 2\u0027b01: cnt\u003c=cnt-1; default: cnt\u003c=cnt; endcase\n    end\n  end\nendmodule","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Qualcomm, AMD","topic":"FIFO","test_cases":[{"name":"empty_on_reset","input":"after reset","expected":"empty=1,full=0"},{"name":"order","input":"write 1,2,3 then read","expected":"read 1,2,3 in order"},{"name":"full","input":"write 8 items","expected":"full=1"},{"name":"no_underflow","input":"read when empty","expected":"dout unchanged, empty stays 1"}],"subject_id":2,"id":65},{"title":"[Interview] Sequence Detector 1011 (overlapping)","prompt":"Design a Moore/Mealy FSM that asserts \u0027found\u0027 when the serial input produces the pattern 1011 (overlapping allowed).","constraints":"One bit per clock; overlapping matches counted.","expected_output":"found=1 the cycle the pattern completes.","starter_code":"module seq1011(input clk, rst_n, x, output found);\n  // your code\nendmodule","solution_code":"module seq1011(input clk, rst_n, x, output found);\n  localparam S0=0,S1=1,S10=2,S101=3;\n  reg [1:0] st;\n  always @(posedge clk or negedge rst_n)\n    if(!rst_n) st\u003c=S0;\n    else case(st)\n      S0:  st \u003c= x?S1:S0;\n      S1:  st \u003c= x?S1:S10;\n      S10: st \u003c= x?S101:S0;\n      S101:st \u003c= x?S1:S10;\n    endcase\n  assign found = (st==S101) \u0026 x;\nendmodule","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Intel, Nvidia","topic":"FSM","test_cases":[{"name":"basic","input":"1011","expected":"found pulses on last bit"},{"name":"overlap","input":"1011011","expected":"found twice"},{"name":"none","input":"0000","expected":"found never"}],"subject_id":2,"id":66},{"title":"[Interview] Compute Max Frequency","prompt":"Given Tcq=0.2ns, Tlogic=1.5ns, Tsetup=0.1ns, Tskew=0.05ns, write a function/expression for the minimum clock period and Fmax.","constraints":"Use the setup equation Tclk+Tskew \u003e= Tcq+Tlogic+Tsetup.","expected_output":"Tclk_min = 1.75ns, Fmax ~ 571 MHz.","starter_code":"// Express Tclk_min and Fmax\n// Tclk_min = ?\n// Fmax = 1/Tclk_min","solution_code":"// Tclk_min = Tcq+Tlogic+Tsetup-Tskew = 0.2+1.5+0.1-0.05 = 1.75 ns\n// Fmax = 1/1.75ns = 571.4 MHz","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Qualcomm","topic":"Fmax","test_cases":[{"name":"period","input":"given delays","expected":"1.75ns"},{"name":"fmax","input":"1/period","expected":"~571MHz"}],"subject_id":3,"id":67},{"title":"[Interview] Parameterized Priority Encoder","prompt":"Write a parameterized WIDTH-bit priority encoder returning the index of the highest set bit and a valid flag.","constraints":"Use always_comb; handle the all-zero case with valid=0.","expected_output":"idx = position of MSB that is 1; valid=|in.","starter_code":"module prio_enc #(parameter WIDTH=8)(input logic [WIDTH-1:0] in,\n  output logic [$clog2(WIDTH)-1:0] idx, output logic valid);\n  // your code\nendmodule","solution_code":"module prio_enc #(parameter WIDTH=8)(input logic [WIDTH-1:0] in, output logic [$clog2(WIDTH)-1:0] idx, output logic valid);\n  always_comb begin\n    idx = \u00270; valid = 1\u0027b0;\n    for (int i=0;i\u003cWIDTH;i++) if (in[i]) begin idx=i[$clog2(WIDTH)-1:0]; valid=1\u0027b1; end\n  end\nendmodule","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Nvidia, AMD","topic":"Encoders","test_cases":[{"name":"msb","input":"in=8\u0027b0010_1000","expected":"idx=5,valid=1"},{"name":"zero","input":"in=0","expected":"valid=0"},{"name":"lsb","input":"in=8\u0027b0000_0001","expected":"idx=0,valid=1"}],"subject_id":4,"id":68},{"title":"[Interview] Constrained-Random Packet Class","prompt":"Write a SystemVerilog class for a packet with rand length (1..64) and a payload array; add a constraint that even lengths are twice as likely as odd.","constraints":"Use rand, constraint blocks and dist.","expected_output":"randomize() produces legal packets with the required distribution.","starter_code":"class packet;\n  rand int len;\n  // constraints\nendclass","solution_code":"class packet;\n  rand int len;\n  rand byte payload[];\n  constraint c_len { len inside {[1:64]}; }\n  constraint c_dist { len dist { [1:64:/2] :/ 2 }; }\n  constraint c_size { payload.size() == len; }\nendclass","difficulty":"hard","is_interview":true,"is_premium":true,"company":"Intel","topic":"Randomization","test_cases":[{"name":"range","input":"randomize x1000","expected":"all len in 1..64"},{"name":"size","input":"any solve","expected":"payload.size()==len"}],"subject_id":5,"id":69},{"title":"[Interview] UVM Driver run_phase Skeleton","prompt":"Write the run_phase of a UVM driver that pulls items from the sequencer and drives them, using get_next_item/item_done.","constraints":"Use seq_item_port; honor the handshake with item_done.","expected_output":"Driver continuously fetches and drives transactions.","starter_code":"task run_phase(uvm_phase phase);\n  // your code\nendtask","solution_code":"task run_phase(uvm_phase phase);\n  forever begin\n    seq_item_port.get_next_item(req);\n    drive_item(req);        // user task to wiggle pins\n    seq_item_port.item_done();\n  end\nendtask","difficulty":"medium","is_interview":true,"is_premium":true,"company":"Qualcomm, Nvidia","topic":"Driver","test_cases":[{"name":"loop","input":"sequence of N items","expected":"all N driven and item_done called"}],"subject_id":6,"id":70},{"title":"[Interview] Request-Grant Property","prompt":"Write a concurrent assertion: every req must be followed by gnt within 1 to 4 cycles, disabled during reset.","constraints":"Use disable iff and a delay range.","expected_output":"Assertion fails if gnt does not arrive within the window.","starter_code":"// property p_req_gnt; ... endproperty\n// assert property (...);","solution_code":"property p_req_gnt;\n  @(posedge clk) disable iff(!rst_n)\n  req |-\u003e ##[1:4] gnt;\nendproperty\nassert property (p_req_gnt);","difficulty":"medium","is_interview":true,"is_premium":true,"company":"AMD","topic":"Properties","test_cases":[{"name":"in_window","input":"req then gnt @+2","expected":"pass"},{"name":"too_late","input":"req then gnt @+6","expected":"fail"},{"name":"reset","input":"req during reset","expected":"disabled (no fail)"}],"subject_id":7,"id":71},{"title":"[Interview] AXI-Lite Write Handshake FSM","prompt":"Design the slave-side write FSM for AXI4-Lite: accept AW and W, then issue B (OKAY).","constraints":"Use VALID/READY on AW, W, B; single transfers only.","expected_output":"After AW and W are accepted, BVALID asserts with BRESP=OKAY until BREADY.","starter_code":"module axil_wr(input clk,rst_n, input awvalid,wvalid,bready,\n  output reg awready,wready,bvalid, output [1:0] bresp);\n  // your code\nendmodule","solution_code":"module axil_wr(input clk,rst_n, input awvalid,wvalid,bready, output reg awready,wready,bvalid, output [1:0] bresp);\n  assign bresp=2\u0027b00; // OKAY\n  reg got_aw, got_w;\n  always @(posedge clk or negedge rst_n) begin\n    if(!rst_n) begin awready\u003c=0;wready\u003c=0;bvalid\u003c=0;got_aw\u003c=0;got_w\u003c=0; end\n    else begin\n      awready \u003c= awvalid \u0026 ~got_aw;\n      wready  \u003c= wvalid  \u0026 ~got_w;\n      if(awvalid\u0026\u0026awready) got_aw\u003c=1;\n      if(wvalid\u0026\u0026wready)   got_w\u003c=1;\n      if(got_aw\u0026\u0026got_w\u0026\u0026!bvalid) bvalid\u003c=1;\n      if(bvalid\u0026\u0026bready) begin bvalid\u003c=0; got_aw\u003c=0; got_w\u003c=0; end\n    end\n  end\nendmodule","difficulty":"hard","is_interview":true,"is_premium":true,"company":"ARM, Qualcomm","topic":"AXI-Lite","test_cases":[{"name":"write","input":"AW+W accepted","expected":"BVALID with OKAY"},{"name":"complete","input":"BREADY asserted","expected":"BVALID drops, ready for next"}],"subject_id":9,"id":72},{"title":"Multi-Clock SDC Setup","prompt":"Define two clocks: a 500 MHz core clock on port clk_core and a 200 MHz IO clock on port clk_io, and mark them asynchronous to each other.","constraints":"Use create_clock and set_clock_groups -asynchronous.","expected_output":"Two named clocks with correct periods; cross-clock paths are not timed.","starter_code":"# Write your SDC here\n# clk_core = 500 MHz (2 ns), clk_io = 200 MHz (5 ns)","solution_code":"create_clock -name clk_core -period 2.0 [get_ports clk_core]\ncreate_clock -name clk_io   -period 5.0 [get_ports clk_io]\nset_clock_groups -asynchronous \\\n  -group {clk_core} -group {clk_io}","subject_id":8,"id":73},{"title":"False Path and Multicycle Path","prompt":"Constrain a reset net to be a false path and allow a slow datapath reg2reg to take 2 cycles.","constraints":"Use set_false_path for rst_n and set_multicycle_path 2 (setup) with the matching hold exception.","expected_output":"Reset is not timed; the multicycle path is checked over 2 cycles.","starter_code":"# Write the timing exceptions here","solution_code":"set_false_path -from [get_ports rst_n]\nset_multicycle_path 2 -setup -from [get_pins src_reg/Q] -to [get_pins dst_reg/D]\nset_multicycle_path 1 -hold  -from [get_pins src_reg/Q] -to [get_pins dst_reg/D]","subject_id":8,"id":74},{"title":"Generated (Divided) Clock","prompt":"A flop divides clk by 2 to produce clk_div at its Q pin. Define the generated clock for STA.","constraints":"Use create_generated_clock -divide_by 2 referencing the master clock clk.","expected_output":"STA sees clk_div as clk/2 derived from clk.","starter_code":"# Master clock clk already defined on port clk\n# Define the generated clock on div_reg/Q","solution_code":"create_generated_clock -name clk_div \\\n  -source [get_ports clk] -divide_by 2 \\\n  [get_pins div_reg/Q]","subject_id":8,"id":75},{"title":"Input/Output Delay Budget","prompt":"Set input delay 1.5 ns and output delay 1.2 ns on all data ports relative to clk, and a max transition of 0.3 ns.","constraints":"Use set_input_delay, set_output_delay, set_max_transition.","expected_output":"IO timing budgets and a transition design rule are applied.","starter_code":"# clk already created with create_clock\n# Write the IO and DRC constraints","solution_code":"set_input_delay  -clock clk 1.5 [remove_from_collection [all_inputs] [get_ports clk]]\nset_output_delay -clock clk 1.2 [all_outputs]\nset_max_transition 0.3 [current_design]","subject_id":8,"id":76},{"title":"Clock Uncertainty (Skew + Jitter)","prompt":"Apply 0.15 ns setup uncertainty and 0.05 ns hold uncertainty to model skew and jitter on clk.","constraints":"Use set_clock_uncertainty with -setup and -hold.","expected_output":"Available period is reduced for setup and increased margin required for hold.","starter_code":"# clk already defined\n# Write the uncertainty constraints","solution_code":"set_clock_uncertainty -setup 0.15 [get_clocks clk]\nset_clock_uncertainty -hold  0.05 [get_clocks clk]","subject_id":8,"id":77},{"title":"Two-Flop Synchronizer","prompt":"Synchronize an asynchronous 1-bit signal into the clk domain using two flip-flops.","constraints":"Module name: top. Inputs: clk, rst_n, async_in. Output: sync_out.","expected_output":"sync_out is async_in delayed by two clk cycles, metastability-hardened.","starter_code":"module top(input clk, input rst_n, input async_in, output sync_out);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input async_in, output sync_out);\n  reg s1, s2;\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) {s2, s1} \u003c= 2\u0027b00;\n    else        {s2, s1} \u003c= {s1, async_in};\n  assign sync_out = s2;\nendmodule","subject_id":10,"id":78},{"title":"Divisible-by-3 FSM","prompt":"Read a serial bit stream MSB-first and assert div3 when the number seen so far is divisible by 3.","constraints":"Module name: top. Inputs: clk, rst_n, in. Output: div3. Track remainder mod 3.","expected_output":"div3=1 whenever the accumulated value % 3 == 0.","starter_code":"module top(input clk, input rst_n, input in, output div3);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input in, output div3);\n  reg [1:0] rem;\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) rem \u003c= 2\u0027d0;\n    else case ({rem, in})\n      3\u0027b00_0: rem \u003c= 2\u0027d0; 3\u0027b00_1: rem \u003c= 2\u0027d1;\n      3\u0027b01_0: rem \u003c= 2\u0027d2; 3\u0027b01_1: rem \u003c= 2\u0027d0;\n      3\u0027b10_0: rem \u003c= 2\u0027d1; 3\u0027b10_1: rem \u003c= 2\u0027d2;\n      default: rem \u003c= 2\u0027d0;\n    endcase\n  assign div3 = (rem == 2\u0027d0);\nendmodule","subject_id":10,"id":79},{"title":"Population Count (Ones Counter)","prompt":"Count the number of 1s in an 8-bit input.","constraints":"Module name: top. Input: data[7:0]. Output: count[3:0].","expected_output":"count = number of set bits (0..8).","starter_code":"module top(input [7:0] data, output [3:0] count);\n  // Write code here\nendmodule","solution_code":"module top(input [7:0] data, output [3:0] count);\n  integer i;\n  reg [3:0] c;\n  always @(*) begin\n    c = 4\u0027d0;\n    for (i = 0; i \u003c 8; i = i + 1) c = c + data[i];\n  end\n  assign count = c;\nendmodule","subject_id":10,"id":80},{"title":"Find First Set (Lowest Set Bit Index)","prompt":"Return the index of the lowest set bit of an 8-bit input, with a valid flag.","constraints":"Module name: top. Input: data[7:0]. Outputs: idx[2:0], valid.","expected_output":"idx points to the LSB-most 1; valid=0 if data==0.","starter_code":"module top(input [7:0] data, output reg [2:0] idx, output reg valid);\n  // Write code here\nendmodule","solution_code":"module top(input [7:0] data, output reg [2:0] idx, output reg valid);\n  integer i;\n  always @(*) begin\n    idx = 3\u0027d0; valid = 1\u0027b0;\n    for (i = 7; i \u003e= 0; i = i - 1)\n      if (data[i]) begin idx = i[2:0]; valid = 1\u0027b1; end\n  end\nendmodule","subject_id":10,"id":81},{"title":"Gray Code Counter","prompt":"Build a 4-bit counter that outputs values in Gray-code order.","constraints":"Module name: top. Inputs: clk, rst_n. Output: gray[3:0].","expected_output":"Successive outputs differ by exactly one bit.","starter_code":"module top(input clk, input rst_n, output [3:0] gray);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, output [3:0] gray);\n  reg [3:0] bin;\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) bin \u003c= 4\u0027d0;\n    else        bin \u003c= bin + 4\u0027d1;\n  assign gray = bin ^ (bin \u003e\u003e 1);\nendmodule","subject_id":10,"id":82},{"title":"Switch Debouncer","prompt":"Debounce a noisy button: output stays stable and only updates after the input is steady for N samples.","constraints":"Module name: top. Inputs: clk, rst_n, noisy. Output: clean. Use a saturating counter (N=4).","expected_output":"clean follows noisy only after 4 consecutive equal samples.","starter_code":"module top(input clk, input rst_n, input noisy, output reg clean);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input noisy, output reg clean);\n  reg [1:0] cnt;\n  reg sync;\n  always @(posedge clk or negedge rst_n) begin\n    if (!rst_n) begin cnt \u003c= 2\u0027d0; clean \u003c= 1\u0027b0; sync \u003c= 1\u0027b0; end\n    else begin\n      sync \u003c= noisy;\n      if (sync == clean) cnt \u003c= 2\u0027d0;\n      else if (cnt == 2\u0027d3) begin clean \u003c= sync; cnt \u003c= 2\u0027d0; end\n      else cnt \u003c= cnt + 2\u0027d1;\n    end\n  end\nendmodule","subject_id":10,"id":83},{"title":"Glitch-Free Clock Multiplexer","prompt":"Select between two clocks clk0 and clk1 without producing glitches on clk_out.","constraints":"Module name: top. Inputs: clk0, clk1, rst_n, sel. Output: clk_out. Use the standard gated-handshake mux.","expected_output":"Output switches cleanly only when the target clock is low.","starter_code":"module top(input clk0, input clk1, input rst_n, input sel, output clk_out);\n  // Write code here\nendmodule","solution_code":"module top(input clk0, input clk1, input rst_n, input sel, output clk_out);\n  reg q0a, q0b, q1a, q1b;\n  // path 0 enabled when sel=0 and clk1 path is off\n  always @(posedge clk0 or negedge rst_n)\n    if (!rst_n) q0a \u003c= 1\u0027b0; else q0a \u003c= ~sel \u0026 ~q1b;\n  always @(negedge clk0 or negedge rst_n)\n    if (!rst_n) q0b \u003c= 1\u0027b0; else q0b \u003c= q0a;\n  // path 1 enabled when sel=1 and clk0 path is off\n  always @(posedge clk1 or negedge rst_n)\n    if (!rst_n) q1a \u003c= 1\u0027b0; else q1a \u003c= sel \u0026 ~q0b;\n  always @(negedge clk1 or negedge rst_n)\n    if (!rst_n) q1b \u003c= 1\u0027b0; else q1b \u003c= q1a;\n  assign clk_out = (clk0 \u0026 q0b) | (clk1 \u0026 q1b);\nendmodule","subject_id":11,"id":84},{"title":"Clock Gating Cell (Latch-Based)","prompt":"Implement an integrated clock-gating cell: gate clk with enable, using a low-active latch to avoid glitches.","constraints":"Module name: top. Inputs: clk, en. Output: gclk. Latch en on the low phase of clk.","expected_output":"gclk pulses only when enable was sampled high; no partial clock pulses.","starter_code":"module top(input clk, input en, output gclk);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input en, output gclk);\n  reg en_lat;\n  always @(*)\n    if (!clk) en_lat = en;   // transparent when clk low\n  assign gclk = clk \u0026 en_lat;\nendmodule","subject_id":11,"id":85},{"title":"Pulse Synchronizer (Toggle Handshake)","prompt":"Pass a single-cycle pulse from a fast source clock to a slower destination clock safely.","constraints":"Module name: top. Inputs: sclk, dclk, rst_n, pulse_in. Output: pulse_out. Use toggle + 2-flop sync + edge detect.","expected_output":"Each src pulse produces exactly one dst pulse.","starter_code":"module top(input sclk, input dclk, input rst_n, input pulse_in, output pulse_out);\n  // Write code here\nendmodule","solution_code":"module top(input sclk, input dclk, input rst_n, input pulse_in, output pulse_out);\n  reg tog;\n  always @(posedge sclk or negedge rst_n)\n    if (!rst_n) tog \u003c= 1\u0027b0; else if (pulse_in) tog \u003c= ~tog;\n  reg s1, s2, s3;\n  always @(posedge dclk or negedge rst_n)\n    if (!rst_n) {s3, s2, s1} \u003c= 3\u0027b000;\n    else        {s3, s2, s1} \u003c= {s2, s1, tog};\n  assign pulse_out = s3 ^ s2;\nendmodule","subject_id":11,"id":86},{"title":"Low-Power Counter with Enable","prompt":"Build an 8-bit counter that only toggles flops when count_en is high (clock-enable style, saves power).","constraints":"Module name: top. Inputs: clk, rst_n, count_en. Output: cnt[7:0].","expected_output":"cnt holds when count_en=0, increments when count_en=1.","starter_code":"module top(input clk, input rst_n, input count_en, output reg [7:0] cnt);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input count_en, output reg [7:0] cnt);\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n)        cnt \u003c= 8\u0027d0;\n    else if (count_en) cnt \u003c= cnt + 8\u0027d1;\nendmodule","subject_id":11,"id":87},{"title":"Valid-Ready Skid Buffer","prompt":"Implement a 1-deep skid buffer that registers a valid/ready stream without dropping data when downstream stalls.","constraints":"Module name: top. Inputs: clk, rst_n, in_valid, in_data[7:0], out_ready. Outputs: in_ready, out_valid, out_data[7:0].","expected_output":"No data loss; in_ready deasserts when the buffer is full and downstream is stalled.","starter_code":"module top(input clk, input rst_n, input in_valid, input [7:0] in_data, input out_ready, output in_ready, output out_valid, output [7:0] out_data);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input in_valid, input [7:0] in_data, input out_ready, output in_ready, output out_valid, output [7:0] out_data);\n  reg full;\n  reg [7:0] buf_data;\n  assign in_ready  = !full;\n  assign out_valid = full;\n  assign out_data  = buf_data;\n  always @(posedge clk or negedge rst_n) begin\n    if (!rst_n) begin full \u003c= 1\u0027b0; buf_data \u003c= 8\u0027d0; end\n    else begin\n      if (in_valid \u0026\u0026 in_ready) begin buf_data \u003c= in_data; full \u003c= 1\u0027b1; end\n      else if (out_valid \u0026\u0026 out_ready) full \u003c= 1\u0027b0;\n    end\n  end\nendmodule","subject_id":12,"id":88},{"title":"One-Hot to Binary Encoder","prompt":"Convert an 8-bit one-hot input to a 3-bit binary index.","constraints":"Module name: top. Input: onehot[7:0] (exactly one bit set). Output: bin[2:0].","expected_output":"bin = index of the set bit.","starter_code":"module top(input [7:0] onehot, output reg [2:0] bin);\n  // Write code here\nendmodule","solution_code":"module top(input [7:0] onehot, output reg [2:0] bin);\n  integer i;\n  always @(*) begin\n    bin = 3\u0027d0;\n    for (i = 0; i \u003c 8; i = i + 1)\n      if (onehot[i]) bin = i[2:0];\n  end\nendmodule","subject_id":12,"id":89},{"title":"Pipelined 8-bit Adder (2 stages)","prompt":"Add two 8-bit numbers with one pipeline register so the sum appears one cycle later.","constraints":"Module name: top. Inputs: clk, rst_n, a[7:0], b[7:0]. Output: sum[8:0] (registered).","expected_output":"sum = a + b, delayed by one clock.","starter_code":"module top(input clk, input rst_n, input [7:0] a, input [7:0] b, output reg [8:0] sum);\n  // Write code here\nendmodule","solution_code":"module top(input clk, input rst_n, input [7:0] a, input [7:0] b, output reg [8:0] sum);\n  always @(posedge clk or negedge rst_n)\n    if (!rst_n) sum \u003c= 9\u0027d0;\n    else        sum \u003c= a + b;\nendmodule","subject_id":12,"id":90},{"title":"Fixed-Priority Arbiter (4 requests)","prompt":"Grant the lowest-index active request among four; lower index has higher priority.","constraints":"Module name: top. Input: req[3:0]. Output: gnt[3:0] (one-hot, at most one set).","expected_output":"gnt selects the lowest-index requesting bit.","starter_code":"module top(input [3:0] req, output [3:0] gnt);\n  // Write code here\nendmodule","solution_code":"module top(input [3:0] req, output [3:0] gnt);\n  assign gnt[0] = req[0];\n  assign gnt[1] = req[1] \u0026 ~req[0];\n  assign gnt[2] = req[2] \u0026 ~req[1] \u0026 ~req[0];\n  assign gnt[3] = req[3] \u0026 ~req[2] \u0026 ~req[1] \u0026 ~req[0];\nendmodule","subject_id":12,"id":91}]};
